-- Poems batch 304
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('671a0262-89c6-4640-a510-dbd8270b85df','再赴蒲津陪解梁張守安邑王宰游靜林','范純仁','宋','宋诗','song-poetry','','[]','千騎翩翩逐郡侯，條山重繼昔年遊。',64,'全唐诗/poet.song.36000.json','["千騎翩翩逐郡侯，條山重繼昔年遊。", "翠深疊嶂煙嵐晚，綠滿長郊稼穡秋。", "勝概不知行客老，征驂聊爲主人留。", "預思別後登臨處，應見黄河入海流。"]'),
('c1861964-2f6f-49fb-be9f-e424d54dcc81','贈張大夫','范純仁','宋','宋诗','song-poetry','','[]','白首衰顔愧復來，當時懷抱向誰開。',64,'全唐诗/poet.song.36000.json','["白首衰顔愧復來，當時懷抱向誰開。", "登臨彷彿驚前夢，遊賞從容憶舊臺。", "旨酒欲斟懷老伴，高吟難敵想天才。", "會須早逐君歸去，茅屋荒田半草萊。"]'),
('473e7110-8118-47a9-b163-75f51d2cdace','寄上文潞公','范純仁','宋','宋诗','song-poetry','','[]','孫閣重登愧玳簪，情同倦翼託高林。',64,'全唐诗/poet.song.36000.json','["孫閣重登愧玳簪，情同倦翼託高林。", "嵩邙未敵仁基厚，河洛寧如福海深。", "善教每聞當鏤骨，重知難報欲霑襟。", "至誠懷德逾饑渴，不比尋常勢利心。"]'),
('17d2678d-eb65-471f-bdc3-b455aff04650','寄上西京留守子華相公','范純仁','宋','宋诗','song-poetry','','[]','疏頑曾是費鑪錘，從昔叨蒙國士知。',64,'全唐诗/poet.song.36000.json','["疏頑曾是費鑪錘，從昔叨蒙國士知。", "一阻門牆驚歲月，幾回魂夢到嵩伊。", "神僊客佩黄金印，燕趙人斟白玉巵。", "薄宦浪拋東閣去，君恩未報歎衰遲。"]'),
('a8739559-da36-4020-96f3-8dcf4b598fb0','寄鮮于子駿西臺','范純仁','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','僚友難逢不世賢，洛臺經歲共清閒。',64,'全唐诗/poet.song.36000.json','["僚友難逢不世賢，洛臺經歲共清閒。", "蒹葭豈合依良玉，培塿何能望泰山。", "直道難堪從俗尚，清新原足重人間。", "期君致主登廊廟，茅屋荒田我自還。"]'),
('c49a5305-a842-4399-b903-3daafe381860','和薛中散踏青詞','范純仁','宋','宋诗','song-poetry','','[]','遶郭依依柳漸青，綺羅深處畫船橫。',32,'全唐诗/poet.song.36000.json','["遶郭依依柳漸青，綺羅深處畫船橫。", "坐中唯欠賢鄉老，把酒向風無限情。"]'),
('015abd4e-93b3-4174-8480-4a5b55a14921','寄和子華相公王園賞梅','范純仁','宋','宋诗','song-poetry','','[]','玉艷霜葩萬朵攢，曾陪宴席醉中看。',32,'全唐诗/poet.song.36000.json','["玉艷霜葩萬朵攢，曾陪宴席醉中看。", "西州縱有尋花處，亦待頑童格舞干。"]'),
('027ff0da-d5ea-4d14-b70f-20b031b619e2','題河中府名閫堂','范純仁','宋','宋诗','song-poetry','','[]','誰擘中條太華開，萬家填郭聳樓臺。',64,'全唐诗/poet.song.36000.json','["誰擘中條太華開，萬家填郭聳樓臺。", "嶽呈仙掌日邊見，河瀉龍門天上來。", "煙靄遠分秦甸闊，山川都抱舜城回。", "堅碑應是當年石，重見吾皇詠起哉。"]'),
('a7d7a728-3164-41b4-83c7-d857ff0b0817','寄題張運使先壠永慕亭','范純仁','宋','宋诗','song-poetry','','[]','武夷山色倚天青，中有賢儒謝世榮。',64,'全唐诗/poet.song.36000.json','["武夷山色倚天青，中有賢儒謝世榮。", "自以高名傳積慶，不教黄壤掩清名。", "構亭傍壠同虛寢，陟岵無時見孝誠。", "寧獨顯親由富貴，還能厚德庇群生。"]'),
('19f07122-801b-46ed-b45c-ce4002a59d5f','入河中府','范純仁','宋','宋诗','song-poetry','','[]','道傍禾忝穗交垂，旌旆紛紛曳綵霓。',64,'全唐诗/poet.song.36000.json','["道傍禾忝穗交垂，旌旆紛紛曳綵霓。", "山夾兩河嗟地險，雲埋萬堞覺城低。", "十年不到身如夢，五馬重來路欲迷。", "却據歸鞍下長坂，轅門迎謁引行齊。"]'),
('45aa8c7a-3a7a-42ca-b247-6e4d0135164b','謝張解州作名閫堂記','范純仁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','氣如巨浪瀉長江，清似寒冰滿玉缸。',64,'全唐诗/poet.song.36000.json','["氣如巨浪瀉長江，清似寒冰滿玉缸。", "幾與賈生摩壁壘，未令張子見麾幢。", "色絲幼婦宜傳久，肉袒牽羊合亟降。", "欲近雲章刊翠石，却憂染翰孰能雙。"]'),
('5c02390a-702c-4563-b796-e906ef751a84','秋日席上','范純仁','宋','宋诗','song-poetry','','[]','邊霜肅肅滿川梁，無限秋懷付一觴。',64,'全唐诗/poet.song.36000.json','["邊霜肅肅滿川梁，無限秋懷付一觴。", "白酒聊同佳客醉，黄花不減故園香。", "民兵已許歸南畝，聖澤行聞赦叛羌。", "得脫征衣歸里社，大能酩酊樂時康。"]'),
('883cabf5-ec91-4ead-bf34-4e97df82909a','遊寡阜廟二首  其一','范純仁','宋','宋诗','song-poetry','','[]','古祠東北據孤峰，臺殿岧嶢出半空。',64,'全唐诗/poet.song.36000.json','["古祠東北據孤峰，臺殿岧嶢出半空。", "廛市縱橫棋局布，雲煙重疊畫圖中。", "登高覽勝慚吾祖，放意尋山憶謝公。", "却愛夕陽照歸騎，翩翩旗旆滿川紅。"]'),
('fbaa1eca-b94c-4e39-9d14-94f08419eb7b','遊寡阜廟二首  其二','范純仁','宋','宋诗','song-poetry','','[]','逾旬積雨喜新晴，民物熙然百穀成。',64,'全唐诗/poet.song.36000.json','["逾旬積雨喜新晴，民物熙然百穀成。", "風葉蕭騷林野薄，霜天寥廓日華清。", "千山甫隔烏延塞，兩水傍臨不窟城。", "但得年豐人足食，犬羊餘種豈須平。"]'),
('7e48b408-f74e-4dbd-87a8-d8217c9734cd','和韓持國見贈兼簡王微之','范純仁','宋','宋诗','song-poetry','','[]','身由疲病難從政，性本顓愚不學禪。',32,'全唐诗/poet.song.36000.json','["身由疲病難從政，性本顓愚不學禪。", "到老豈能成一事，饑餐渴飲謾隨緣。"]'),
('f10818c7-1150-402a-b0da-c02f1540c23d','和持國','范純仁','宋','宋诗','song-poetry','','[]','時奉清歡消鄙吝，真同寒水滌塵沙。',64,'全唐诗/poet.song.36000.json','["時奉清歡消鄙吝，真同寒水滌塵沙。", "尊傾玉粒醅浮蟻，叢合金英菊有花。", "湖面烟霞如澤國，波心亭館似仙家。", "四時風月皆堪賞，不獨霜前愛物華。"]'),
('def903aa-d311-4113-8ba2-745c7bebe269','偶成','范純仁','宋','宋诗','song-poetry','','[]','橫笛佳人用意深，數聲高起潩湖陰。',32,'全唐诗/poet.song.36000.json','["橫笛佳人用意深，數聲高起潩湖陰。", "梅花落盡還堪惜，留取殘英伴醉吟。"]'),
('ed020afe-3b5e-48ec-bcc4-d76dd2d2d561','西湖四時四首  其一','范純仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','白鷺文鴛鑒裏飛，紅橋朱閣影參差。',32,'全唐诗/poet.song.36000.json','["白鷺文鴛鑒裏飛，紅橋朱閣影參差。", "疏林密雪皆堪賞，不特尋芳避暑時。"]'),
('e1548e4e-4574-424c-9ff1-b0567663cf1c','西湖四時四首  其二','范純仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','萬頃琉璃蹙翠鱗，日遲風暖物華新。',32,'全唐诗/poet.song.36000.json','["萬頃琉璃蹙翠鱗，日遲風暖物華新。", "千花百草遊人路，應謂壺中別有春。"]'),
('70614fe6-29f2-4b27-aa63-164f125e4c1b','西湖四時四首  其三','范純仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','深堂高閣啟清風，舟泛荷香柳影中。',32,'全唐诗/poet.song.36000.json','["深堂高閣啟清風，舟泛荷香柳影中。", "日月待公逃暑飲，官無拘檢是琳宮。"]'),
('b9905526-c9bb-464e-8e7e-c5c2736203b3','西湖四時四首  其四','范純仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夕陽照水晚登樓，皎月涵波夜泛舟。',32,'全唐诗/poet.song.36000.json','["夕陽照水晚登樓，皎月涵波夜泛舟。", "珍重前賢開展意，中年長願守閒州。"]'),
('ea262697-3068-40e6-a15f-b41927b40c0e','和微之以足疾不赴西湖賞雪','范純仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','年來遇景彊追攀，長恐身衰興易闌。',96,'全唐诗/poet.song.36000.json','["年來遇景彊追攀，長恐身衰興易闌。", "八十康寧天下少，四并聚會古爲難。", "客塵隨念須頻拂，世網縈人且自寬。", "布政未能躋樂俗，愛賢猶喜共清歡。", "湖光映雪凝深碧，野色當軒展素紈。", "心似白公何慮脚，燕堂深暖小安禪。"]'),
('7103154e-00a5-4d34-a965-a5a230d0a1e8','和持國贈微之','范純仁','宋','宋诗','song-poetry','','[]','元老邀賓樂事并，每居右席愧群英。',64,'全唐诗/poet.song.36000.json','["元老邀賓樂事并，每居右席愧群英。", "里中耆舊唯公長，醉裏篇章映古清。", "柔袂緩舒鸞鶴舞，短簫輕引鳳凰鳴。", "莫嫌尊酒過從數，向老交遊更有情。"]'),
('46e1ad1a-2823-4f61-acbd-ac09ad9a04b4','贈持國持國以瑞鷓鴣歌之','范純仁','宋','宋诗','song-poetry','','[]','三十年來解榻賓，今朝重喜奉陳蕃。',64,'全唐诗/poet.song.36000.json','["三十年來解榻賓，今朝重喜奉陳蕃。", "松筠雅操寒逾勁，膠漆深情老益敦。", "槐位已慚同致主，棠陰還許繼爲藩。", "古今此會應難得，醉飲休辭罄綠尊。"]'),
('7d6004ae-b53a-4b7a-a79c-7d13f0eaae8d','謝微之見贈','范純仁','宋','宋诗','song-poetry','','[]','屬邑逢公喜望塵，便陪將漕向江濱。',64,'全唐诗/poet.song.36000.json','["屬邑逢公喜望塵，便陪將漕向江濱。", "當時早重朋僚契，晚歲重敦道義親。", "華衮已慚無德稱，琳宮彌羨最閒身。", "相過無惜頻歡醉，八十康寧有幾人。"]'),
('57d2c39e-9e2c-4dfe-9c5d-12cc2763ac35','和持國光祿堂賞梅兼寄彝叟德孺','范純仁','宋','宋诗','song-poetry','','[]','叨榮報國老無成，辭疾還鄉負物情。',64,'全唐诗/poet.song.36000.json','["叨榮報國老無成，辭疾還鄉負物情。", "身近良朋如倚玉，心懷諸弟若摇旌。", "成行每羨隨陽雁，得友何慚出谷鶑。", "光祿官閒容謁告，掃除門巷待同行。"]'),
('097e16bf-1f65-4e8f-86a6-380adb81b9c8','奉寄西京玉汝相公','范純仁','宋','宋诗','song-poetry','','[]','三紀榮途愧彙征，數逢憂患見交情。',64,'全唐诗/poet.song.36000.json','["三紀榮途愧彙征，數逢憂患見交情。", "江吳切喜陪經席，關陝還容竝使旌。", "大尹綵旟方畫隼，上陽喬木欲遷鶑。", "銅駝金谷春遊盛，誰伴朱輪五馬行。"]'),
('5dd8c529-cf71-49d3-be77-0f92afad6ea0','和持國聽琵琶二首  其一','范純仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','美人成列抹朱絃，勸得嘉賓醉滿筵。',32,'全唐诗/poet.song.36000.json','["美人成列抹朱絃，勸得嘉賓醉滿筵。", "却笑西湖遊賞處，村歌社舞謾盈船。"]'),
('66b1670c-5fb1-46a1-949d-35267e11f515','和持國聽琵琶二首  其二','范純仁','宋','宋诗','song-poetry','','[]','須知絕藝好娛賓，能使知音作伯倫。',32,'全唐诗/poet.song.36000.json','["須知絕藝好娛賓，能使知音作伯倫。", "累月應將笞樂籍，恐公重作獨醒人。"]'),
('24446c2f-5ae9-4a2c-b429-0d234e603f15','和持國謝見招游湖二首  其一','范純仁','宋','宋诗','song-poetry','','[]','樂天向老占青蛾，裴令高年欲聽歌。',32,'全唐诗/poet.song.36000.json','["樂天向老占青蛾，裴令高年欲聽歌。", "擬假紅妝助歡醉，莫嫌賓主白髯多。"]'),
('8f130717-9184-4edb-8967-51d7e57b1b03','和持國謝見招游湖二首  其二','范純仁','宋','宋诗','song-poetry','','[]','白傅歸來西洛宅，裴公居在永豐坊。',32,'全唐诗/poet.song.36000.json','["白傅歸來西洛宅，裴公居在永豐坊。", "好歌愧乏牛家妓，不見淳于醉後狂。"]'),
('83fe454d-3277-4e12-90b5-cf6a0574ab46','和李徽之正議','范純仁','宋','宋诗','song-poetry','','[]','致主唯將盛德臨，世推文定總朝簪。',64,'全唐诗/poet.song.36000.json','["致主唯將盛德臨，世推文定總朝簪。", "先門自昔蒙知早，開閣當時用意深。", "功業所存皆國計，忠賢有後見天心。", "冢卿耆德承家慶，福壽康寧映古今。"]'),
('1611281d-44be-4553-a551-eaf227376e0f','過洛謁文潞公遊東田','范純仁','宋','宋诗','song-poetry','','[]','東田不到幾經年，孫閣重登荷眷憐。',64,'全唐诗/poet.song.36000.json','["東田不到幾經年，孫閣重登荷眷憐。", "清世莫尊唯尚父，朱顔難老是真仙。", "四朝弼亮繄賢業，八表昇平頼化權。", "門館舊生彌幸會，再陪几杖向林泉。"]'),
('763a58e8-69be-453b-9afc-a0e2fb392d17','送滕達道龍圖交代歸闕','范純仁','宋','宋诗','song-poetry','','[]','三紀分携念友生，天涯相見眼重明。',64,'全唐诗/poet.song.36000.json','["三紀分携念友生，天涯相見眼重明。", "詔恩幸忝交承契，尊酒聊伸故舊情。", "我守塞垣華髮短，君歸鄉國錦衣榮。", "何時共老江湖去，雞黍相過樂太平。"]'),
('d9fa5d0c-e0a7-434c-83f4-e55452f660d7','秋晴思西湖寄韓少師','范純仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','樓閣參差霜葉紅，湖光秋色畫圖中。',64,'全唐诗/poet.song.36000.json','["樓閣參差霜葉紅，湖光秋色畫圖中。", "移船影動波心月，橫笛聲隨水面風。", "當日席間先醉客，如今塞上獨衰翁。", "思君情緒兼歸興，暗逐汾川日夜東。"]'),
('54f17b4f-5bc7-462d-9adf-c8a7190f75de','寄西京留守韓玉汝','范純仁','宋','宋诗','song-poetry','','[]','四朝出處久親依，共上青雲更復誰。',64,'全唐诗/poet.song.36000.json','["四朝出處久親依，共上青雲更復誰。", "里室相鄰同晏卜，廟堂曾忝奉蕭規。", "恩榮過分知難報，憂患頻經覺早衰。", "一意待公還宰席，放歸箕潁養癃疲。"]'),
('0ff5a0c8-4a6d-420e-bd5a-47c389a2f22a','九日遊西山開化歸會柳溪示程憲','范純仁','宋','宋诗','song-poetry','','[]','登高觀稼適同時，賓從喧闐逐隼旗。',64,'全唐诗/poet.song.36000.json','["登高觀稼適同時，賓從喧闐逐隼旗。", "殿閣崔巍初日照，林巒蕭索曉風吹。", "山空笳鼓穿雲響，徑險車徒出谷遲。", "坐阻車公歸興速，却尋黄菊醉西池。"]'),
('043efa55-66c8-4400-9d28-e54d80bd0d72','酬王定國','范純仁','宋','宋诗','song-poetry','','[]','守麾猶得長諸侯，全晉提封二十州。',64,'全唐诗/poet.song.36000.json','["守麾猶得長諸侯，全晉提封二十州。", "畫角悠揚高戍晚，黄榆摇落故關秋。", "防邊戰士多鄉思，竝塞胡兒學漢謳。", "早晚罷兵容請老，邀君同醉潩湖頭。"]'),
('644c86fb-a1ec-48e2-b059-f464c958b525','酬程定塞提刑','范純仁','宋','宋诗','song-poetry','','[]','衰疲敢憚守邊州，老去光陰似水流。',64,'全唐诗/poet.song.36000.json','["衰疲敢憚守邊州，老去光陰似水流。", "塞馬春深無苜蓿，田家雪足望麳麰。", "清笳只解添鄉思，白酒聊堪解客愁。", "獨喜平刑賢使者，能將德慶紹箕裘。"]'),
('3c839692-2217-4ccc-97db-cbf1414254f0','讀老杜憶弟詩寄二弟','范純仁','宋','宋诗','song-poetry','','[]','昔賢遇亂多分散，我汝逢時各宦遊。',32,'全唐诗/poet.song.36000.json','["昔賢遇亂多分散，我汝逢時各宦遊。", "乃信人生歡聚少，安危俱不免離憂。"]'),
('12fcf5fb-3ee9-40e4-920f-a50bbc31773b','寄二弟','范純仁','宋','宋诗','song-poetry','','[]','宦名驅役費光陰，寒暑憂勞晝夜侵。',64,'全唐诗/poet.song.36000.json','["宦名驅役費光陰，寒暑憂勞晝夜侵。", "多病形骸衰易感，無涯思慮老難禁。", "離群終日嗟予季，聚首何時獲我心。", "精力已疲恩未報，懷歸體國念俱深。"]'),
('109da238-6f17-4b4b-bf00-33f7574da6ab','迎文潞公再謝重事歸洛','范純仁','宋','宋诗','song-poetry','','[]','河陽洛下春遊盛，兩處風光屬一家。',32,'全唐诗/poet.song.36000.json','["河陽洛下春遊盛，兩處風光屬一家。", "不獨都人瞻几杖，笑迎唯有滿城花。"]'),
('d90159a4-2f75-4b1a-b3b6-96fa44fb38c9','送潞公遊河陽河清','范純仁','宋','宋诗','song-poetry','','[]','安車乘興賞春妍，榮盛歡康世莫肩。',64,'全唐诗/poet.song.36000.json','["安車乘興賞春妍，榮盛歡康世莫肩。", "舊舍訟棠重蔽芾，昔遊晝錦復蟬聯。", "子孫擁節迎家府，稚艾爭途看壽仙。", "堪歎三川疲病守，陪公不及望公還。"]'),
('686f87e7-1a26-418a-9c50-0f2a18ac3862','洛花已開報潞公','范純仁','宋','宋诗','song-poetry','','[]','花開朝夕望車塵，花意慇懃恰似人。',32,'全唐诗/poet.song.36000.json','["花開朝夕望車塵，花意慇懃恰似人。", "晴日暖風催更急，看看開遍洛陽春。"]'),
('49501f1f-5d26-40f7-ab04-b5e23b6bbd27','贈蘄簟與潞公二首  其一','范純仁','宋','宋诗','song-poetry','','[]','雙文封卷如筒小，六月鋪張滿榻寒。',32,'全唐诗/poet.song.36000.json','["雙文封卷如筒小，六月鋪張滿榻寒。", "曾是吐茵狂醉客，敢塵齋閤助清歡。"]'),
('b1b7a87e-e859-4c12-8ffe-b5ccd0c5aed4','贈蘄簟與潞公二首  其二','范純仁','宋','宋诗','song-poetry','','[]','凉簟資公逃暑用，東池應伴淥波寒。',32,'全唐诗/poet.song.36000.json','["凉簟資公逃暑用，東池應伴淥波寒。", "高眠宜享華胥樂，曾致皇家奠枕安。"]'),
('68c3c155-f805-48d4-bcf1-bc6535888e90','病中寄太原韓玉汝','范純仁','宋','宋诗','song-poetry','','[]','弱柳何由羨老松，衰姿勁節本難同。',64,'全唐诗/poet.song.36000.json','["弱柳何由羨老松，衰姿勁節本難同。", "河南羸卧漳濱叟，塞北鷹揚渭上翁。", "多病未能謀早退，壯猷方看策元功。", "幸公再致唐虞化，庶託餘生壽域中。"]'),
('2ed139c4-4b9d-469c-9f82-1bbfe95cc89d','次韵持國謝送酒','范純仁','宋','宋诗','song-poetry','','[]','重九思公向洛陽，三秋此日念何長。',64,'全唐诗/poet.song.36000.json','["重九思公向洛陽，三秋此日念何長。", "心隨白酒聊相寄，頭插黄花想共嘗。", "盈幅忽慚瓊玖報，開尊應伴綺羅香。", "明年花好能來否，元老同期醉壽觴。"]'),
('4ca89373-8a7c-4a11-945e-2032a904377e','龍門秋日上潞公二首  其一','范純仁','宋','宋诗','song-poetry','','[]','龍門秋色勝春時，新霽登臨景更奇。',64,'全唐诗/poet.song.36000.json','["龍門秋色勝春時，新霽登臨景更奇。", "二室峰巒侵碧漢，兩涯樓殿照清伊。", "鳴泉亂瀉香山道，翠柏深藏白傅祠。", "獨恨不能陪杖屨，思公空作寄公詩。"]'),
('20e37398-65b4-41ae-985f-fc5e92fbb212','龍門秋日上潞公二首  其二','范純仁','宋','宋诗','song-poetry','','[]','郊原經雨絕纖塵，短麥蒙茸蓋壠新。',64,'全唐诗/poet.song.36000.json','["郊原經雨絕纖塵，短麥蒙茸蓋壠新。", "霜葉妝林成錦段，溪風吹水作龍鱗。", "秋山蒼翠濃如畫，晴日鮮明暖似春。", "遍叩禪關止三宿，猶慚高退自由身。"]'),
('3b979929-e61b-414d-aa5d-1c6d97dfd2cf','三弟得告來見省','范純仁','宋','宋诗','song-poetry','','[]','一門遭遇世應稀，詔許尋兄荷主慈。',64,'全唐诗/poet.song.36000.json','["一門遭遇世應稀，詔許尋兄荷主慈。", "屈指共驚游宦久，差肩却想事親時。", "慚卿才識加昏耗，嗟季情懷畏別離。", "報國爾曹心尚壯，無能唯我復先衰。"]'),
('3a1398b3-8fd4-4f40-90e5-501dd1fe38b7','喜弟妹相聚','范純仁','宋','宋诗','song-poetry','','[]','宦遊離索每相望，弟妹俱來喜莫量。',64,'全唐诗/poet.song.36000.json','["宦遊離索每相望，弟妹俱來喜莫量。", "言笑從容忘世味，盤筵簡率任家常。", "清朝幸免鴒原急，白首欣逢雁序長。", "安得身閒歸里社，一尊共醉樂時康。"]'),
('a3ecec73-e409-41c6-8685-743d6e91a2ee','題潞公翰墨卷後','范純仁','宋','宋诗','song-poetry','','[]','四朝勳業載旂常，九十精神正壽康。',32,'全唐诗/poet.song.36000.json','["四朝勳業載旂常，九十精神正壽康。", "燕翼自當傳百世，豈徒書法付諸郎。"]'),
('ba613115-c255-4745-bb80-780ae3ca938f','昔帥環慶爲部將所訟馮君學士被制鞠獄而獲平反今相遇於洛','范純仁','宋','宋诗','song-poetry','','[]','忠臣守正不謀身，處己雖危道益尊。',64,'全唐诗/poet.song.36000.json','["忠臣守正不謀身，處己雖危道益尊。", "直爲冕旒宣聖訓，豈唯囹圄被寬恩。", "陰功自可資耆壽，餘慶猶當見子孫。", "徒有愛賢無所達，行將歸老愧難論。"]'),
('8bd18720-1982-4201-989c-7e9f66a9d83d','酬持國携具見訪之作','范純仁','宋','宋诗','song-poetry','','[]','兩家契義世難倫，老去相逢意愈親。',64,'全唐诗/poet.song.36000.json','["兩家契義世難倫，老去相逢意愈親。", "衰暗豈能宣上化，高閑空惜致堯人。", "論交白社逾三紀，接武黄扉近十春。", "終日追陪何所樂，從容言笑盡天真。"]'),
('6ae9af16-42f0-42b0-b01d-e11298fdb7ba','和劉公舒相訪二首  其一','范純仁','宋','宋诗','song-poetry','','[]','嘉賓嘉景喜相陪，况有良朋冒雪來。',64,'全唐诗/poet.song.36000.json','["嘉賓嘉景喜相陪，况有良朋冒雪來。", "湖漲碧波三十頃，枝妝玉蓓萬千枚。", "白頭道舊情難盡，淥酒相期醉幾回。", "衰暮若非君顧我，平生懷抱向誰開。"]'),
('efb3d906-6844-4c76-b9a5-09709237c764','和劉公舒相訪二首  其二','范純仁','宋','宋诗','song-poetry','','[]','上庠英妙已相陪，隨計觀光亦竝來。',64,'全唐诗/poet.song.36000.json','["上庠英妙已相陪，隨計觀光亦竝來。", "給札偶容親硯席，掄才同是中條枚。", "他年闊別常千里，此地過從只兩回。", "衰病從來游宴少，爲君尊酒喜頻開。"]'),
('79be4344-0310-4c46-b135-df21e7529ec3','到漢東和張伯常六首  其一','范純仁','宋','宋诗','song-poetry','','[]','道義相期久益芳，忘年敦契自南陽。',64,'全唐诗/poet.song.36000.json','["道義相期久益芳，忘年敦契自南陽。", "榮公三樂今誰似，李白千篇敏異常。", "願見却須煩枉駕，奉歡先已闢東堂。", "故情新約知無改，松柏從來耐雪霜。"]'),
('82ba407d-e57c-4f9c-b430-1320a84a99c0','到漢東和張伯常六首  其二','范純仁','宋','宋诗','song-poetry','','[]','寵榮踰分自顛躋，珍重高人早拂衣。',64,'全唐诗/poet.song.36000.json','["寵榮踰分自顛躋，珍重高人早拂衣。", "山郡經時無好客，鈴齋終日敞閒扉。", "瓊瑶獲報欣情重，酒醴將誠愧物微。", "道義充盈文筆健，應容殘朽再親依。"]'),
('d8c49703-bcad-4957-ba32-95eeee03843d','到漢東和張伯常六首  其三','范純仁','宋','宋诗','song-poetry','','[]','思君日日上高樓，心逐西南漢水流。',64,'全唐诗/poet.song.36000.json','["思君日日上高樓，心逐西南漢水流。", "側聽車音常有待，互酬詩興未能休。", "高陽簪履成陳迹，西洛衣冠散舊遊。", "獨有地僊年八十，逍遥林下笑公侯。"]'),
('3c3e07aa-aa41-4880-ac09-30d7a307e68c','到漢東和張伯常六首  其四','范純仁','宋','宋诗','song-poetry','','[]','浮名驅逐阻音塵，一別伊川十二春。',64,'全唐诗/poet.song.36000.json','["浮名驅逐阻音塵，一別伊川十二春。", "顧我衰殘如槁木，羨公眉壽若靈椿。", "寒梅乍吐香尤馥，白酒新篘味頗醇。", "對景便思同一醉，都忘衰病在漳濱。"]'),
('8d764723-d316-4800-979f-357deef2b8cd','到漢東和張伯常六首  其五','范純仁','宋','宋诗','song-poetry','','[]','高標早與利名疏，獨向先門肯曳裾。',64,'全唐诗/poet.song.36000.json','["高標早與利名疏，獨向先門肯曳裾。", "舉眼正無羈客伴，解顔頻喜故人書。", "相期消息應端的，久別情懷待展舒。", "聞說山城春色早，安車乘興莫徐徐。"]'),
('92170a5a-90e7-4367-a98d-7e3327f54098','到漢東和張伯常六首  其六','范純仁','宋','宋诗','song-poetry','','[]','詩筒相續到隨城，練句揮毫老益精。',64,'全唐诗/poet.song.36000.json','["詩筒相續到隨城，練句揮毫老益精。", "尺素屢兼雙鯉贈，一言相諾百金輕。", "酒思佳客忘懷飲，梅吐新香撲鼻清。", "但得安車尋舊約，敢施行馬待先生。"]'),
('f942616d-afd2-44bc-89fa-8160309c95bc','神宗皇帝挽詩四首  其一','范純仁','宋','宋诗','song-poetry','','[]','舜孝高千古，堯仁化萬方。',48,'全唐诗/poet.song.36000.json','["舜孝高千古，堯仁化萬方。", "睿文超聖域，神武振皇綱。", "典冊辭徽號，山河復舊疆。", "玉輿悲晚駕，陵路柏蒼蒼。"]'),
('ff442c05-f7ff-4406-bd3b-e28e2e57e42a','神宗皇帝挽詩四首  其二','范純仁','宋','宋诗','song-poetry','','[]','應運千齡契，持盈七閏間。',48,'全唐诗/poet.song.36000.json','["應運千齡契，持盈七閏間。", "當年叨法從，終日奉威顔。", "鳳輦知何往，龍髯杳莫攀。", "深恩無路報，慟哭向橋山。"]'),
('acb53f0d-649b-4e66-bd61-a5ecb3360975','神宗皇帝挽詩四首  其三','范純仁','宋','宋诗','song-poetry','','[]','紫塞持戎節，青蒲職諫垣。',48,'全唐诗/poet.song.36000.json','["紫塞持戎節，青蒲職諫垣。", "囊封矜朴直，牘背辨深冤。", "終頼重瞳顧，難忘再造恩。", "微軀如獲殉，黄鳥不須論。"]'),
('d16db8f8-599a-4b3b-9aa6-253a90051210','神宗皇帝挽詩四首  其四','范純仁','宋','宋诗','song-poetry','','[]','祖祭連馳道，宸儀出殯宮。',48,'全唐诗/poet.song.36000.json','["祖祭連馳道，宸儀出殯宮。", "旌旛縈曉露，笳鼓咽悲風。", "雨泣千官送，雲奔萬國同。", "丹心隨籠水，先到裕陵東。"]'),
('e46db758-b119-45ee-8075-e5999c0f9885','慈聖光獻皇后挽詞二首  其一','范純仁','宋','宋诗','song-poetry','','[]','帝圖綿永合無涯，天降真人動魯沙。',64,'全唐诗/poet.song.36000.json','["帝圖綿永合無涯，天降真人動魯沙。", "兩奉離明來繼業，久膺舜養似重華。", "徽音遠過周文母，儉德深懲漢外家。", "仙仗忽遥靈寢閉，悲風空引戟幡斜。"]'),
('1dc2d6cf-ed92-4dd9-aac7-a69966410bcf','慈聖光獻皇后挽詞二首  其二','范純仁','宋','宋诗','song-poetry','','[]','畫梁歸燕拂輕埃，慶壽宮花亦盛開。',64,'全唐诗/poet.song.36000.json','["畫梁歸燕拂輕埃，慶壽宮花亦盛開。", "平日仙蹤何處覓，今年春色爲誰來。", "寢門永隔慈孫問，陵路俄瞻吉仗回。", "聖主孝思刑四海，千秋萬載詠烝哉。"]'),
('4069035f-6928-4a34-abb3-a5ae5f316f90','富相公挽詞五首  其一','范純仁','宋','宋诗','song-poetry','','[]','河嶽神靈降，唐虞景運開。',48,'全唐诗/poet.song.36000.json','["河嶽神靈降，唐虞景運開。", "致君優聖域，躋俗在春臺。", "天上台星坼，人間梁木摧。", "霜風咽笳鼓，斷續送餘哀。"]'),
('400e1464-3ef6-47aa-a5b7-56f37a2f1c3e','富相公挽詞五首  其二','范純仁','宋','宋诗','song-poetry','','[]','二紀經綸業，三朝翊戴勳。',48,'全唐诗/poet.song.36000.json','["二紀經綸業，三朝翊戴勳。", "忘身裨庶政，憂國見遺文。", "東閤散群彥，北邙歸大墳。", "邦人仰旟旐，灑淚向寒雲。"]'),
('84a6e741-591f-4082-8b8f-f3560b584f68','富相公挽詞五首  其三','范純仁','宋','宋诗','song-poetry','','[]','千齡遭際盛，五福始終全。',48,'全唐诗/poet.song.36000.json','["千齡遭際盛，五福始終全。", "還政周星紀，懷忠入夜泉。", "華夷思舊德，河洛遶新阡。", "空有云亡歎，何由止逝川。"]'),
('93ea6a4d-e4d7-49c7-b072-d3b7986a1213','富相公挽詞五首  其四','范純仁','宋','宋诗','song-poetry','','[]','皇天不憗遺，聖製極哀榮。',48,'全唐诗/poet.song.36000.json','["皇天不憗遺，聖製極哀榮。", "遼海千年去，明堂一柱傾。", "赤松違素志，白日閉佳城。", "康濟無窮事，皆爲後世程。"]'),
('4246b9a1-306f-455d-b4b3-61ca53168cc2','富相公挽詞五首  其五','范純仁','宋','宋诗','song-poetry','','[]','北走單車馴猰貐，東徂萬室活饑羸。',64,'全唐诗/poet.song.36000.json','["北走單車馴猰貐，東徂萬室活饑羸。", "謀深先帝承祧日，功在仁皇與子時。", "英氣不隨鐘漏盡，高名長與日星垂。", "登龍孤客懷知遇，慟哭秋原欲訴誰。"]'),
('d9562ef8-7568-4110-925f-cd5083a947e2','安州張大卿挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','廉良漢循吏，清簡晉名臣。',48,'全唐诗/poet.song.36000.json','["廉良漢循吏，清簡晉名臣。", "五福歸休日，三朝盡瘁身。", "潛心窮聖典，遺德化鄉人。", "燕翼看賢嗣，才名服搢紳。"]'),
('aa5bb5eb-55e7-4080-95e7-80259f2cf3f6','安州張大卿挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','瞻風從漢上，託庇在襄城。',48,'全唐诗/poet.song.36000.json','["瞻風從漢上，託庇在襄城。", "開豁心相照，推揚義不輕。", "俄嗟黄壤隔，莫展素車情。", "空望涓溪月，淋浪涕泗橫。"]'),
('3441e245-2bb8-4935-9b77-f628cc6a84ef','安州張大卿挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','寒風咽笳鼓，曉月带旌旛。',48,'全唐诗/poet.song.36000.json','["寒風咽笳鼓，曉月带旌旛。", "觸目傷陳迹，書紳記緒言。", "應山藏石槨，夢澤對松門。", "逝水何由止，清名後世存。"]'),
('05c64b7b-028d-4834-8d4b-9a4a6c9b82af','張益孺學士挽詞二首  其一','范純仁','宋','宋诗','song-poetry','','[]','儒業高群彥，詞場第一流。',48,'全唐诗/poet.song.36000.json','["儒業高群彥，詞場第一流。", "能聲喧幕府，穩步到瀛洲。", "晝繡臨鄉郡，紆朱葬舊丘。", "他年文苑傳，應有盛名留。"]'),
('5abc69ed-3cec-4427-abb6-77810b69d9dd','張益孺學士挽詞二首  其二','范純仁','宋','宋诗','song-poetry','','[]','官曹曾共職，友益頼多聞。',48,'全唐诗/poet.song.36000.json','["官曹曾共職，友益頼多聞。", "信道甘違俗，同心獨有君。", "漳濱俄感疾，泉下忽脩文。", "致主平生志，蕭條掩一墳。"]'),
('752b71f3-3f2e-4c22-987c-590307cdb4a6','謝師厚挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','妙年辭筆已驚人，不謂明時阻致君。',64,'全唐诗/poet.song.36000.json','["妙年辭筆已驚人，不謂明時阻致君。", "白首郎中歸白水，青衿弟子到青雲。", "淵明雅有歸田興，賈傅空留弔屈文。", "千載定應無孔孟，一言誰爲誄孤墳。"]'),
('25e6ca7f-0448-40f1-92a1-19fa556dd0bb','謝師厚挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','天地鍾奇秀，公應爲世生。',48,'全唐诗/poet.song.36000.json','["天地鍾奇秀，公應爲世生。", "何慳一老遺，遽奪萬人英。", "千古長齎恨，重泉不掩名。", "繆當幽穸誌，深愧色絲銘。"]'),
('d0005c1a-7205-43ad-8e95-6ceb8bd55d65','謝師厚挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','侍行游鄧學，纔喜識荆州。',48,'全唐诗/poet.song.36000.json','["侍行游鄧學，纔喜識荆州。", "一顧蒙青眼，相知到白頭。", "坤維同謫後，星紀等閒周。", "不意終天別，交頤涕不收。"]'),
('681e88dd-dbd6-4ad8-9421-acca883f85c4','王安之朝議挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','行己無瑕玷，終身樂太平。',48,'全唐诗/poet.song.36000.json','["行己無瑕玷，終身樂太平。", "人間五福備，宦亞九卿榮。", "冠蓋傳風範，鄉關憶老成。", "幽窀窮厚地，不掩是清名。"]'),
('043fe121-f50d-4a1e-a3a4-af38bf831179','王安之朝議挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','族望高全蜀，交游華衆賢。',48,'全唐诗/poet.song.36000.json','["族望高全蜀，交游華衆賢。", "退身將一紀，遺德滿二川。", "雅道何人繼，家聲有子傳。", "爲文慚幼婦，謬諾誌新阡。"]'),
('46fcec51-bbca-4c86-8baf-3e2744799a2d','王安之朝議挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','多難求分務，相依得古人。',48,'全唐诗/poet.song.36000.json','["多難求分務，相依得古人。", "道心閒裏契，友分老來親。", "不謂終天別，纔離一月新。", "無由瞻几杖，灑淚向秋旻。"]'),
('0e54286b-a9db-4c6a-a631-330a289a455d','程明道挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','綵衣方養志，諫省遽翹英。',48,'全唐诗/poet.song.36000.json','["綵衣方養志，諫省遽翹英。", "短命嗟顔子，長星喪孔明。", "臨津失舟楫，支厦闕梁楹。", "名節同伊水，滔滔萬古清。"]'),
('c7ebe84b-4dd1-4cf0-ac21-c25fa97e3196','程明道挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','天乎喪吾道，命矣歎斯人。',48,'全唐诗/poet.song.36000.json','["天乎喪吾道，命矣歎斯人。", "後學隳梁木，明時奪國珍。", "孔懷存愛弟，皓首奈慈親。", "唯有延陵誌，斯文久愈新。"]'),
('c26ae735-201b-47f5-b3af-78dc36d7f076','程明道挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','素忝金蘭契，情由道義親。',48,'全唐诗/poet.song.36000.json','["素忝金蘭契，情由道義親。", "聖時方際遇，英氣忽沈淪。", "琴在無鍾子，斤存失郢人。", "遥聞歸葬日，清淚滿衣巾。"]'),
('d433b263-ffa4-4513-82b0-bb3c77214643','司馬溫公挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','精誠皎白日，利澤漲滄溟。',48,'全唐诗/poet.song.36000.json','["精誠皎白日，利澤漲滄溟。", "志苦生靈樂，身勞社稷寧。", "人間失軒鑒，天上坼台星。", "唯有真儒效，長留簡冊青。"]'),
('3a427a66-16ce-41eb-ad98-9887faa03b07','司馬溫公挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','竟因勞瘁沒，誰翊太平基。',48,'全唐诗/poet.song.36000.json','["竟因勞瘁沒，誰翊太平基。", "哀訃驚朝聽，嚴禋罷慶儀。", "梁摧大厦日，舟失濟川時。", "千古商巖畔，應陪傅說祠。"]'),
('929304c8-a10b-4289-b6ec-a8f6adc43217','司馬溫公挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','兩宮思舊德，異禮賁忠魂。',48,'全唐诗/poet.song.36000.json','["兩宮思舊德，異禮賁忠魂。", "翠輦親臨後，蟬冠錫命尊。", "霜風咽笳鼓，寒日慘旌旛。", "不獨知心客，徘徊哭寢門。"]'),
('909569a1-db7a-4196-b0e5-5cb442363c34','毌清臣中散挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','先府西征日，高賢進謁時。',48,'全唐诗/poet.song.36000.json','["先府西征日，高賢進謁時。", "驊騮神異骨，丹鳳羽毛奇。", "外計留關决，中朝失表儀。", "濟時才不展，已有令名垂。"]'),
('94121d6f-265f-4290-bb34-b02d5cc214c6','毌清臣中散挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','奉使頻聯職，寬條喜共頒。',48,'全唐诗/poet.song.36000.json','["奉使頻聯職，寬條喜共頒。", "蒹葭倚白玉，培塿對高山。", "勇退輸先識，榮歸得早閒。", "塞垣聞訃日，感舊涕潺湲。"]'),
('3beea7c3-1db6-48dd-8cc4-65873affab0f','毌清臣中散挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','鄉里尊耆德，朝廷重老成。',48,'全唐诗/poet.song.36000.json','["鄉里尊耆德，朝廷重老成。", "銅符辭寵命，琳館遂高情。", "天下三尊盛，人間五福榮。", "豈唯身獨享，有子紹家聲。"]'),
('0b94e8dd-c429-4b9e-a86e-465afc7d9579','盧通議挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','耆舊今多少，唯公景德人。',48,'全唐诗/poet.song.36000.json','["耆舊今多少，唯公景德人。", "家鄰吳市卒，名重漢廷臣。", "路在猶耕月，門閒似送春。", "空堂餘畫像，彷彿舊精神。"]'),
('e1cb7761-965a-46f3-8ba6-530513223f16','盧通議挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','教子生前貴，休官物外榮。',48,'全唐诗/poet.song.36000.json','["教子生前貴，休官物外榮。", "去家金節重，開戶玉棺輕。", "江水元如舊，松林長未成。", "祗應山鳥恨，長向壠頭鳴。"]'),
('6877fbf3-7d6b-482d-ae4f-b17ea8053d9a','盧通議挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','誰記先生事，聲名五十年。',48,'全唐诗/poet.song.36000.json','["誰記先生事，聲名五十年。", "素風人不及，陰德世相傳。", "氣與詩流合，官隨子舍遷。", "門閭迷故客，悵望白雲天。"]'),
('eae4fddf-bfd3-4f8b-848e-776a952b18e2','孫曼叔尚書挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','少海風雲會，先朝眷遇隆。',48,'全唐诗/poet.song.36000.json','["少海風雲會，先朝眷遇隆。", "直辭裨衮闕，妙翰照琳宮。", "未展陶鈞手，徒高羽翼功。", "卹終皆盛典，傷衋出宸衷。"]'),
('446eace6-bc0d-473a-8f8b-c46a60e77a60','孫曼叔尚書挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','彼俗爭同好，唯公恥妄隨。',48,'全唐诗/poet.song.36000.json','["彼俗爭同好，唯公恥妄隨。", "青松寒不改，白玉涅難淄。", "梁壞營居日，舟沈欲濟時。", "空留良史筆，長俾善人思。"]'),
('a67acb0b-7d37-4d70-bb24-a4c880c5c61c','孫曼叔尚書挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','交分逾三絕，官聯歷四朝。',48,'全唐诗/poet.song.36000.json','["交分逾三絕，官聯歷四朝。", "心知俱白首，接武近青霄。", "逝水嗟何及，英魂恨莫招。", "空悲柏城路，風雨暮蕭蕭。"]'),
('75578452-360a-4af1-98ea-5135a2328992','龍圖張公挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','儀鳳來丹穴，麒麟瑞聖時。',48,'全唐诗/poet.song.36000.json','["儀鳳來丹穴，麒麟瑞聖時。", "壺冰凝雅操，冠玉聳英姿。", "敦閱今儒將，循良古吏師。", "未登台鼎貴，胡不到期頤。"]'),
('c20c85fc-f709-4c72-ad4c-f11d8b3a0285','龍圖張公挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','四紀澄清志，三朝盡瘁身。',48,'全唐诗/poet.song.36000.json','["四紀澄清志，三朝盡瘁身。", "褰帷躋雅俗，緩带息邊塵。", "聖世殲民望，中原喪國珍。", "千秋仗良史，直筆紀賢臣。"]'),
('60e0d7ee-e3bc-4ce4-96ad-7f754bcf25a3','龍圖張公挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','兄事兒童日，情親五十年。',48,'全唐诗/poet.song.36000.json','["兄事兒童日，情親五十年。", "西州官共久，畿邑政相連。", "謫籍孤蹤遠，亨衢衆望先。", "那知不復見，一別遂終天。"]'),
('20348cdd-5030-40ae-8f5c-f6f09213e704','鮮于諫議挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','左蜀稱多彥，唯公第一流。',48,'全唐诗/poet.song.36000.json','["左蜀稱多彥，唯公第一流。", "青蒲曾悟主，白首未封侯。", "名節傳千古，英靈掩一丘。", "平生僚友分，懷想涕難收。"]'),
('7e6d5f45-5e3a-4911-9cfd-23b8019eb0eb','鮮于諫議挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','命矣纔中壽，天乎喪哲人。',48,'全唐诗/poet.song.36000.json','["命矣纔中壽，天乎喪哲人。", "逢時身已病，達晚志難伸。", "清儉貧彌樂，文章老更醇。", "貽謀有餘慶，孫子自振振。"]'),
('fd7b8c88-edec-481d-929c-cba850ecf85c','鮮于諫議挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','曾向西都陪白社，同爲御史带烏紗。',64,'全唐诗/poet.song.36000.json','["曾向西都陪白社，同爲御史带烏紗。", "盤筵真率無多品，歌舞相參作一家。", "連日賞窮伊闕寺，乘春看盡洛陽花。", "那知遥作終天別，不預鄉人挽葬車。"]'),
('82b32b23-2622-4352-9e0f-91573dfb5a6c','申國太師呂公晦叔挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','冢宰傳三世，元勳輔六朝。',48,'全唐诗/poet.song.36000.json','["冢宰傳三世，元勳輔六朝。", "承家同鄭武，致主必唐堯。", "梁壞將何仰，川流不可邀。", "新阡人散後，林柏暮蕭蕭。"]'),
('492f87a2-7ee4-4f80-a15b-ea46c4215818','申國太師呂公晦叔挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','儀物羅西甸，恩榮葬上公。',48,'全唐诗/poet.song.36000.json','["儀物羅西甸，恩榮葬上公。", "悠揚蒿里日，慘淡柏城風。", "河嶽收英氣，旂常紀茂功。", "傳家多令子，將復繼遺忠。"]'),
('9bc85594-a1c8-430f-bf7a-d62a8f6c4382','申國太師呂公晦叔挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','達尊推國老，雅量寔予師。',48,'全唐诗/poet.song.36000.json','["達尊推國老，雅量寔予師。", "世翊千齡運，哀聞二聖悲。", "傷心瞻傅象，竭力奉蕭規。", "多少忠賢淚，非唯哭己知。"]'),
('b3339a44-417c-4f5d-9ba0-a8e0a6966eab','蜀郡范公景仁挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','翰苑文章伯，金華侍從臣。',48,'全唐诗/poet.song.36000.json','["翰苑文章伯，金華侍從臣。", "四朝行直道，一意在生民。", "白首唯憂國，青雲早退身。", "囊中有遺藁，不學茂陵人。"]'),
('e450a838-e034-47e6-bd3c-ef1764b97f0a','蜀郡范公景仁挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','伊洛相逢日，忠賢盛集時。',48,'全唐诗/poet.song.36000.json','["伊洛相逢日，忠賢盛集時。", "游從敦氣義，唱和若塤箎。", "漢嗣資商老，堯章憶后夔。", "云亡時共惜，不獨故人悲。"]'),
('f8a019c4-8671-484a-9261-135f1283a14f','蜀郡范公景仁挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','新阡近箕潁，故國遠岷峨。',48,'全唐诗/poet.song.36000.json','["新阡近箕潁，故國遠岷峨。", "禁從同儕少，門風吉士多。", "笑言如昨夢，身世逐頹波。", "唯有高名在，千年不可磨。"]'),
('4663f80a-7202-4c30-9a2f-532188be2ad5','李師中待制挽詞二首  其一','范純仁','宋','宋诗','song-poetry','','[]','才識無前輩，文章有古風。',48,'全唐诗/poet.song.36000.json','["才識無前輩，文章有古風。", "愛時甘屢黜，報國仗孤忠。", "夙有請纓志，竟成標柱功。", "子孫傳善慶，不獨在其躬。"]'),
('b5700329-a3d1-4519-b6fb-fbe7e16aea12','李師中待制挽詞二首  其二','范純仁','宋','宋诗','song-poetry','','[]','歷陽相遇日，流落喜俱存。',48,'全唐诗/poet.song.36000.json','["歷陽相遇日，流落喜俱存。", "不起騷人歎，唯知聖主恩。", "蟹膏紅滿筯，蟻酒白盈尊。", "豈謂江邊別，深情不再論。"]'),
('82da95b7-76ef-453f-80b3-06b25fbc40dd','康國韓公子華挽詞二首  其一','范純仁','宋','宋诗','song-poetry','','[]','棣萼聯三事，台星聚一門。',48,'全唐诗/poet.song.36000.json','["棣萼聯三事，台星聚一門。", "誠心多士服，德望四朝尊。", "傅相騎箕遠，蕭規與漢存。", "兩宮臨奠日，哀慟見殊恩。"]'),
('22397bf9-5370-477c-9a5d-c4ba278f16b2','康國韓公子華挽詞二首  其二','范純仁','宋','宋诗','song-poetry','','[]','弟兄俱是龍門客，數載難忘國士知。',64,'全唐诗/poet.song.36000.json','["弟兄俱是龍門客，數載難忘國士知。", "疲馬每憐諳遠道，焦桐竟待掛朱絲。", "青雲空費提携力，白首應無報稱期。", "未到柏城持葬紼，祖庭長慟涕淋漓。"]'),
('98762a0b-ec8f-4022-80a8-caedec9a0029','李彥深哀詞二首  其一','范純仁','宋','宋诗','song-poetry','','[]','妙年親研席，壯歲各西東。',48,'全唐诗/poet.song.36000.json','["妙年親研席，壯歲各西東。", "場屋騰文價，鄉關振義風。", "不違顔巷陋，竟哭阮途窮。", "頼得賢夫子，遺驂爲送終。"]'),
('0269e7be-af9d-4af5-87d9-dd14021843f3','李彥深哀詞二首  其二','范純仁','宋','宋诗','song-poetry','','[]','汲汲親師友，翹翹絕輩流。',48,'全唐诗/poet.song.36000.json','["汲汲親師友，翹翹絕輩流。", "讀書求體要，知命釋窮愁。", "清白傳三世，才華掩一丘。", "平生懷舊淚，爲子獨難收。"]'),
('ad9d76a1-b92e-4e7b-9076-b24f978d79da','王樂道觀文挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','人間失詞伯，天上落文星。',48,'全唐诗/poet.song.36000.json','["人間失詞伯，天上落文星。", "商皓終辭漢，桓榮厭授經。", "重泉齎志業，喬嶽返英靈。", "身後千年事，空留竹簡青。"]'),
('00706338-65c8-41aa-80d7-9db4e9969a23','王樂道觀文挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','秘殿承新寵，儲宮冠舊僚。',48,'全唐诗/poet.song.36000.json','["秘殿承新寵，儲宮冠舊僚。", "從龍登紫極，扶日上青霄。", "暝壑移舟遠，長川閱水遥。", "瞻懷柏城路，丹旐去飄飄。"]'),
('e0e161f8-e890-4521-8046-ee03f0fb9748','王樂道觀文挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','纔罷荆州市，俄歸蒿里墳。',48,'全唐诗/poet.song.36000.json','["纔罷荆州市，俄歸蒿里墳。", "鹽梅失群望，羽翼有前勳。", "浪作登龍客，慚無幼婦文。", "辱知無以報，灑淚向嵩雲。"]'),
('8ca40648-91bb-49c0-847a-1b94cd054b24','張掞龍圖挽詞三首  其一','范純仁','宋','宋诗','song-poetry','','[]','宣力三朝舊，於身五福全。',48,'全唐诗/poet.song.36000.json','["宣力三朝舊，於身五福全。", "家風良將後，經術古人前。", "丁令終辭世，留侯定得僊。", "貽謀有賢嗣，素業盡能傳。"]'),
('55822c49-be72-475d-a596-56f4b3cc971b','張掞龍圖挽詞三首  其二','范純仁','宋','宋诗','song-poetry','','[]','江邊承訃日，羈宦正摧頹。',48,'全唐诗/poet.song.36000.json','["江邊承訃日，羈宦正摧頹。", "早獲登龍便，慙無附驥才。", "寄詩招悸魄，引水活枯腮。", "白首知難報，長言致一哀。"]'),
('ef4263da-0f06-4cb2-bf37-6d87191d6bb6','張掞龍圖挽詞三首  其三','范純仁','宋','宋诗','song-poetry','','[]','二紀金華侍從臣，昇平看足作閒人。',64,'全唐诗/poet.song.36000.json','["二紀金華侍從臣，昇平看足作閒人。", "身躋顯仕由稽古，世有陰功爲庇民。", "但見朝廷方貴老，那知河嶽遽收神。", "哀榮終始公無憾，况有清名服搢紳。"]'),
('7ce52609-e48f-4706-9634-8941f65a20b2','望日示康廣宏','范純仁','宋','宋诗','song-poetry','','[]','清晨三綠袍，羅拜北堂高。',48,'全唐诗/poet.song.36000.json','["清晨三綠袍，羅拜北堂高。", "積善因先烈，遺光及爾曹。", "勿矜從事早，當念起家勞。", "脩立皆由己，何人可佩刀。"]'),
('07809c3a-4255-499f-9b53-c8e1a4c63489','籌思堂','范純仁','宋','宋诗','song-poetry','','[]','亭爲籌思設，公將稱此名。',48,'全唐诗/poet.song.36000.json','["亭爲籌思設，公將稱此名。", "致誠通造化，審慮敵權衡。", "境寂居忘倦，心虛照自明。", "詎同遊宴事，休戚繫群生。"]'),
('c81f7a8f-e7f0-4b2d-97e6-870c0efd9a93','寄西京張法曹','范純仁','宋','宋诗','song-poetry','','[]','幕府三年客，群居幾日親。',48,'全唐诗/poet.song.36000.json','["幕府三年客，群居幾日親。", "初分闕口路，猶見洛陽人。", "壠麥晴將秀，田花晚自春。", "向家行漸近，豈復倦征輪。"]'),
('73e26215-aabd-4803-b330-65da075403c1','睢陽五老圖','范純仁','宋','宋诗','song-poetry','','[]','榮名雅望退休閑，聲譽清高已納冠。',64,'全唐诗/poet.song.36000.json','["榮名雅望退休閑，聲譽清高已納冠。", "匡國多方開五老，齊名有道列雙桓。", "耆英後會成威烈，相貌前圖壯世寒。", "吾道欲如公道立，百年藻鑑動人看。"]'),
('9adc4c8b-bf0a-4bb1-a19c-9bb42f7730be','句  其一','范純仁','宋','宋诗','song-poetry','','[]','因隨芳草行來遠，爲愛清波歸去遲。',16,'全唐诗/poet.song.36000.json','["因隨芳草行來遠，爲愛清波歸去遲。"]'),
('834219ff-09d7-4076-b46e-d89f9ceb078b','句  其二','范純仁','宋','宋诗','song-poetry','','[]','君行方在急流間。',8,'全唐诗/poet.song.36000.json','["君行方在急流間。"]'),
('7a5e806f-42bd-4ff5-a1a1-f67a11924b2a','句  其三','范純仁','宋','宋诗','song-poetry','','[]','平生懷古意。',6,'全唐诗/poet.song.36000.json','["平生懷古意。"]'),
('01a36dfb-8144-4544-bc93-1a7b4b02b2d4','運司園亭十詠 山堂','章楶','宋','宋诗','song-poetry','','[]','古木鬰參天，蒼苔下封路。',48,'全唐诗/poet.song.36000.json','["古木鬰參天，蒼苔下封路。", "幽花無時歇，醜石終朝踞。", "水竹散清潤，烟雲變晨暮。", "何必憶山林，直有山林趣。"]'),
('0cd02602-0290-4028-95a7-970bd449ae92','運司園亭十詠 玉溪堂','章楶','宋','宋诗','song-poetry','','[]','堂因水得名，方沼當其後。',48,'全唐诗/poet.song.36000.json','["堂因水得名，方沼當其後。", "漪瀾蕩榱桷，窗戶挹花柳。", "蟲魚不避人，鷗鷺若相友。", "午枕夏簟凉，此樂亦奚有。"]'),
('b7ce8577-128e-4fcf-9efc-18578b90919d','運司園亭十詠 雪峰樓','章楶','宋','宋诗','song-poetry','','[]','層構壓池塘，不僭亦不偪。',48,'全唐诗/poet.song.36000.json','["層構壓池塘，不僭亦不偪。", "影浮綠水靜，寒凝雪山色。", "撫檻接修竹，連檐引蒼栢。", "注目望長安，無奈濃雲隔。"]'),
('e6198237-50c9-4dad-8479-d823715f19a0','運司園亭十詠 海棠軒','章楶','宋','宋诗','song-poetry','','[]','珍葩寄幽島，正對孤軒植。',48,'全唐诗/poet.song.36000.json','["珍葩寄幽島，正對孤軒植。", "優柔自俯仰，紅綠若組織。", "春酣晴日曛，坐久濃香逼。", "池面凈可鑒，朝霞罩澄碧。"]'),
('1463c470-5bc6-45e9-ace4-7b94638a9f99','運司園亭十詠 月臺','章楶','宋','宋诗','song-poetry','','[]','蜀地饒夜雨，輕陰多蔽天。',48,'全唐诗/poet.song.36000.json','["蜀地饒夜雨，輕陰多蔽天。", "見月月無幾，築臺邀嬋娟。", "高疑桂影近，俯視雲幄連。", "顧盼已塵外，欲挹瑶宮仙。"]'),
('f9119443-bf6a-4dd7-9206-0b457a28c7f9','運司園亭十詠 翠錦亭','章楶','宋','宋诗','song-poetry','','[]','楩楠百尺餘，排列拱檐際。',48,'全唐诗/poet.song.36000.json','["楩楠百尺餘，排列拱檐際。", "畏日自成陰，隆冬寧滅翠。", "虛曠得寂理，懶僻恣濃睡。", "誰知官府中，獲此沖漠味。"]'),
('0166a690-4d8d-48fc-b4b9-05c074ca7d8a','運司園亭十詠 潺玉亭','章楶','宋','宋诗','song-poetry','','[]','傍砌釃小渠，回環是流水。',48,'全唐诗/poet.song.36000.json','["傍砌釃小渠，回環是流水。", "石蜃吐珠涎，清響醒人耳。", "風徹竹影碎，月皎波光起。", "颯爽無塵囂，靜適心所喜。"]'),
('090f996d-c423-4089-9223-72e9e5cdc6f1','運司園亭十詠 茅庵','章楶','宋','宋诗','song-poetry','','[]','竹間構圓庵，所向自瀟灑。',48,'全唐诗/poet.song.36000.json','["竹間構圓庵，所向自瀟灑。", "珍禽弄巧舌，宛是居山野。", "默坐見真心，萬緣盡虛假。", "勿陋尋尺地，茲焉息意馬。"]'),
('35b99071-d3ce-4cd7-b242-daa620e46b8a','運司園亭十詠 水閣','章楶','宋','宋诗','song-poetry','','[]','架木浮水中，略彴通孤島。',48,'全唐诗/poet.song.36000.json','["架木浮水中，略彴通孤島。", "扶疏花影反，潑刺跳魚小。", "風月所得多，經營信云巧。", "隠几寂無人，朱蘭萃幽鳥。"]'),
('495f81eb-443b-45a6-842e-d693730f9ed9','運司園亭十詠 小亭','章楶','宋','宋诗','song-poetry','','[]','花邊二小亭，雙跨清渠上。',48,'全唐诗/poet.song.36000.json','["花邊二小亭，雙跨清渠上。", "規模雖甚隘，幽僻良可賞。", "幸依佳木陰，未羨大厦廣。", "不足延賞朋，携筇常獨往。"]'),
('dfef9fa3-c59e-4935-9d02-2a110e84f7a8','句','章楶','宋','宋诗','song-poetry','','[]','湖當荆楚百川會，江自岷峨萬里山。',16,'全唐诗/poet.song.36000.json','["湖當荆楚百川會，江自岷峨萬里山。"]'),
('aa3383b7-04d2-4474-bf72-485edf127729','蜀先主廟古柏','裴士禹','宋','宋诗','song-poetry','','[]','武侯翊漢嗣，始欲大神器。',156,'全唐诗/poet.song.36000.json','["武侯翊漢嗣，始欲大神器。", "天命固有常，雲雷極屯否。", "流星墜武帳，萬卒摧銳氣。", "孤負卧龍心，三顧君臣意。", "廟貌今寂寥，握節空垂淚。", "興廢事徒然，無以窮往志。", "陵前古柏樹，千丈起平地。", "根大壓巨鼇，心虛藏野燧。", "風動虬龍枝，雷雨隨聲至。", "疑是虛空間，神明專擁庇。", "不爾千萬年，突兀無枯瘁。", "觀栢又慘然，念侯功業熾。", "功業亙無窮，與柏共蒼翠。"]'),
('21da5b02-2ef2-4efd-8c31-4e5a9a0a5f10','題滴水巖  其一','鞏彥輔','宋','宋诗','song-poetry','','[]','千條玉筯掛巖前，一派銀潢瀉碧天。',32,'全唐诗/poet.song.36000.json','["千條玉筯掛巖前，一派銀潢瀉碧天。", "疑是鮫人在山泣，亂流珠顆落危顛。"]'),
('37963f73-8ac6-4cc8-8e79-279557aa5c28','題滴水巖  其二','鞏彥輔','宋','宋诗','song-poetry','','[]','巖上流泉滴滴來，史君巖下宴頻開。',32,'全唐诗/poet.song.36000.json','["巖上流泉滴滴來，史君巖下宴頻開。", "衰翁閒局官清淡，不許聽歌醉玉杯。"]'),
('bb120963-03ff-475b-8eb9-740b5bc37a60','題滴水巖  其三','鞏彥輔','宋','宋诗','song-poetry','','[]','天然瀟洒絕塵埃，四面如山畫帳開。',32,'全唐诗/poet.song.36000.json','["天然瀟洒絕塵埃，四面如山畫帳開。", "世上何須問仙境，只應此地是蓬萊。"]'),
('a4461b82-1c78-4fd1-bfb3-d9521f47f8e3','句','胡揆','宋','宋诗','song-poetry','','[]','弄珠解佩風流古，緩带輕裘道味閑。',16,'全唐诗/poet.song.36000.json','["弄珠解佩風流古，緩带輕裘道味閑。"]'),
('bb877113-b14c-4a1b-9124-75ad1f641605','句','劉公弼','宋','宋诗','song-poetry','','[]','灘聲來席上，亭影落溪中。',12,'全唐诗/poet.song.36000.json','["灘聲來席上，亭影落溪中。"]'),
('57d9523f-0a73-4bdc-bb54-5fd8892b5451','南峰亭','方仲謀','宋','宋诗','song-poetry','','[]','水色山光照曲闌，芳春時節稱遊觀。',64,'全唐诗/poet.song.36000.json','["水色山光照曲闌，芳春時節稱遊觀。", "鶑花不爲少年惜，尊俎莫辭終日歡。", "香逐好風來席上，景隨佳句落毫端。", "人間勝事今猶古，誰識相并四者難。"]'),
('4320339e-9a3e-473f-af28-653622105371','上丁守','謝履','宋','宋诗','song-poetry','','[]','閩嶺天南表，清源第一州。',24,'全唐诗/poet.song.36000.json','["閩嶺天南表，清源第一州。", "朝廷推重鎮，師帥得賢侯。"]'),
('dc219631-efcd-4bdc-9eac-aff0b7e968e0','詩一首','謝履','宋','宋诗','song-poetry','','[]','蛇岡躡龜背，蝦嶼據龍頭。',24,'全唐诗/poet.song.36000.json','["蛇岡躡龜背，蝦嶼據龍頭。", "岸隔諸蕃國，江通百粵舟。"]'),
('5343f5af-6b1e-4b1b-8251-78e79670f225','句  其一','謝履','宋','宋诗','song-poetry','','[]','近日蓮峰淨，春風石筍抽。',12,'全唐诗/poet.song.36000.json','["近日蓮峰淨，春風石筍抽。"]'),
('0ceaede9-65a7-42ba-ae5a-9d8f43a5ae6c','句  其二','謝履','宋','宋诗','song-poetry','','[]','憑高直接青雲勢，覽勝雙瞻碧玉顔。',16,'全唐诗/poet.song.36000.json','["憑高直接青雲勢，覽勝雙瞻碧玉顔。"]'),
('7326bbb7-1e4b-4090-bd47-4a90172e1f51','南山','許廣淵','宋','宋诗','song-poetry','','[]','路入青山幾萬重，前山行盡路還通。',64,'全唐诗/poet.song.36000.json','["路入青山幾萬重，前山行盡路還通。", "小舟棹急巖溪水，高柳絮飛隄岸風。", "春物老時林遍綠，晚煙收處日垂紅。", "民居稀闊兼窮僻，多使頑夫氣自雄。"]'),
('c5c7b924-2e3f-4cea-a887-e0d128b917fd','蛻龍洞  其一','許廣淵','宋','宋诗','song-poetry','','[]','山遠洞難窮，相傳舊隠龍。',48,'全唐诗/poet.song.36000.json','["山遠洞難窮，相傳舊隠龍。", "蟠泥知幾載，穿石見遺蹤。", "靈骨巖中換，陰雲日下從。", "鄉人祈旱歲，歌舞尚虔恭。"]'),
('f84d3023-27f2-4ed7-95c2-0e2396c3889f','蛻龍洞  其二','許廣淵','宋','宋诗','song-poetry','','[]','往昔開鋤古洞存，神龍曾隠穴山巒。',64,'全唐诗/poet.song.36000.json','["往昔開鋤古洞存，神龍曾隠穴山巒。", "靈蹤何日青天去，雲氣無時白晝寒。", "穿石分明印鱗爪，履泉驚懼作波瀾。", "於今霖雨均方國，來客休疑尚此蟠。"]'),
('5d27ff3f-1f5e-4338-90a6-e5809c458b1c','葛溪','許廣淵','宋','宋诗','song-poetry','','[]','樨川仙化後，溪以葛爲名。',48,'全唐诗/poet.song.36000.json','["樨川仙化後，溪以葛爲名。", "水激翻空白，潭澄到底清。", "山多晴倒影，雨過夜添聲。", "月滿寒光入，魚龍患太明。"]'),
('aa2d4586-f6c0-48c4-968f-19787369927c','杜公井','許廣淵','宋','宋诗','song-poetry','','[]','幾處城中井，標名孰與倫。',48,'全唐诗/poet.song.36000.json','["幾處城中井，標名孰與倫。", "異非深百尺，功在活千人。", "大旱流皆涸，甘泉惠受均。", "無情知水石，誠發應如神。"]'),
('a1579d13-d5e4-43c1-af96-136c3a79a5c2','鍊丹井','許廣淵','宋','宋诗','song-poetry','','[]','葛公高隠處，鑿井碧山前。',48,'全唐诗/poet.song.36000.json','["葛公高隠處，鑿井碧山前。", "鍊就長生藥，空餘白乳泉。", "鼎藏今去水，氣吐舊成煙。", "午夜風雷作，人疑羽珮還。"]'),
('096c0018-fb46-4e30-9560-f62799604616','放生池','許廣淵','宋','宋诗','song-poetry','','[]','天寶當年寺，魚池此日存。',48,'全唐诗/poet.song.36000.json','["天寶當年寺，魚池此日存。", "溪移古岸脚，殿壓舊山根。", "月照霜鐘遠，風開霧閣昏。", "網綸雖廢禁，和氣滿乾坤。"]'),
('ea34c1a9-29b0-4a6f-8e68-4c389d163e2b','題昌國院','許廣淵','宋','宋诗','song-poetry','','[]','軒開環列萬峰青，門對烏伊遂榜名。',64,'全唐诗/poet.song.36000.json','["軒開環列萬峰青，門對烏伊遂榜名。", "千室樓臺憑欄盡，一溪煙水捲簾明。", "爐煙晨起迷雲色，松韵時來雜梵聲。", "峻極祇宜長閉戶，柰何持鉢入東城。"]'),
('ca1e02d9-f11d-4acc-9bf9-a1cfc55f539d','題廣福院','許廣淵','宋','宋诗','song-poetry','','[]','溪光山色照天晴，開豁襟懷遠眼明。',64,'全唐诗/poet.song.36000.json','["溪光山色照天晴，開豁襟懷遠眼明。", "每日風清生竹韵，有時雨過沸灘聲。", "夷猶水上漁舟逸，奮迅簷前燕翼輕。", "珍重老僧無箇事，坐觀群動競經營。"]'),
('9a091664-51f1-4c8f-8d5b-fe37980f8d4a','寧國院','許廣淵','宋','宋诗','song-poetry','','[]','寺結千峰上，門通一徑幽。',48,'全唐诗/poet.song.36000.json','["寺結千峰上，門通一徑幽。", "靜心無物亂，清耳有泉流。", "樓閣先知曉，園林預覺秋。", "因君題秀句，却省昔年游。"]'),
('cdf3a879-b69b-411d-9c62-df874e78d39d','淨名院','許廣淵','宋','宋诗','song-poetry','','[]','杖錫窮危頂，茅菴構白雲。',48,'全唐诗/poet.song.36000.json','["杖錫窮危頂，茅菴構白雲。", "軒窗半峰出，鐘磬別山聞。", "海月曉同色，爐烟晝雜薰。", "莫教深靜處，思慮落塵氛。"]'),
('afd70190-61f4-4c73-8d11-3b3f687b92af','普照院','許廣淵','宋','宋诗','song-poetry','','[]','亂峰環合處，中見古精廬。',48,'全唐诗/poet.song.36000.json','["亂峰環合處，中見古精廬。", "萬事盡不到，數僧閒有餘。", "嶺雲時聚散，松竹晝清虛。", "自辨一泉後，多來長者車。"]'),
('88987e7d-a684-4d1e-b729-95a88bea1646','陳氏園','許廣淵','宋','宋诗','song-poetry','','[]','今日青蕪滿，當年碧瓦稠。',48,'全唐诗/poet.song.36000.json','["今日青蕪滿，當年碧瓦稠。", "軒楹無寸木，池沼有殘丘。", "過客嗟啼鳥，居人竟牧牛。", "子孫誰秀穎，念祖力重修。"]'),
('56c58161-06ba-4620-a070-07b0519c85e8','和徐令南新道中','許廣淵','宋','宋诗','song-poetry','','[]','嶮喦通小徑，湍水度危橋。',48,'全唐诗/poet.song.36000.json','["嶮喦通小徑，湍水度危橋。", "茶女巾蒙髻，樵人斧插腰。", "鳩鳴春晝靜，鶑囀曉林嬌。", "令尹求民瘼，行行聽路謠。"]'),
('5dde3878-d05e-427b-bbc5-a0a00bfbac4a','和晁令首夏道中','許廣淵','宋','宋诗','song-poetry','','[]','山盤村曲曉烟迷，晝靜新禽信意啼。',64,'全唐诗/poet.song.36000.json','["山盤村曲曉烟迷，晝靜新禽信意啼。", "風斂雨痕千嶂碧，日烘蠶箔萬家齊。", "葉憐綠密真成幄，花惜紅深又落泥。", "氣候宜人尤解倦，夕陽歸路遶長溪。"]'),
('5a19e90d-d68d-4d5e-8a00-6dabd5507782','甯國院','許廣淵','宋','宋诗','song-poetry','','[]','杉松鬰鬰際青天，堂殿重重蘸碧泉。',64,'全唐诗/poet.song.36000.json','["杉松鬰鬰際青天，堂殿重重蘸碧泉。", "山合不能遮日月，徑深無礙入雲煙。", "彌陀佛建千人會，照律師來五戒傳。", "乘興登臨與僧話，分明水戲在簾前。"]'),
('209caa77-6813-4f46-bb88-fdf2ade06c03','惠濟院','許廣淵','宋','宋诗','song-poetry','','[]','建剎基千古，淩雲閣數層。',48,'全唐诗/poet.song.36000.json','["建剎基千古，淩雲閣數層。", "成群皆舊衲，那箇是真僧。", "未滅惟心火，長明總佛燈。", "泉靈名惠濟，濟物有時增。"]'),
('32abb40c-32ee-4045-8b2e-2870d0087f3c','春日遊隠居寺','許廣淵','宋','宋诗','song-poetry','','[]','荒村十里居人少，中有僧廬掛隠名。',64,'全唐诗/poet.song.36000.json','["荒村十里居人少，中有僧廬掛隠名。", "高閣截空霜月古，群山臨檻竹風清。", "潺潺鳴溜將心滌，艷艷新花共眼明。", "珍重肩吾能自適，嘗招詩友避暄行。"]'),
('773b4430-291e-4216-a9f3-70bca0de0b8d','羅隠宅','許廣淵','宋','宋诗','song-poetry','','[]','廢宅百年後，荒基一畝平。',48,'全唐诗/poet.song.36000.json','["廢宅百年後，荒基一畝平。", "獨憐新檜柏，誰識舊軒楹。", "閭里清風在，溪山秀氣明。", "當時苦吟夜，應使鬼神驚。"]'),
('3392d14d-a44e-4850-93d3-35a219688b59','句','許廣淵','宋','宋诗','song-poetry','','[]','片雲晴點墨，滴露夜揮毫。',12,'全唐诗/poet.song.36000.json','["片雲晴點墨，滴露夜揮毫。"]'),
('d9360d4b-810e-4ff4-ad70-92ed8ed36ab0','詩一首','丁騭','宋','宋诗','song-poetry','','[]','秀出眉山有慶門，風流長與蜀山存。',32,'全唐诗/poet.song.36000.json','["秀出眉山有慶門，風流長與蜀山存。", "翰林未老生曾嫡，想見纍纍百世孫。"]'),
('770f1e16-d8e0-4daa-b4ce-f4c34d28e5e6','秦君亭','張思','宋','宋诗','song-poetry','','[]','蟬蛻真爲一世豪，雙蝸逐逐笑吾曹。',32,'全唐诗/poet.song.36000.json','["蟬蛻真爲一世豪，雙蝸逐逐笑吾曹。", "秦君已去亭長在，著向山高更覺高。"]'),
('36859731-8b1a-44dd-bac7-39a290c5519f','碧玉峽','張思','宋','宋诗','song-poetry','','[]','野迥方知天廣大，身高更覺石岧嶢。',32,'全唐诗/poet.song.36000.json','["野迥方知天廣大，身高更覺石岧嶢。", "泉人試爲平章看，勝絕何如透碧霄。"]'),
('ed012222-0835-4b68-876a-1d6e86791c5c','醉石','張思','宋','宋诗','song-poetry','','[]','席地爲茵寄此生，漥樽獨酌有餘清。',32,'全唐诗/poet.song.36000.json','["席地爲茵寄此生，漥樽獨酌有餘清。", "簑衣和月卧不醒，江上數峰雲自橫。"]'),
('fb6b10e1-3ba6-4bca-a6cc-09b6dea62881','昌山','李渤','宋','宋诗','song-poetry','','[]','嶙峋峭壁武溪東，聳起昌文疊秀峰。',64,'全唐诗/poet.song.36000.json','["嶙峋峭壁武溪東，聳起昌文疊秀峰。", "空谷流聲渾管籥，斷雲出岫倚崆峒。", "依稀玉韞含輝曉，爛熳花飛點翠融。", "自是山靈開淑氣，遥看拱璧鬰青葱。"]'),
('f3705930-4bd8-4e6b-bdef-2b2abe70584b','武溪','李渤','宋','宋诗','song-poetry','','[]','扁舟初泛入瀧船，隠約乘槎上漢年。',64,'全唐诗/poet.song.36000.json','["扁舟初泛入瀧船，隠約乘槎上漢年。", "岸狹束成三級浪，山高分得一毫天。", "掃開盤石那無酒，流出桃花恐有仙。", "青史若能留姓字，直須來此釣溪烟。"]'),
('2f3c5b52-c137-457b-be45-2e64a759c5f8','冬宿別業','李巖','宋','宋诗','song-poetry','','[]','移榻三冬暮，聯床半夜寒。',48,'全唐诗/poet.song.36000.json','["移榻三冬暮，聯床半夜寒。", "不眠霜瓦曉，細語壁燈殘。", "雁澤棲何定，鴒原且自寬。", "鴻飛非所羨，聊託一枝安。"]'),
('6e5e435a-15ac-409a-97ca-f9d8f52bd5e1','玉井雲根','李巖','宋','宋诗','song-poetry','','[]','雲根一竇發清瀾，紺宇何須結綺欄。',64,'全唐诗/poet.song.36000.json','["雲根一竇發清瀾，紺宇何須結綺欄。", "夜霄定知奎斗澈，浪翻應有蟄龍蟠。", "支機水沸銀河湧，海眼秋清寶鑒寒。", "自是源泉開淑氣，還看雪液更漫漫。"]'),
('fbde5650-e946-4f7a-8d4c-a3a47b181203','宿臨江驛','李中','宋','宋诗','song-poetry','','[]','候館寥寥輟棹過，酒醒無奈旅愁何。',64,'全唐诗/poet.song.36000.json','["候館寥寥輟棹過，酒醒無奈旅愁何。", "雨昏郊郭行人少，葦暗汀洲宿雁多。", "干祿已悲凋髮鬢，結茅終愧負煙蘿。", "篇章早晚遲知己，苦志忘形自有魔。"]'),
('6d80047f-f95f-42ce-b4ae-6149329b8706','紀夢','蘇隨','宋','宋诗','song-poetry','','[]','夢乘鸞鶴到仙家，侍女風流魏月華。',64,'全唐诗/poet.song.36000.json','["夢乘鸞鶴到仙家，侍女風流魏月華。", "琥珀盞斟千歲酒，琉璃瓶種四時花。", "金函藏籙文刊玉，石壁題名篆點沙。", "一枕北窗初睡覺，日移門外柳陰斜。"]'),
('3006c10b-78c5-433e-b7ef-26d211e060da','定山虎跑泉和韵','葛敏求','宋','宋诗','song-poetry','','[]','幾年埋塞稱筠根，虎識靈源爲剖分。',64,'全唐诗/poet.song.36000.json','["幾年埋塞稱筠根，虎識靈源爲剖分。", "僻處舊應無客到，遺蹤久不使人聞。", "細穿幽竇聲投石，猛出層巖冷噴雲。", "頼有賢侯精鑒在，圖經補緝得完文。"]'),
('6f0aa527-3047-4640-87e2-07d8e6a5f56a','麻姑山一首贈陳仲父賢良兼泰伯先生','黄通','宋','宋诗','song-poetry','','[]','麻姑山直斗牛角，形勝擁斷東南隅。',384,'全唐诗/poet.song.36000.json','["麻姑山直斗牛角，形勝擁斷東南隅。", "五百年來畜英氣，特爲吾宋生真儒。", "李姓覯名泰伯字，風骨古秀飄髯鬚。", "其人於世少似者，無乃稷契荀孟徒。", "自傷出處苦奇剝，不得寸祿遮妻孥。", "歸來築室郡北郭，反關唯作文字娛。", "先生之門足高第，中間仲父有輩無。", "曾繼先生列科舉，簡編滿載三十車。", "先生不遇子亦退，高文懿行夸江湖。", "麻源谷口田數頃，歲計取足無贏餘。", "生涯俯就隠意决，便棄城邑廬郊墟。", "上有慈親享甘旨，下有子弟森庭除。", "平生胸臆渺溟渤，惟學虞卿窮著書。", "平生志氣薄雲漢，惟學子陵閒釣魚。", "每當春秋社時候，萬象瀟洒神仙居。", "巖花野卉照几席，溪風谷靄清襟裾。", "先生乘興或還往，殺雞炊黍開尊壺。", "共評古今正經史，不知口角清涎濡。", "名教果有如是樂，彥輔之言誠豈誣。", "蓮社竹谿詫高逸，究竟未免歸狂愚。", "爭如仲父與泰伯，相樂以道情愉愉。", "文酒逢迎二十載，一日不見已爲疏。", "松門大開俗不到，水雲軒檻空清虛。", "仰愛二友嗟不與，欲別仙墅猶踟躕。"]'),
('5128b2fd-d853-40d6-8fb1-d8a6f2f17c96','遊熙春臺','黄通','宋','宋诗','song-poetry','','[]','吾閩山水州，佳麗發于邵。',48,'全唐诗/poet.song.36000.json','["吾閩山水州，佳麗發于邵。", "中有登高山，迥與蓬萊肖。", "萬家雞犬環，四面城池繞。", "木老煙蒼蒼，天低雲杳杳。"]'),
('17e07557-ba2f-4e05-87a4-923e487de632','秋興','黄通','宋','宋诗','song-poetry','','[]','訟庭無事意徘徊，長嘯西風酒滿杯。',32,'全唐诗/poet.song.36000.json','["訟庭無事意徘徊，長嘯西風酒滿杯。", "溪上小樓秋色裏，一番新雁趁雲來。"]'),
('c7421296-6bd8-4912-a0e7-780bf2289106','元夕燈火','黄通','宋','宋诗','song-poetry','','[]','秦樓十二玉梯橫，紫府千門夜不扃。',32,'全唐诗/poet.song.36000.json','["秦樓十二玉梯橫，紫府千門夜不扃。", "疑是嫦娥弄春色，彩雲移下一天星。"]'),
('f52789fb-deed-4ec9-8954-c6879c33413a','凉軒','黄通','宋','宋诗','song-poetry','','[]','古邑已清曠，凉軒尤灑然。',48,'全唐诗/poet.song.36000.json','["古邑已清曠，凉軒尤灑然。", "簷楹低竹樹，城郭带雲泉。", "鑄水孤吟地，流觴避暑天。", "應嗟吾土隘，無處畜風烟。"]'),
('a9ef7d87-732a-40d1-a6e9-3fcce2758cfa','峴山','黄通','宋','宋诗','song-poetry','','[]','仙翁移守明年春，□書小子中自論。',384,'全唐诗/poet.song.36000.json','["仙翁移守明年春，□書小子中自論。", "□嗟羊公不血食，乃表乞廟於山樊。", "因復爲山發風詠，辭氣浩浩涵胚渾。", "又不柬棄賤且鄙，似欲瓴甋聯璵璠。", "捧詩那能測崖岸，但覺俗骨銷沈昏。", "師丈之命重違辟，手摩空腹强忍言。", "召伯聽訟棠樹下，後人思伯樹不殘。", "羊公遊處峴山首，後人見山即汍瀾。", "或者怪之輒致詰，厥□何惠施元元。", "答云賢者豈徒爾，其事雖遠迹可根。", "昔者郟鄏鼎既□，三姓竊出窺中原。", "野鬼狂神盜社稷，渴龍饑虎摇乾坤。", "于時生靈乃何物，蛇豕口吻恣吐吞。", "丁黄那復顧邦土，荒城白晝啼幽冤。", "□石未安晉已奪，晉□將至漢之濆。", "公來有意補膏血，寧重黔首輕兒孫。", "朝問疾苦歷萬室，莫復逋逃開四門。", "衆化以術公以道，人伏以威公以恩。", "□□□時用□□，使民□戴如□□。", "不然楚山盡奇秀，豈將懷□□□村。", "山舊有亭亭有碑，碑前□見墮淚痕。", "獨使庭堅忽不祀，可□今古多朱轓。", "仙翁下車郡即治，旋日鞭馬城南奔。", "踟躕山頭念往事，言不輕發心暗捫。"]'),
('1caede1a-af14-40dd-9201-1bd144b7e1e1','句','黄通','宋','宋诗','song-poetry','','[]','天惠樵陽豈厚哉，文翁旌旆兩回來。',16,'全唐诗/poet.song.36000.json','["天惠樵陽豈厚哉，文翁旌旆兩回來。"]'),
('eae00d24-83a1-4517-9769-bba27feafcc2','題淮陰侯廟','黄好謙','宋','宋诗','song-poetry','','[]','築壇拜日恩雖重，躡足封時慮已深。',32,'全唐诗/poet.song.36000.json','["築壇拜日恩雖重，躡足封時慮已深。", "隆準早知同鳥喙，將軍應起五湖心。"]'),
('328aa35e-df86-4691-8574-c608b1e605d1','史院席上次首相吳公元韵','黄履','宋','宋诗','song-poetry','','[]','禮攽三事宴，史發兩朝餘。',48,'全唐诗/poet.song.36000.json','["禮攽三事宴，史發兩朝餘。", "偶綴金閨彥，來紬石室書。", "法良司馬不，辭措子游歟。", "盛事逢衰嬾，重須讀五車。"]'),
('66239825-8fb3-4d73-87ea-2ef0d177ec08','送程給事知越州','黄履','宋','宋诗','song-poetry','','[]','浩然行思脫塵埃，畫鷁橫堤雁陣催。',64,'全唐诗/poet.song.36000.json','["浩然行思脫塵埃，畫鷁橫堤雁陣催。", "申伯此時南國去，次公何日潁川來。", "鑒湖清句秋多興，魏闕丹心老不灰。", "勳業古來餘事耳，離亭含笑倒樽罍。"]'),
('c52fc6fa-1789-4d27-bb12-412bd451540f','閏八月十日同運使正仲大夫提刑若愚司封運判全玉朝奉遊雨花亭','黄履','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','閏月稍豐暇，清晨適逢休。',288,'全唐诗/poet.song.36000.json','["閏月稍豐暇，清晨適逢休。", "驅車偕群公，始爲斯亭遊。", "鍾山來艮維，大江西北流。", "臺成古到今，舉目意已周。", "晉有尸黎密，嘗棲崗之幽。", "君王懷高風，立剎旌往由。", "法雲生梁朝，雲氣如蟠虯。", "七齡依寶亮，俊發欽徐劉。", "講經此寺中，天花盈空浮。", "紛紛白雪飛，柳絮未可侔。", "近來有賢宰，亭于岡上頭。", "吳侯因名之，潛德光千秋。", "昔人登泰山，芥視十二州。", "余亦歎群雄，一毛爭九牛。", "豈知振大林，至有八龍留。", "因末爲推本，祕思聊一抽。", "燈明天人師，說法歷劫悠。", "欲放眉間光，洗足先雙收。", "入無量義處，身心安如丘。", "陀羅與殊沙，普散千億洲。", "雲公於此時，講已不可儔。", "况當幽巖中，松拂久唱酬。", "所以善哮吼，保誌稱爲優。", "誰言此華來，天地相應求。"]'),
('ca714152-6b81-425a-b493-f3855098b83e','次韵和正仲燕保寧覽輝遊崇勝鳳臺','黄履','宋','宋诗','song-poetry','','[]','霜晨飲保寧，亭午遊崇勝。',240,'全唐诗/poet.song.36000.json','["霜晨飲保寧，亭午遊崇勝。", "兩寺連一崗，相遠亦相映。", "登臨目所擊，今古坐可證。", "重輕歎吳鼎，白黑昭晉乘。", "山空霸氣滅，花草埋幽徑。", "松孤不易立，修竹無衰盛。", "徘徊鳳凰臺，默默揆所稱。", "虞恩動植被，周道乾坤正。", "儀韶與鳴岐，如影隨形憑。", "宋文三十年，陳迹俛仰竟。", "因公肆筆題，發我悲秋興。", "鄙哉草間活，起自青衣偵。", "弱嗣弛嚴訓，元嘉僅澄靜。", "鳳兮何德衰，來貽後人訂。", "微幹生巨枝，雖有理亦橫。", "非類心必殊，同聲始相應。", "邇來王蜀朝，攻殺日靡定。", "而彼四靈物，迭出如爲佞。", "因知德未臻，不足稱符命。", "已矣勿復陳，杯中醉賢聖。"]'),
('c7771b61-7f8c-457e-a59f-abcd13b7e4ff','次韵酬提舉林彥伯見贈','黄履','宋','宋诗','song-poetry','','[]','一篇遺我價十州，累幅溢目如星稠。',160,'全唐诗/poet.song.36000.json','["一篇遺我價十州，累幅溢目如星稠。", "清時名遂事高尚，啟期三樂消百憂。", "嗟余與公晚相值，讀此始歎真詩流。", "辭嚴義篤起余興，白雲遶筆窗前遊。", "乍如無鹽燭青鏡，顧視西子知狂羞。", "又如午夜按長劍，恍惚不辨明珠投。", "爲公聊敘我來幸，皇華相厚如相酬。", "民淳事簡稱迂拙，閱月偶諧庭今修。", "因尋遺跡共登覽，乘醉賡詠馳如郵。", "王襄宣布豈足頌，愧公直欲昭旂旒。"]'),
('c603abfe-d288-4ed3-bbdc-3642cdcc37d8','次韵和若愚登寶公塔','黄履','宋','宋诗','song-poetry','','[]','寶塔登題稱逸材，雲關岫幌半天開。',64,'全唐诗/poet.song.36000.json','["寶塔登題稱逸材，雲關岫幌半天開。", "獨龍下峙鍾形峻，靈鷲旁連翼勢迴。", "翠琰名傳千載遠，紫金身應四朝來。", "十虛含吐真空裏，假步移文亦小哉。"]'),
('7f38dbcf-2dca-4304-94fa-e41335f82bfa','次韵和全玉九日同遊清凉寺過高齋','黄履','宋','宋诗','song-poetry','','[]','秋雁三山度，晨雞五點號。',240,'全唐诗/poet.song.36000.json','["秋雁三山度，晨雞五點號。", "節逢黄菊秀，庵陟白雲高。", "共泛忘憂物，聊停好善旌。", "論心如淡水，得句勝連鼇。", "事簡曹參市，民熙李耳牢。", "感辰資友露，乘暇集賓蒿。", "嶺鬰青牛氣，潮翻白鷺濤。", "清時豐遠覽，故國喜相遭。", "笑整龍山帽，閑追老鵲艘。", "少陵懷北闕，靖節傲東臯。", "傅亮吟登館，劉伶醉捧糟。", "行藏雲出岫，物我海容舠。", "支鶴鳴沖漢，莊魚靜樂濠。", "日斜車轉鹿，風勁服添羔。", "愛景重鋪席，窮歡更賦毛。", "臂珍牛渚蟹，池溢馬臺醪。", "霸氣卑蝸角，塵機息兔毫。", "斷金心內固，挫物筆端豪。", "烏府風雲器，皇華柱石曹。", "吾衰亦何幸，拭目歎風騷。"]'),
('4cb3dfb3-c389-434c-9db7-eb2526a9f936','二十七日登長干塔','黄履','宋','宋诗','song-poetry','','[]','龍盤虎踞爭岧嶢，長干窣堵當中標。',352,'全唐诗/poet.song.36000.json','["龍盤虎踞爭岧嶢，長干窣堵當中標。", "幾年遐想入清夢，秋杪登攀英氣飄。", "因思此塔屢成壞，相傳起自阿育朝。", "宿緣土麵獲今報，八萬四千成一朝。", "列在中華十有九，惟茲末後名方昭。", "自從五鳳例遭毀，下逮咸和纔可條。", "牛停金像既希有，水泛銅趺如默要。", "太元末年劉慧達，四顧異氣山之椒。", "三函中出三舍利，圓正光潔如瓊瑶。", "數層寶勢僅增立，梁詔方且鋪根苗。", "陳亡火烈復堙墜，興廢豈亦隨所招。", "偉哉天命集真主，湯霓武旆澄氛妖。", "六幽葵藿向堯日，千仞鳳凰儀舜韶。", "太宗繼志符節合，章聖游文金石調。", "詩書仁義溢庠序，佛老餘教通逍遥。", "祥符庚戌感光瑞，累歲九成淩紫霄。", "迄今八十有二載，香火瞻奉傾齯髫。", "群公偕我躡危級，放身物外情何超。", "心閑不逐去帆動，量廓那知空界遼。", "奇峰萬點逼冬瘦，江水九道來迢迢。", "共欣華旦此緣勝，大千永峙爲津橋。", "興餘更就竹閒飲，妙音盈耳成長謠。"]'),
('6ceeec35-c5db-48af-abc7-d4e08f412270','次韵和正仲遊華嚴此君亭','黄履','宋','宋诗','song-poetry','','[]','邂逅相遇三詩翁，適我願兮江之東。',249,'全唐诗/poet.song.36000.json','["邂逅相遇三詩翁，適我願兮江之東。", "每乘高興即同賦，矧值修竹華嚴宮。", "迫窮收棄勢相遠，交我以淡情何重。", "古來金石論賢達，應求本自聲氣同。", "清晨登此亭，亭前羅層峰。", "浮雲開白日，金影升珠櫳。", "高標不逐四時變，翠色可奪千葩紅。", "一日無此君，子猷嘯詠已不濃。", "清風颯然至，淵明喜動羲人容。", "化龍况是葛陂杖，待鳳幸列朝陽桐。", "伶倫裁嶰谷，律呂因雌雄。", "太和尚可致天地，煩想豈特疏心胸。", "下逮漢蔡邕，取椽製笛柯亭中。", "與夫皮爲冠兮葉爲酒，皆自荆陽之貢東南之美兮，冒霜停雪拂景雲而縈惠風。", "吾曹對此但欲適清樂，不學渭川之人兮資千畝以敵萬鍾。"]'),
('92a01eea-1c86-4379-8760-cc72b0739e59','次韵全玉遊永慶寺觀陳井','黄履','宋','宋诗','song-poetry','','[]','西北有招提，洒然塵垢外。',180,'全唐诗/poet.song.36000.json','["西北有招提，洒然塵垢外。", "茲遊久未遑，欣與高軒會。", "邃室儼圖畫，危亭隠松檜。", "逍遥步荒徑，蓊密拂輕蓋。", "開冬含餘清，幽律驚爽籟。", "行行轉城隅，亭午雲容晦。", "六朝三百秋，覽迹增悲慨。", "金輿成寒灰，簪笏散煙靄。", "龍沈景陽井，欄刻惟存戒。", "更餘三品石，默默冷相對。", "我視此邦傾，如魚自中潰。", "民財盡錙銖，民命輕草芥。", "三閣與十賓，積累成大憝。", "昔人賦黍離，摇摇發行邁。", "偶來牽我思，已涉南榮誡。"]'),
('0907c1d8-8bab-49a9-8311-72ed2418d846','十一月十日同謁惠烈廟','黄履','宋','宋诗','song-poetry','','[]','山北迢迢十里餘，使華聯轡謁神居。',64,'全唐诗/poet.song.36000.json','["山北迢迢十里餘，使華聯轡謁神居。", "吳朝崇構飛蟲後，梁帝停焚驟雨初。", "松蓋交陰垂道路，棠枝孤秀聳庭除。", "太平應禱邦人頼，惠烈新加益顯歟。"]'),
('d1b57586-7a6e-417d-9ea7-aba2b9496e00','十六日題紫極宮鍾阜軒','黄履','宋','宋诗','song-poetry','','[]','十里龍盤走勢來，此軒清對此山開。',64,'全唐诗/poet.song.36000.json','["十里龍盤走勢來，此軒清對此山開。", "日華先覿東方出，春令長瞻北斗回。", "地壓靈鼇爲勝境，城遷巧冶作瑶臺。", "何年隠几成余志，世味於今已似灰。"]'),
('75cfdda0-f429-47d8-b717-80c8d471a71a','正仲移漕二浙用李白留別王嵩韵以送之','黄履','宋','宋诗','song-poetry','','[]','二疏辭漢廷，故里揮黄金。',112,'全唐诗/poet.song.36000.json','["二疏辭漢廷，故里揮黄金。", "謝公扶晉業，不改東山心。", "余亦何爲者，時動莊{罒/与}吟。", "七閩三徑荒，白髮西汜侵。", "徒欣倦飛翼，獲蔭遊鳳林。", "方同塤篪吹，又遠金玉音。", "日月正光華，海嶽增高深。", "晝錦雖適願，霖雨斯層岑。", "送公悲且歡，聊拂綠綺琴。"]'),
('503fb61c-fa50-441f-a3a2-1b9cdb12f747','次韵酬郭子功行次新林見寄','黄履','宋','宋诗','song-poetry','','[]','感君故意長，赴我同襟期。',108,'全唐诗/poet.song.36000.json','["感君故意長，赴我同襟期。", "愧無芳蘭美，叨沐清風吹。", "舒文振頹波，歲莫起我思。", "大鵬息六月，飲啄宜天池。", "如何偕鷦鷯，深林安一枝。", "固窮顔如丹，欲老頭未絲。", "元凱承華勳，正值休明時。", "脫身事幽討，徒使余心悲。", "况當雪紛紛，更得新林詩。"]'),
('f79c2fb5-f4e1-4189-af3f-406b28e0fea7','次韵酬子功行次白鷺洲見寄','黄履','宋','宋诗','song-poetry','','[]','已隠南山霧，聊經白鷺洲。',72,'全唐诗/poet.song.36000.json','["已隠南山霧，聊經白鷺洲。", "初聞未得見，悵望登高樓。", "空城凝寒雲，目極徒離憂。", "咫尺邈千里，此夕如三秋。", "何當侵星來，樽前得詩流。", "一飲詩百篇，同銷萬古愁。"]'),
('0f56dcd6-15ac-471b-817d-36a4a853d530','次韵酬子功見贈','黄履','宋','宋诗','song-poetry','','[]','一緒連文璧幾重，早年宏麗壓機龍。',64,'全唐诗/poet.song.36000.json','["一緒連文璧幾重，早年宏麗壓機龍。", "心閑自結千巖月，音妙誰聽萬壑松。", "清入奇懷詩信筆，暗通大道酒盈鍾。", "賓筵忽得陽春句，屬和翻愁雪意濃。"]'),
('c84bb000-ffd8-4944-b07f-ece18751fa85','次韵酬運判張德父燈夕不赴','黄履','宋','宋诗','song-poetry','','[]','南國星橋鐵鎖開，朋簪聊醉鳳凰臺。',64,'全唐诗/poet.song.36000.json','["南國星橋鐵鎖開，朋簪聊醉鳳凰臺。", "同民所樂嘗聞孟，與物爲春略似駘。", "龍曜乍增崑岫出，佛華重散朅陀來。", "發篇示我雖溫麗，欺魄連牆肯至哉。"]'),
('8c5f1c0d-515b-4a6b-aff1-1011a2419593','白鷺亭送運判張全翁','黄履','宋','宋诗','song-poetry','','[]','一寸逍遥氣自春，等閑語默見天真。',64,'全唐诗/poet.song.36000.json','["一寸逍遥氣自春，等閑語默見天真。", "艱難世事嘗來徧，平淡交情久更親。", "會面只驚蓬鬢改，離亭還折柳條新。", "世間冷暖隨通塞，三紀如常有幾人。"]'),
('1c6e6b60-7fc6-4b15-b245-ba0c553139de','戲答提舉劉宜翁看山','黄履','宋','宋诗','song-poetry','','[]','處世能無欲，看山豈有難。',24,'全唐诗/poet.song.36000.json','["處世能無欲，看山豈有難。", "吾心度禪定，山亦不須看。"]'),
('4d643dd7-7ff0-483c-bbbb-358db948e3c1','送華陽劉法師','黄履','宋','宋诗','song-poetry','','[]','餐霞積金峰，行年五十六。',240,'全唐诗/poet.song.36000.json','["餐霞積金峰，行年五十六。", "身輕曠世龜，眸瑩新生犢。", "偶乘飛鳬來，就我簷下宿。", "傾蓋如久要，片言會心曲。", "嗟余亦何有，所慎止能燭。", "乍聆屑霏霏，虛室增蘭馥。", "僊經累萬卷，學者紛麻粟。", "大車循垣途，幾人契華轂。", "赤水遺玄珠，離智不能燭。", "延章洞秋石，應手黄芽熟。", "先生得何深，清名達堯屋。", "優詔辭窐衡，太平高逸躅。", "陰功期三千，餘事付神籙。", "臘窮一雨清，歸興藹幽谷。", "安期棗如瓜，茅君朮比玉。", "臨行笑遺余，可返鬢毛綠。", "屈眴文兜綿，團虬色浮粥。", "聊將報齊桃，不俟從季卜。", "白雲暫去來，碧嶺本無辱。", "預爲明月思，可望不可掬。"]'),
('7846ea73-063f-45aa-9c8a-b31e63d861ad','題紫溪驛','黄履','宋','宋诗','song-poetry','','[]','行盡高山到紫溪，昔年曾此侍親歸。',32,'全唐诗/poet.song.36000.json','["行盡高山到紫溪，昔年曾此侍親歸。", "而今只見經遊地，不見慈顔淚滿衣。"]'),
('c7458ae9-0ced-43e6-8180-4a9605cd18a5','句','范亦顔','宋','宋诗','song-poetry','','[]','神仙遠來宅奧境，五嶽跼蹐兒孫從。',16,'全唐诗/poet.song.36000.json','["神仙遠來宅奧境，五嶽跼蹐兒孫從。"]'),
('0e0384f7-3587-44df-bbb3-f284c2302ca9','將過益昌先寄馮允南使君','楊壽祺','宋','宋诗','song-poetry','','[]','衮衮京華志氣低，歸心長伴日輪西。',64,'全唐诗/poet.song.36000.json','["衮衮京華志氣低，歸心長伴日輪西。", "蒼顔白髮因新選，明月清風思舊溪。", "屈指光陰時節晚，舉頭霄漢路歧迷。", "巴陵太守應憐我，準擬經過醉似泥。"]'),
('e421f9a8-9b18-49dd-9836-1e09dd608aad','送程給事知越州','張修','宋','宋诗','song-poetry','','[]','紫泥封詔下天關，青鎖俄虛侍從班。',64,'全唐诗/poet.song.36000.json','["紫泥封詔下天關，青鎖俄虛侍從班。", "朝袖暫懷新印綬，繡衣榮過舊家山。", "鑒湖風月供吟筆，稽嶺煙霞入醉顔。", "宸眷未應容滿歲，使車行被命書還。"]'),
('45958ce0-f789-4eb7-a3fa-510692ead396','寄隠士','單錫','宋','宋诗','song-poetry','','[]','巖頭鬰鬰凌寒柏，柏間時復雲封白。',64,'全唐诗/poet.song.36000.json','["巖頭鬰鬰凌寒柏，柏間時復雲封白。", "苔蒼草碧自年年，絕奇中有參同客。", "道通下躡天根深，山靈啼泣穹崖陰。", "春深不問花開落，寂寂空山千萬尋。"]'),
('a56e7e0a-b466-476d-93b6-fdc71179da9f','聚遠樓','單錫','宋','宋诗','song-poetry','','[]','井邑銀山匝畫屏，層簷飛翼入蒼冥。',64,'全唐诗/poet.song.36000.json','["井邑銀山匝畫屏，層簷飛翼入蒼冥。", "曉穿簾幙扶桑日，夜浸欄桿紫漢星。", "春水漲來斜澗白，爐煙抹去半峰青。", "無邊光景歸吟日，莫向樽前辨醉醒。"]'),
('bf494dfe-88b3-4909-8318-77b716f67f58','巾山廣軒','陸長倩','宋','宋诗','song-poetry','','[]','凌虛雲磴陟崔嵬，軒檻仍從絕頂開。',64,'全唐诗/poet.song.36000.json','["凌虛雲磴陟崔嵬，軒檻仍從絕頂開。", "邑屋萬家迷向背，江流三面自縈迴。", "金山每恨波濤阻，星石曾登培塿來。", "爲是會稽東部郡，不教更號小蓬萊。"]'),
('9ad88c4d-4e0e-4a85-98a1-b4492a055789','遊碧照庵  其一','陸長倩','宋','宋诗','song-poetry','','[]','松蓋松幢引步高，躋攀終日自忘勞。',64,'全唐诗/poet.song.36000.json','["松蓋松幢引步高，躋攀終日自忘勞。", "寒泉澄澈新鎔鏡，華棟崢嶸下冠鼇。", "軒到嫩嵐濃欲滴，庵依疊嶂勢偏豪。", "雙旌暮迫城闉去，止觀回應羨毳袍。"]'),
('e9970107-8a20-4ce4-94e6-aadecb47bcae','遊碧照庵  其二','陸長倩','宋','宋诗','song-poetry','','[]','平旦前騶出郡闉，松堤石磴自無塵。',64,'全唐诗/poet.song.36000.json','["平旦前騶出郡闉，松堤石磴自無塵。", "寒雲明滅天開幙，霜草青紅地展茵。", "靈剎迥非勞世境，凈庵常屬悟空人。", "更憐萬竹千杉色，不問嚴冬與早春。"]'),
('b2722f5c-e8ba-41d1-93ee-94865b588ae8','送程給事知越州','余京','宋','宋诗','song-poetry','','[]','越守新除漢夕郎，剸繁從古籍才良。',64,'全唐诗/poet.song.36000.json','["越守新除漢夕郎，剸繁從古籍才良。", "一麾偃息專方面，千騎雍容過故鄉。", "近侍暫虛青瑣闥，還朝行捧紫泥章。", "邦人喜慶今何幸，復見前龔與後黄。"]'),
('23b977eb-89ab-44d9-986c-18a40a382d20','游俠曲','王觀','宋','宋诗','song-poetry','','[]','雪擁燕南道，酒闌中夜行。',60,'全唐诗/poet.song.36000.json','["雪擁燕南道，酒闌中夜行。", "千里不見讎，怒鬚如立釘。", "出門氣吹霧，南山雞未啼。", "腰間解下聶政刀，袖中擲去朱亥椎，冷笑邯鄲乳口兒。"]'),
('2d4de831-0ef7-4814-82ee-056d5db2626c','莫惱翁','王觀','宋','宋诗','song-poetry','','[]','穀垂乾穗豆垂角，雨足年登不勝樂。',60,'全唐诗/poet.song.36000.json','["穀垂乾穗豆垂角，雨足年登不勝樂。", "烏巾紫領銀鬚長，白酒滿杯翁自酌。", "翁醉不知秋色凉，兒捋翁鬚孫撼床。", "莫惱翁，翁年已高萬事慵。"]'),
('4a66c749-c6d8-4615-9ced-2334e8e747bf','醉眠亭','王觀','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','松陵江畔客，築室從何年。',140,'全唐诗/poet.song.36000.json','["松陵江畔客，築室從何年。", "世俗徒紛紛，不知李子賢。", "在彼既不知，不如醉且眠。", "聲名衮衮誰知命，醉非愛酒眠非病。", "長江渾渾無古今，群山迴合來相映。", "呼奴沽酒不可遲，買魚斫鱠煩老妻。", "何必紉繩繫飛兔，百年長短空自知。", "直將竛虱視天地，冥冥支枕窮四時。", "九衢足塵土，朱門多是非。", "秋風老蓴鱸，扁舟何日歸。"]'),
('ec931648-8451-4225-a58a-0546253951df','九日石莊阻雨','王觀','宋','宋诗','song-poetry','','[]','佳節不易至，故園胡未歸。',72,'全唐诗/poet.song.36000.json','["佳節不易至，故園胡未歸。", "對雨坐長歎，中心如有違。", "登高望川陸，重陰蔽雲霏。", "晚禾易生耳，豆落將爲萁。", "農功既莫惜，孰云佳菊開。", "掇英泛美酒，已負鄰翁期。"]'),
('267c4d01-cfaf-4cc8-9c2e-7e41d141c989','九日狼山','王觀','宋','宋诗','song-poetry','','[]','山盤水轉小橋通，殿角崢嶸倚亂峰。',64,'全唐诗/poet.song.36000.json','["山盤水轉小橋通，殿角崢嶸倚亂峰。", "世上自聞真法力，巖前無復白狼蹤。", "蜃噴海氣昏危塔，龍戲江聲雜暮鐘。", "爲愛贊公房外月，解鞍求宿願從容。"]'),
('f6e74084-34a4-437d-8169-bfe982318f34','九龍巖','王觀','宋','宋诗','song-poetry','','[]','山寒蟄龍眠忽醒，黄衣九老巖下行。',112,'全唐诗/poet.song.36000.json','["山寒蟄龍眠忽醒，黄衣九老巖下行。", "手持屈曲千歲藤，慮驚世人藏姓名。", "山前樵子折腰迎，九老相顧笑不停。", "摧天霹靂飛一聲，舉目惟見煙冥冥。", "開山老僧爲余說，異事傳聞忘歲月。", "至今山椒泉滿地，赤白繞空中不竭。", "好分餘澤入千家，免使辛勤夜蹋車。"]'),
('6e1a499c-0224-4b9f-ae17-3f1e302beed7','句  其一','王觀','宋','宋诗','song-poetry','','[]','思霑道濕黄梅雨，敢放宮恩石井冰。',16,'全唐诗/poet.song.36000.json','["思霑道濕黄梅雨，敢放宮恩石井冰。"]'),
('95ad5b62-d164-4670-b712-e36907c5aceb','句  其二','王觀','宋','宋诗','song-poetry','','[]','炎威不到軒窗外，冷氣常存枕簟中。',16,'全唐诗/poet.song.36000.json','["炎威不到軒窗外，冷氣常存枕簟中。"]'),
('1b8c964a-8a40-4446-b030-f075364d1e00','題泗州庵庵壁','蓋抃','宋','宋诗','song-poetry','','[]','十年三上未登科，此去行期晝錦過。',32,'全唐诗/poet.song.36000.json','["十年三上未登科，此去行期晝錦過。", "上黨有人傳預兆，夢生頭角見天和。"]'),
('f26255bd-4b70-4fc3-8910-f24d9d165ca4','句','范純僖','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭春暖浮仙鷁，桂嶺花飛擁侯旌。',16,'全唐诗/poet.song.36000.json','["洞庭春暖浮仙鷁，桂嶺花飛擁侯旌。"]'),
('d44168e7-3c73-4c91-9c82-3e4c4cea64dc','送鄧德甫','蔣擴','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','高談耳冷幾經秋，解逅長沙得少留。',32,'全唐诗/poet.song.36000.json','["高談耳冷幾經秋，解逅長沙得少留。", "莫畏洞庭風浪險，主翁元是濟川舟。"]'),
('c2cb369c-bc4e-43d8-a271-567f9ebc0878','戲書僧房窗紙','陝府知縣','宋','宋诗','song-poetry','','[]','爾非慧遠我非陶，何事窗間酒一瓢。',32,'全唐诗/poet.song.36000.json','["爾非慧遠我非陶，何事窗間酒一瓢。", "僧野避人聊自醉，卧看風竹影蕭蕭。"]'),
('fc5de3f6-c474-49bd-a8dc-c4af500000c8','早梅','楊則之','宋','宋诗','song-poetry','','["\u548f\u7269", "\u6885\u82b1", "\u6292\u6000", "\u548f\u7269\u8bd7"]','數萼初含雪，孤清畫本難。',48,'全唐诗/poet.song.36000.json','["數萼初含雪，孤清畫本難。", "有香終是別，雖瘦亦勝寒。", "橫笛和愁聽，斜枝倚病看。", "朔風如解意，容易莫吹殘。"]'),
('b61e4c7d-8c11-4038-ade7-018d51a8965c','雪霽觀梅','楊則之','宋','宋诗','song-poetry','','[]','荒園晚景斂寒煙，數朵清新破雪邊。',64,'全唐诗/poet.song.36000.json','["荒園晚景斂寒煙，數朵清新破雪邊。", "幽艷有誰能畫得，冷香無主頼詩傳。", "看來最畏前村笛，折去難逢野渡船。", "向晚十分終更好，靜兼江月淡娟娟。"]'),
('f8edfc0e-86a0-4ea8-b4a5-bbb905846460','壓雲軒','楊則之','宋','宋诗','song-poetry','','[]','闌干橫礙鳥飛遲，砌下危根老更奇。',32,'全唐诗/poet.song.36000.json','["闌干橫礙鳥飛遲，砌下危根老更奇。", "僧在上頭忘歲月，不知山脚雨多時。"]'),
('840bdede-6bf9-4d4b-9f20-a900c91e88f2','題慧聚寺','楊則之','宋','宋诗','song-poetry','','[]','雪晴山色一重重，因暇尋幽訪古蹤。',64,'全唐诗/poet.song.36000.json','["雪晴山色一重重，因暇尋幽訪古蹤。", "神疊石基成寶殿，柱圖靈品感真龍。", "僧居漸遠林間地，客枕曾聞月下鐘。", "會得登臨便無事，門前流水照青松。"]'),
('38aeff18-a9ab-4b57-bd7c-bbb0c7c02212','遊慧聚寺','楊則之','宋','宋诗','song-poetry','','[]','壓雲開半殿，寶炬耀金幢。',48,'全唐诗/poet.song.36000.json','["壓雲開半殿，寶炬耀金幢。", "峭峻山無對，玲瓏寺不雙。", "鐘聲清戀塢，林影冷摇窗。", "老媿詩魔在，登臨詎易降。"]'),
('b8a4b7af-5d79-4b15-a176-5f43e392bbfc','應制依韵和御製後苑賞花釣魚','沈遘','宋','宋诗','song-poetry','','[]','春入花房次第開，上林先望屬車來。',64,'全唐诗/poet.song.36000.json','["春入花房次第開，上林先望屬車來。", "時忘萬物均民樂，恩許羣臣奉燕杯。", "鳳下朝陽時鼓舞，魚游太液自徘徊。", "愚心願獻千年壽，豈特歡娛一日陪。"]'),
('692df5d4-88f9-4506-8c23-063ca9af066e','杭州燕思閣分題四首 七言得偃松院','沈遘','宋','宋诗','song-poetry','','[]','古寺半空人跡稀，老松自偃何年有。',96,'全唐诗/poet.song.36000.json','["古寺半空人跡稀，老松自偃何年有。", "擢幹欲聳不及尋，蟠枝却覆遂盈畝。", "群鳳曬日相婆娑，病蛟眠沙獨蚴蟉。", "五月南風翠幄凉，三冬朔雪穹廬厚。", "本知託植須岡陵，豈應詘身此培塿。", "往來不用爲嘆嗟，題詩調笑兒女口。"]'),
('4fe1f802-ac20-400c-870d-e349ab3e8475','杭州燕思閣分題四首 五言得巽亭','沈遘','宋','宋诗','song-poetry','','[]','守居鳳凰背，茲亭壓其顛。',96,'全唐诗/poet.song.36000.json','["守居鳳凰背，茲亭壓其顛。", "蒼崖當前斷，崩騰勢將騫。", "洪濤從天來，萬鼓瀉百川。", "高士耳目曠，壯夫胸膽搴。", "維昔孰經始，蔣侯世稱賢。", "斯人去已久，陳迹亦屢遷。", "我來感且慕，拂拭頗增妍。", "尚存甘棠意，善政或有傳。"]'),
('ee3db209-ba7e-42ba-992b-d8d51b3559e9','杭州燕思閣分題四首 五言得歸字','沈遘','宋','宋诗','song-poetry','','[]','相識已恨晚，相從每嫌稀。',96,'全唐诗/poet.song.36000.json','["相識已恨晚，相從每嫌稀。", "如何復相失，頓與中懷違。", "淮江風波接，來云遠我圻。", "一朝晤語隔，詎能忘嘆欷。", "置酒衆賓賦，觴筆交橫飛。", "高亭山氣佳，落日暑力微。", "金池莫辭滿，後會豈易希。", "病夫意不淺，亦且倒載歸。"]'),
('b72cfa76-2186-483f-ae6f-d01da022a6aa','杭州燕思閣分題四首 七言得胡龏馬','沈遘','宋','宋诗','song-poetry','','[]','古來畫馬爲世貴，前有韓幹後胡龏。',112,'全唐诗/poet.song.36000.json','["古來畫馬爲世貴，前有韓幹後胡龏。", "幹之所圖獨御蚤，鑄金有式易爲好。", "龏閱衆馬兼漢胡，遂窮能事絕代無。", "陰山七騎實龏造，傳之至今爲畫寶。", "筆端神妙難盡譽，會見真馬騰在圖。", "真馬今人亦何識，但愛幹馬肥且澤。", "後世復有伯樂生，丹青雖渝尚典刑。"]'),
('f182f30c-6ae5-44bb-8de5-d9dbfd9e4e12','五言送劉泌歸建州','沈遘','宋','宋诗','song-poetry','','[]','東都宦遊客，風塵厭已久。',84,'全唐诗/poet.song.36000.json','["東都宦遊客，風塵厭已久。", "欣然理扁舟，歸雁不回首。", "身與汴流下，心先淮波走。", "何時過江望，家山見孤嶁。", "武夷天下名，衆溪環左右。", "幽尋莫辭倦，勝事不可負。", "逍遥其無幾，官期諒難後。"]'),
('60b17e19-8d3a-4ece-a2c5-9ece480f2470','七言何公南祕閣公會','沈遘','宋','宋诗','song-poetry','','[]','公從書閣登詞掖，西帥重歸始五年。',64,'全唐诗/poet.song.36000.json','["公從書閣登詞掖，西帥重歸始五年。", "當日諸寮半榮落，後來幾輩雜愚賢。", "齋前花樹多新植，架上塵籤亂舊編。", "嘉遇榮名時所貴，從容感詠屬觴篇。"]'),
('d780b450-83bd-4065-b10d-8c25fabeda05','七言送沈景休知常州','沈遘','宋','宋诗','song-poetry','','[]','疊鼓翻波汴流響，雙旌照地秋日晴。',176,'全唐诗/poet.song.36000.json','["疊鼓翻波汴流響，雙旌照地秋日晴。", "蘭陵使君下齋舸，都門送客冠蓋傾。", "使君去從金馬署，顔朱髮漆意氣橫。", "十年待詔困囊粟，千騎乞得專名城。", "城居雖小地迺大，物衆力薄俗喜爭。", "惠窮遷暴各有術，從來治者難其平。", "使君才勇固自許，一州詎足煩神明。", "從容談笑期月爾，坐聽道路傳能聲。", "教行民服已無事，乘時豫樂與衆并。", "惠山荆溪兩秀絕，丹轂畫隼當春行。", "還有歌詩寫高興，賓客誰許從唱賡。"]'),
('21465ca2-d66c-4e67-9882-df2123f27e7e','七言送詩僧思齊歸吳','沈遘','宋','宋诗','song-poetry','','[]','西風送霜河水落，東都歸客不可留。',128,'全唐诗/poet.song.36000.json','["西風送霜河水落，東都歸客不可留。", "囊衣卷詩載輕舸，飄然獨下東南州。", "吳山木落衆峰出，越湖潦散孤嶼浮。", "橘丹蓴紫新薦俎，若下醪美不計售。", "十年塵埃一日去，猿初脫檻鷹下韝。", "幽潜遠颺肯回首，送之却顧令人愁。", "鱸魚正肥張翰老，田園將蕪陶潜憂。", "子歸應有問予者，爲解區區茲有由。"]'),
('15ab949e-66b2-4136-8f5c-56fcde2257b1','七言送何中復赴高陵簿','沈遘','宋','宋诗','song-poetry','','[]','昔初送君向秦關，君時失意多悲嘆。',160,'全唐诗/poet.song.36000.json','["昔初送君向秦關，君時失意多悲嘆。", "今來送君復西去，君懷新命多歡語。", "別君重見凡四年，顔色如故氣軒軒。", "文章學問益老富，卓然遠致信可賢。", "長安古都今大府，并護關西諸節度。", "邇臣元老來後先，賢士大夫還而聚。", "君持利器往從之，當能一發胸中奇。", "莫嗟須臾廷下屈，我有鎡基又乘時。", "君家湘衡萬餘里，十年遠遊何所事。", "高車駟馬終當歸，努力無爲故人恥。"]'),
('9cf82145-81cd-4637-be59-4515ee63a7f7','五言送張吉老兩浙提刑','沈遘','宋','宋诗','song-poetry','','[]','秋日響船鼓，西風轉檣烏。',48,'全唐诗/poet.song.36000.json','["秋日響船鼓，西風轉檣烏。", "使節東南行，光華滿江吳。", "里門過舊遊，弩矢方前驅。", "威嚴勉自勵，寧顧舊酒徒。"]'),
('6050f92d-ca05-4808-bc9d-8a64fa3447ec','五言贈梅聖俞柑實','沈遘','宋','宋诗','song-poetry','','[]','柑實來海濱，萬里亦以勤。',60,'全唐诗/poet.song.36000.json','["柑實來海濱，萬里亦以勤。", "中州富佳果，乃無一與倫。", "薦之君子堂，豈以多爲珍。", "甘滋露欲晞，華色丹猶新。", "愛之勿久留，有酒應速賓。"]'),
('3b8dd887-db15-4793-8b41-6c7bee554d51','五言天台山送僧象微歸山','沈遘','宋','宋诗','song-poetry','','[]','吾聞天台久，嘗讀興公賦。',288,'全唐诗/poet.song.36000.json','["吾聞天台久，嘗讀興公賦。", "茲爲東南鎮，神靈之所據。", "奇挺究萬狀，嵩岱不足語。", "頗疑說過夸，特爲辭之嫭。", "象微迺州民，能識山之故。", "從容試爲問，聊得一二疏。", "赤城建霞標，上與牛斗附。", "萬有八千丈，矗若天一柱。", "瀑布發高源，飛流翻四注。", "雪霜浮虛空，晦明亂朝莫。", "巖足多丹石，光華燦寶璐。", "楢溪百餘仞，欲濟毛骨怖。", "九折凌峻梁，五界窮幽路。", "芝蘭散奇草，松桂羅嘉樹。", "祥風吹白雲，飄然若可御。", "幽閟足龏怪，纖悉難畢具。", "凡跡古不到，神物陰自護。", "傳聞昔人說，中有洞天處。", "是名不死墟，衆真所游聚。", "玉堂敞金庭，碧林列瑶圃。", "有能從而求，得之迺仙去。", "斯言寧可信，良非吾所慕。", "吾志本丘壑，久已失厥趣。", "誰言石渠客，乃甚轍中鮒。"]'),
('0ad707be-06f6-4a6d-98e4-c864e3591606','七言滑州新修東園  其一','沈遘','宋','宋诗','song-poetry','','[]','漢家東郡古延津，詔屬王畿命邇臣。',64,'全唐诗/poet.song.36000.json','["漢家東郡古延津，詔屬王畿命邇臣。", "儀物增榮都府舊，恩光流浹吏民新。", "已明條教康罷俗，更飾林園樂盛辰。", "蚤賦中和來奏御，知公不久整歸輪。"]'),
('ec5176bc-accb-48ec-9813-d42fe75c97ee','七言滑州新修東園  其二','沈遘','宋','宋诗','song-poetry','','[]','北輔爲藩自昔優，使君深壯稱公侯。',64,'全唐诗/poet.song.36000.json','["北輔爲藩自昔優，使君深壯稱公侯。", "樓臺重拂前人記，池圃更新此日遊。", "比歲豐和多愷樂，乘春臨賞幾遲留。", "使君詩藻無窮思，賓席誰堪奉唱酬。"]'),
('d0852d7a-36b2-4193-936d-4d40df058902','七言贈楊樂道建茶','沈遘','宋','宋诗','song-poetry','','[]','建溪石上摘先春，萬里封包數數珍。',32,'全唐诗/poet.song.36000.json','["建溪石上摘先春，萬里封包數數珍。", "羸病從來苦多飲，高情應只屬詩人。"]'),
('80db92a0-2f54-4b18-8891-6fdac56f1f0d','五言和楊樂道省中述懷','沈遘','宋','宋诗','song-poetry','','[]','少小學書史，頗知道所存。',144,'全唐诗/poet.song.36000.json','["少小學書史，頗知道所存。", "功名謂陳迹，古人不復論。", "既困乃干澤，羽翼何翩翻。", "初登羣玉府，猶接文字言。", "晚落司會廷，始從俗吏煩。", "朱墨事勾校，笞榜窮奸諼。", "終日坐當案，曾不聞休番。", "舊學泯不講，舊志茲益昏。", "中悼素尚違，仰愧前修尊。", "去之未云果，蕩爾何當返。", "覽君自警作，使我忘囂袢。", "友道久寥闊，期君於此敦。"]'),
('1dca5946-cf46-4645-9aca-660b580212ff','五言王景彝省舍孤竹','沈遘','宋','宋诗','song-poetry','','[]','濯濯青玉竿，矯矯孤雲姿。',48,'全唐诗/poet.song.36000.json','["濯濯青玉竿，矯矯孤雲姿。", "潜根失其托，憔悴非故時。", "主人幸加憐，曷不徙所宜。", "歲寒風霜節，無愧君子知。"]'),
('f498477d-38cf-47af-ab59-7049a0a541c7','七言和邵興宗還館','沈遘','宋','宋诗','song-poetry','','[]','三年重到集仙庭，却理陳編不自停。',64,'全唐诗/poet.song.36000.json','["三年重到集仙庭，却理陳編不自停。", "閣下舊題幾已暗，壁中遺簡尚餘青。", "故人擾擾誰相好，世事悠悠我特醒。", "坐看重雲開白日，獨摇修翮入高冥。"]'),
('4a73b359-c63f-4847-871d-dcf5d879b427','七言和陳和叔祕閣會話','沈遘','宋','宋诗','song-poetry','','[]','羣玉嵯峨壓石渠，我初通籍預讎書。',64,'全唐诗/poet.song.36000.json','["羣玉嵯峨壓石渠，我初通籍預讎書。", "三年未壓承明直，一日更從俗吏居。", "對案不堪文墨弊，離群長恨笑言疏。", "紫宸蚤退春朝永，時得期君過舊廬。"]'),
('d4f06009-4d72-4abd-b67d-98d829350c64','五言送李瑜通判潤州','沈遘','宋','宋诗','song-poetry','','[]','吳越千里廣，故鄣臨上游。',72,'全唐诗/poet.song.36000.json','["吳越千里廣，故鄣臨上游。", "江山號天險，人物自風流。", "在昔爲成國，於今亦大州。", "時平除圄守，地勝足遨遊。", "青嶂南朝寺，蒼烟北固樓。", "蓴鱸秋末老，行棹莫遲留。"]'),
('67cf2703-10f1-4833-990a-4c2e5900268a','七言送梅公儀知杭州','沈遘','宋','宋诗','song-poetry','','[]','禁閣深嚴帝策書，侍臣才調蜀相如。',64,'全唐诗/poet.song.36000.json','["禁閣深嚴帝策書，侍臣才調蜀相如。", "屢從金馬辭番直，又下承明佩左魚。", "弩矢前驅登北固，壺漿迎路過姑蘇。", "使君詩老江山勝，早晚新篇到石渠。"]'),
('28363d03-811a-41f0-927c-d567a70acf76','五言送許當通判泉州','沈遘','宋','宋诗','song-poetry','','[]','我昔溫陵行，始初得許侯。',192,'全唐诗/poet.song.36000.json','["我昔溫陵行，始初得許侯。", "溫陵故佳勝，况從吉士游。", "日月雖無幾，所樂良綢繆。", "歸來十載間，再見朝王州。", "故人重相遇，尊酒更勸酬。", "歡意我已衰，壯心君益遒。", "君顔反更少，我但未白頭。", "乃知中都勞，豈若江湖優。", "嗟哉石渠客，有似魚被鈎。", "何不斷去之，未知所從流。", "羨君翩然歸，春風帆畫舟。", "錦衣鄉治中，弩矢驅道周。", "舊廬何光輝，高堂薦甘羞。", "仕者固應爾，自餘信悠悠。", "送君喜寧已，顧我愧莫收。", "幸君謝友朋，我志無所求。"]'),
('8ed8aec7-94c6-44c4-8d8b-71d65cf8b985','五言送陳舜俞壽州從事','沈遘','宋','宋诗','song-poetry','','[]','天下賢良選，公車凡幾人。',72,'全唐诗/poet.song.36000.json','["天下賢良選，公車凡幾人。", "君侯獨高第，聲實兩無倫。", "鸑鷟來丹穴，麒麟出九真。", "推先東國士，傾動漢廷臣。", "未引金閨籍，聊爲幕府賓。", "還家莫留滯，行看壽陽春。"]'),
('d18de91e-6bbc-46a9-97c0-080469b335e2','七言和吳沖卿省舍觀蘇才翁題壁','沈遘','宋','宋诗','song-poetry','','[]','空堂老壁隃塵昏，蘇子之蹟世所珍。',64,'全唐诗/poet.song.36000.json','["空堂老壁隃塵昏，蘇子之蹟世所珍。", "龍虎變化生風雲，拏石攫木力萬鈞。", "斯人豪奇邁倫羣，平生慷慨半道淪。", "高辭壯論胡不存，惜哉獨以技藝聞。"]'),
('989c6ec0-3e0f-4190-9ce4-547b0f90e5e4','五言沈沔天隠樓','沈遘','宋','宋诗','song-poetry','','[]','吳會富山水，吳興盛人物。',288,'全唐诗/poet.song.36000.json','["吳會富山水，吳興盛人物。", "風流自南朝，德譽世不沒。", "吾宗州之望，譜序遠且蕃。", "煌煌全盛時，冠蓋充里門。", "吾廬兩溪旁，足跡遠城市。", "宛自仙者居，胡然人間世。", "自我登羣玉，十年未得歸。", "秋風東南望，悵息欲下飛。", "軒軒吾宗子，自少慕奇偉。", "仕意一不如，去之若泥滓。", "起樓臨孤墅，自以天隠名。", "超焉謝朋友，於茲寄生平。", "我初聞以疑，今迺送而喜。", "出處亦何常，要之不苟爾。", "俗化日以薄，士路令人哀。", "吾黨多狂簡，不知所以裁。", "子歸慎厥修，先之以廉讓。", "風行自田閭，來者知所尚。", "庶幾吾州士，禮義世弗虧。", "庶幾吾宗門，長爲衆表儀。", "毋獨矜汝名，母獨行乎怪。", "鳥獸非所群，山林固何頼。", "吾雖縻於此，亦若與子遊。", "勔哉其無悶，勿爲至人羞。"]'),
('6690499a-d471-4490-80d5-1c6dfb35122a','五言杭州僧修廣法喜堂','沈遘','宋','宋诗','song-poetry','','[]','圂圂學佛者，營營良足悲。',72,'全唐诗/poet.song.36000.json','["圂圂學佛者，營營良足悲。", "不知佛之樂，誰使汝學爲。", "廣師吾州秀，智解迺天資。", "既以法爲喜，萬緣脫若遺。", "高堂客滿坐，妙談破羣疑。", "來者豈不辨，辨此堂之題。"]'),
('2ac973f7-f38d-47c0-b277-58d404106ddd','七言景德寺考試院和李子儀重陽日','沈遘','宋','宋诗','song-poetry','','[]','勁風疏雨深秋節，古寺重扃獨坐人。',64,'全唐诗/poet.song.36000.json','["勁風疏雨深秋節，古寺重扃獨坐人。", "菊色未開期有待，萸香欲佩使誰紉。", "登高莫作西城望，把鏡須憐白髮新。", "持酒勸君休惜醉，定知歸日不盈旬。"]'),
('f3f070ff-c0f1-4281-b38d-8ab369837f20','七言景德寺考試院壁和王介甫所題詩二首  其一','沈遘','宋','宋诗','song-poetry','','[]','石藍開盡紅著地，瓜蔓半枯黄倒垂。',32,'全唐诗/poet.song.36000.json','["石藍開盡紅著地，瓜蔓半枯黄倒垂。", "坐看一夜芳意歇，風霜即是蚤寒時。"]'),
('71de86cc-7d38-4c04-b042-2fa22db1be2e','七言景德寺考試院壁和王介甫所題詩二首  其二','沈遘','宋','宋诗','song-poetry','','[]','夜風吹雨冷通帷，鳴雁初聞一一悲。',32,'全唐诗/poet.song.36000.json','["夜風吹雨冷通帷，鳴雁初聞一一悲。", "幸好歸時歸未得，愁來莫讀壁間詩。"]'),
('14d13496-962b-441e-82c3-0b586adf7133','七言次韵和王景彝十一月朔早朝','沈遘','宋','宋诗','song-poetry','','[]','日上扶桑闢九關，天威咫尺不違顔。',64,'全唐诗/poet.song.36000.json','["日上扶桑闢九關，天威咫尺不違顔。", "簪紳就次初傳警，內外分朝迭進班。", "霜壓陛隅螭闖首，風摇殿戶獸鳴環。", "聖君從諫寬狂直，丹檻無容復敢攀。"]'),
('252014f7-fa76-4a7e-bca1-5f568a9aaf53','五言次韵和宋次道省直','沈遘','宋','宋诗','song-poetry','','[]','少小學文史，焉知事簿書。',48,'全唐诗/poet.song.36000.json','["少小學文史，焉知事簿書。", "時爲吏舍直，端與玉山疏。", "叢竹聊相對，孤斟强自攄。", "猶欣二三子，佳句數開予。"]'),
('d768ae38-5523-4623-ba2b-d1cd2c6ab90c','七言次韵和次道十一月朔早朝','沈遘','宋','宋诗','song-poetry','','[]','紫宸陛戟百重深，拜朔官儀列弁簪。',64,'全唐诗/poet.song.36000.json','["紫宸陛戟百重深，拜朔官儀列弁簪。", "旭日未全開宿靄，清風先已斂羣陰。", "邇臣自識宵衣志，下士徒懷夙退心。", "虞氏致平猶有戒，願聞歌載誦餘音。"]'),
('00f271fd-9b0f-4b6d-98b9-99208d03e7b7','五言送余良孺大監致仕歸鄉','沈遘','宋','宋诗','song-poetry','','[]','士有逢辰泰，榮名四十期。',120,'全唐诗/poet.song.36000.json','["士有逢辰泰，榮名四十期。", "更持使者節，數建守臣麾。", "清懿推朝品，慈良號吏師。", "修塗方自致，壯志未容衰。", "雅尚先知止，歸心浩若馳。", "君恩寵年至，監尹峻官儀。", "緩带金鱗重，安輿紫綬垂。", "達尊傾我里，盛觀聳當時。", "擺落公門事，逍遥野老嬉。", "維應愛玉體，五福保期頤。"]'),
('582ce386-047d-4072-a15a-55f2134208cc','七言次韵和樂道出省後見寄','沈遘','宋','宋诗','song-poetry','','[]','君從司會陛延閣，更職華光奉講論。',64,'全唐诗/poet.song.36000.json','["君從司會陛延閣，更職華光奉講論。", "却顧簿書勞已甚，獨懷僚友意仍存。", "新居近指西城路，舊約還尋北海樽。", "便欲相期五人者，軒車蚤晚下宮門。"]'),
('2a85e119-f3c4-4593-aa69-b3fd0b3c763c','五言和劉原甫陽春宜白雪','沈遘','宋','宋诗','song-poetry','','[]','陽春宜白雪，良時宜少年。',96,'全唐诗/poet.song.36000.json','["陽春宜白雪，良時宜少年。", "試攀瓊樹枝，芳意已覺妍。", "梅花初厭多，楊花乍疑早。", "園林光氣生，衆物競鮮好。", "一春都幾日，行樂遽勿遲。", "何辭踏泥出，猶當秉燭歸。", "少年自應然，老大寧復爾。", "豈不感物華，尚能强醇醴。"]'),
('b60aaae2-96e5-4f87-be56-249dd6623def','五言送韓玉汝知洋州','沈遘','宋','宋诗','song-poetry','','[]','帝制一海內，畫州以域民。',252,'全唐诗/poet.song.36000.json','["帝制一海內，畫州以域民。", "小大雖有殊，執任兩各均。", "祖宗初垂統，所重尤守臣。", "授受何其艱，便坐躬簡輪。", "承平彌百年，法敝幾不泯。", "其文豈弗具，其實蓋已淪。", "遂令師帥官，十九非其人。", "韓侯出名家，英聲邁儔倫。", "昔爲兩劇縣，遺美今猶新。", "匪直郡邑良，固是臺閣珍。", "胡然不留用，出駕雙朱輪。", "洋州實大府，左右控蜀秦。", "厥土從古樂，厥俗於茲淳。", "侯才何足施，談笑坐養神。", "君子學無苟，不讓誠當仁。", "既富而後教，禮義庶可循。", "坐聽千里謠，上徹九重宸。", "表以視四方，寵以厲縉紳。", "因之明黜陟，審辨玉與珉。", "尚使天下治，復如前代純。", "鄙言真區區，感激爲侯陳。"]'),
('aae3d820-d823-4ebb-8c86-01ffbf68c86f','七言送辛有終知鄂州','沈遘','宋','宋诗','song-poetry','','[]','江漢交流古要津，高牙大旆壓城闉。',64,'全唐诗/poet.song.36000.json','["江漢交流古要津，高牙大旆壓城闉。", "昔尊丞相初開府，今屬郎官試治民。", "迎路壺漿因問俗，前車弩矢便行春。", "由來美化先南國，遺樂猶應詠錯薪。"]'),
('2a621101-0aa2-4881-9cd9-10a01a4c38bf','五言蓬萊山送徐仲微赴蓬萊令','沈遘','宋','宋诗','song-poetry','','[]','渤海三神山，蓬萊隠嵯峨。',156,'全唐诗/poet.song.36000.json','["渤海三神山，蓬萊隠嵯峨。", "仙人桂葉舟，浮矣明月波。", "驚塵不可到，飛鳥不能過。", "世人但傳聞，欲往爲奈何。", "胡然古荒王，甘心事欺詑。", "於今禱祠跡，往往存山阿。", "當時燕齊間，方士肩相摩。", "遺俗頗淪胥，官不嚴禁訶。", "子去爲邑尹，施舍各有科。", "茲實繫教化，無宜反媕婀。", "平生學詩書，仁術嘗切磋。", "毋曰百里小，民人豈不多。", "誰當之武城，敢復聞弦歌。"]'),
('509c07d2-5fee-4547-97f0-c94f79d80c05','七言送句諶通判潁川','沈遘','宋','宋诗','song-poetry','','[]','朝驅款段北省客，莫駕屏星州治中。',64,'全唐诗/poet.song.36000.json','["朝驅款段北省客，莫駕屏星州治中。", "朱顔綠髮出塵土，長纓高蓋生清風。", "彼都之勝實樂國，潁汝交貫淮波通。", "使子乞得一麾去，寧復汲汲須江東。"]'),
('29b53ceb-079f-4f71-9f79-9562d6fd64fe','五言和鄰幾答李公達遺嘉慶李','沈遘','宋','宋诗','song-poetry','','[]','朱實出東土，名獨與衆殊。',48,'全唐诗/poet.song.36000.json','["朱實出東土，名獨與衆殊。", "友人重家果，分贈比明珠。", "堆盤薄霞色，熨齒清露腴。", "恨君賞意淺，有酒空盈壺。"]'),
('fc99fddf-edf7-4405-a033-0f63f2e58e5a','五言次韵和沖卿省直','沈遘','宋','宋诗','song-poetry','','[]','省舍實褊迫，强分庭與軒。',96,'全唐诗/poet.song.36000.json','["省舍實褊迫，强分庭與軒。", "君看午熱時，何異炊甑然。", "內景雖屢清，外物苦益喧。", "濁河不足滌，當尋崑崙源。", "顧身無羽翼，大叫不得前。", "却圖須臾濟，雪散和冰丸。", "嗟我江湖人，胡爲投此間。", "羨君富高興，尚堪吟詠煩。"]'),
('d3d1e200-570b-4cdf-b59d-da7e9ee042ea','五言次韵和鄰幾喜司馬君實錢君倚章伯鎮入省之作','沈遘','宋','宋诗','song-poetry','','[]','我本魯連徒，放跡江湖濱。',240,'全唐诗/poet.song.36000.json','["我本魯連徒，放跡江湖濱。", "强茲就朝列，俯仰羞衆人。", "初從東觀游，尚得文字親。", "晚爲大農屬，始與俗吏倫。", "簿書異我學，勾校違我貞。", "有如鍛戈劍，而乃驅匠輪。", "顛倒失所措，左右迷厥津。", "怳不知適從，但欲逃深榛。", "獨幸良友朋，志尚略一均。", "繼今三君來，益欣得有鄰。", "誰云典司殊，舍次密若鱗。", "誰云晤語希，牖戶日屢巡。", "論文必高妙，談道皆淵淳。", "揮弄麈白玉，傾倒巾紫綸。", "謂應饜饑渴，寧復辭昏晨。", "願言勿有倦，行即徂秋春。", "宦游固難常，出處各有循。", "公等其謂何，我意益欲踆。", "一朝成契闊，相望楚與秦。", "高會不得再，空將寄音塵。"]'),
('d7477c84-e671-4186-868c-cecf4a8e8b10','五言次韵和景彝秋興','沈遘','宋','宋诗','song-poetry','','[]','蘭蕙含清露，芙蕖墮綠波。',48,'全唐诗/poet.song.36000.json','["蘭蕙含清露，芙蕖墮綠波。", "暑隨朝雨盡，凉入暮天多。", "已覺金行早，誰調玉燭和。", "西風但高詠，將奈綠醽何。"]'),
('5dfac23b-1a43-489e-943d-1cc767d98af8','五言次韵和邵不疑省直','沈遘','宋','宋诗','song-poetry','','[]','藹藹大農府，陰陰道南廬。',96,'全唐诗/poet.song.36000.json','["藹藹大農府，陰陰道南廬。", "夜直何其頻，我性實已疏。", "每來兀兀坐，中懷鬰不舒。", "幸茲新凉至，燈火理舊書。", "秋風吹我衣，浩然發歸思。", "念我去江湖，人事不復記。", "擾擾彌十年，忽忽都一寐。", "中夜慎勿思，無枕不得睡。"]'),
('3abbe3f4-9eb8-4e2a-904a-30f98846319b','七言和君倚景靈行','沈遘','宋','宋诗','song-poetry','','[]','東城大道何逶迤，中直清廟表六扉。',230,'全唐诗/poet.song.36000.json','["東城大道何逶迤，中直清廟表六扉。", "右臨景靈秘館之翼翼，左带相國浮圖之巍巍。", "道旁第舍多赩赫，車無停輪馬交策。", "風塵勃鬰千丈高，素衣化緇雙眥塞。", "南阡窮巷我所居，上下省戶兩歲餘。", "病軀羸乘實厭畏，每趨徑路宮城隅。", "宮牆倚空背環極，隠嶙樓臺露金碧。", "朝霞夕照天半明，牆下行人徒眩惑。", "我嘗入謁得縱觀，威容物采嚴且完。", "鸞車歲歲躬獻享，孝思肸蠁通神歡。", "重門設衛日常闔，靈境那令世人雜。", "但見長松怪石列若屏，突兀陰森兩遮匝。", "我家東南滄海涯，乘時偶來觀德輝。", "歸飛故隠自有期，何必於此空歎欷。"]'),
('df00304d-5019-4cac-a87e-c7a5ce71b644','五言次韵和君實苦雨三首  其一','沈遘','宋','宋诗','song-poetry','','[]','浩浩雨不止，寥寥風且寒。',48,'全唐诗/poet.song.36000.json','["浩浩雨不止，寥寥風且寒。", "敢言裘褐具，尚幸室廬完。", "彌月天形晦，無時轍跡乾。", "田臯何處在，誰復顧蕭蘭。"]'),
('43c82df2-d2b1-4bf9-8786-c9bb8e7c6e39','五言次韵和君實苦雨三首  其二','沈遘','宋','宋诗','song-poetry','','[]','不見清秋月，悠悠雨過弦。',48,'全唐诗/poet.song.36000.json','["不見清秋月，悠悠雨過弦。", "重陽初未解，委照固無偏。", "安得長風御，都驅宿藹旋。", "還當三五夕，圓魄獨當天。"]'),
('287bd90b-e3dc-4243-89c7-e988854e3c0a','五言次韵和君實苦雨三首  其三','沈遘','宋','宋诗','song-poetry','','[]','積潦高秋後，幽居病客心。',48,'全唐诗/poet.song.36000.json','["積潦高秋後，幽居病客心。", "每憐荷折蓋，猶愛菊包金。", "獨坐有餘恨，臨觴莫厭深。", "多情省郎直，永夜祗清吟。"]'),
('8b7ab9c5-4c6e-46c2-8d3b-e1483ae7a892','五言送徐同年諤出京','沈遘','宋','宋诗','song-poetry','','[]','激立幾年志，淹遲一日亨。',48,'全唐诗/poet.song.36000.json','["激立幾年志，淹遲一日亨。", "還家晝錦樂，拜壽綵衣榮。", "未辟諸侯府，無矜晚宦情。", "重來奏千牘，應笑舊題名。"]'),
('575c29b4-86c8-4a6e-9b69-944b46d04d67','代人進南郊禮成','沈遘','宋','宋诗','song-poetry','','[]','宋德承天序，郊丘必以時。',120,'全唐诗/poet.song.36000.json','["宋德承天序，郊丘必以時。", "先期發明詔，戒日具多儀。", "閟館嚴真祖，清宮謹大祠。", "孝思追祖考，禋祀致神祇。", "三聖同升侑，群靈罔弗祗。", "聲文更舊律，鼎鬲列親規。", "禮樂榮觀洽，雲雷慶澤施。", "歡聲充有截，盛事極無遺。", "皇祚千齡永，成能萬世宜。", "臣心奚以答，歌頌一毫釐。"]'),
('6a74d0b0-00e3-4a80-b7f8-8b5c2c493930','晚雨後過城東','沈遘','宋','宋诗','song-poetry','','[]','東城雨始歇，紫陌無纖埃。',72,'全唐诗/poet.song.36000.json','["東城雨始歇，紫陌無纖埃。", "佳氣四面起，游光泛樓臺。", "日莫市井合，叫舞何喧豗。", "我時騎過之，顧瞻顔屢開。", "欣其幸如此，平歲無愁猜。", "吾人雖安坐，猶能詠康哉。"]'),
('a9b7cb8b-3444-42d1-af6c-d60f3066868c','和江鄰幾送文丞相還游普安院','沈遘','宋','宋诗','song-poetry','','[]','擾擾市朝士，一身衆役該。',288,'全唐诗/poet.song.36000.json','["擾擾市朝士，一身衆役該。", "官曹畏職業，人事煩往來。", "朝出被風雨，莫還衝塵埃。", "竟歲長若此，何時能休哉。", "適聞丞相行，巾車城西隈。", "冠蓋盛出送，車馬相喧豗。", "吾有四君子，約言共追陪。", "烏躔轉背午，歸來倦支骸。", "道旁有精舍，聊茲釋鞍彍。", "殿閣鬰四合，高明絕纖灰。", "曲池含清波，魚鳥中沿洄。", "禁園直南望，參差隠樓臺。", "秋風肅衆物，野氣日夕佳。", "幽趣坌來會，俗紛頓可推。", "高情緬山水，劇語雜譏詼。", "清賞何以娛，一枰聊爲開。", "豈徒事爭决，要且資歡咍。", "謂言坐上客，茲樂那易諧。", "城中苦多事，况復日月催。", "功名未有立，壯志先欲摧。", "幸時得閒暇，一出紓吾懷。", "此言固可結，此願惟恐乖。", "須臾夕照下，欲起姑徘徊。", "攬轡更留顧，餘興無窮涯。"]'),
('07cbbfea-1284-4e88-8733-cc4a05b01538','七言和王微之漁陽圖','沈遘','宋','宋诗','song-poetry','','[]','燕山自是漢家地，北望分明掌股間。',32,'全唐诗/poet.song.36000.json','["燕山自是漢家地，北望分明掌股間。", "休作畫圖張屋壁，空令壯士老朱顔。"]'),
('be3839bc-d116-468a-b3a7-072819749170','五言送袁陟通判撫州','沈遘','宋','宋诗','song-poetry','','[]','上林珊瑚枝，太液琉璃波。',72,'全唐诗/poet.song.36000.json','["上林珊瑚枝，太液琉璃波。", "孔鸞相徘徊，鳬鷃不敢過。", "嘉樹日零落，清流成惡腐。", "凡鳥鬬嬉鳴，珍群摇翮去。", "去兮將安之，江山斂羽儀。", "何時復來還，聊以三歲期。"]'),
('e715dd31-54a0-49ef-8a15-2f93ca1a6ced','五言過江鄰幾官舍  其一','沈遘','宋','宋诗','song-poetry','','[]','君舍城之背，蕭然十畝餘。',48,'全唐诗/poet.song.36000.json','["君舍城之背，蕭然十畝餘。", "四垣通野墅，一舸泛官渠。", "夏木陰成後，凉天雨歇初。", "公門日無事，觴詠莫容疏。"]'),
('092f909d-b62f-4866-8430-ef3d6889fec8','五言過江鄰幾官舍  其二','沈遘','宋','宋诗','song-poetry','','[]','碕岸淺可弄，平流清且漪。',48,'全唐诗/poet.song.36000.json','["碕岸淺可弄，平流清且漪。", "葭蒲亂垂影，魚鳥悉浮嬉。", "浩蕩江湖思，差池林壑期。", "誰能共茲語，終約不吾欺。"]'),
('bde90c83-c166-4499-a933-9e46345df65f','五言過江鄰幾官舍  其三','沈遘','宋','宋诗','song-poetry','','[]','願見豈辭遠，况從吾友行。',48,'全唐诗/poet.song.36000.json','["願見豈辭遠，况從吾友行。", "清談開憤懣，高詠聽鏗鍧。", "赤日煩暑却，晚風凉氣生。", "歸鞍任傾倒，莫惜釂餘觥。"]'),
('2f86c000-f955-4301-94e0-3aba462fd7e7','五言奉酬楊祖二閣老中書省齋宿見寄','沈遘','宋','宋诗','song-poetry','','[]','詞省非吾據，維應頼兩公。',48,'全唐诗/poet.song.36000.json','["詞省非吾據，維應頼兩公。", "自憐雖壯齒，多病祗衰翁。", "飲興端難强，詩情久已窮。", "還家即高卧，客轍任西東。"]'),
('3cca8839-3b04-42f8-95b2-5129c082c934','七言送蘇結赴蜀州推官','沈遘','宋','宋诗','song-poetry','','[]','嘉陵劍閣萬里道，自古當爲行役憂。',64,'全唐诗/poet.song.36000.json','["嘉陵劍閣萬里道，自古當爲行役憂。", "於今帝制自無外，仕者何必盡中州。", "我昔成都兩歲留，春風秋月多遨遊。", "須知錦城雖云樂，不如早還滄海頭。"]'),
('3073257e-732e-43d2-8e80-0ab4899d7707','五言後殿考進士解嘲','沈遘','宋','宋诗','song-poetry','','[]','絳闕連碧城，白日橫采霓。',96,'全唐诗/poet.song.36000.json','["絳闕連碧城，白日橫采霓。", "鈞天萬舞徹，鸞鳳鳴且飛。", "我爲帝所遊，十日不知返。", "我樂殊未央，尚恨春晝短。", "東風吹蟠桃，花落滿我衣。", "拂去還復來，悠然生我思。", "顧謝衆仙人，我自人間世。", "世累雖可憎，天上亦多事。"]'),
('a9e101ae-b971-4f21-97ca-f52bea34c301','七言和吳仲庶延藝閣後牡丹花  其一','沈遘','宋','宋诗','song-poetry','','[]','零落欄桿暗蘚侵，花苞憔悴怨春深。',32,'全唐诗/poet.song.36000.json','["零落欄桿暗蘚侵，花苞憔悴怨春深。", "吾君意在延經藝，不學前王宴豫心。"]'),
('2a1c6d6c-0be3-4e4c-927a-e0539d9d1a96','七言和吳仲庶延藝閣後牡丹花  其二','沈遘','宋','宋诗','song-poetry','','[]','承明待詔盡名儒，一願當君奏六符。',32,'全唐诗/poet.song.36000.json','["承明待詔盡名儒，一願當君奏六符。", "獨笑開元供奉客，惟將歌句奉歡娛。"]'),
('08ad3f17-4735-44b6-887d-2c4d5ad6a419','七言送密學施侍郎知杭州','沈遘','宋','宋诗','song-poetry','','[]','塞外風烟河上塵，歸來始覺二毛新。',64,'全唐诗/poet.song.36000.json','["塞外風烟河上塵，歸來始覺二毛新。", "承明自厭頻趨直，滄海還思一濯巾。", "幕府旌旗初壓境，畫船歌吹便行春。", "湖山滿目舊游在，何日從公醉紫蓴。"]'),
('b63ac925-9734-438a-aa9e-30a21dda8195','奉祠東太乙宮七首 七言步虛辭二首 其一','沈遘','宋','宋诗','song-poetry','','[]','碧城絳闕半夜開，翠旗玉節相徘徊。',32,'全唐诗/poet.song.36000.json','["碧城絳闕半夜開，翠旗玉節相徘徊。", "景光散墮燈火蔽，步虛一聲天上來。"]'),
('89a8e90a-7fe2-4382-a984-2117c8151a36','奉祠東太乙宮七首 七言步虛辭二首 其二','沈遘','宋','宋诗','song-poetry','','[]','赤烏鼓舞揚朝暉，白榆零落收夕霏。',32,'全唐诗/poet.song.36000.json','["赤烏鼓舞揚朝暉，白榆零落收夕霏。", "侍臣再拜謝神貺，步虛一聲天上歸。"]'),
('a1f208ed-6386-4879-99d4-3c8df3984a3c','奉祠東太乙宮七首 五言讀道書一首','沈遘','宋','宋诗','song-poetry','','[]','甘泉三日齋，讀盡群王書。',36,'全唐诗/poet.song.36000.json','["甘泉三日齋，讀盡群王書。", "天風起寒門，便欲凌太虛。", "顧身無羽翼，歎息知何如。"]'),
('d09e3891-43ce-4a93-9ce2-d93729c66613','奉祠東太乙宮七首 五言齊居有感一首','沈遘','宋','宋诗','song-poetry','','[]','城中塵埃多，白日迷東西。',96,'全唐诗/poet.song.36000.json','["城中塵埃多，白日迷東西。", "城中市井喧，半夜猶鼓鼙。", "我本江海人，偶來東都客。", "寸心雖自丹，兩鬢頗欲白。", "一爲城南宿，晚若與世違。", "不聞車馬音，但見烟霞飛。", "自喜復自羞，胡然久羈旅。", "秋風弄濤時，聊可整歸艣。"]'),
('899d9252-4111-4c78-95b0-a25a3538b432','奉祠東太乙宮七首 七言致齋一首','沈遘','宋','宋诗','song-poetry','','[]','君王無意學神仙，獨爲蒼生致吉蠲。',32,'全唐诗/poet.song.36000.json','["君王無意學神仙，獨爲蒼生致吉蠲。", "四月麥苗殊未好，一番靈雨即豐年。"]'),
('683fea49-497c-4737-acef-812071dbd391','奉祠東太乙宮七首 七言祀畢大雨一首','沈遘','宋','宋诗','song-poetry','','[]','由來聖作與天通，甘澤祥飈撤俎中。',32,'全唐诗/poet.song.36000.json','["由來聖作與天通，甘澤祥飈撤俎中。", "更賜太元千歲策，平明馳賀未央宮。"]'),
('3d6c341b-a342-4eb8-bd0e-1aaa85a0b41a','奉祠東太乙宮七首 七言齋居寄楊祖二閣老一首','沈遘','宋','宋诗','song-poetry','','[]','蕭洒城南尺五天，晝凉高枕夢遊仙。',32,'全唐诗/poet.song.36000.json','["蕭洒城南尺五天，晝凉高枕夢遊仙。", "勞君揮翰紫宸裏，汗浥朝衣不得眠。"]'),
('841697de-c7ee-444f-a1e3-24fe16aee398','七言西太乙宮致齋遣興二首  其一','沈遘','宋','宋诗','song-poetry','','[]','城中暑雨方鬰陶，城外秋風已蕭瑟。',32,'全唐诗/poet.song.36000.json','["城中暑雨方鬰陶，城外秋風已蕭瑟。", "下馬解衣高枕眠，惟恐祠官報歸日。"]'),
('33c01e82-5f9b-4def-be4b-7156f2f528ee','七言西太乙宮致齋遣興二首  其二','沈遘','宋','宋诗','song-poetry','','[]','我來西郊始三日，超然便若與世違。',32,'全唐诗/poet.song.36000.json','["我來西郊始三日，超然便若與世違。", "市朝迺在咫尺爾，况復萬里滄浪歸。"]'),
('8e87db18-8f68-42e3-b4bb-752ecb7823e7','七言訪凈因璉上人一首','沈遘','宋','宋诗','song-poetry','','[]','春風才得馬蹄乾，便向城西學問禪。',32,'全唐诗/poet.song.36000.json','["春風才得馬蹄乾，便向城西學問禪。", "不是重陰開白日，自披雲霧睹青天。"]'),
('3b390a00-217f-4024-aa00-8231811868b7','次韵和張元常中秋夜不見月','沈遘','宋','宋诗','song-poetry','','[]','月色初無別，人心自有分。',48,'全唐诗/poet.song.36000.json','["月色初無別，人心自有分。", "長令照清夜，猶勝掩重雲。", "老去歡難强，衰來飲易醺。", "君家富歌管，獨不使人聞。"]'),
('5ccb3186-f402-48b9-916f-8da0f92c2601','送劉定下第','沈遘','宋','宋诗','song-poetry','','[]','六科收賢才，所得豈非真。',96,'全唐诗/poet.song.36000.json','["六科收賢才，所得豈非真。", "奈何如劉子，反爾棄若淪。", "衆頗爲我嗟，我斯自能信。", "言也尚莫知，行之得無訒。", "謝去不復顧，所重非吾身。", "孝友且爲政，况茲有民人。", "廣陵昔富都，今已空殘甚。", "行矣思自强，公卿皆子任。"]'),
('a7c01363-9851-47cb-b9fd-be849dd2ee34','弔普濟大師','沈遘','宋','宋诗','song-poetry','','[]','鄉里多長者，平生愛斯人。',48,'全唐诗/poet.song.36000.json','["鄉里多長者，平生愛斯人。", "誰言相識晚，俯仰跡已陳。", "短章昔固許，掛劍義所申。", "空堂對孤詠，寂寞猶相親。"]'),
('6f70c6b8-79df-469b-81db-3c559e3fd3f2','南漪堂','沈遘','宋','宋诗','song-poetry','','[]','山繞湖堂寺繞山，平生願向此中閑。',64,'全唐诗/poet.song.36000.json','["山繞湖堂寺繞山，平生願向此中閑。", "青雲白水相浮蕩，野客高僧獨往還。", "少年自嫌軒冕累，因循將恐鬢鬚斑。", "南漪最是逍遥地，且挹清波濯愧顔。"]'),
('308bce65-506a-41ab-86ed-7aceaa8fdb6a','次韵和少述秋興','沈遘','宋','宋诗','song-poetry','','[]','浩蕩西風動客裾，飄然歸思滿田廬。',64,'全唐诗/poet.song.36000.json','["浩蕩西風動客裾，飄然歸思滿田廬。", "少時豈省爲名誤，老去真知與世疏。", "勝事祗隨詩句盡，壯懷猶向酒杯舒。", "南山已有終年約，三徑何年得自除。"]'),
('df16e006-2d92-4a4f-899d-3f9633028c8b','送諸進士赴試禮部','沈遘','宋','宋诗','song-poetry','','[]','吾州號多士，今茲見諸生。',96,'全唐诗/poet.song.36000.json','["吾州號多士，今茲見諸生。", "自非中正舊，焉識鄉里評。", "但喜後來秀，紛若春華榮。", "高會存故事，工歌追鹿鳴。", "勸酬皆嘉賓，雜奏瑟與笙。", "何以爲子贈，贈子毋驕盈。", "一獻未足信，要之觀厥成。", "行矣其自厲，傾耳聞吉聲。"]'),
('545d0d79-0fe7-491c-8e55-b4279fdfadd1','次韵和李審言上元寄王巖夫','沈遘','宋','宋诗','song-poetry','','[]','此都豪麗歲仍豐，此夕都人凱樂中。',64,'全唐诗/poet.song.36000.json','["此都豪麗歲仍豐，此夕都人凱樂中。", "車馬笙簫千里至，樓臺燈火九衢通。", "香輿軋軋凌風駛，粉袂翩翩照地紅。", "病守行春真莫强，更堪攀倚少年叢。"]'),
('bd1a5045-e4af-4887-9fe0-ba7355c6a477','次韵和王巖夫有美堂會諸年契','沈遘','宋','宋诗','song-poetry','','[]','西寺題名墨尚新，今爲賓主此堂人。',64,'全唐诗/poet.song.36000.json','["西寺題名墨尚新，今爲賓主此堂人。", "縱談更起揮青麈，極醉何妨倒紫綸。", "梁苑舊遊皆已往，吳山高會正臨春。", "欲知勝事常難得，嘉句先應動薦紳。"]'),
('b28780e9-e6e1-4575-b1e5-82d86795d339','次韵和盧中甫有美堂會諸年契','沈遘','宋','宋诗','song-poetry','','[]','華屋陳高會，春風衆物新。',48,'全唐诗/poet.song.36000.json','["華屋陳高會，春風衆物新。", "嘉賓共科籍，勝事動邦人。", "大白期無算，清談信絕塵。", "詩豪兩難敵，弱力厭千鈞。"]'),
('d091dddb-a280-4415-8a75-b018775cc3d5','次韵和王仲至李審言見寄','沈遘','宋','宋诗','song-poetry','','[]','相如未用尚文園，暴勝威名世已傳。',64,'全唐诗/poet.song.36000.json','["相如未用尚文園，暴勝威名世已傳。", "攬轡一時高莫挹，著書千首浩無邊。", "顧慙局趣何能駕，望絕騏騮不得前。", "聖世料材方責實，便應歸泛五湖船。"]'),
('26879fb0-fde0-4158-a440-fa266f05860f','次韵和王巖夫見寄','沈遘','宋','宋诗','song-poetry','','[]','前日移舟就近村，送君西望大梁門。',64,'全唐诗/poet.song.36000.json','["前日移舟就近村，送君西望大梁門。", "九重宮闕天光遠，千里江湖水氣昏。", "壯士遨遊應自適，少年離別枉傷魂。", "北州爲政須當厲，即上青雲款帝閽。"]'),
('4de8ac03-2d00-4ecf-8a1e-a2bbc6d73fb0','次韵和審言與孫少述會遊審言以病不至','沈遘','宋','宋诗','song-poetry','','[]','三吳高士厭英躔，乘興南來得暫延。',64,'全唐诗/poet.song.36000.json','["三吳高士厭英躔，乘興南來得暫延。", "俗役更思拋吏几，勝遊還約泛湖船。", "平生慕義如饑渴，自昔論交孰後先。", "獨恨良朋不相對，一吟嘉句重悁悁。"]'),
('f9d7c726-d82c-43d3-a774-bf5407fa0693','次韵和少述見贈兼簡審言','沈遘','宋','宋诗','song-poetry','','[]','十年高卧占東南，禹穴幽縱久已探。',64,'全唐诗/poet.song.36000.json','["十年高卧占東南，禹穴幽縱久已探。", "峻節千尋山壁立，虛懷萬頃海波涵。", "愧非仲舉能延士，頼有君公爲對談。", "大句聯來兩豪絕，應知弱力已難堪。"]'),
('5025dd07-cf35-4ed6-aca0-6648ba1d7678','許當郎中自溫陵寄詩敘舊遊之感奉酬','沈遘','宋','宋诗','song-poetry','','[]','少小溫陵客，於今記昔遊。',48,'全唐诗/poet.song.36000.json','["少小溫陵客，於今記昔遊。", "故人情最厚，嘉句遠相求。", "勝事成陳迹，流年換白頭。", "僧坊屢題壁，知有舊痕不。"]'),
('c8baeeea-c4ae-4b85-b5b7-b0da1a5ea4cc','江陰楊使君寄示與楊從事唱和詩一軸奉酬','沈遘','宋','宋诗','song-poetry','','[]','使君嶷嶷下中臺，幕府飄飄得上才。',64,'全唐诗/poet.song.36000.json','["使君嶷嶷下中臺，幕府飄飄得上才。", "仲寶初招庾郎至，微之還遇竇生來。", "江山滿目歸吟筆，賓主相忘屬酒杯。", "自愧鄰城非勝賞，聯章大軸爲誰開。"]'),
('801e8184-db59-4fe2-b10a-5e0d763a7f27','次韵和孫少述潤州望海樓','沈遘','宋','宋诗','song-poetry','','[]','北固峨峨鐵甕完，京口浩浩海門連。',64,'全唐诗/poet.song.36000.json','["北固峨峨鐵甕完，京口浩浩海門連。", "鵬摶羊角來天外，鰲戴方壺獻几前。", "西府旌旗猶壯睹，南朝宮殿盡蒼烟。", "登臨不用成悲感，自得開懷一曠然。"]'),
('412a4faa-c55c-4642-9e49-25456c977588','次韵和少述雪中見寄','沈遘','宋','宋诗','song-poetry','','[]','坐看和氣變農愁，三白前占歲大收。',64,'全唐诗/poet.song.36000.json','["坐看和氣變農愁，三白前占歲大收。", "未及勸耕巡屬縣，不妨釃酒望高樓。", "剡中人遠空相憶，韓子詩成枉見投。", "正欲與君論出處，扁舟何日肯東浮。"]'),
('bc0bf629-9d0c-4bf3-8454-ca041839dabe','和少述春日四首  其一','沈遘','宋','宋诗','song-poetry','','[]','春日融融二月晴，春風藹藹百花明。',32,'全唐诗/poet.song.36000.json','["春日融融二月晴，春風藹藹百花明。", "少年嬉逐正應急，何處歌簫走馬聲。"]'),
('bce4f4ab-c9a4-438d-b354-a06c7cfe4160','和少述春日四首  其二','沈遘','宋','宋诗','song-poetry','','[]','風流自古吳王國，一一湖山盡勝遊。',32,'全唐诗/poet.song.36000.json','["風流自古吳王國，一一湖山盡勝遊。", "上巳清明最佳節，萬家臨禊錦維舟。"]'),
('80d62f81-d8e6-4702-b27d-8537f7b44beb','和少述春日四首  其三','沈遘','宋','宋诗','song-poetry','','[]','初晴池閣暖無塵，花落絲飛不避人。',32,'全唐诗/poet.song.36000.json','["初晴池閣暖無塵，花落絲飛不避人。", "秖愛年年好光景，須知華髪一番新。"]'),
('b4e916ad-0d60-4970-ba51-e31556eb3dba','和少述春日四首  其四','沈遘','宋','宋诗','song-poetry','','[]','卧病江東又見春，高齋長日坐生塵。',32,'全唐诗/poet.song.36000.json','["卧病江東又見春，高齋長日坐生塵。", "看花飲酒應難强，猶有詩情謝故人。"]'),
('32d06180-1db1-40b8-8b12-33115a9138c1','謝王勝之行部浙東還示詩','沈遘','宋','宋诗','song-poetry','','[]','雒陽貴公子，才氣蓋九州。',204,'全唐诗/poet.song.36000.json','["雒陽貴公子，才氣蓋九州。", "言從承明觀，出治東諸侯。", "繡衣自天下，龍節橫江浮。", "威聲雷霆發，惠澤河漢流。", "簿領謝俗吏，清談揖前修。", "三月初行部，飛帆絕潮頭。", "諸山嶙嶙出，委蛇轉前騶。", "衆川淙淙來，方洋放扁舟。", "仁智得所好，逍然忘百憂。", "歷訪寧憚遠，窮探詎辭幽。", "高懷期康樂，遯跡嘉遠游。", "從容顧賓從，此樂復有不。", "長歌裁大句，從者誰敢酬。", "歸來特示我，明珠知闇投。", "我本丘樊士，久巳失厥謀。", "終無考槃刺，但有伐檀羞。", "庶幾不遠復，未愧公閱休。"]'),
('0fad131b-5b1b-47f6-88f1-612086c70184','江氏明薦堂','沈遘','宋','宋诗','song-poetry','','[]','夫子剛且勇，一摧遂終身。',48,'全唐诗/poet.song.36000.json','["夫子剛且勇，一摧遂終身。", "於今斗牛間，鬰然氣不申。", "平生慕用意，碣刻留千春。", "更爲祠堂詠，尚代雞酒陳。"]'),
('2c8e26f3-11ca-4aaf-9340-1c9fda50530e','次韵和鞠顔叔游山','沈遘','宋','宋诗','song-poetry','','[]','吏案方無事，朋游出近山。',132,'全唐诗/poet.song.36000.json','["吏案方無事，朋游出近山。", "相從得所好，終日有餘閑。", "棄置形骸外，逍遥宇宙間。", "谷風吹淅淅，澗水濯潺潺。", "灌木開雲蔭，餘花散錦班。", "輕輿留石步，短棹下湖灣。", "古寺群峰合，孤洲萬竹環。", "紫鱗驚躍起，白羽倦飛還。", "對酒忘塵事，臨流見病顔。", "支離真可笑，光景信難攀。", "且共隤然醉，誰知是閉關。"]'),
('d1e8e401-bf9a-48a9-8708-8eb75b277cc2','平望道中','沈遘','宋','宋诗','song-poetry','','[]','積水不知際，孤舟緣斷隄。',48,'全唐诗/poet.song.36000.json','["積水不知際，孤舟緣斷隄。", "新晴寒氣薄，短日暮天低。", "爲客情猶昨，重來路已迷。", "區區何計了，長負舊林栖。"]'),
('e6ead2e2-b839-4683-98fb-6eb27bcc402f','將至京口先寄孫少述并呈晏子俞','沈遘','宋','宋诗','song-poetry','','[]','爲郡無聞困米鹽，先生有道獨幽潜。',64,'全唐诗/poet.song.36000.json','["爲郡無聞困米鹽，先生有道獨幽潜。", "豫章因甚尊徐孺，益部何能詘蜀嚴。", "已脫簿書身自放，肆尋山水意寧厭。", "京江最欲方洋處，願從屏星卷畫幨。"]'),
('752120bf-6c2d-468e-8e63-90b6337178cc','奉酬潤州余少卿見寄','沈遘','宋','宋诗','song-poetry','','[]','兩鎮旌旗對撫邦，老成循政獨難雙。',64,'全唐诗/poet.song.36000.json','["兩鎮旌旗對撫邦，老成循政獨難雙。", "賜環已許歸西省，擁檝方來絕大江。", "後乘願陪幽賞盡，詩新頓使勇心降。", "主人意厚春潮小，且卷孤帆偃畫杠。"]'),
('6b237639-bcdd-486b-8538-adf9190e474f','到淮南','沈遘','宋','宋诗','song-poetry','','[]','吳山已遠見淮山，未覺風塵上客顔。',32,'全唐诗/poet.song.36000.json','["吳山已遠見淮山，未覺風塵上客顔。", "家在滄浪重回首，彷徉且作半年閑。"]'),
('d1d6f4bf-8474-47d1-94c7-21d7b61de435','戲盧中甫錢才翁','沈遘','宋','宋诗','song-poetry','','[]','晴日春風花氣浮，少年嬉逐滿揚州。',32,'全唐诗/poet.song.36000.json','["晴日春風花氣浮，少年嬉逐滿揚州。", "誰憐居士身常病，獨坐空船理白頭。"]'),
('c9c8fe64-7172-47bb-900f-33a79a7b8358','山光寺一首','沈遘','宋','宋诗','song-poetry','','[]','高臺已傾曲池平，江都宮殿野草生。',32,'全唐诗/poet.song.36000.json','["高臺已傾曲池平，江都宮殿野草生。", "隋家事遠不須問，淮南非復百年城。"]'),
('6a7591fd-e4c1-432b-914f-b0506b360975','謝太傅廟','沈遘','宋','宋诗','song-poetry','','[]','功業由來出偶然，晉師豈必勝苻堅。',32,'全唐诗/poet.song.36000.json','["功業由來出偶然，晉師豈必勝苻堅。", "謝公更欲收民望，故築新城坐自全。"]'),
('28db17cb-ae19-4a46-a168-5ef61d863d08','自揚州與中甫才翁偕行','沈遘','宋','宋诗','song-poetry','','[]','相遇得所好，相從如所期。',48,'全唐诗/poet.song.36000.json','["相遇得所好，相從如所期。", "平生慕朋友，形跡無牽羈。", "道路遠千里，冬春踰再時。", "要將窮吾樂，勿厭行遲遲。"]'),
('ce2ee22d-f020-482b-bb28-00f364609af6','和才翁行次山陽','沈遘','宋','宋诗','song-poetry','','[]','灧灧春波繞廓回，飛花無數逐風埃。',32,'全唐诗/poet.song.36000.json','["灧灧春波繞廓回，飛花無數逐風埃。", "山陽舊客誰相識，尪病區區又到來。"]'),
('2172990d-df70-4e34-957f-6a5b7e13a03c','甓社湖','沈遘','宋','宋诗','song-poetry','','[]','青天澹無雲，白水平無波。',72,'全唐诗/poet.song.36000.json','["青天澹無雲，白水平無波。", "拖舟鏡中行，奈此清絕何。", "我行不自亟，三日才百里。", "卷卷何所感，似泛吳江水。", "湖水清無際，清極不可觸。", "吾纓初自潔，將安濯吾足。"]'),
('134a9f2b-8b72-402a-9735-1747a167a898','和中甫新開湖','沈遘','宋','宋诗','song-poetry','','[]','渺渺清波百里浮，昔遊曾是一扁舟。',32,'全唐诗/poet.song.36000.json','["渺渺清波百里浮，昔遊曾是一扁舟。", "十年人事都如夢，猶識湖邊舊客郵。"]'),
('6f16fda3-64f7-4f72-8b0a-a621ccae9bf1','和中甫呂氏園亭','沈遘','宋','宋诗','song-poetry','','[]','長日陰陰雨與風，病夫高卧一舟中。',32,'全唐诗/poet.song.36000.json','["長日陰陰雨與風，病夫高卧一舟中。", "少年歡氣誰能遏，縱走名園看落紅。"]'),
('60e98a84-6088-4d35-aed2-33a800391ce3','題揚州山光寺','沈遘','宋','宋诗','song-poetry','','[]','高臺已傾池已平，隋家宮殿春草生。',32,'全唐诗/poet.song.36000.json','["高臺已傾池已平，隋家宮殿春草生。", "千年前事何足歎，淮南非復舊時城。"]'),
('7271df97-1db5-4dc7-8f47-7de126c38cd7','十一月二十二日朝辭','沈遘','宋','宋诗','song-poetry','','[]','朝辭承明殿，莫下金馬門。',84,'全唐诗/poet.song.36000.json','["朝辭承明殿，莫下金馬門。", "伏讀明詔意，仰思聖主恩。", "蠢彼獯鬻氏，禮數迺弟昆。", "帝初務息民，金繒代更屯。", "嗣皇謹遵業，使傳交塞垣。", "下臣非知古，有舌詎得論。", "恭承丁寧命，敢不夙夜奔。"]'),
('6a6c2e3b-d383-4f1f-825a-32522a94ec17','五言出都','沈遘','宋','宋诗','song-poetry','','[]','十年中都官，未審去宮闕。',84,'全唐诗/poet.song.36000.json','["十年中都官，未審去宮闕。", "一朝使萬里，驛騎催早發。", "徘徊景陽道，瞻望未央闥。", "高城接浮雲，佳氣正蟠鬰。", "我馬何遲遲，中情屢如失。", "王事戒靡盬，臣心敢它卹。", "曷月還歸哉，歸期幸可必。"]'),
('85410007-1160-43d8-acdd-9772b3038a55','五言出都日大雪','沈遘','宋','宋诗','song-poetry','','[]','朔風萬里來，一夜卷飛雪。',120,'全唐诗/poet.song.36000.json','["朔風萬里來，一夜卷飛雪。", "漫漫國門路，轉轂失故轍。", "鳥翼壓不開，馬蹄僵欲折。", "問我行安之，銜命使胡羯。", "君恩念勤遠，敦遣禮無缺。", "賜金戒私裝，卜日出漢節。", "太官載供張，廐馬先簡閱。", "光華自難勝，敢復訴勞苶。", "獨哀徒御衆，驅馳犯寒切。", "每懷實靡及，勗爾保嘉烈。"]'),
('b9dd04ef-e20a-44a5-805a-8bf25ad31ad9','五言陳橋驛','沈遘','宋','宋诗','song-poetry','','[]','天命豈人力，神功非智闚。',96,'全唐诗/poet.song.36000.json','["天命豈人力，神功非智闚。", "藝祖昔臣周，周德久已衰。", "上將分六師，北征在郊圻。", "士卒中夜起，神器倉猝移。", "誰言一朝變，迺定萬世基。", "國門一舍地，傳舍猶當時。", "故老無復存，遺話嗟何知。", "維留威神在，凜然萬方歸。"]'),
('7678c364-d56e-422d-9def-949e99a91dcc','五言城北別親友','沈遘','宋','宋诗','song-poetry','','[]','朝出北門道，後車何轟轟。',180,'全唐诗/poet.song.36000.json','["朝出北門道，後車何轟轟。", "顧皆我親友，送我胡中行。", "置酒古寺堂，勸酌紛縱橫。", "飲闌眎四坐，悄若意弗平。", "試問坐上客，客言安敢承。", "謂我自慷慨，固無兒女情。", "幸當無事時，奚忽爲北征。", "憐我不受辱，往拜單于營。", "憂我衰病餘，跋涉萬里程。", "二者所不堪，奈何誰使令。", "我笑謂坐客，我豈徇利名。", "仕既不得已，王命方丁寧。", "上羞傅介子，下愧蘇子卿。", "第結匈奴心，以保先帝盟。", "惓惓謝親友，敢辭釂餘觥。"]'),
('27c1e2f9-b72d-4219-92e1-13f66eeabb4d','五言信武殿','沈遘','宋','宋诗','song-poetry','','[]','匈奴昔南牧，先帝躬濯征。',156,'全唐诗/poet.song.36000.json','["匈奴昔南牧，先帝躬濯征。", "旌旗從天下，龍虎百萬兵。", "元臣坐帷幄，大將當鼓鉦。", "黄蓋臨城樓，城下萬歲聲。", "卷起黄河波，飄入單于營。", "單于膽先破，犬羊亂縱橫。", "大黄殪賢王，京觀封鯢鯨。", "甘雨洗原野，清風掃羶腥。", "王師奏凱歸，殘胡稽顙盟。", "於今五十載，北塞維蠶耕。", "黎民亦何知，但見原廟成。", "下臣方奉使，過謁慓若驚。", "威神敢云測，尚冀通精誠。"]'),
('812f6fcd-d25d-4b0f-a9e1-8c7bfe096fa7','五言道中見新月寄內','沈遘','宋','宋诗','song-poetry','','[]','離別始十日，已若十歲長。',180,'全唐诗/poet.song.36000.json','["離別始十日，已若十歲長。", "行行見新月，淚下不成行。", "念我一身出，萬里使臨湟。", "王命不得辭，上馬猶慨慷。", "一日不見君，中懷始徊徨。", "我行朔方道，風沙雜冰霜。", "朱顔最先黧，綠髪次第蒼。", "腰带減舊圍，衣巾散餘香。", "郵亭苦夜永，燈火寒無光。", "獨歌使誰和，孤吟詎成章。", "輾轉不得寐，感極還自傷。", "思君知何如，百語不一詳。", "胡雁方南飛，玉音未可望。", "願君愛玉體，日看庭樹芳。", "欲知歸期蚤，東風弄浮陽。"]'),
('9c75bb5d-038e-478c-9a59-4ba232535612','七言烽火臺二首  其一','沈遘','宋','宋诗','song-poetry','','[]','歷歷相望隠舊堆，狐穿兔穴半空摧。',32,'全唐诗/poet.song.36000.json','["歷歷相望隠舊堆，狐穿兔穴半空摧。", "行人不識問野老，云是昔時烽火臺。"]'),
('31d69dd5-a4ca-42c4-8c06-93488193b986','七言烽火臺二首  其二','沈遘','宋','宋诗','song-poetry','','[]','烽火銷來五十年，居民初不識戈鋋。',32,'全唐诗/poet.song.36000.json','["烽火銷來五十年，居民初不識戈鋋。", "耕桑滿野帝何力，千里邊城自晏然。"]'),
('c40f2f02-775d-4889-8d1f-515b7c727c8d','七言老農問','沈遘','宋','宋诗','song-poetry','','[]','使者輶車歲不停，金繒兼載價連城。',32,'全唐诗/poet.song.36000.json','["使者輶車歲不停，金繒兼載價連城。", "洛陽年少今何怯，未省傳聞敢請纓。"]'),
('566bbaa2-ddb1-44d6-a4ed-f610191847c9','七言答老農','沈遘','宋','宋诗','song-poetry','','[]','聖主仁恩務息民，收兵方外卷威神。',32,'全唐诗/poet.song.36000.json','["聖主仁恩務息民，收兵方外卷威神。", "老農自保太平樂，焉用空言羞使臣。"]'),
('af65e2ed-3984-4689-83dc-2c64ccccaa5f','七言將至瀛州從事張祥寄詩和答','沈遘','宋','宋诗','song-poetry','','[]','驛騎驅馳萬里身，錦貂渾欲變緇塵。',64,'全唐诗/poet.song.36000.json','["驛騎驅馳萬里身，錦貂渾欲變緇塵。", "平生未識行邊地，今日初欣遇故人。", "洗眼已驚雙鯉至，相看應訝二毛新。", "羨君獨得從軍樂，三歲高陽幕裏賓。"]'),
('e8205c5b-d367-43b2-8220-3a9b35f8ce1e','七言道中示三使二首  其一','沈遘','宋','宋诗','song-poetry','','[]','初持詔節下宮衙，四牡臨門敢顧家。',64,'全唐诗/poet.song.36000.json','["初持詔節下宮衙，四牡臨門敢顧家。", "稍遠郊畿還感慨，却瞻原隰自光華。", "使行萬里誰非病，義重千鈞始拜嘉。", "遥指燕山數歸日，都城猶未有多花。"]'),
('0ece3e62-2587-41fb-9739-dad192ad1191','七言道中示三使二首  其二','沈遘','宋','宋诗','song-poetry','','[]','漢家恩信撫群戎，坐息邊民樂歲豐。',64,'全唐诗/poet.song.36000.json','["漢家恩信撫群戎，坐息邊民樂歲豐。", "自古所求中國治，於今無復四夷功。", "金繒但取一州賦，使介何辭萬里通。", "顧我衰羸豈堪此，共揚威命頼諸公。"]'),
('1a55fcf9-1249-444a-80f6-049020409f8e','七言雄州遇唐子方奉使先還奉贈','沈遘','宋','宋诗','song-poetry','','[]','擁節纔臨塞北垣，正逢歸騎下幽燕。',64,'全唐诗/poet.song.36000.json','["擁節纔臨塞北垣，正逢歸騎下幽燕。", "昔初並命銀臺下，今獨先還赭案前。", "胡地風沙辭異域，漢家日月望中天。", "邊城尊酒雖云樂，聞說腥膻更慘然。"]'),
('0143b10a-10ca-4af3-bc27-625606e6d8f6','使還雄州曹使君夜會戲贈三首  其一','沈遘','宋','宋诗','song-poetry','','[]','風霜滿面使胡歸，洗眼看君喜可知。',32,'全唐诗/poet.song.36000.json','["風霜滿面使胡歸，洗眼看君喜可知。", "更出佳人對紅燭，今宵醉倒欲何辭。"]'),
('4968e3df-0e96-4434-9138-a066e49f9bf1','使還雄州曹使君夜會戲贈三首  其二','沈遘','宋','宋诗','song-poetry','','[]','法曲新聲出禁坊，邊城一聽醉千觴。',32,'全唐诗/poet.song.36000.json','["法曲新聲出禁坊，邊城一聽醉千觴。", "明朝便是南歸客，已覺身飛日月傍。"]'),
('ed70a89c-8054-4ae7-b41a-f4be40e82105','使還雄州曹使君夜會戲贈三首  其三','沈遘','宋','宋诗','song-poetry','','[]','粉面嬌環紅綉裙，主翁獨遣勸佳賓。',32,'全唐诗/poet.song.36000.json','["粉面嬌環紅綉裙，主翁獨遣勸佳賓。", "它時金谷重相遇，還許尊前問故人。"]'),
('33b95ff4-7c26-4139-a247-8312fde9db6f','發瓦橋十里而河梁敗還坐客亭復上馬戲詠道旁垂柳二首  其一','沈遘','宋','宋诗','song-poetry','','[]','客亭門外纖纖柳，解使行人去復還。',32,'全唐诗/poet.song.36000.json','["客亭門外纖纖柳，解使行人去復還。", "爲謝春風摇蕩意，上林桃杏正堪攀。"]'),
('d74b615a-4d29-4a21-836b-f8662c149ebe','發瓦橋十里而河梁敗還坐客亭復上馬戲詠道旁垂柳二首  其二','沈遘','宋','宋诗','song-poetry','','[]','行盡塘陂日已西，回頭綠樹却遲遲。',32,'全唐诗/poet.song.36000.json','["行盡塘陂日已西，回頭綠樹却遲遲。", "柔條秀絕向人甚，忍不從容折一枝。"]'),
('903bf7f5-2548-454a-8976-7fc6a8b8a50f','過','沈遘','宋','宋诗','song-poetry','','[]','風沙敝盡舊狐裘，走馬歸來過冀州。',64,'全唐诗/poet.song.36000.json','["風沙敝盡舊狐裘，走馬歸來過冀州。", "聞報故人當邂逅，便臨近館爲遲留。", "不容傾蓋論時事，空寄新詩寫客愁。", "却望後車塵已合，簫聲清斷去如流。"]'),
('4b96a23a-b36e-43de-85d0-857107f1c90d','至澶州遇吳長文謁告歸奉贈','沈遘','宋','宋诗','song-poetry','','[]','萬里風霜一病身，歸來初喜渡河津。',64,'全唐诗/poet.song.36000.json','["萬里風霜一病身，歸來初喜渡河津。", "舉頭已近長安日，洗眼先逢玉署人。", "平昔每嫌疏館舍，今茲暫許接車塵。", "延英對後應多暇，東閣期誰共賞春。"]'),
('2e0d2fef-a78c-4d5c-9b3b-7bdcd78b3b23','還家自戲二首  其一','沈遘','宋','宋诗','song-poetry','','[]','憶昨邊城初見春，纖纖垂柳正矜新。',32,'全唐诗/poet.song.36000.json','["憶昨邊城初見春，纖纖垂柳正矜新。", "不知遠客貪歸意，欲把狂絲繫畫輪。"]'),
('fc69084e-d129-45ba-8dc9-0490c60f95c2','還家自戲二首  其二','沈遘','宋','宋诗','song-poetry','','[]','遠客歸來眼自明，小桃滿院笑相迎。',32,'全唐诗/poet.song.36000.json','["遠客歸來眼自明，小桃滿院笑相迎。", "當時若折邊城柳，定負春風薄行名。"]'),
('4239aa5d-9bbf-41b3-a991-aa67fbf86f18','出都','沈遘','宋','宋诗','song-poetry','','[]','秋風歸夢入東吳，乞得城居占越湖。',32,'全唐诗/poet.song.36000.json','["秋風歸夢入東吳，乞得城居占越湖。", "聖主恩深未知報，豈如張翰爲蓴鱸。"]'),
('7a5bd2fa-2f50-487f-9ccf-9c1edc1b9039','贈李審言','沈遘','宋','宋诗','song-poetry','','[]','使節葳蕤出漢宮，我方受瑞守江東。',64,'全唐诗/poet.song.36000.json','["使節葳蕤出漢宮，我方受瑞守江東。", "解還印綬甘元禮，霽去威嚴幸弱翁。", "金珮並辭丹屏下，畫舲相接汴波中。", "過江弩矢應交路，斂避須如御史驄。"]'),
('03b5e8cb-2653-4cc3-a737-5bd33b7ec48a','贈王平甫','沈遘','宋','宋诗','song-poetry','','[]','輕舟喜出大梁城，更得高才共載行。',32,'全唐诗/poet.song.36000.json','["輕舟喜出大梁城，更得高才共載行。", "海內相知君與操，從容尊酒論平生。"]'),
('1944966f-8e19-465e-9d4e-922081298c0a','漕舟','沈遘','宋','宋诗','song-poetry','','[]','漕舟上太倉，一鍾且千金。',48,'全唐诗/poet.song.36000.json','["漕舟上太倉，一鍾且千金。", "太倉無陳積，漕舟來無極。", "畿兵已十萬，三垂戍更多。", "廟堂方濟師，將奈東南何。"]'),
('78092905-c7cf-483e-9642-ee8bf867362e','汴河贈審言','沈遘','宋','宋诗','song-poetry','','[]','黄流千里從天來，中貫帝居縈斗魁。',32,'全唐诗/poet.song.36000.json','["黄流千里從天來，中貫帝居縈斗魁。", "與君共宣聖主德，餘波漸暨東南垓。"]'),
('dad5a223-07c5-4f06-ae97-8d1c13dc4f76','平甫許詩未至還贈','沈遘','宋','宋诗','song-poetry','','[]','平生每愧不能詩，今與詩豪晝夜隨。',32,'全唐诗/poet.song.36000.json','["平生每愧不能詩，今與詩豪晝夜隨。", "已許大篇須强和，少收鋒鍔始相知。"]'),
('381557ba-fb74-4138-b0b5-96ca0ef36498','淮陰侯廟','沈遘','宋','宋诗','song-poetry','','[]','淮陰本自市人子，始定三齊便請王。',32,'全唐诗/poet.song.36000.json','["淮陰本自市人子，始定三齊便請王。", "明哲保身非所責，如何終欲比張良。"]'),
('68eb8953-81d8-48e4-b51e-93ccf77c5a21','和平甫寄介甫羨會稽之行','沈遘','宋','宋诗','song-poetry','','[]','君家兄弟古人期，入直西垣已恨遲。',32,'全唐诗/poet.song.36000.json','["君家兄弟古人期，入直西垣已恨遲。", "莫羨迂疏乞州去，朝廷多事待論思。"]'),
('7ef60785-c4ee-4a74-9201-fd2efa85c502','和平甫越州','沈遘','宋','宋诗','song-poetry','','[]','六朝開國盡東州，此地常居第一流。',64,'全唐诗/poet.song.36000.json','["六朝開國盡東州，此地常居第一流。", "四海今皆歸聖主，萬兵猶得眎元侯。", "江山執勝登臨好，市邑空殘賦役稠。", "我去正應千百慮，不知能復縱吟不。"]'),
('9f4553f5-6641-43f9-9067-aa120da8420c','淮山','沈遘','宋','宋诗','song-poetry','','[]','淮山萬重紫，淮波千里清。',48,'全唐诗/poet.song.36000.json','["淮山萬重紫，淮波千里清。", "聊茲快吾目，又以潔吾纓。", "夷門多塵埃，黄河自泥濁。", "我行何遲遲，回望未央閣。"]'),
('e351ffd9-ba99-4673-91a0-5d1bfdf40dad','將至錢塘先寄施侍郎','沈遘','宋','宋诗','song-poetry','','[]','憶時送公公索詩，欲從公醉亦狂辭。',64,'全唐诗/poet.song.36000.json','["憶時送公公索詩，欲從公醉亦狂辭。", "今叨東鎮恩方厚，更過鄰城喜可知。", "已分尊前非敵量，獨憐湖上失春期。", "江南地煖霜無力，橘綠蓴丹蟹自肥。"]'),
('48a05ec9-7f76-4827-ad52-9fef8c250c31','送十二叔歸巴陵','沈遘','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','讀書不遇古所有，閒居得地今日稀。',64,'全唐诗/poet.song.36000.json','["讀書不遇古所有，閒居得地今日稀。", "世故紛紛定難了，况獨身已與衆違。", "洞庭水清君山碧，白酒滿市魚滿磯。", "都門一到十日耳，猶恨風塵汙我衣。"]'),
('62adba1e-e0ec-40bc-9c9c-8a537c2ab58a','至樂齋','沈遘','宋','宋诗','song-poetry','','[]','至人得至美，迺能遊至樂。',48,'全唐诗/poet.song.36000.json','["至人得至美，迺能遊至樂。", "茲理難與言，紛紛徒爾學。", "五經陳縱橫，夫豈非糟粕。", "吾方任常然，來者尚吾覺。"]'),
('e308f097-9166-4cce-b62e-04f0c3856e29','晝寐','沈遘','宋','宋诗','song-poetry','','[]','衙退冠佩捐，吏休簿書却。',24,'全唐诗/poet.song.36000.json','["衙退冠佩捐，吏休簿書却。", "山城賓客稀，永日卧高閣。"]'),
('db7c5dc2-92e4-4b04-ba06-037a1fd0e98b','山中樂','沈遘','宋','宋诗','song-poetry','','[]','誰言府中居，自得山中樂。',24,'全唐诗/poet.song.36000.json','["誰言府中居，自得山中樂。", "獨醉還自醒，無人事酬酢。"]'),
('d76513d4-35ce-40bc-8430-46aa2577fef8','鑑湖','沈遘','宋','宋诗','song-poetry','','[]','鑑湖千頃山四連，昔爲大澤今平田。',32,'全唐诗/poet.song.36000.json','["鑑湖千頃山四連，昔爲大澤今平田。", "庸夫况可與慮始，萬年之利一朝毀。"]'),
('7c566a4e-6ec7-47f3-92c9-4437c4f1a912','愛山','沈遘','宋','宋诗','song-poetry','','[]','朝凭秦望紫玉几，莫倚卧龍青錦屏。',32,'全唐诗/poet.song.36000.json','["朝凭秦望紫玉几，莫倚卧龍青錦屏。", "平生愛山今日足，尚恨軒冕縈吾形。"]'),
('41f250e7-8b4d-4d97-baca-855ae053e501','依韵和韓子華游趙氏園亭','沈遘','宋','宋诗','song-poetry','','[]','春色先從禁苑來，侯家次第競池臺。',64,'全唐诗/poet.song.36000.json','["春色先從禁苑來，侯家次第競池臺。", "清明已近鞦韆動，上巳相尋曲水開。", "繡幕風微花自舞，金爐日永麝銷灰。", "病夫歡意那能强，漫作山公倒載回。"]'),
('eb36cbdb-6d1b-45aa-a098-3aac27076b66','彭州使郎中寄示懷舊之篇輒次韵奉酬','沈遘','宋','宋诗','song-poetry','','[]','昔下承明得善藩，初無佳政可勝殘。',64,'全唐诗/poet.song.36000.json','["昔下承明得善藩，初無佳政可勝殘。", "與民共樂湖山好，遭世承平法制寬。", "當日清談羞俗士，歸來白髪困塵鞍。", "羨君正逐春遨盛，豈減東州舊賞歡。"]'),
('f27ec9a7-89ae-4988-8267-3d10b249eab7','將赴會稽過杭州寶月大師法喜堂','沈遘','宋','宋诗','song-poetry','','[]','悠悠十年別，惚惚一夢中。',48,'全唐诗/poet.song.36000.json','["悠悠十年別，惚惚一夢中。", "故人已白髪，相對一病翁。", "日短語不盡，潮生舟復東。", "自笑更自愧，此身猶飛蓬。"]'),
('dbba146a-3309-4414-85bc-27779ef70bc7','將赴淮南再過蕭山昭慶寺闍梨叔師所居','沈遘','宋','宋诗','song-poetry','','[]','始作山陰行，還尋廣陵路。',48,'全唐诗/poet.song.36000.json','["始作山陰行，還尋廣陵路。", "此身未許閑，長負滄洲趣。", "往來古寺居，再與高僧遇。", "俗慮雖暫空，勞生竟難訴。"]'),
('e0aac5f5-c07e-41d0-97fd-f093a4ebbc8d','依韵和杭州施正臣與李審言王道粹宴有美堂唱酬','沈遘','宋','宋诗','song-poetry','','[]','昔爲鄰政愧難參，今讀新詩歎召南。',64,'全唐诗/poet.song.36000.json','["昔爲鄰政愧難參，今讀新詩歎召南。", "美化由來稱樂國，勝遊還足發清談。", "江山臨眺乘秋霽，旌節聯歸卷夕嵐。", "病客區區方北去，尚思堂下暫停驂。"]'),
('a148c873-98e1-419b-a385-ef38a6a5a525','依韵和李審言見贈敘舊','沈遘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','自與公家三世舊，坐看高閈壓亨衢。',64,'全唐诗/poet.song.36000.json','["自與公家三世舊，坐看高閈壓亨衢。", "楩柟屢構明堂厦，麟鳳更參聖代符。", "結友固應皆以義，論詩何獨取於愚。", "歸舟早晚乘潮度，猶得西湖一笑無。"]'),
('02379783-3d79-40fd-92f7-24ecc4375920','依韵和施正臣遊聖果寺二首  其一','沈遘','宋','宋诗','song-poetry','','[]','盤崖絕巘與天通，汗漫烟霞謝世籠。',64,'全唐诗/poet.song.36000.json','["盤崖絕巘與天通，汗漫烟霞謝世籠。", "聳起浮圖山突兀，自然衙石玉青葱。", "古人興廢千年上，游客登臨一嘯中。", "誰爲燕然愧班竇，弧城羈據亦銘功。"]'),
('0e5525c1-9ac3-4c51-922d-fff15739f5e7','依韵和施正臣遊聖果寺二首  其二','沈遘','宋','宋诗','song-poetry','','[]','長愛高僧住絕岑，定知無復俗緣侵。',64,'全唐诗/poet.song.36000.json','["長愛高僧住絕岑，定知無復俗緣侵。", "人生擾擾應從昔，世事悠悠豈獨今。", "軒冕儻來真可愧，山林歸去莫嫌深。", "孟軻事業誰能及，告子唯先不動心。"]'),
('d4209c1a-4f10-4aee-b295-615ad4ad342a','贈剡縣桃源宮王道士','沈遘','宋','宋诗','song-poetry','','[]','我昔剡谿遊，道人亦相遇。',120,'全唐诗/poet.song.36000.json','["我昔剡谿遊，道人亦相遇。", "重來十歲餘，顔色宛如故。", "顧我病衰早，鬢毛已蒼然。", "乃知世上榮，詎若山中閑。", "道人家東都，問胡不歸北。", "北方多風塵，素衣化爲黑。", "斯言吾所信，吾志亦江湖。", "瀟洒會稽守，平生欣莫如。", "君恩容苟安，顧奉三年計。", "幸爾數到城，閒談北方事。"]'),
('5eb17679-d554-48fb-bb48-b43dfc5e82e1','次韵和不疑借書鄰幾遇其寢','沈遘','宋','宋诗','song-poetry','','[]','嗟我江湖人，野性實疏簡。',144,'全唐诗/poet.song.36000.json','["嗟我江湖人，野性實疏簡。", "况從衰病侵，事事益以懶。", "豈不思自强，所資乃有限。", "但愛江夫子，平生事高散。", "維於讀書動，晝夜不去眼。", "每勞從事賢，獨使簿書綰。", "揮署曾不勞，兼人信無赧。", "有時倦欲休，就席初不煖。", "鄰友更借書，丁丁叩門版。", "尤厭吏舍喧，牛羊閧棚棧。", "不如歸吾廬，靜對日晼晚。", "詩成還示我，足以驚幽孱。"]'),
('55f28570-b6fb-4001-821f-ecb336e7fc48','次韵和沖卿中秋不見月','沈遘','宋','宋诗','song-poetry','','[]','木葉飄飄客正悲，浮雲更起蔽朱曦。',64,'全唐诗/poet.song.36000.json','["木葉飄飄客正悲，浮雲更起蔽朱曦。", "分無好月臨清夜，且共芳樽樂盛時。", "密戶那憂風蕩燭，重簾寧怯露侵肌。", "金壺漏盡玉山倒，天外晴陰誰復知。"]'),
('569b27b4-e864-4c40-9df1-08caa5212da2','大行皇帝挽歌辭五首  其一','沈遘','宋','宋诗','song-poetry','','[]','正統千齡接，端朝四紀長。',48,'全唐诗/poet.song.36000.json','["正統千齡接，端朝四紀長。", "無爲獨高拱，博施極多方。", "昔也稱何力，今焉怨彼蒼。", "維應傳聖嗣，有以慰民望。"]'),
('e0d95f32-bcf7-4586-a84c-f53f404df3cc','大行皇帝挽歌辭五首  其二','沈遘','宋','宋诗','song-poetry','','[]','歷數當興運，謳歌屬太平。',48,'全唐诗/poet.song.36000.json','["歷數當興運，謳歌屬太平。", "成康能述業，文景善持盈。", "海外咸來獻，區中不識兵。", "至仁終莫報，何以盡群情。"]'),
('bdf3cbad-cb62-4dd0-9b5e-b769f8d37733','大行皇帝挽歌辭五首  其三','沈遘','宋','宋诗','song-poetry','','[]','欲識承平事，君王五十年。',48,'全唐诗/poet.song.36000.json','["欲識承平事，君王五十年。", "耕桑連萬里，歌吹被三邊。", "德至消群慝，恩深極漏泉。", "如何一朝變，群慟訴蒼天。"]'),
('f66fe010-713c-4bf5-9a23-5311b3fc6a27','大行皇帝挽歌辭五首  其四','沈遘','宋','宋诗','song-poetry','','[]','四海蒼生衆，真知不世逢。',48,'全唐诗/poet.song.36000.json','["四海蒼生衆，真知不世逢。", "方將請巡幸，然後議登封。", "鑄鼎未云就，乘雲安所從。", "尤哀此下國，無路望髯龍。"]'),
('d37da604-ef5e-4e8b-8332-89e72f13c063','大行皇帝挽歌辭五首  其五','沈遘','宋','宋诗','song-poetry','','[]','西望陵臺遠，陰陰白日錯。',48,'全唐诗/poet.song.36000.json','["西望陵臺遠，陰陰白日錯。", "孤臣欲從死，累世未酬恩。", "身隔千官列，心隨萬國奔。", "維臨滄海上，泣血就湔痕。"]'),
('7d7c0f13-0740-4129-941c-5d818fb0e139','陳府君挽歌辭','沈遘','宋','宋诗','song-poetry','','[]','吳會多長者，斯人昔所欽。',48,'全唐诗/poet.song.36000.json','["吳會多長者，斯人昔所欽。", "高材誰復見，令聞獨留今。", "松柏開原勢，笳簫送水陰。", "安知此吉卜，有子服朝簪。"]'),
('57ebc49b-1a28-405c-85c0-856161f3f4ba','吳正肅公挽歌辭三首  其一','沈遘','宋','宋诗','song-poetry','','[]','天下賢良選，當時第一才。',48,'全唐诗/poet.song.36000.json','["天下賢良選，當時第一才。", "文章祕群玉，事業照三台。", "暫作東山去，還期宣室來。", "蒼生方願治，梁木何先摧。"]'),
('ff7cfe5d-85f1-4abd-a230-94248c5d692e','吳正肅公挽歌辭三首  其二','沈遘','宋','宋诗','song-poetry','','[]','四海瞻師宰，中朝倚典刑。',48,'全唐诗/poet.song.36000.json','["四海瞻師宰，中朝倚典刑。", "胡然賦全器，獨弗與多齡。", "柱石虧宮廟，鹽梅輟鼎鉶。", "風流不可挹，無愧史臣名。"]'),
('13001c8f-7931-46a7-a34e-37ba5ee96f86','吳正肅公挽歌辭三首  其三','沈遘','宋','宋诗','song-poetry','','[]','笳鼓周南地，公嘗此保釐。',48,'全唐诗/poet.song.36000.json','["笳鼓周南地，公嘗此保釐。", "都人懷舊德，行路起新悲。", "昔我祈難老，今天莫憗遺。", "呼嗟如可贖，猶願百身爲。"]'),
('422b05c1-f61d-4a3a-9b17-c653699ea240','晏元獻公挽歌辭二首  其一','沈遘','宋','宋诗','song-poetry','','[]','英才動先聖，盛業啟今王。',48,'全唐诗/poet.song.36000.json','["英才動先聖，盛業啟今王。", "朝庭尊元老，官師仰典常。", "才還宣室對，遽歎哲人亡。", "獨有勳名在，書爲後世光。"]'),
('2cbe5a1d-77b2-46de-a2de-9f2966a9a7c4','晏元獻公挽歌辭二首  其二','沈遘','宋','宋诗','song-poetry','','[]','四海尚多事，君心屬太平。',48,'全唐诗/poet.song.36000.json','["四海尚多事，君心屬太平。", "天胡不遺憗，邦早奪耆英。", "柱石傾宮構，鹽梅廢鼎烹。", "斯人無復見，誰意在蒼生。"]'),
('49210554-fe75-41a2-9b8e-bf2cf7401b1f','天錄研匜歌','沈遘','宋','宋诗','song-poetry','','[]','張君贈我古研滴，四脚爬沙角如戟。',240,'全唐诗/poet.song.36000.json','["張君贈我古研滴，四脚爬沙角如戟。", "肉翼絡髀老獸姿，世不能名眼未識。", "我知此爲天祿兒，口銜一寸黄金匜。", "蟾蜍嚼月兩吻坼，天鯨胸穴雙泉飛。", "玉聲琮琤珠迸落，影射巖石光瀺灂。", "未央書殿立髬髵，曾見揚雄老投閣。", "子孫晚出中平間，渴烏翻車灑平洛。", "宗資墓口卧露霜，頭角頓挫仍騰攫。", "爾來拂拭傍几案，眉目睢盱苔蘚剝。", "形模不入世俗用，疑付大手傳糟粕。", "未能點綴清廟頌，開闢大易摛春秋。", "就令□□□□□，末勢猶足爲遷彪。", "物無貴賤繫所用，千金乞我直暗投。", "圖書散落愈□下，晚歲惟有齏鹽謀。", "學注蟲魚問老圃，無乃塌颯爲匜羞。"]'),
('d40d41ca-cfe5-4b47-a453-7e55752a1842','夏日獨居','王安國','宋','宋诗','song-poetry','','[]','竹苗敷夏陰，蘿蔓蔽朝亮。',96,'全唐诗/poet.song.36000.json','["竹苗敷夏陰，蘿蔓蔽朝亮。", "感此節物佳，百骸適無恙。", "委蛇投廣厦，蕭瑟絕遺響。", "稍酬簡編餘，俄得冠裾放。", "身雖勢利中，心隨弦歌尚。", "默然想聖賢，游世無得喪。", "抱關秉翟間，未分棄冗長。", "人生適意難，聊各安所鄉。"]'),
('bd77853b-938a-40b7-8ad3-e6fcf336666d','平居','王安國','宋','宋诗','song-poetry','','[]','絺綌散薰風，平居觸事慵。',48,'全唐诗/poet.song.36000.json','["絺綌散薰風，平居觸事慵。", "古今饒得失，義命孰違從。", "水鳥迎秋舫，山花映夕舂。", "故鄉圖畫見，生死愧塵容。"]'),
('3711f8b5-6d14-497e-a71a-a03d2fc11b5b','池上春日','王安國','宋','宋诗','song-poetry','','[]','一池春水綠於苔，水上花枝間竹開。',64,'全唐诗/poet.song.36000.json','["一池春水綠於苔，水上花枝間竹開。", "芳草有時依舊長，文禽無事等閒來。", "年顔近老空多感，風雅含情愧不才。", "獨有前人脩禊在，荒亭終日此徘徊。"]'),
('8702d305-ca30-4de1-a940-931e9cdcf6b5','春陰','王安國','宋','宋诗','song-poetry','','[]','似雨非晴意思深，宿酲牽率卧春陰。',64,'全唐诗/poet.song.36000.json','["似雨非晴意思深，宿酲牽率卧春陰。", "若憐燕子寒相並，生怕梨花晚不禁。", "薄薄簾帷欺欲透，遥遥歌管壓來沉。", "北園南陌狂無數，祇有芳菲會此心。"]'),
('40b15b0e-2c79-4712-9ca3-32ba4ef79e6e','假寐','王安國','宋','宋诗','song-poetry','','[]','計較平生分閉關，偶然容得近人寰。',64,'全唐诗/poet.song.36000.json','["計較平生分閉關，偶然容得近人寰。", "春風池沼魚兒戲，暮雨樓臺燕子閒。", "假寐塵侵黄卷上，行吟花墜綠苔間。", "了無一事撩方寸，自是頹齡令鬢斑。"]'),
('c9525291-3a66-46ff-9f00-6143dc229b60','苦熱','王安國','宋','宋诗','song-poetry','','[]','出門無路避飛沙，長夏那堪暑氣加。',64,'全唐诗/poet.song.36000.json','["出門無路避飛沙，長夏那堪暑氣加。", "永晝火雲空爍石，華堂冰水未沉瓜。", "月明葱嶺千秋雪，風靜天河八月槎。", "終借羽翰乘興往，煩冤誰此戀生涯。"]'),
('5c650f66-a7f3-47ef-9f21-20dfccc1fea4','繚垣','王安國','宋','宋诗','song-poetry','','[]','繚垣烏鵲近人飛，簾外曈曈日上遲。',64,'全唐诗/poet.song.36000.json','["繚垣烏鵲近人飛，簾外曈曈日上遲。", "檜作寒聲風過夜，梅含春意雪殘時。", "古今無物爲真樂，出處何心更詭隨。", "寄語年華聊一笑，未應長負醉鄉期。"]'),
('ea37f38e-d1ff-4e84-a3cd-8956fba8712e','遊廬山宿棲賢寺','王安國','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','古屋蕭蕭卧不周，披裘起坐興綢繆。',64,'全唐诗/poet.song.36000.json','["古屋蕭蕭卧不周，披裘起坐興綢繆。", "千山月午乾坤晝，一壑泉鳴風雨秋。", "跡入塵中慚有累，心期物外欲何求。", "明朝松路須惆悵，忍更無詩向此遊。"]'),
('34cf5ab1-d1d8-4f59-8fd2-e442b6d0b376','杭州呈勝之','王安國','宋','宋诗','song-poetry','','[]','遊觀須知此地佳，紛紛人物敵京華。',64,'全唐诗/poet.song.36000.json','["遊觀須知此地佳，紛紛人物敵京華。", "林巒臘雪千巖水，城郭春風二月花。", "彩舫笙歌吹落日，畫樓燈燭映殘霞。", "如君援筆宜摹寫，付與塵埃北客誇。"]'),
('7a1fd295-7a58-4985-8e55-b6f517072e2c','金明池','王安國','宋','宋诗','song-poetry','','[]','霓旌遠遠拂樓船，滿地春風錦繡筵。',64,'全唐诗/poet.song.36000.json','["霓旌遠遠拂樓船，滿地春風錦繡筵。", "三島路深遊閬苑，九霞觴滿奏鈞天。", "仗歸金闕浮雲外，人望池臺落日邊。", "最引平生江海趣，波瀾一段草如烟。"]'),
('4eb8c0c4-e886-47f0-9791-787cabbb1101','贈三靈程道人','王安國','宋','宋诗','song-poetry','','[]','三靈山下新安水，瀟灑人間畫不如。',64,'全唐诗/poet.song.37000.json','["三靈山下新安水，瀟灑人間畫不如。", "收得市朝忙日月，歸來田里老樵漁。", "君能知命忘機久，我愧於時觸事疏。", "從此卜鄰同笑傲，何須强著解嘲書。"]'),
('e3e71506-1ac9-4513-8fe0-5c594c7adbfe','和魏道輔雨中見示','王安國','宋','宋诗','song-poetry','','[]','移病憛憛久雨中，鳴騶時聽六街東。',64,'全唐诗/poet.song.37000.json','["移病憛憛久雨中，鳴騶時聽六街東。", "忽吟佳客詩消暑，遠勝前人檄愈風。", "海運我殊慚斥鷃，陸沉君合伴翔鴻。", "更酬珠玉思談笑，裹飯何須厭屢空。"]'),
('2ce56ea6-3ae9-4810-bc5a-386494846ebf','雨意','王安國','宋','宋诗','song-poetry','','[]','柱礎霑濡雨意成，翩翩鳥雀隔簾鳴。',64,'全唐诗/poet.song.37000.json','["柱礎霑濡雨意成，翩翩鳥雀隔簾鳴。", "侵尋爽氣來欹枕，想像滄波去濯纓。", "已識古今無得喪，祗須彼我不相迎。", "囅然一笑呼歸騎，聊更飛毫戲友生。"]'),
('3895cef4-0e32-45eb-aa5e-cddc136f48a3','黄梅花','王安國','宋','宋诗','song-poetry','','[]','庾嶺開時媚雪霜，梁園春色占中央。',64,'全唐诗/poet.song.37000.json','["庾嶺開時媚雪霜，梁園春色占中央。", "未容鶑過毛先類，已覺蜂歸蠟有香。", "弄月似浮金屑水，飄風如舞麴塵場。", "何人剩著栽培力，太液池邊想菊裳。"]'),
('5ea3e54a-5dbc-4bf0-927a-5f839462a198','送李子儀知明州','王安國','宋','宋诗','song-poetry','','[]','兒童劇戲甬東天，小別侵尋二十年。',64,'全唐诗/poet.song.37000.json','["兒童劇戲甬東天，小別侵尋二十年。", "海岸樓臺青嶂外，人家簫鼓白鷗邊。", "哀容愁問州民事，勝槩欣逢太守賢。", "爲我剩題瀟灑句，遥聞鳳詔待詩仙。"]'),
('9d00de52-cf63-4954-a03e-c95405a7bbfe','送烏子山給事赴揚州','王安國','宋','宋诗','song-poetry','','[]','都人供帳國門東，淮海兵符節制中。',64,'全唐诗/poet.song.37000.json','["都人供帳國門東，淮海兵符節制中。", "青瑣論思虛夜月，朱幡游衍值秋風。", "侯嗟誰在思張仲，民喜重臨得次公。", "內外忘懷能自適，何時談笑一樽同。"]'),
('67ae40b2-f393-4ff7-b758-b3f90a3cea58','送德之提刑郎中赴廣西','王安國','宋','宋诗','song-poetry','','[]','天扶開寶至熙寧，和氣薰蒸瘴癘停。',64,'全唐诗/poet.song.37000.json','["天扶開寶至熙寧，和氣薰蒸瘴癘停。", "五管閭閻如按堵，六朝仁聖喜祥刑。", "欲推恩澤求膚使，果見謀猷簡大庭。", "嗟我白頭甘抱槧，看君歸日上青冥。"]'),
('f7801163-d5bb-44e4-8af0-ccf82b59f78f','送文淵使君郎中赴當塗','王安國','宋','宋诗','song-poetry','','[]','看花金谷屢銜盃，先後歸時出處乖。',64,'全唐诗/poet.song.37000.json','["看花金谷屢銜盃，先後歸時出處乖。", "朝日衣冠辭魏闕，春風旗鼓過秦淮。", "談間咸慶連雲屋，事外歡娛付水齋。", "回首未成東下計，可無書札寫離懷。"]'),
('2c054328-b3c6-4f69-a9a2-5618a896c5c8','金山同正之吉甫會宿作寄城中二三子','王安國','宋','宋诗','song-poetry','','[]','寺壓蒼厓勢欲傾，歡然西度爲誰興。',64,'全唐诗/poet.song.37000.json','["寺壓蒼厓勢欲傾，歡然西度爲誰興。", "雲隨草樹縈層岫，江浸樓臺點萬燈。", "坐久不知身寂寞，夢回猶覺氣軒騰。", "思君城郭塵埃滿，相逐尋閒亦未能。"]'),
('b1854900-3ac6-4e21-a892-3678cffc183d','西湖春日','王安國','宋','宋诗','song-poetry','','["\u897f\u6e56"]','爭得才如杜牧之，試來湖上輒題詩。',64,'全唐诗/poet.song.37000.json','["爭得才如杜牧之，試來湖上輒題詩。", "春烟寺院敲茶鼓，夕照樓臺卓酒旗。", "濃吐雜芳薰巘崿，濕飛雙翠破漣漪。", "人間幸有蓑兼笠，且上漁舟作釣師。"]'),
('32299a96-6dfe-4d39-acfe-b37f88710772','中夏','王安國','宋','宋诗','song-poetry','','[]','朝晡廣厦坐欹斜，稍覺炎天氣象加。',64,'全唐诗/poet.song.37000.json','["朝晡廣厦坐欹斜，稍覺炎天氣象加。", "紫玉簫攢湘竹笋，赤霜袍爛海榴花。", "悠悠物外身無事，擾擾人閒智有涯。", "五鼎一瓢何必問，且憑詩句度年華。"]'),
('6a82866f-0e3d-426e-b48d-73b61db4e392','雨餘','王安國','宋','宋诗','song-poetry','','[]','雨餘宮闕映秋旻，漠漠槐花水上新。',64,'全唐诗/poet.song.37000.json','["雨餘宮闕映秋旻，漠漠槐花水上新。", "夜有蝭蟧催節物，朝無沆瀣助精神。", "形如槁木聊依世，名若浮煙底徇人。", "莫笑長吟銷短景，故園回首隔參辰。"]'),
('d12631ad-5045-4d6a-a020-0353345c8d61','得雨','王安國','宋','宋诗','song-poetry','','[]','青天赤日水如湯，車馬飛塵百尺長。',64,'全唐诗/poet.song.37000.json','["青天赤日水如湯，車馬飛塵百尺長。", "望歲人人憂旱魃，舞雩旦旦待商羊。", "清衷凌物回天鑒，膏澤乘時助歲穰。", "自有股肱歌盛德，芻蕘誰敢僭揄揚。"]'),
('2cbdce63-3808-405f-a334-fa00a539bb72','次韵景文雪中見寄','王安國','宋','宋诗','song-poetry','','[]','未能談笑破愁城，猶幸都無俗事攖。',64,'全唐诗/poet.song.37000.json','["未能談笑破愁城，猶幸都無俗事攖。", "載酒何人過揚子，評詩今日得鍾嶸。", "杜門落漠塵埃隔，掃逕侵尋霰雪生。", "誰向梁園能授簡，看君文格出天成。"]'),
('50de621c-d14d-4c09-949b-fad91c1e5271','雪意','王安國','宋','宋诗','song-poetry','','[]','雪意悠悠底未成，年華促促尚誰驚。',64,'全唐诗/poet.song.37000.json','["雪意悠悠底未成，年華促促尚誰驚。", "浮雲稍助春來暗，薄日遲回午後明。", "靜見游塵侵蘚迹，忽聞落葉掃階聲。", "此時俯僂無酬酢，世諦吾心棄不爭。"]'),
('af7b6bca-bf90-4d90-9927-bbb026757cf4','憶梅花','王安國','宋','宋诗','song-poetry','','[]','禁街人語絕諠譁，庭下微吟斗柄斜。',64,'全唐诗/poet.song.37000.json','["禁街人語絕諠譁，庭下微吟斗柄斜。", "萬里雲容今霰雪，一陽泉脈動萌芽。", "頓忘人世蓬心累，已任天年葆鬢加。", "早晚翩然青雀舫，滿江春色看梅花。"]'),
('44210fb2-985a-4416-9244-e0efa926b033','梅花','王安國','宋','宋诗','song-poetry','','[]','醉筆題詩紫界牆，梅花零落撲衣裳。',64,'全唐诗/poet.song.37000.json','["醉筆題詩紫界牆，梅花零落撲衣裳。", "天香又雜杯中淥，春色還驚鬢上蒼。", "涉世何妨爲白璧，流年未必抵黄粱。", "一吟起我平生志，今古冥冥出處忘。"]'),
('f1e0f3b3-7b79-4bd1-bbd5-639cf5f0ed00','郊外','王安國','宋','宋诗','song-poetry','','[]','野曠天寒氣象嘉，浮雲濃淡日初斜。',64,'全唐诗/poet.song.37000.json','["野曠天寒氣象嘉，浮雲濃淡日初斜。", "澤中雨漲無鳴鶻，荷下波翻有怒蛙。", "簫鼓殘聲來帝闕，漁樵歸徑見人家。", "塵簪羞把黄花插，不耐飛蓬鬬鬢華。"]'),
('e4d1fb2b-45c6-4c67-96e8-c10e0e9afdc2','宋匪躬太祝先輩示及劉貢父伯仲三人同年登第之詩因奉一篇','王安國','宋','宋诗','song-poetry','','[]','六朝文物事當奇，閥閱如今舉世推。',64,'全唐诗/poet.song.37000.json','["六朝文物事當奇，閥閱如今舉世推。", "射策人爭看三虎，薦書吾早識孤羆。", "集英曉日臚傳後，瓊苑春風宴喜時。", "共羨絲綸歸世掌，還看驂隔鳳凰池。"]'),
('1b490465-8442-4c2d-9ec4-2aec011412d1','同器之過金山奉寄兼呈潜道','王安國','宋','宋诗','song-poetry','','[]','憶同支遁宿嶔崟，不負平生壯觀心。',64,'全唐诗/poet.song.37000.json','["憶同支遁宿嶔崟，不負平生壯觀心。", "北固山隨三楚盡，中泠水入九江深。", "紛紛落月摇窗影，杳杳歸舟送梵音。", "東去何時來蠟屐，天邊爽氣夢相尋。"]'),
('630231b1-2c01-4f80-b87b-03528f2e9eca','紀夢','王安國','宋','宋诗','song-poetry','','[]','萬頃波濤木葉飛，笙簫宮殿號靈芝。',32,'全唐诗/poet.song.37000.json','["萬頃波濤木葉飛，笙簫宮殿號靈芝。", "揮毫不似人間世，長樂鐘聲夢覺時。"]'),
('d5307450-def1-4322-ad23-2b15c123fb5c','滕王閣感懷','王安國','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','滕王平昔好追遊，高閣依然枕碧流。',64,'全唐诗/poet.song.37000.json','["滕王平昔好追遊，高閣依然枕碧流。", "勝地幾經興廢事，夕陽偏照古今愁。", "城中樹碧千家市，天際人歸一葉舟。", "極目烟波吟不盡，西山重疊亂雲浮。"]'),
('bbb35965-3a0d-425a-bd80-57ae5767d7b9','讀魏世家','王安國','宋','宋诗','song-poetry','','[]','亹亹談先王，古今誰有得。',72,'全唐诗/poet.song.37000.json','["亹亹談先王，古今誰有得。", "施爲雖緒餘，要在情不匿。", "嗟彼三代後，淪胥入戰國。", "翟璜聞一言，慙俛慙李克。", "論材稱權衡，輕重無物惑。", "吾心能如此，乃可任人責。"]'),
('775a3e5c-a40c-4b8b-b461-a8f7774ba5ca','夏日獨居','王安國','宋','宋诗','song-poetry','','[]','晰晰池沼鯈，綠萍隨下上。',144,'全唐诗/poet.song.37000.json','["晰晰池沼鯈，綠萍隨下上。", "黳黳堂廡燕，白晝容俛仰。", "顧我亦晏如，環廬花藥長。", "無材助太平，得地幸閒曠。", "稍涉千古書，日覺神明王。", "乘閒盼物情，自適忘外奬。", "涵濡覆載仁，誰廢魚麗唱。", "黄塵洮隴戍，黑霧荆衡饟。", "奔波喝道邊，畢命營邊障。", "吾此獨何爲，飛潜樂能饗。", "何時聞解嚴，慰彼西南望。", "當使少陵翁，得見廉頗將。"]'),
('ac307e42-054d-4155-8259-a5c8eabe28d4','堂上有遺羶','王安國','宋','宋诗','song-poetry','','[]','堂上有遺羶，堂下無聚蟻。',96,'全唐诗/poet.song.37000.json','["堂上有遺羶，堂下無聚蟻。", "但知嗜欲求，不必風雨至。", "客方笑營營，貪得故無幾。", "安知萬類中，趨舍忘彼己。", "天乎顧人寰，等是一時戲。", "受形巨細分，阽危後先爾。", "浸淫蚍蜉生，穴柱從此始。", "莊生亦知言，信矣當棄智。"]'),
('5631c16b-5a8d-443c-bcc1-19869de456d6','題吳長文得蘭亭康相墓顔魯公斷碑','王安國','宋','宋诗','song-poetry','','[]','魯公之忠曠世無，吾愛斯人何必書。',368,'全唐诗/poet.song.37000.json','["魯公之忠曠世無，吾愛斯人何必書。", "九原寥寥不可詰，筆法彷彿精神餘。", "况公於藝自天縱，一字宜用千金摹。", "想當揮灑笑談際，不復靳惜唯所須。", "山砠水險勇鑱刻，照耀楚越連秦吳。", "百年兵火變陵谷，萬里玉石埋榛蕪。", "時平好事搜遺蹟，窮極南北緣崎嶇。", "耳聞目見略已盡，疑有斷裂留樵漁。", "那知數尺翳塵土，洗滌近出都城居。", "松煤到紙覺飛動，氣象磊落超鍾虞。", "吳卿獲此喜驚坐，朝昏把翫過明珠。", "携來贈客客爲賦，爽邁遠並前賢驅。", "自云感激得妙理，學入勝處繇勤劬。", "余聞書史羸蟠礴，意匠不爲形骸拘。", "能將聲利瓦礫棄，點畫應手成璠璵。", "公遭亂世生死俱，見危授命真丈夫。", "俯仰兵刃猶簪裾，毫端妍醜骨睢盱。", "試懷局縮較精粗，體勢豈暇烟雲舒。", "區區技巧尚乃爾，欲鳴道德宜何如。", "嗟哉荒烟幾日月，豪俊忽徙臨庭除。", "由來始棄終見取，鑒裁誰敢欺錙銖。", "物微顯晦亦有待，人生通塞無巧愚。", "寄謝紛紛馳騖徒，真僞枉以好惡誣。"]'),
('fd138033-51ee-49fd-a9ef-87650a26c926','詩一首','王安國','宋','宋诗','song-poetry','','[]','吳興太守美如何，太守從來惡祝鮀。',32,'全唐诗/poet.song.37000.json','["吳興太守美如何，太守從來惡祝鮀。", "生若不爲上柱國，死時猶合作閻羅。"]'),
('bcd692f6-b314-4370-ac05-410649d3bef3','滕王閣詩','王安國','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','地勢遠連徐孺亭，窮南有客兩曾經。',64,'全唐诗/poet.song.37000.json','["地勢遠連徐孺亭，窮南有客兩曾經。", "簷前燕雀鳴相鬬，潭裏蛟龍困未醒。", "亂靄蒼茫侵樹色，驚濤浩蕩失天形。", "當時好景無同賞，對此悲歌孰爲聽。"]'),
('280e2b41-3031-49ee-9b8a-a8d5d41890f8','詩一首','王安國','宋','宋诗','song-poetry','','[]','三見齊王不一言，須知自古致君難。',32,'全唐诗/poet.song.37000.json','["三見齊王不一言，須知自古致君難。", "紛紛齊虜誇迂闊，口舌從來易得官。"]'),
('3261cfdd-af74-4ac5-b02f-a06464af7c93','忘言','王安國','宋','宋诗','song-poetry','','[]','宋國旌孝子，東門毀以斃。',168,'全唐诗/poet.song.37000.json','["宋國旌孝子，東門毀以斃。", "楚王好細腰，後宮餒而殪。", "物情信可憐，徇外易生死。", "身存寵可誇，亡矣安所恃。", "吾今思彼哉，未足語釋利。", "擾擾智驚愚，卑卑學阿世。", "吹噓出虹蜺，頓挫入塵滓。", "愛憎雖人爲，榮辱乃天使。", "恩無斯須懷，怨已塞天地。", "百年呼吸中，毫髪誰豫己。", "適者默然窺，陰陽驅意氣。", "始終本何有，一息累萬世。", "由來適人適，宿昔多如此。", "喟余聊自欲，安得忘言士。"]'),
('efef87c7-69b1-4fd5-9518-d6e2612beb8c','送聶剡縣兼呈沈越州','王安國','宋','宋诗','song-poetry','','[]','剡溪清瀉映檀欒，天姥花飛載酒船。',64,'全唐诗/poet.song.37000.json','["剡溪清瀉映檀欒，天姥花飛載酒船。", "憶我少年來蠟屐，羨君今日去鳴弦。", "從容人樂漁樵外，瀟灑詩隨簿領邊。", "太守相逢應見問，爲言多病憶林泉。"]'),
('1e1bd7b3-e378-4058-baf5-fa715a373501','送客至西陵作','王安國','宋','宋诗','song-poetry','','[]','若耶溪畔醉秋風，獵獵船旗照水紅。',32,'全唐诗/poet.song.37000.json','["若耶溪畔醉秋風，獵獵船旗照水紅。", "後夜錢塘酒樓上，夢魂應繞浙江東。"]'),
('0203db94-a9fb-4c03-88fa-38d02084f601','題琵琶亭','王安國','宋','宋诗','song-poetry','','[]','夜泊潯陽宿酒樓，琵琶亭畔荻花秋。',32,'全唐诗/poet.song.37000.json','["夜泊潯陽宿酒樓，琵琶亭畔荻花秋。", "雲沈鳥沒事已往，月白風清江自流。"]'),
('6aef868c-96d2-4009-8cdf-b912e947f57b','句  其一','王安國','宋','宋诗','song-poetry','','[]','檻外風吹前渡語，江邊影落萬山燈。',32,'全唐诗/poet.song.37000.json','["檻外風吹前渡語，江邊影落萬山燈。", "半空月上方清澈，萬里潮來自沸騰。"]'),
('7f173977-7d6a-47d6-b873-ad27d75f1a7c','句  其二','王安國','宋','宋诗','song-poetry','','[]','孔明勿問襄陽龐。',8,'全唐诗/poet.song.37000.json','["孔明勿問襄陽龐。"]'),
('bf970bdd-b172-4fce-8fa2-7a8d38fd7f51','句  其三','王安國','宋','宋诗','song-poetry','','[]','因郎憔悴却羞郎。',8,'全唐诗/poet.song.37000.json','["因郎憔悴却羞郎。"]'),
('9686742d-8cda-47d3-b3d9-075b9db761ba','句  其四','王安國','宋','宋诗','song-poetry','','[]','誰使詩仙來鳳沼，俗傳賈客過鷄林。',16,'全唐诗/poet.song.37000.json','["誰使詩仙來鳳沼，俗傳賈客過鷄林。"]'),
('21dd7d29-0508-4229-8da7-6919ce0cd6f8','句  其五','王安國','宋','宋诗','song-poetry','','[]','傾家何計效。',6,'全唐诗/poet.song.37000.json','["傾家何計效。"]'),
('ec486e7a-3777-46c5-b795-be2e1abeb4a4','句  其六','王安國','宋','宋诗','song-poetry','','[]','風暄翠幕春沽酒，露濕筠籠夜賣花。',16,'全唐诗/poet.song.37000.json','["風暄翠幕春沽酒，露濕筠籠夜賣花。"]'),
('ba91008f-9e31-401d-88d5-c60fb4bbb309','句  其七','王安國','宋','宋诗','song-poetry','','[]','當時徐氏擅筆墨，夜圍夢墮空中簁。',16,'全唐诗/poet.song.37000.json','["當時徐氏擅筆墨，夜圍夢墮空中簁。"]'),
('a6cc41fa-f65d-4a76-84b0-2e48ffb5a4b1','句  其八','王安國','宋','宋诗','song-poetry','','[]','山月入松金破碎。',8,'全唐诗/poet.song.37000.json','["山月入松金破碎。"]'),
('90302099-f6c7-4a92-ad6b-be4b284319ca','句  其九','王安國','宋','宋诗','song-poetry','','[]','方竹同吾操，端然直物間。',12,'全唐诗/poet.song.37000.json','["方竹同吾操，端然直物間。"]'),
('ea8d7379-5c90-4bfb-8ac8-ec2090331576','句  其一○','王安國','宋','宋诗','song-poetry','','[]','江田百頃春風種，山果千株夜雨涵。',16,'全唐诗/poet.song.37000.json','["江田百頃春風種，山果千株夜雨涵。"]'),
('e7af961d-7ee9-4141-8c4e-a2a6be234068','句  其一一','王安國','宋','宋诗','song-poetry','','[]','半夜樓臺浮海口，萬家簫鼓遞江風。',16,'全唐诗/poet.song.37000.json','["半夜樓臺浮海口，萬家簫鼓遞江風。"]'),
('0b2cbbbd-b6dd-40c8-9865-678e995004de','句  其一二','王安國','宋','宋诗','song-poetry','','[]','平地風烟飛白鳥，半山雲木卷蒼藤。',16,'全唐诗/poet.song.37000.json','["平地風烟飛白鳥，半山雲木卷蒼藤。"]'),
('7227ea95-bcac-4f63-a26d-2327b3b6b31f','句  其一三','王安國','宋','宋诗','song-poetry','','[]','海鵬未擊三千里，天馬須歸十二閑。',16,'全唐诗/poet.song.37000.json','["海鵬未擊三千里，天馬須歸十二閑。"]'),
('18316398-f3bb-4592-b003-9baff1669ab2','句  其一四','王安國','宋','宋诗','song-poetry','','[]','宮殿影摇河漢外，江湖夢斷鼓鐘邊。',16,'全唐诗/poet.song.37000.json','["宮殿影摇河漢外，江湖夢斷鼓鐘邊。"]'),
('4ae9cebe-70a8-4fb9-aa07-19ba9e2e702b','句  其一五','王安國','宋','宋诗','song-poetry','','[]','北海知天諭牛馬，東方傲俗任龍蛇。',16,'全唐诗/poet.song.37000.json','["北海知天諭牛馬，東方傲俗任龍蛇。"]'),
('670befdb-f0f3-40ad-844e-efa7b8948f7c','句  其一六','王安國','宋','宋诗','song-poetry','','[]','九月清霜送陶令，千年白日見滕公。',16,'全唐诗/poet.song.37000.json','["九月清霜送陶令，千年白日見滕公。"]'),
('8fc37dd8-1658-4cbd-a50c-cb8943bd64e5','句  其一七','王安國','宋','宋诗','song-poetry','','[]','人得交遊是風月，天開圖畫即江山。',16,'全唐诗/poet.song.37000.json','["人得交遊是風月，天開圖畫即江山。"]'),
('c1eabaab-20ef-4b07-ac10-f6e016759cc5','句  其一八','王安國','宋','宋诗','song-poetry','','[]','山圍燕作畫圖出，水作夜窗風雨來。',16,'全唐诗/poet.song.37000.json','["山圍燕作畫圖出，水作夜窗風雨來。"]'),
('3bce8035-28ee-4bff-b3cc-e653bd91ded7','句  其一九','王安國','宋','宋诗','song-poetry','','[]','坐嘯月華青嶂外，徐吟帆起白雲邊。',16,'全唐诗/poet.song.37000.json','["坐嘯月華青嶂外，徐吟帆起白雲邊。"]'),
('23b0cf5e-3736-482a-bd9e-5622aeea68d8','海棠','李定','宋','宋诗','song-poetry','','[]','青帝行春信自專，精心知向海棠偏。',64,'全唐诗/poet.song.37000.json','["青帝行春信自專，精心知向海棠偏。", "不霑工部風騷力，猶占句芒造化權。", "倚檻半開紅朵密，遶池初應翠枝連。", "誰人與拔栽瓊苑，看與花王鬬後先。"]'),
('0e3b4238-64da-485b-b390-9341639ef6f1','和石揚休海棠','李定','宋','宋诗','song-poetry','','[]','輕紅如杏素遮梨，直似佳人照碧池。',64,'全唐诗/poet.song.37000.json','["輕紅如杏素遮梨，直似佳人照碧池。", "已是化工教艷絕，莫嫌青帝與開遲。", "烟滋綽約明雙臉，雨借夭饒入四脂。", "西蜀有名須得地，瓊林高壓百花奇。"]'),
('22b3a3a3-d973-4360-8627-18f5dbfe5369','垂虹亭','李定','宋','宋诗','song-poetry','','[]','一夢江湖三十年，青山隠隠水漫漫。',32,'全唐诗/poet.song.37000.json','["一夢江湖三十年，青山隠隠水漫漫。", "當時把酒誰人在，回首重來獨倚闌。"]'),
('61415f73-170b-41f9-9fb5-4212b3f42b4c','琴溪','李定','宋','宋诗','song-poetry','','[]','芳草茸茸襯馬蹄，兩陪憲節過琴溪。',64,'全唐诗/poet.song.37000.json','["芳草茸茸襯馬蹄，兩陪憲節過琴溪。", "東風又屬梨花月，膏雨新調燕子泥。", "郵舍亭空蒼蘚合，釣臺人去暮雲棲。", "此行不憚驅馳遠，千里江山入品題。"]'),
('bc01fd29-ef97-48e6-9a62-78f41cabaa38','謁贛上東江祠祈雨有作','孔宗翰','宋','宋诗','song-poetry','','[]','東江禱雨真靈迹，香火未收簷溜滴。',64,'全唐诗/poet.song.37000.json','["東江禱雨真靈迹，香火未收簷溜滴。", "城中到此夜五更，渡口歸時水三尺。", "高田溜滿入低田，萬耦齊耕破曉烟。", "但願吾民得飽飯，年年歲歲是豐年。"]'),
('c6add031-0aa1-4e19-92f2-67825078a8f4','題壁','孔宗翰','宋','宋诗','song-poetry','','[]','屈指從來十七年，交親零落一潸然。',32,'全唐诗/poet.song.37000.json','["屈指從來十七年，交親零落一潸然。", "嬋娟再見中秋月，依舊清輝照客眠。"]'),
('6f2c9805-ec54-425a-98cc-f68af3843057','和吳中復遊海雲寺','楊希元','宋','宋诗','song-poetry','','[]','三春行樂盛刀州，况是春光欲盡頭。',64,'全唐诗/poet.song.37000.json','["三春行樂盛刀州，况是春光欲盡頭。", "使節在郊觀似堵，香輪爭道去如流。", "正逢鈴閣多閒日，肯對花時負勝遊。", "會得公心惜歡意，欲歸猶自儘遲留。"]'),
('cd5a3cd7-c103-43f6-9a8c-433c71f2be3a','雜詩呈逢原','孫覺','宋','宋诗','song-poetry','','[]','鴻雁最知時，未逃羅與網。',48,'全唐诗/poet.song.37000.json','["鴻雁最知時，未逃羅與網。", "不能忘稻粱，千里安得往。", "鳴蜩腹空虛，見喙因其響。", "丹鳳穴九霄，虞人常夢想。"]'),
('0375e8f2-d903-4f76-b57f-6e9a0daa2b44','因覽蓬萊觀雪唱和謹成二首  其一','孫覺','宋','宋诗','song-poetry','','[]','重湖複嶺去連延，氛靄消沈雪後天。',64,'全唐诗/poet.song.37000.json','["重湖複嶺去連延，氛靄消沈雪後天。", "縹緲三山浮海上，參差群玉露峰巔。", "使君宴集仍侵曉，遷客登臨欲判年。", "灑落塵懷對清絕，向來身世兩翛然。"]'),
('d561b80b-866e-4604-a10b-cb6d1b9ebea8','因覽蓬萊觀雪唱和謹成二首  其二','孫覺','宋','宋诗','song-poetry','','[]','蓬萊高閣與天同，雪過欄干萬里空。',64,'全唐诗/poet.song.37000.json','["蓬萊高閣與天同，雪過欄干萬里空。", "湖海乍驚銀漢落，乾坤都在玉壺中。", "扁舟漾漾思乘月，病骨飄飄欲御風。", "輒莫畫圖傳北闕，承明人更出江東。"]'),
('d1ec52f3-aae2-4c8c-bc55-855badf68e3c','題召伯斗野亭','孫覺','宋','宋诗','song-poetry','','[]','淮海無林邱，曠澤千里平。',120,'全唐诗/poet.song.37000.json','["淮海無林邱，曠澤千里平。", "一渠閑防潴，物色故不清。", "老僧喜穿築，北戶延朱甍。", "簷楯斗杓落，簾幃河漢傾。", "平湖杳無涯，湛湛春波生。", "結纜嗟已晚，不見芙蓉城。", "尚想紫芡盤，明珠出新烹。", "平生有微尚，一舟聊寄行。", "遇勝輒偃蹇，霜鬚刷澄明。", "可待齒牙豁，歸歟謝浮榮。"]'),
('b82ce7c1-241e-4cc9-8ee1-77e9af558112','初至湯泉','孫覺','宋','宋诗','song-poetry','','[]','川谷閟深阻，天時正莽蒼。',48,'全唐诗/poet.song.37000.json','["川谷閟深阻，天時正莽蒼。", "聊同不速客，來浴自然湯。", "茂宰藹休政，道人棲凈坊。", "怳如登十地，熱惱頓清凉。"]'),
('bbea18a5-1d33-4483-94ae-c67fe54f0178','過六合水亭懷裴博士','孫覺','宋','宋诗','song-poetry','','[]','昔同裴博士，酌酒俯庭柯。',48,'全唐诗/poet.song.37000.json','["昔同裴博士，酌酒俯庭柯。", "晚岫潭潭碧，風池瑟瑟波。", "蒼崖遺老沒，白首故人過。", "轉眄成陳迹，勞生可奈何。"]'),
('14642c00-9ade-46ca-b437-1e4d593ca55f','題閻求仁虛樂亭','孫覺','宋','宋诗','song-poetry','','[]','禪房幽構徑彎環，噪鵲鳴鳩盡日閑。',64,'全唐诗/poet.song.37000.json','["禪房幽構徑彎環，噪鵲鳴鳩盡日閑。", "隠几冥濛超物表，畫圖彷彿見林間。", "褰簾雲吐池中月，岸幘天橫竹外山。", "秋興已闌成麗句，板輿時此慰慈顔。"]'),
('65f947ef-6027-4f84-94a2-747870dba92d','次韵秦少游','孫覺','宋','宋诗','song-poetry','','[]','青髮從遊各白袍，老來邂逅更陶陶。',64,'全唐诗/poet.song.37000.json','["青髮從遊各白袍，老來邂逅更陶陶。", "尺書繼月傳雙鯉，相見何時詠百勞。", "諫草十年聊閣筆，坐棠三郡不更刀。", "靈崖濼水堪行樂，時事紛紛劇蝟毛。"]'),
('941bcf8e-f4b4-4188-844b-66a4bc3e04df','客有傳朝議欲以子瞻使高麗大臣有惜其去者白罷之作詩以紀其事','孫覺','宋','宋诗','song-poetry','','[]','文章異域有知音，鴨綠差池一醉吟。',64,'全唐诗/poet.song.37000.json','["文章異域有知音，鴨綠差池一醉吟。", "穎士聲名動倭國，樂天辭筆過雞林。", "節髦零落氈吞雪，辯舌縱橫印佩金。", "奉使風流家世事，幾隨浪拍海東岑。"]'),
('46976864-b658-44af-873c-21ff8bd2204f','顯之禪老許以草庵見處作詩以約之','孫覺','宋','宋诗','song-poetry','','[]','汨汨塵勞不自堪，駝裘鞭馬度晴嵐。',64,'全唐诗/poet.song.37000.json','["汨汨塵勞不自堪，駝裘鞭馬度晴嵐。", "洞天窅窕清都邃，神水歊蒸翠釜涵。", "列岫過霜仍晻曖，雙松迎臘正驂驔。", "此心久已蒙師指，更許山中爲結庵。"]'),
('013b7a22-e10b-4d24-8792-f17acd7eeae7','遊龍洞','孫覺','宋','宋诗','song-poetry','','[]','側徑縈紆入杳冥，神鑱鬼鑿路巖扃。',64,'全唐诗/poet.song.37000.json','["側徑縈紆入杳冥，神鑱鬼鑿路巖扃。", "天懸乳石嬰華蓋，壁隠莓苔矗翠屏。", "九道寒江雲外白，一池陽井雪中青。", "還同康樂登臨海，可共羊何筆不停。"]'),
('1387698f-7e49-4f2e-9b8a-0f3fc5138a6b','介亭','孫覺','宋','宋诗','song-poetry','','[]','真人昔未起，奔鹿駭四方。',144,'全唐诗/poet.song.37000.json','["真人昔未起，奔鹿駭四方。", "連延天目山，兩乳百里長。", "有地跨江海，無種生侯王。", "中宵燎穹旻，列石表壇場。", "朱旗大梁野，英氣吞八荒。", "寥寥百年後，故物亦已亡。", "所餘彼巉巖，峰巔屹相望。", "主人承明老，星斗工文章。", "築亭紫霄上，坐客蒼株旁。", "攀雲弄明月，曉星生扶桑。", "禹山隔波濤，簡書永埋藏。", "願逢希夷使，水土還故常。"]'),
('f3c83926-68bd-445d-9403-b0af40c98f2b','題范公堂','孫覺','宋','宋诗','song-poetry','','[]','蕭蕭獄曹掾，有堂名范公。',168,'全唐诗/poet.song.37000.json','["蕭蕭獄曹掾，有堂名范公。", "歲月益已久，父老傳清風。", "維時狴牢下，枉直情畢通。", "太守異趣舍，挺然不回從。", "事事爭救之，粉屏記其終。", "殆公三年歸，字滿無所容。", "官小俸祿薄，家居率窮空。", "賣馬以自給，徒行氣彌充。", "後公在朝廷，搢紳伏其忠。", "三黜坐正諫，流離成老翁。", "我欲繪公像，置祠獄官中。", "公名塞天壤，文字未易工。", "不若揭以榜，因之曉愚蒙。", "後來仰高山，相與傳無窮。"]'),
('a6a328c2-82d8-4a54-ad98-5028c6edb558','登集僊臺','孫覺','宋','宋诗','song-poetry','','[]','海風吹清秋，林葉颯已落。',240,'全唐诗/poet.song.37000.json','["海風吹清秋，林葉颯已落。", "山巔出高臺，隠隠在寥廓。", "賓從果幽期，層軒瞰郊郭。", "鳴騶應崖谷，籃輿轉林薄。", "茲地已荒凉，茲人故冥寞。", "文識都未磨，山川恍如昨。", "畫屏見群峰，濃淡正參錯。", "烟雲下卷舒，欻若搴翠幕。", "蓮開碧扶疏，眉修清綽約。", "長松不知年，拔起立旁礴。", "群龍上空虛，奮怒爭拏攫。", "叢篁與延蔓，斤斧聊疏削。", "深或翳蟲蛇，暮唯栖鳥雀。", "兩楠最瀟灑，前軒宜所託。", "枝幹晚青青，幾冒風霜惡。", "更憐山下人，偏得山中樂。", "種田灌山谿，却老斸山藥。", "榮辱祇偶然，人生似蒲博。", "蹉跎繆軒冕，志尚本丘壑。", "欲學山前翁，收身及耕鑿。"]'),
('ab6561d5-9bb3-49f7-a287-a655f0cbcf3c','寄黄山故人','孫覺','宋','宋诗','song-poetry','','[]','鬢毛黑漆面如丹，曾待親輿作長官。',64,'全唐诗/poet.song.37000.json','["鬢毛黑漆面如丹，曾待親輿作長官。", "天祿讎書身長大，江都入夢涕漣瀾。", "窗中山色經秋瘦，枕底溪聲入夜寒。", "三十六峰應好在，何年更得上樓看。"]'),
('094a6902-f2d2-4714-99a3-73d0bc6752f7','句  其一','孫覺','宋','宋诗','song-poetry','','[]','千里暮山橫紫翠，一鈎新月破黄昏。',16,'全唐诗/poet.song.37000.json','["千里暮山橫紫翠，一鈎新月破黄昏。"]'),
('82cafd8f-015c-40ed-9c3f-ce90ab48948f','句  其二','孫覺','宋','宋诗','song-poetry','','[]','兒童竊食不知禁，格磔山禽滿院飛。',16,'全唐诗/poet.song.37000.json','["兒童竊食不知禁，格磔山禽滿院飛。"]'),
('f5adc009-7235-4b14-82e6-14f9953a0928','存目','孫覺','宋','宋诗','song-poetry','','[]','詩題：寄墨首句：徂徠無老松。',14,'全唐诗/poet.song.37000.json','["詩題：寄墨首句：徂徠無老松。"]'),
('c36f67c7-8cf4-44f6-9a1c-4bdd1ef43078','和孔司封題蓬萊閣','顧臨','宋','宋诗','song-poetry','','[]','萬壑千巖滿數楹，當中秦望翠開屏。',64,'全唐诗/poet.song.37000.json','["萬壑千巖滿數楹，當中秦望翠開屏。", "朝遊簫吹聞仙樂，夜散燈光墮列星。", "聊寄蘧廬消白日，何須扁舸到滄溟。", "飄然賦此得真意，直欲乘空御鶴翎。"]'),
('2d5d3235-08b2-4c63-80cf-c936d8c09899','送程給事知越州','顧臨','宋','宋诗','song-poetry','','[]','飄飄清骨倦黄扉，想見蓬萊出一麾。',64,'全唐诗/poet.song.37000.json','["飄飄清骨倦黄扉，想見蓬萊出一麾。", "流壑秀巖饒勝賞，過家上塚喜頻歸。", "如淮公釀年來富，鬬虎巨螯秋正肥。", "張翰思鱸方鼓頷，都門將別欲東飛。"]'),
('7c04999e-3dc2-4fc8-a237-1d0cc1b47d70','題靜照堂','顧臨','宋','宋诗','song-poetry','','[]','踏暑夏日長，履霜冬日短。',72,'全唐诗/poet.song.37000.json','["踏暑夏日長，履霜冬日短。", "乞詩賁新堂，經年不辭緩。", "虛室莓苔青，客衣塵土滿。", "自矜非俗求，容色長衎衎。", "盈篋寶珠璣，東歸春正暖。", "靜照名已傳，主人宜亦反。"]'),
('3ce75eb8-f1a3-49da-b6ec-33b4b12475d1','駕幸太學','顧臨','宋','宋诗','song-poetry','','[]','五紀寥寥舊典章，一朝清蹕下膠庠。',64,'全唐诗/poet.song.37000.json','["五紀寥寥舊典章，一朝清蹕下膠庠。", "旗常日月隨天轉，文武衣冠列宿行。", "拜老徒煩嗟漢室，談經戒逸慕周王。", "已叨法從陪臨幸，賡詠虞廷喜載颺。"]'),
('73516760-38df-478e-b3c2-921686472839','句','顧臨','宋','宋诗','song-poetry','','[]','雨中林學士，柏下顧將軍。',12,'全唐诗/poet.song.37000.json','["雨中林學士，柏下顧將軍。"]'),
('00f804d8-824c-4b9b-8553-2c281dc0585e','送程給事知越州','趙君錫','宋','宋诗','song-poetry','','[]','鸞臺給事領東藩，畫鼓朱旗下浚川。',64,'全唐诗/poet.song.37000.json','["鸞臺給事領東藩，畫鼓朱旗下浚川。", "夕拜暫辭青瑣闥，晝行爭看錦衣船。", "高才治郡廷中服，秀句驚人海內傳。", "越國湖山應動色，烟嵐迎馬待新篇。"]'),
('39e54a7b-99ae-4d84-ae20-14d97b97fe3d','紀恩寵送太師潞公西歸  其一','趙君錫','宋','宋诗','song-poetry','','[]','樂人都用教坊家，席上羣公換口誇。',32,'全唐诗/poet.song.37000.json','["樂人都用教坊家，席上羣公換口誇。", "內裏宣來蕉葉盞，御前賜出縷金花。"]'),
('d11d3e06-3a88-4e3a-84e3-56a6fbd64b77','紀恩寵送太師潞公西歸  其二','趙君錫','宋','宋诗','song-poetry','','[]','坐上纔初佳句傳，中官寫得便聞天。',32,'全唐诗/poet.song.37000.json','["坐上纔初佳句傳，中官寫得便聞天。", "聖人含笑搜尋了，依韵當時賜和篇。"]'),
('3339046f-91f0-416a-82fc-e61ed19dee5e','紀恩寵送太師潞公西歸  其三','趙君錫','宋','宋诗','song-poetry','','[]','西苑重排餞會時，新篇御製降彤墀。',32,'全唐诗/poet.song.37000.json','["西苑重排餞會時，新篇御製降彤墀。", "明朝上巳無公事，赴宴臣僚總進詩。"]'),
('cc2e791a-e7c7-4a69-a175-80a11a7b4354','送程給事知越州','王說','宋','宋诗','song-poetry','','[]','曉色光華去玉京，畫船新指會稽行。',64,'全唐诗/poet.song.37000.json','["曉色光華去玉京，畫船新指會稽行。", "地嚴瑣闥通班貴，道出吳門過里榮。", "亭惹春雲蘭渚靜，波涵秋月鑑湖清。", "吏師詩匠高當世，卧鎮何妨詠太平。"]'),
('727ce195-dfd3-41dc-91a6-8709de5624be','廣勝寺','王說','宋','宋诗','song-poetry','','[]','山亭十里見纖微，暫出紅塵已息機。',64,'全唐诗/poet.song.37000.json','["山亭十里見纖微，暫出紅塵已息機。", "次第一行寒雁去，淺深千片亂霞飛。", "青山不斷何年有，流水無窮底處歸。", "自古興亡安足問，世間人事轉頭非。"]'),
('d9aa914b-05ba-4b71-9aa9-efe5a1c2294d','忠烈詩','徐積','宋','宋诗','song-poetry','','[]','在昔皇祐，蠻黨交構。',260,'全唐诗/poet.song.37000.json','["在昔皇祐，蠻黨交構。", "聚爲伏梟，起爲攫獸。", "出人不意，其鋒甚銳。", "州無敵兵，城無守備。", "所在奔亡，賊勢益張。", "橫身扞蔽，爰有晉康。", "羸兵數百，摧堅沮敵。", "殊死血戰，氣吞逆賊。", "按劍一呼，眥裂吻拆。", "凶焰方熾，公方虎視。", "人方憂死，飽食鼾睡。", "勇如項籍，哀歌惻惻，爲虞姬泣。", "康州不然，忘其妻息。", "猛如敖曹，强梁粗豪，伏藏於橋。", "康州不然，坐叱凶妖。", "李陵壯夫，終降匈奴，老母何辜。", "顔魯雖賢，所守不堅，大節不全。", "奇哉康州，其勇絕類。", "以義配勇，其本在內。", "不動如山，不傾如地。", "何物可摇，何兵可制。", "如令不死，社稷所恃。", "如令復生，可備宿衛。", "佩刀驂乘，勢戟殿陛。"]'),
('74dbfc93-a259-4f6f-8a26-5e22ba9545ab','和楊掾月蝕篇','徐積','宋','宋诗','song-poetry','','[]','元豐之元歲戊午，斗柄斜指西南維。',390,'全唐诗/poet.song.37000.json','["元豐之元歲戊午，斗柄斜指西南維。", "月行赤道日南陸，營丘分野星虛危。", "昨夕既望復今夕，盛若不損盈不虧。", "安知變起在頃刻，突如有物侵其肌。", "其始色變甚蒼黄，須臾赤黑相合離。", "良久烟焰極薰燎，一團白玉燒爲灰。", "黄琮蒼璧不可辨，枯株死兔將安歸。", "孰烏其吻吞巨皿，孰丹其汗流墨池。", "如食非食始爲薄，有物無物不可知。", "蝦蟆何物敢張口，麒麟何故敢爭鬬。", "是何星曜敢侵犯，自是其形不可久。", "君不見對月數眉毛，須臾引臂不見手。", "嗟吁天上之神物，乃有如此事。", "所蔽至甚不可解，凶而家室亡而身。", "不然借使幸而免，後世譏笑遭惡名。", "君不見漢朝賈生文有餘，其心大勇其才疏。", "當時如必用其術，紛紛不免危其軀。", "鼂錯堂堂蔽於刻，公孫規規蔽於諛。", "谷永之才蔽權勢，有若鷹犬供指呼。", "霍光雖賢亦有蔽，何不早去顯與馮子都。", "劉歆致位爲國師，豈若揚雄久以爲大夫。", "蔽於太高李膺輩，蔽於已甚陳蕃徒。", "竇武不斷蔽可痛，柬之不忍蔽可吁。", "王允所蔽在無權，荀彧所蔽不早圖。"]'),
('b1016422-c118-4f37-84e1-ec77eb725c0e','大河上天章公顧子敦','徐積','宋','宋诗','song-poetry','','[]','萬物皆有性，順其性爲大。',288,'全唐诗/poet.song.37000.json','["萬物皆有性，順其性爲大。", "順之則無變，反之則有害。", "禹之治河也，浚川而掘地。", "水行乎地中，其性安而遂。", "因地爲之防，猶恐不足制。", "故附之山足，使循山而行。", "山不可必得，或原阜丘陵。", "水行乎兩間，既固而既寧。", "及將近下流，山遠而地平。", "渠裂爲二道，河分爲九形。", "雖暴不得怒，雖盛不得盈。", "所以順而制，歸之於滄溟。", "後代蒙其業，歷世六七十。", "凡千有餘年，而無所决溢。", "國君與世主，豈皆盡有德。", "蓋繇河未徙，一皆循禹迹。", "河道既一徙，下涉乎戰國。", "水行平地上，迺堤防堙塞。", "其時兩堤間，實容五十里。", "水既有游息，堤無所嚙毀。", "後世迫而壞，河役始煩促。", "伐盡魏國薪，下盡淇園竹。", "羣官皆負薪，天子自臨督。", "其牲用白馬，其璧用白玉。"]'),
('295238e5-78be-49b7-8baf-782aac94722c','李太白雜言','徐積','宋','宋诗','song-poetry','','[]','噫嘻欷奇哉，自開闢以來，不知幾千萬餘年。',346,'全唐诗/poet.song.37000.json','["噫嘻欷奇哉，自開闢以來，不知幾千萬餘年。", "至於開元間，忽生李詩仙。", "是時五星中，一星不在天。", "不知何物爲形容，何物爲心胸。", "何物爲五臟，何物爲喉嚨，開口動舌生雲風。", "當時大醉騎遊龍，開口向天吞玉虹。", "玉虹不死蟠胸中，然後吐出光焰萬丈凌虛空。", "蓋自有詩人以來，我未嘗見大澤深山。", "雪霜冰霰，晨霞夕霏。", "萬化千變，雷轟電掣。", "花葩玉潔，青天白雲，秋江曉月。", "有如此之人，有如此之詩。", "屈生何悴，宋玉何悲。", "賈生何戚，相如何疲。", "人生胡用自縲絏，當須犖犖不可羈。", "乃知公是真英物，萬疊秋山聳清骨。", "當時杜甫亦能詩，恰如老驥追霜鶻。", "戴烏紗，著宮錦，不是高歌即酣飲。", "飲時獨對月明中，醉來還抱清風寢。", "嗟君逸氣何飄飄，枉教謫下青雲霄。", "大抵人生有用有不用，豈可戚戚反效兒女曹。", "採蟠桃於海上，尋紫芝於山腰。", "吞漢武之金莖沆瀣，吹弄玉之秦樓鳳簫。"]'),
('980dbe2d-5348-4383-ae36-0137a7744e33','送程守','徐積','宋','宋诗','song-poetry','','[]','蜀之有眉，有山有江。',240,'全唐诗/poet.song.37000.json','["蜀之有眉，有山有江。", "江大而浚，山形甚龐。", "是生程公，爲國重器。", "可處大任，可决大事。", "凡有措置，凡有施設。", "堅不可摇，牢不可拔。", "所以蜀人，號爲鐵塔。", "維公有子，爲山陽守。", "所性所養，質直真厚。", "維其質直，不浮不苟。", "不生巧心，不爲利口。", "維其真厚，不矯不激。", "體無邪氣，面無邪色。", "視其氣貌，察其動靜。", "可知所養，可知所性。", "可知其德，可知其政。", "質直真厚，故不生事。", "不爲小數，不任小智。", "以恕輔法，因法行恕。", "不煩不苛，不暴不怒。", "遂使斯民，如行大路。", "無險可虞，無傷可慮。", "肌膚以完，手足可措。", "姦凶以衰，盜賊亦沮。"]'),
('29f352ed-c847-40e5-baef-00162517b365','送李端叔','徐積','宋','宋诗','song-poetry','','[]','有人頗似長沙傅，得官亦望長沙去。',379,'全唐诗/poet.song.37000.json','["有人頗似長沙傅，得官亦望長沙去。", "去時好賦楚江謠，還使風騷滿江路。", "便須酌酒弔三閭，正是忠魂冤憤處。", "縣令如今未去時，蘭亭故事猶可爲。", "莫惜千筒萬筒往，諸君方壯我已疲。", "登科學究文章豪，數奇老將詩能高。", "長沙縣令號才吏，方將睥睨謝與曹。", "凉風即是八九月，紅萸黄菊花將發。", "正是詩家得意時，莫學古人悲莫節。", "東南美者有吳姬，紅襦繡袂無所施。", "把酒一卮輕皓腕，得詩一句勝蛾眉。", "山夫野叟只如此，諸君達者應相嗤。", "有酒且慢飲，有歌且慢謳。", "共君說懷抱，未語先搔頭。", "良久欲說說不得，胸中有物如山丘。", "君不聞東家女子花見羞，十六未嫁便悲憂。", "牆頭樓上到日晚，馬驟車奔如水流。", "西家亦有閨中女，月璧龍珠求未許。", "有心自比蟠桃花，無言竊笑陽臺雨。", "謝鯤便是妾家鄰，敗唇折齒猶相語。", "何况五陵輕俠兒，拋金擲玉教人非。", "一夫奔處千夫馳，不論榮辱與刺譏。", "羶中之蟻醯中雞，攫金逐獸兩眼迷。", "主人下馬客已齊，拜起俯仰容正卑。"]'),
('8158e11d-e354-44b6-a988-9387d9694870','上趙少師','徐積','宋','宋诗','song-poetry','','[]','義高德厚賢在躬，進榮退美光初終。',224,'全唐诗/poet.song.37000.json','["義高德厚賢在躬，進榮退美光初終。", "越有神明相元功，疾憂之外康寧中。", "乃眷乃顧爰徂東，徒御雖寡人望雄。", "其高可仰厚可宗，茲行允美江淮風。", "父老相呼告兒童，三朝無事繄厥忠。", "公謀公惠世所蒙，肆安於賈田安農。", "溫衣蔽體食飽胸，小攘大竊消姦凶。", "州牢縣獄囚多空，歡心和氣成年豐。", "汝曹雖騃念所從，汝心汝貌加愛恭。", "薪蒸勿采米勿舂，亟歌屢舞馳省公。", "有人昔與公車逢，汝陰潁尾洛與嵩。", "山有迹兮水有蹤，水之鶴兮山之松。", "一朝賜號逍遥翁，馬資僕費官與供。", "汝曹努力吾老癃，公若再來勤築宮。"]'),
('948bc1c5-e32c-43c6-8355-b9a6b21901cb','俊老行送林次中赴都司','徐積','宋','宋诗','song-poetry','','[]','熙寧察院一開口，誰人膽落御史手。',288,'全唐诗/poet.song.37000.json','["熙寧察院一開口，誰人膽落御史手。", "其時面堅黑髭鬚，力欲回天氣衝斗。", "一從蹭蹬作外官，所居不苟心迹安。", "剛不可回堅不變，頭如霜雪心如丹。", "所以論者悅而服，所養有義其質端。", "東西南北二十載，一朝有敕却召還。", "皂囊封上曉班肅，繡衣步入秋霜寒。", "義有所徇乞得身，白日降下天上人。", "黄金龍節青囊印，赤帷熊乘朱斑輪。", "以其餘才修職分，以其餘力娛精神。", "望淮樓上對秋色，玉女花前泣晚春。", "時時共帳過南郭，來就陶潜漉酒巾。", "與人論事不必合，直無所苟氣色真。", "持此以往無不可，古人所以爲正臣。", "淮南一路事如草，嘉苗惡莠俱分了。", "中心皎皎如斯乎，外計區區何足道。", "兩宮日月方齊明，羣公戮力營太平。", "公議急須招俊老，清風先已過南京。"]'),
('9443d810-bcfb-43d7-99bc-b52105ab0aa9','魯恭王祠','徐積','宋','宋诗','song-poetry','','[]','帝子非無賢，孰有恭王者。',288,'全唐诗/poet.song.37000.json','["帝子非無賢，孰有恭王者。", "脫身辭漢儲，一芥視天下。", "勇故不失義，智故不失幾。", "身既脫諸險，德亦潜其輝。", "羣姦非無目，渾渾無罅窺。", "陰謀不得奮，佞舌不得施。", "以此終其身，萬世不可非。", "初王受漢封，奉詔實都魯。", "如何千載後，廟貌在東楚。", "豈非王之賜，生嘗及茲土。", "所以淮上人，世世作神宇。", "然而鬼神道，不可接形聲。", "所感唯以德，所通唯以誠。", "去年冬不雪，江淮非一城。", "人心誰無戚，蔡守最不寧。", "守乃款王祠，俯伏祈於廷。", "其日臘且盡，其夕大雪零。", "前驅方入郭，後乘猶在坰。", "田者歡於野，途者歡於行。", "如饑哺斯食，如疾醫斯平。", "驕陽遁無迹，和氣來有形。", "因知王之心，雖歿不變更。", "好誠而樂義，凜凜如平生。", "一禱輒已應，爲賜良不輕。"]'),
('4e8b329e-da35-406a-bf1f-0e66f404b916','莫飲吳江水寄陳瑩中','徐積','宋','宋诗','song-poetry','','[]','莫飲吳江水，胸中恐有波濤起。',124,'全唐诗/poet.song.37000.json','["莫飲吳江水，胸中恐有波濤起。", "莫食湘江魚，令人冤憤成悲呼。", "湘江之竹可爲箭，吳江之水好淬劍。", "箭射讒夫心，劍斫讒夫面。", "讒夫心雖破，胸中膽猶大。", "讒夫面雖破，口中舌猶在。", "生能人爲患，死能爲鬼害。", "患兮害兮將奈何，兩卮薄酒一長歌。", "灑向風烟付水波，遣弔胥山共汨羅。"]'),
('dcbed558-6296-490c-998f-232f8570cbef','瓊花歌','徐積','宋','宋诗','song-poetry','','[]','春皇自厭花多紅，欲得花顔如玉容。',388,'全唐诗/poet.song.37000.json','["春皇自厭花多紅，欲得花顔如玉容。", "春皇青女深相得，先教斂與秋霜色。", "乃有雪月供光，星榆獻白，艑量銀漢琉璃濕。", "人閒美玉搗作灰，荆山崑山鬼神泣。", "天上有人名玉女，投壺之外能爲素。", "姑射神人解種花，先須此物爲根芽。", "天罅地竅掬精粹，蟾身驪頷偷光華。", "其時正是天地交，二氣上下陰陽調。", "此花孕育得其正，其閒邪氣無纖毫。", "所以其色爲正色，出乎其類拔乎萃。", "一如君子有諸內，粹然其色見於外。", "三月將盡四月前，百花開盡春蕭然。", "揚州日暖花開未，春香不動花房閉。", "仙掌秋高玉露濃，蛟人泣下珠璣碎。", "黄鸝本是花中客，啼盡好聲求不得。", "春皇費盡養花心，春風使盡開花力。", "春歸鶑去花始開，誰人放出深閨來。", "唐家天子太平時，太真浴罷華清池。", "紅裳繡袂厭君眼，更作地仙披羽衣。", "麻姑睡起蓬萊島，風吹玉面秋天曉。", "洛川女子能長生，水中肌骨成瑶瓊。", "褒姒不見諸侯兵，盡日不笑如無情。", "宋玉移家安在哉，東鄰不畫臙脂腮。", "卓文君去成都速，錦衣金翠慵裝束。"]'),
('b0dfea44-a797-4847-b6a9-c5887537e8e9','姚黄','徐積','宋','宋诗','song-poetry','','[]','黄河南畔伊川北，姚家宅是真花窟。',384,'全唐诗/poet.song.37000.json','["黄河南畔伊川北，姚家宅是真花窟。", "古來多少豪奢兒，埋却千鶑萬鶑骨。", "中央精粹得之多，西方秀氣來相和。", "天與明光常借日，水宮暗脈正通河。", "春風如酒半酣時，誰教穀雨報花期。", "司馬坂前嬌半啟，洛陽城內人俱知。", "姚家門巷車馬填，牆頭牆下人差肩。", "花上紅綃都蔽日，花傍翠幕恰如烟。", "玉面兒來爭供帳，錦袍郎去鬬拋錢。", "無人不說姚花好，費却春功亦不少。", "日長風暖綠梢低，坐上金仙困將倒。", "麴塵餠劑和香檀，何以貯之承露槃。", "爛錦脫來嫌太艷，鮮衣染就欲驂鸞。", "君看此花肌肉豐，一尺餘高千萬重。", "粧面深藏青步障，寶冠斜墮碧霞叢。", "步摇好稱釵鳳凰，玉鐶犀佩珠鳴璫。", "帝女何緣心好道，阿嬌安用金爲房。", "紺窠累棲舒雁雛，沈烟噴出狻猊爐。", "一種養成餘意態，千花瘦盡春肌膚。", "峨峨一器欹且傾，覆杯難辨鍾與觥。", "染以鮫綃求正色，叩之玉挺希宮聲。", "魏家紅共牛家碧，迭霸花中聳高格。", "如今俛首甘下風，九十種中爲第一。", "此花莫似武昭儀，出得宮來不畫眉。"]'),
('bc9e7aae-05e3-4c28-a43e-8a3dec683f6c','大松','徐積','宋','宋诗','song-poetry','','[]','東海有物天下雄，萬靈戮力生奇松。',384,'全唐诗/poet.song.37000.json','["東海有物天下雄，萬靈戮力生奇松。", "天精地粹萃其下，滄溟百道來相通。", "一根直去穿九泉，一根斜插鯨魚淵。", "遠者壓折巨鼇背，近者倒纏山根偏。", "小枝可就千鈞弓，大枝可挂萬斛鍾。", "唯有老幹苦難狀，呂光營外堆玄龍。", "身披北帝雄犀甲，虎賁連臂圍不匝。", "無計都將大地遮，有心盡把浮雲刷。", "樛枝入地旋復上，怪怪奇奇非一狀。", "谷陵相變任古今，土木兩行專王相。", "列幟空遺渭川壘，犒師留得楊隋帳。", "玄駒來撼亭亭蓋，淥魚飛入蒼蒼浪。", "最是半霄風雨聲，山妖走盡川魅驚。", "十萬爭揮鐵槊騎，百千齊闞黑旗兵。", "有時海面波濤小，一部仙韶下蓬島。", "殘聲逐水散鳴琴，遺響穿雲聚啼鳥。", "混沌死來凡幾朝，清氣濁氣痕未消。", "獨葉聳來新蓋鳳，雙柯合處舊藏蛟。", "其本既異其事殊，德若有容材有餘。", "大鵬斥鷃皆可居，相忘有似江湖魚。", "美哉此木真不凡，能以智免斧斤閒。", "過盡工師無所用，莊周應作不材看。", "大松大松如此奇，方輿圓蓋不可知。", "陰陽山海氣合離，不然神物相護持。"]'),
('1bd13fe3-6e0a-4de5-9959-ba34d8352fcb','芰荷歌','徐積','宋','宋诗','song-poetry','','[]','孔雀團花翡翠鈿，青皇拋盡買花錢。',144,'全唐诗/poet.song.37000.json','["孔雀團花翡翠鈿，青皇拋盡買花錢。", "淥魚飛膽大如拳，琉璃瓦墜紫微天。", "湘妃曲譜誰可傳，彩毫不動斜卷牋。", "我家食客常三千，盃槃一樣青瑶圓。", "麻姑下來尋水仙，不見波瀾只見烟。", "昨夜秋風吹洞房，起來先著碧霞裳。", "半含笑面齊鬬粧，家家院落紺爲牆。", "不道採花人在傍，貪看飛來白紵郎。", "亦有美人貞且良，獨在碧綃幃下藏。"]'),
('ebbb6bc1-4177-4600-a43a-1f9cb0537f73','雙樹海棠  其一','徐積','宋','宋诗','song-poetry','','[]','獨樹已難有，雙株豈易培。',288,'全唐诗/poet.song.37000.json','["獨樹已難有，雙株豈易培。", "東風三月後，濃艷一時開。", "種是鴛鴦骨，根非玳瑁胎。", "英英萬千數，滴滴四三枚。", "恐淡添猩血，矜香棄麝煤。", "鮫綃翡翠眼，寶鈿珊瑚杯。", "絳節朝真去，丹砂駐貌迴。", "童粧兩株色，花格一仙才。", "自得驂鸞侶，何煩跨鳳臺。", "明珠留漢水，碧洞寄天台。", "對舉霓裳步，高鋪繡被堆。", "超如御烟霧，勢欲擺塵埃。", "冶艷皆泥滓，卑枝亦草萊。", "好臨湘水照，莫近宋家栽。", "漢殿昭陽寵，唐家學士才。", "浴終蘭液濺，帖就茜羅裁。", "惜粉輕勻面，偷霞試點顋。", "急窺鸞鑑了，齊報玉人來。", "不是沾紅雪，仍非汙落梅。", "啼痕纔彷彿，佇立各徘徊。", "真態有如此，深情安在哉。", "歌闌都不語，舞困可堪推。", "淡若疑相犯，烘然笑自媒。", "畫眉郎忽誤，挾彈客應猜。"]'),
('540f2cd3-6a22-45e2-a482-7f09fb3ec420','雙樹海棠  其二','徐積','宋','宋诗','song-poetry','','[]','此花出在海州東，千濤萬浪圍山峰。',272,'全唐诗/poet.song.37000.json','["此花出在海州東，千濤萬浪圍山峰。", "不知誰是栽花翁，花根屈曲蟠雙虹。", "英英鬬繁葩葩豐，晨霞夕霞滴不供。", "欻有神物射蛟龍，團團血濺摇春風。", "超然花格非凡容，吳姬半嚲釵頭紅。", "誰人移下海中山，神仙姊妹來人閒。", "人閒無玉可消斑，歌姬舞態都且閑。", "當時血淚亂瑶關，金槃洗面痕猶殷。", "吹簫郎去先騎鸞，粧未成時情已闌。", "漢臯臺下嬌蹣跚，曾解明珠瑶佩環。", "無媒不嫁矜殊顔，自共美人香往還。", "霓衣同步紺雲車，麻姑面上藏丹砂。", "綠鬢已墜金釵斜，酒紅不著羅衫遮。", "且教半笑含春華，但恐分飛成亂霞。", "宜哉天下爲名花，連根都種名卿家。", "溫溫容態孰可加，有如女德貞無邪。", "共君醉倒插烏紗，從他羣兒笑啞啞。"]'),
('3c8f326d-5fde-41f0-b879-7af96fa54fd6','玉女花  其一','徐積','宋','宋诗','song-poetry','','[]','揚花可與名玉妃，楚花可與名玉女。',64,'全唐诗/poet.song.37000.json','["揚花可與名玉妃，楚花可與名玉女。", "天上瑶臺是本居，人在月宮合同處。", "一點難容赤水霞，平生冷笑巫山雨。", "此女持身色太嚴，玉璧如槃求不許。"]'),
('fb64378d-d77c-4d21-bcb0-5fd6c94576de','玉女花  其二','徐積','宋','宋诗','song-poetry','','[]','國艷雖殊情太少，蛾眉不畫雙瞳瞭。',96,'全唐诗/poet.song.37000.json','["國艷雖殊情太少，蛾眉不畫雙瞳瞭。", "新就明河洗面來，更佩明珠踏瑶草。", "不用朱鸞與紫霞，玉麒麟駕白雲車。", "君看面上都無邪，更看身上都無瑕。", "越王國女金可邀，卓王孫女琴可招。", "更有秦王家弄玉，嫁人只被愛吹簫。"]'),
('fcac5fac-2859-41a3-826b-e26ab1431f03','和李道源清風謠','徐積','宋','宋诗','song-poetry','','[]','漫翁說盡清風好，猶能顧我邀吟藁。',384,'全唐诗/poet.song.37000.json','["漫翁說盡清風好，猶能顧我邀吟藁。", "吟時欲倚白雲飛，到時恐在紅塵表。", "有如列子御風行，百骸齊奮雙瞳瞭。", "借問清風何處來，玉水之心玉山杪。", "曾經崑閬拂瑶花，亦度瀟湘過蓬島。", "借問清風何處居，深寄碧蘆藏綠篠。", "芭蕉徑舞鳳衣寒，薜荔牆翻龍甲老。", "遺英墮籜無處尋，一徑十年未曾掃。", "但恐春深花木稀，定知秋後冰霜早。", "快心何羨楚王臺，披襟適得麻姑爪。", "中山酒客飲輒醒，八斗司徒醉不倒。", "簫聲易咽笛聲哀，客思難平物容愀。", "君看簷前避暑巢，不是巖烏即沙鳥。", "萬谷藏冰山氣來，千濤噴雪江聲遶。", "借問此閒清奈何，况是中宵月華皎。", "鷄鳴漏盡眠不成，披衣起看冰壺曉。", "便乘枯木飲明河，仍御雙鳬入冥杳。", "籐牀角簟無所施，綀布蒲葵價彌小。", "有客俄如夢覺時，竊笑夢中何擾擾。", "中心無累清則明，蔽者常稀欲者少。", "兒啼女笑坐可忘，獸鬬禽嬉悟俱了。", "毀譽一過遺如空，富貴浮雲視彌藐。", "古人凜凜良可思，世俗紛紛何足道。", "嘗聞外物可娛中，所以詩人取萱草。"]'),
('2d3f522f-b15a-402c-9afe-b94930cddb1c','望淮篇示門人','徐積','宋','宋诗','song-poetry','','[]','閑花落盡春無有，脚踏青紅望淮走。',192,'全唐诗/poet.song.37000.json','["閑花落盡春無有，脚踏青紅望淮走。", "到淮適值晚潮來，滿淮鼓吹風波吼。", "傳聲急喚釣魚船，船未到時洗雙手。", "買得船中雙白魚，便訪村前五青柳。", "旋烹野茗問村醪，五柳陰中坐良久。", "此行大略類陶潜，但乏黄花白衣酒。", "操舟人去一點鷗，帆入雲開何處收。", "孤鷗浴處依淺灘，修竿放餌投深流。", "豈無野婦荷而汲，亦有老翁行且謳。", "君看此景直幾錢，此時正是夕陽天。", "便教金印大如斗，何似魚庵共釣船。", "有人問君莫要說，懷中取出吟翁篇。"]'),
('48f7607b-fceb-42ec-82e8-6f6b24ceaf79','太華','徐積','宋','宋诗','song-poetry','','[]','怪怪不可狀，誰云仞五千。',192,'全唐诗/poet.song.37000.json','["怪怪不可狀，誰云仞五千。", "直侵黄道穿，高傍白榆篇。", "秀氣環秦甸，濃嵐滴渭川。", "掌高長托日，漢狹半含巔。", "夜響金丹杵，秋香玉井蓮。", "排虛摧勁翮，橫銳决浮烟。", "隠豹文章異，孤松節操堅。", "渴虹麤飲澗，饑虎瘦吞泉。", "磴道奇花合，杉株古蔓纏。", "羣材皆挺特，餘壤可陶甄。", "義獸期臻萃，妖狐困墜顛。", "二關資控扼，萬里却腥羶。", "真勢南衝斗，雄姿北闞燕。", "波濤清大海，風雨到窮邊。", "鎮壓地常靜，磨礱天更圓。", "他山皆俯視，何物可齊肩。"]'),
('8436eaa3-df3a-497a-b0ba-d1af52f14c97','管春風','徐積','宋','宋诗','song-poetry','','[]','我是蓬萊山上客，爲管春風歸不得。',192,'全唐诗/poet.song.37000.json','["我是蓬萊山上客，爲管春風歸不得。", "今年更是春來遲，江南未寄梅花枝。", "探春童子青霞衣，時時去上青雲梯。", "春風消息苦不遠，瑶臺瑶水冰霜淺。", "蟠桃花在海東邊，此花不煩春一點。", "東風日夜來人間，到時先催草根輭。", "大都紅紫心先動，小桃先覺枝頭重。", "更有纖纖楊柳枝，路傍先得行人弄。", "詩翁自愛蟠桃花，鸞鶴不在無雲車。", "城南夜半無酒家，和冰和雪吞月華。", "有客笑中携劍去，偷得銀瓶與肥羜。", "詩公兩眼看浮雲，爲管春風不回顧。"]'),
('e3073ddb-124b-4d30-8a8e-3d1fc647c15f','高樓春','徐積','宋','宋诗','song-poetry','','[]','山陽有客似相如，身著儒衣當酒壚。',144,'全唐诗/poet.song.37000.json','["山陽有客似相如，身著儒衣當酒壚。", "塵埃市井不到處，烟霞往往生衣裾。", "一竿橫掛數幅帛，題云酒味如醍醐。", "三月高樓滿春色，椒漿瓊液盈金壺。", "盤羅江筍烹淮魚，櫻實赤玉梅紺膚。", "彈絲敲金半空裏，醉揮玉爵撞珊瑚。", "憑闌直下是烟火，坐上清風凌太虛。", "夜深正然紅蠟燭，羅幕遮風留客宿。", "是人俱愛何家樓，自是何君德如玉。"]'),
('e6cc3277-28c3-4cd4-b2cb-756c5ff30b1a','淮之水示門人馬存','徐積','宋','宋诗','song-poetry','','[]','君不見淮之水，春風吹，春雨洗。',95,'全唐诗/poet.song.37000.json','["君不見淮之水，春風吹，春雨洗。", "青薰衣，綠染指。", "漁不來，鷗不起。", "瀲瀲灧灧天盡頭，只見孤帆不見舟。", "斜陽欲落未落處，盡是人間今古愁。", "今古愁兮將奈何，莫使騷人聞棹歌。", "我曹自是浩歌客，笑聲酒面春風和。"]'),
('aa92dcd8-8278-4cc3-a50b-e3d9a6f4a76b','項羽別虞姬','徐積','宋','宋诗','song-poetry','','[]','垓下將軍夜枕戈，半夜忽然聞楚歌。',64,'全唐诗/poet.song.37000.json','["垓下將軍夜枕戈，半夜忽然聞楚歌。", "詞酸調苦不可聽，拔山力盡無如何。", "將軍夜起帳中舞，八百兒郎淚如雨。", "此時上馬復何言，虞兮虞兮奈何汝。"]'),
('e6e95abd-b2c2-49c0-b6f2-6cd26ff6f9ff','虞姬別項羽','徐積','宋','宋诗','song-poetry','','[]','妾向道，向道將軍施恩義，將軍一心靳財利。',214,'全唐诗/poet.song.37000.json','["妾向道，向道將軍施恩義，將軍一心靳財利。", "妾向道，向道將軍莫要爲人患，坑却降兵二十萬。", "懷王子嬰皆被誅，天地神人咸憤怨。", "妾向道，向道將軍莫如任賢能，却信姦言疑范增。", "當時若用范增者，將軍早已安天下。", "天下成敗在一人，將軍左右多姦臣。", "受却漢王金四萬，賣却君身與妾身。", "妾向道，向道將軍不肯聽，將軍雖把漢王輕。", "漢王聰明有大度，天下英雄能駕御。", "將軍唯恃力拔山，到此悲歌猶不悟。", "將軍不悟兮空悲歌，將軍雖悟兮其奈何。", "賤妾須臾爲君死，將軍努力渡江波。"]'),
('778935c2-2475-4150-b504-2b415bc665f3','白雲先生','徐積','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','白雲先生面如鐵，一片良心似明月。',309,'全唐诗/poet.song.37000.json','["白雲先生面如鐵，一片良心似明月。", "腹中和氣如春陽，齒下清風欲爲雪。", "羣兒走馬正讙讙，先生高躅方尋山。", "嵩山泰山俱有約，先訪王喬後陳摶。", "浮丘嚴駕欲迎子，玉女整衣開瑶關。", "山中自是逍遥家，手磨紅蕊生龍霞。", "鼎中氣焰成何物，不煉黄金煉丹砂。", "明月一聲何處嘯，但覺半夜鸞鳳叫。", "猿不敢號虎不鳴，一夜清風生萬竅。", "此路高深易迷錯，只見先生一雙脚。", "山中不似俗人家，有客但尋猿與鶴。", "西峰猶有秦宮女，身上亂毛如鳥羽。", "秦時人事不忍聞，若見斯人莫與語。", "先生何以遺時人，先生有語醇乎醇。", "莫分巧拙與强弱，莫將外物成天真。", "豈不見北邙山下狐狸窟，掘出枯骸與陳骨。", "其閒豈無鄉原人，其閒豈無强梁物。", "强梁物，鄉原人，當時爾等空紛紛。", "後來之事竟何如，不及癡兒醉夢之浮雲。"]'),
('643a219b-f65a-4c96-bfc4-70adec33a9a2','山中樂','徐積','宋','宋诗','song-poetry','','[]','洞裏桃花開早春，洞中酒熟宴真人。',239,'全唐诗/poet.song.37000.json','["洞裏桃花開早春，洞中酒熟宴真人。", "紅蕊紫芝俱在手，本家猿鶴亦隨身。", "採拾飣餖隨所有，物無不義即是真。", "何須謝傅山東妓，却用陶潜漉酒巾。", "漉酒復漉酒，何必金印大如斗。", "一瓢復一瓢，莫辨人間淳與澆。", "時情大抵惡貧賤，此閒却是青雲霄。", "君不見古人自謂爲賢豪，或入於佞或以驕。", "但言富貴我所欲，一身不保領與腰。", "孔光屈身事董賢，谷永陰與王鳳交。", "賈謐之黨遍天下，望塵拜者尤爲妖。", "須臾苟得快所欲，終以血肉污斧刀。", "假令當日幸而免，後世譏笑安能逃。", "豈如孫登但長嘯，眼看時事如鴻毛。", "嵇康阮籍不與語，何况紛紛兒女曹。"]'),
('d205a377-671e-420b-83ca-adb7db94c7f6','花下飲','徐積','宋','宋诗','song-poetry','','[]','我向桃花下，立飲一盃酒。',156,'全唐诗/poet.song.37000.json','["我向桃花下，立飲一盃酒。", "盃酒先濡鬚，花香隨入口。", "花爲酒家媼，春作詩翁友。", "此時酒量開，酒量添一斗。", "君看陌上春，令人笑拍手。", "半青籬畔草，半綠畦中韭。", "閑烏下牛背，奔豚穿狗竇。", "潜身貓相雀，引喙禽呼偶。", "包麻鄰乞火，穿桑兒餉糗。", "物類雖各殊，所樂亦同有。", "誰知花下情，猶能憶楊柳。", "中心卒無累，外物任相揉。", "余方寓之樂，自號閒人叟。"]'),
('18a41a9f-b652-4233-be86-b797d85e08e1','江南春','徐積','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','今年是處春風早，江南地煖春更好。',80,'全唐诗/poet.song.37000.json','["今年是處春風早，江南地煖春更好。", "春風先把江山掃，次入梅花後芳草。", "芳草春深更有情，直共江山到洞庭。", "落花流水從武陵，湖中有山春更青。", "日欲落時一點明，少年莫上岳陽城。"]'),
('077152d9-71d8-41f1-a77a-84cc29f430a5','歡樂辭','徐積','宋','宋诗','song-poetry','','[]','吁嗟人兮，人生凡幾何。',220,'全唐诗/poet.song.37000.json','["吁嗟人兮，人生凡幾何。", "汝胡不思兮，故爲擾擾而紛紛。", "人生如一夢兮，萬事如浮雲。", "汝胡不思兮，胡不爲直道兮。", "胡爲薄物細故兮，疲精而勞神。", "汝之所得兮，余以爲失兮。", "汝之所失兮，余以爲得兮。", "汝胡不思兮，胡不爲義而爲仁。", "仁義之道如大路兮，人皆可以行兮，汝反以爲艱兮。", "汝胡不思兮，胡爲失性而離真。", "禍既自召兮，福亦自棄兮。", "汝胡不思兮，胡爲乎災及其身。", "善惡之報各以其類至兮，汝胡不思兮，胡不觀乎古之人與今之人。", "嗟予言不可忽兮，汝胡不思兮。", "汝其書諸紳，吁嗟人兮。"]'),
('ec6dced3-8f87-4ee9-81c0-15a1b8dde550','登高辭','徐積','宋','宋诗','song-poetry','','[]','九月九日兮，登高何爲。',169,'全唐诗/poet.song.37000.json','["九月九日兮，登高何爲。", "古有此語兮，吾未暇論其是非。", "菊花黄兮茱萸紫，二花此時還鬬開。", "花滿握兮酒滿盃，人人欲上高樓臺。", "我與世人雖異好，此時亦難平襟懷。", "因思雕蟲篆刻事，此文乃是儒之災。", "如今此災亦可避，不辭萬里登崔嵬。", "其如此物避不得，但恐積蠹傷良才。", "是以天下美璞少，甚於矛戟戕瓊瑰。", "縱有美璞直萬鎰，埋之塵土何由來。", "聖朝有意去災害，願將此物爲渠魁。"]'),
('b84d80f4-957b-42c4-a675-24cb85ed807d','淮陰義婦  其一','徐積','宋','宋诗','song-poetry','','[]','酷賊姦讎既已除，銜冤抱恥正號呼。',64,'全唐诗/poet.song.37000.json','["酷賊姦讎既已除，銜冤抱恥正號呼。", "當時但痛君非命，今日方知妾累夫。", "捨義取生真鄙事，殺身沈子乃良圖。", "幾年污辱無由雪，長使清淮滌此軀。"]'),
('c103d9ca-b254-42f7-b4c3-334f1629eab1','淮陰義婦  其二','徐積','宋','宋诗','song-poetry','','[]','淮陰婦人何决烈，貌好如花心似鐵。',32,'全唐诗/poet.song.37000.json','["淮陰婦人何决烈，貌好如花心似鐵。", "殺身沈子須臾閒，身雖已死名不滅。"]'),
('0ce5dc17-b606-42eb-8242-9227cf6b178c','北神烈婦','徐積','宋','宋诗','song-poetry','','[]','海水猶可泛，君身不可犯。',48,'全唐诗/poet.song.37000.json','["海水猶可泛，君身不可犯。", "淮水猶可潴，君名不可汙。", "鸞鳳猶可馴，冰霜猶可親。", "不是雲閒月，即是月邊雲。"]'),
('9fcf20a7-d3a9-4909-8b77-8274f12b7dba','贈子瞻  其一','徐積','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','翰林主人其姓蘇，左臂不任十上書。',82,'全唐诗/poet.song.37000.json','["翰林主人其姓蘇，左臂不任十上書。", "幾年乞得江與湖，吳中父老爭歡呼。", "玉堂金戶不肯居，肯來南郭尋樵夫。", "樵夫所識山與水，除此如何論奇偉。", "八月十五錢塘江，海門山下潮頭起。", "”。"]'),
('8c422146-a0c1-489c-bd8b-92317a652ce7','贈子瞻  其二','徐積','宋','宋诗','song-poetry','','["\u897f\u6e56"]','翰林豈特文章工，赤心白日相貫通。',320,'全唐诗/poet.song.37000.json','["翰林豈特文章工，赤心白日相貫通。", "先與吳人除二凶，次與吳田謀常豐。", "乃與徒役開西湖，狹者使廣塞者除。", "溉田不知幾萬夫，其田立變爲膏腴。", "世世可知無旱枯，吳人衣食常有餘。", "有餘之人善可趣，官司亦可省刑誅。", "無窮之利誰與俱，前有白傅後有蘇。", "翰林如此能成務，吳人叩額呼爲父。", "未知何處立生祠，定是吳山行坐處。", "翰林却過淮之東，無人不看眉陽公。", "玉堂氣貌將以恭，又到南城尋老農。", "仍使尊中酒不空，玉泉最好白醅醲。", "便將玉水傾喉嚨，須臾醉倒無憂翁。", "老翁雖醉不敢迂，記得杭州三事書。", "欲毗舜智臯陶謨，事防沮隔有所拘。", "翰林此說若行諸，聖朝惠澤可大敷。", "譬如雷雨動天衢，曠然霈然而廓如。", "無分草木與蟲魚，一時奮振皆霑濡。", "滿堂飲酒盡歡娛，更無一人泣向隅。", "老農雖然無所逋，願同衆口齊歡呼。"]'),
('4d7dedac-5797-49d8-b483-8a3db52f66d3','贈子瞻  其三','徐積','宋','宋诗','song-poetry','','[]','昔者益州牧，意欲見杜微。',144,'全唐诗/poet.song.37000.json','["昔者益州牧，意欲見杜微。", "不能以身往，使人輿致之。", "雖用爲諫議，待士禮已非。", "而况君房輩，端坐呼子陵。", "子陵胸中氣，直與青雲平。", "豈肯爲人屈，彼亦徒驕矜。", "孰如揚州牧，自處遜與恭。", "德不矜其盛，事不矜其功。", "南郭已三顧，迂身爲衰翁。", "以手書所問，視面歎厥容。", "移時能立語，避乘乃鞠躬。", "不知古之人，幾人能如公。"]'),
('a25a3422-fe90-46b6-b955-c7a3c6a2b9f7','感秋和張文潜  其一','徐積','宋','宋诗','song-poetry','','[]','汎汎河中舟，莫繫河上柳。',168,'全唐诗/poet.song.37000.json','["汎汎河中舟，莫繫河上柳。", "君看道傍葉，行人一揮手。", "枝條旦旦空，顔色何可久。", "坐恐霜霰繁，諸媚歸一朽。", "我有千丈松，亭亭不可揉。", "生在孤峰上，獨與雲霞偶。", "羣形靡且紛，不與較妍醜。", "羣動日夜馳，而以靜爲守。", "守松者爲誰，白髪無憾叟。", "蓬蒿可蔽身，糟糠可餬口。", "言者寓於詩，默者寓於酒。", "誰知杯酌閒，便是無何有。", "念子於我深，我於子亦厚。", "記我守松篇，行行重回首。"]'),
('b842982e-5f77-4006-bf91-45d75a2509d2','感秋和張文潜  其二','徐積','宋','宋诗','song-poetry','','[]','張子非不厚，涕泗中夜起。',120,'全唐诗/poet.song.37000.json','["張子非不厚，涕泗中夜起。", "蘭蕙雖已衰，松筠正堪佩。", "君愛蘭與蕙，忘我筠與松。", "君愛洛陽官，棄我淮上翁。", "翁如揚大夫，其心甘賤貧。", "不投天祿閣，却反離騷文。", "騷人雖已歿，萬古爲忠魂。", "欲知冤憤氣，但看蒼梧雲。", "冤情寄湘水，冤聲寄湘竹。", "年年霜露時，夜夜秋聲哭。"]'),
('52c86bd1-a2ae-46ec-b1ae-d99a79643682','感秋和張文潜  其三','徐積','宋','宋诗','song-poetry','','[]','秋風一何慘，物形隨以變。',204,'全唐诗/poet.song.37000.json','["秋風一何慘，物形隨以變。", "秋風如無情，蟲鳥聲俱怨。", "我無外物累，但有屋中燕。", "翩翩勢將去，盼盼如有戀。", "此物雖至微，其舊殆可念。", "而况西郭交，年將屈五指。", "南城文字閒，東臯松竹裏。", "氣類亦相合，老少兩忘齒。", "昔居吾舍傍，今在河之涘。", "船頭纜將解，船上桅將起。", "留君恨不早，此役定難止。", "如何舍我去，處我復何以。", "君看淮泗閒，一派良可喜。", "從來病濁汙，而今稍清泚。", "人方涉其流，冠纓殆可洗。", "此行君樂否，一千五百里。", "未見洛陽山，先見洛陽水。"]'),
('c94d8a36-66af-4224-a5dc-755175ec1cbc','謝周裕之  其一','徐積','宋','宋诗','song-poetry','','[]','樂不須絲竹，花不須桃李。',227,'全唐诗/poet.song.37000.json','["樂不須絲竹，花不須桃李。", "舞不須輕軀，歌不須皓齒。", "人生各有樂，顧我如何爾。", "我是兩柳翁，家在南郭裏。", "詩酒以爲樂，賓客至即喜。", "酒味酸或淡，瓷椀麤而偉。", "或無一飣菜，但費幾張紙。", "人情慕富貴，公何眎賤鄙。", "寒冷載肴酒，暮夜煩屐履。", "孚誠非猝然，餖亦勞止。", "不用卞郎瓠，但坐杜侯椅。", "兩桌合八尺，一爐暖雙趾。", "不以藥隨時，而用繒掩耳。", "或啖魚菹盡，或愛藏蔬美。", "或取鱐與臘，或約酒以指。", "人皆悅真厚，誰敢停箸匕。", "一客癯而清，偶坐爲六子。", "吟聲尚鼓吹，歡情勝羅綺。", "俗物無所用，高會有如此。"]'),
('81c3ad1d-1578-4542-8969-5f8947c700fa','謝周裕之  其二','徐積','宋','宋诗','song-poetry','','[]','義無所不感，誠無所不動。',72,'全唐诗/poet.song.37000.json','["義無所不感，誠無所不動。", "誠義既如此，外物斯何用。", "以外表諸中，以物將其義。", "所謂君子誠，誠亦不虛致。", "人有忘恩者，嗟歎而泣涕。", "我心非土木，亦有眼中淚。"]'),
('2862b9e0-25d4-4fee-9a2c-1f5d8008584f','贈玉師失鸚鵡詞','徐積','宋','宋诗','song-poetry','','[]','紅蹊翠塢風花客，家有千山萬山碧。',256,'全唐诗/poet.song.37000.json','["紅蹊翠塢風花客，家有千山萬山碧。", "一從流落在人閒，玉環絛重金籠窄。", "金籠一片烟霞曉，花艷成團柳枝裊。", "足穿蜀錦茜靴牢，身著吳綾紺袍小。", "參差微露紅霞裙，丹喙即是胭脂唇。", "真是人閒富貴物，何異朱門羅綺身。", "慧性馴姿良可取，只被多言仍巧語。", "前身不是亡國臣，即是傾城傾國女。", "門外人來連報客，點茶沽酒俱催索。", "叫人名字學人言，吳語秦聲俱記得。", "大都有似原人爲，視人歡慼爲笑啼。", "俗客面前多俚語，逢僧輒誦阤羅尼。", "嗟嗟何用畜此禽，歲月養成姦巧深。", "莫信口中一片舌，對面千里萬里心。", "主人曰予未有知，爲愛能言不放歸。", "不道姦心多詐僞，吭腸纔飽脫身飛。"]'),
('43974be8-f174-4389-82c1-7796648b670e','送蔣憲穎叔','徐積','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','五嶺之南，其極西徼。',240,'全唐诗/poet.song.37000.json','["五嶺之南，其極西徼。", "其旁大海，木深山峭。", "內有谿洞，外有交趾。", "皮厚肉堅，鐵爲骨髓。", "雉兔伏藏，猱猿突起。", "動如飄風，猛如湍水。", "獨恩不畏，獨威不懷。", "擾之則去，撫之則來。", "恩之與威，不可去一。", "寬猛交濟，不可無術。", "坐當一面，則有帥臣。", "按刑將漕，要皆得人。", "以德以才，公稱其選。", "能不擇官，義不辭遠。", "始聞有命，嚴裝以需。", "青氈角簟，藥鼎茶爐。", "琴堂舊譜，鈴閣新書。", "史帙籤重，詩囊卷粗。", "前施齋舫，後設行厨。", "公既拜命，不敢寧居。", "迺戒徒御，迺建帆檣。", "鳴刁擊鼓，旗幟開張。", "州人感恩，父老童稚。", "知不可留，以足頓地。"]'),
('b277f21a-3a1d-4091-9b51-7ea99c26366a','謝呂帥寄書','徐積','宋','宋诗','song-poetry','','[]','疇昔逢公時，老人悅公義。',48,'全唐诗/poet.song.37000.json','["疇昔逢公時，老人悅公義。", "率然應公問，而云在藏器。", "公以問爲好，其法爲可傳。", "老語不記時，人事成恍然。"]'),
('88794e52-a013-4a8a-8cd1-b61764da0496','送程運判','徐積','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','江南風物可醒酒，江山氣勢侵牛斗。',256,'全唐诗/poet.song.37000.json','["江南風物可醒酒，江山氣勢侵牛斗。", "大庾梅花入界香，南康瀑布從天吼。", "此閒好共吳人樂，井蛟爲害須除却。", "觀風未到庾公樓，褰帷先上滕王閣。", "仙籟鳴時獨鳳吟，劍池黑處雙龍躍。", "縣令寧無種秫翁，還似王弘就翁酌。", "最是高賢徐穉墳，急齎酒脯祠溟漠。", "部吏爭迎使者車，野人夾道亦歡呼。", "且得官司減鞭笞，若逢水旱放田租。", "關市如何從薄賦，設法通商爲遠圖。", "方今聖世雖無事，須修武備戒不虞。", "生民所恃在城邑，更嚴壁壘完其郛。", "何况荆湖與二廣，溪洞盡是蠻所居。", "一日除書遣受降，便持斧鉞建油幢。", "陣上風神應更偉，軍中才氣亦無雙。", "勢似疾雷從便道，揮兵直指富良江。"]'),
('da4ae6f5-ccc6-4849-a7d3-0919a315c996','代玉師謝蘇子瞻','徐積','宋','宋诗','song-poetry','','[]','海上山翁歸，童子言有客。',72,'全唐诗/poet.song.37000.json','["海上山翁歸，童子言有客。", "身披一鶴氅，足曳雙鳬舄。", "控却大鵬頭，踏著巨鰲脊。", "面带玉山氣，手畫龍泥壁。", "諸仙爭進硯，一笑已投筆。", "其夕刮兩眼，燒却犀一尺。"]'),
('d00d95b3-4305-43ba-bda6-73ca1ba6cbdf','寄李道源','徐積','宋','宋诗','song-poetry','','[]','春風本是詩家友，典却琴書也沽酒。',64,'全唐诗/poet.song.37000.json','["春風本是詩家友，典却琴書也沽酒。", "呼童去問紫霄翁，近來枕上吟詩否。", "不醉不吟將奈何，過却今年春已多。", "胸中壯氣吐不出，看看空作送春歌。"]'),
('360635ef-822a-42cb-a444-98ec6c18ed1c','酬李道源彈琴之句  其一','徐積','宋','宋诗','song-poetry','','[]','數尺焦桐常在手，知子愛歌兼愛酒。',64,'全唐诗/poet.song.37000.json','["數尺焦桐常在手，知子愛歌兼愛酒。", "今朝已是二月三，梅花驛使曾來否。", "古今多少無奈何，古人慷慨良已多。", "爲報陶潜且飲酒，無弦琴上不須歌。"]'),
('eb7f173d-cc33-44be-90e1-d079308a7ebd','酬李道源彈琴之句  其二','徐積','宋','宋诗','song-poetry','','[]','漫翁來索詩千首，須與古人沽美酒。',64,'全唐诗/poet.song.37000.json','["漫翁來索詩千首，須與古人沽美酒。", "近來聲調太尋常，不知得似陽春否。", "漫翁教我歌云何，水遠山長春思多。", "安得桓伊吹短笛，共君慷慨一時歌。"]'),
('f664dd97-f4fb-429a-a855-e0335b27c6c9','和馬秀才','徐積','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','君看淮上翁雖老，胸中意氣從來好。',235,'全唐诗/poet.song.37000.json','["君看淮上翁雖老，胸中意氣從來好。", "白日吟到夜，夜後吟到曉。", "門前是雙柳，樹上無棲鳥。", "西邊是人家，人家兒夜啼。", "四更五更後，往往催鳴鷄。", "東邊是空庭，空庭清風多。", "吟聲上河漢，河漢生銀波。", "移聲入明月，桂樹無停柯。", "蟾蜍不得睡，狡兔將奈何。", "清風却下來，直入淮之水。", "不知淮東西，波浪如何止。", "清風清風不復住，復住射陽湖上路。", "寧知烈士怨曹袁，義鬼哀哀冤來訴。", "此聲未可□臧洪，不須更往吳江去。", "吳江心中有冤血，寃聲吼兮寃氣結。", "奈何乎湘江亦有獨醒夫，醒時何故沈其軀。", "當時魚腹今在無，此聲莫過洞庭湖。"]'),
('d9cb5137-9f79-48b4-af09-07b1de8195b0','謝皇華使者','徐積','宋','宋诗','song-poetry','','[]','皇華使者將就車，先聲即日傳江湖。',240,'全唐诗/poet.song.37000.json','["皇華使者將就車，先聲即日傳江湖。", "良民置酒相歌呼，姦人落膽猾吏逋。", "手中平握三尺書，權衡輕重量錙銖。", "冤聲弊獄一切除，寧其家室完其膚。", "本朝寬大恩涵濡，一物不被成焦枯。", "煩公大手持刀鈇，開塞去擁鋤荆蕪。", "其和易致仁易孚，此行遂與春風俱。", "蠻酋鼠竄稽天誅，官兵指日縛狂奴。", "皮囊插羽徵軍須，人方汲汲公有餘。", "藉公之智須公謀，使星已動宜疾驅。", "非惟一道無無辜，朝廷南顧無憂虞。", "吾州父老將何如，呼其子弟牽僕夫。", "縶之維之馬與駒，晨炊夕爨空其郛。", "亦有下客身鰥孤，懷公禮義心區區。", "寄詩如問公起居，公能報我荆州書。"]'),
('c8feb8a2-1a76-4a09-b06e-4be833514786','謝田守','徐積','宋','宋诗','song-poetry','','[]','前日李山陽，說公安且裕。',192,'全唐诗/poet.song.37000.json','["前日李山陽，說公安且裕。", "精神健復初，决遣敏如故。", "吏復畏其明，民復愛其恕。", "可保長康寧，但更勉將護。", "尋聞車馬出，州人喜可知。", "或出車前望，或走車後隨。", "南郭有賤叟，雖愚亦更喜。", "不敢問公者，恐煩答數紙。", "賤叟固自訟，太守謙愈勞。", "即以出之日，折簡親揮毫。", "送之上尊酒，副以黄巨苞。", "情意專如此，禮義積已高。", "賤叟不能報，自恨如時輩。", "所以作詩者，欲公重自愛。", "自愛以爲國，爲國斯爲民。", "慰我之鄉黨，悅公之慈親。"]'),
('696c8d8d-1b79-49c4-86e3-7588391ceec9','謝畢令','徐積','宋','宋诗','song-poetry','','[]','一身多難過春風，兩眼未見花枝紅。',128,'全唐诗/poet.song.37000.json','["一身多難過春風，兩眼未見花枝紅。", "近來廢却無限吟，今年自覺詩無功。", "畢令與我好相識，遺我春醅表胸臆。", "知我愛酒兼愛詩，使我吟哦醉春色。", "春色半酣正二月，草頭爭露花爭裂。", "是花是草屬詩家，若無此酒幾虛設。", "此酒有似君德醇，先入六腑搜吟魂。", "相將醉魄御烟雲，游遍江淮無限春。"]'),
('f63ef50e-a231-4bf9-9ecf-f8afb077d257','謝王觀文','徐積','宋','宋诗','song-poetry','','[]','東野鰥夫未識公，寄聲直入茅廬中。',64,'全唐诗/poet.song.37000.json','["東野鰥夫未識公，寄聲直入茅廬中。", "茅廬四面生春風，草頭添綠花添紅。", "東野鰥夫最好吟，感公高義藏於心。", "爲公製作平戎曲，彈向蔡家焦尾琴。"]'),
('4029e8f6-7441-43a2-bde8-c8c9d8d717ee','謝呼延禁侍','徐積','宋','宋诗','song-poetry','','[]','有客從京南，來尋淮上叟。',48,'全唐诗/poet.song.37000.json','["有客從京南，來尋淮上叟。", "氣貌良肅雍，辭令亦溫厚。", "如此已可喜，遺我故人書。", "須臾四千里，恍惚游江湖。"]'),
('903dbbf2-19c2-4931-b1ac-008c340d8462','昨日之夕和蔣穎叔','徐積','宋','宋诗','song-poetry','','[]','昨日之夕誰扣扉，大使遣人來索詩。',64,'全唐诗/poet.song.37000.json','["昨日之夕誰扣扉，大使遣人來索詩。", "吟聲一發巢烏飛，一夜清風摇木枝。", "吟亦不住風不停，安知半夜風出城。", "大使船上風霜清，更添南郭吟哦聲。"]'),
('9d17d924-f3cf-4c47-aa82-6a70cc0d64e9','寄崔尉','徐積','宋','宋诗','song-poetry','','[]','人閒多少無奈何，勸君收淚且酣歌。',64,'全唐诗/poet.song.37000.json','["人閒多少無奈何，勸君收淚且酣歌。", "不須載酒但相過，共君摧手踏青莎。", "東臯閒日苦無多，南城應是合吟哦。", "胸中有淚難消磨，惟予詩興如風波。"]'),
('e850dd0b-41a6-41c1-b9ec-1f17f74f2f1a','送張君河朔之行','徐積','宋','宋诗','song-poetry','','[]','嘗聞此道春來遲，山中積雪埋狐狸。',144,'全唐诗/poet.song.37000.json','["嘗聞此道春來遲，山中積雪埋狐狸。", "黄河三月冰正合，朔風凜凜吹人衣。", "吁嗟客路正寒苦，數千里外將何爲。", "答云此去非徒爾，有如羽翼投高枝。", "主人之賢聞天下，出門捨此將安之。", "嗟予贈此復何說，少年養取胸中奇。", "古人之學不可廢，丈夫之操不可移。", "江淮之上親且老，臨行須約將歸時。", "邊城吹角客心亂，此時應望東南飛。"]'),
('50a2d866-2ecb-4494-81a0-b8d6389c398c','答范君錫汎汎愛花之句','徐積','宋','宋诗','song-poetry','','[]','汎汎愛花非愛一，范掾愛花如此密。',208,'全唐诗/poet.song.37000.json','["汎汎愛花非愛一，范掾愛花如此密。", "一從春色到人閒，每月弄花三十日。", "第一花中愛牡丹，待與金釵共玉冠。", "第二桃花及杏花，此花大抵顔色奢。", "又愛牆頭看海棠，亂點燕脂如急粧。", "更無閒暇及芳草，却解迴頭覷綠楊。", "其餘好花有何限，范掾看花眼頭爛。", "見花如見故人來，尋花太緊攀花慢。", "洛陽城內騎馬走，山陽城外坐監酒。", "坐地愛花情更深，時時取酒爲花斟。", "誰知有此風流掾，詩情酒興紛如霰。", "好來閑伴老翁吟，老翁是物吟將遍。", "海閒亦有蟠桃花，可能同發乘桴願。"]'),
('a27b4f2a-55b0-4b1a-92a7-c2fad695c78b','贈倪敦復','徐積','宋','宋诗','song-poetry','','[]','北軒主人吳中清，所居才義皆有名。',64,'全唐诗/poet.song.37000.json','["北軒主人吳中清，所居才義皆有名。", "曾在東臯壓衆賓，人皆閣筆詩已成。", "其時於我最有情，如今相見情更深。", "野人情義亦不輕，夜來枕上爲公吟。"]'),
('73c63935-9102-479b-9e3f-1e418cfdaff5','贈張敏叔','徐積','宋','宋诗','song-poetry','','[]','張家船上雪壓篷，船頭船尾堆玉虹。',96,'全唐诗/poet.song.37000.json','["張家船上雪壓篷，船頭船尾堆玉虹。", "此時半夜明月中，有人兩脚登雲空。", "其人便是吟哦客，能作清詩無俗格。", "更向孤舟雪裏吟，一生多難頭先白。", "白毛吟處徹骨清，喉嚨往往生寒冰。", "可能乘興到南郭，戴家爲子燒破琴。"]'),
('7a465e56-55ac-4e88-a412-d702e8076a4e','送汝弼赴潭倅  其一','徐積','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','莫說江南行路長，山蒼蒼兮水茫茫。',144,'全唐诗/poet.song.37000.json','["莫說江南行路長，山蒼蒼兮水茫茫。", "莫問長沙城遠近，洞庭湖口是瀟湘。", "去時先上岳陽城，夜宿巴陵探陰晴。", "泛洞庭時四五更，出湖口處曈曨明。", "平生聞說潭與衡，今來吏隠駐箳篂。", "四時所見皆所經，湖青草兮廟黄陵。", "眼看君山別洞庭，笑談却作江南行。", "巴陵渡口轉船頭，一帆風過岳陽樓。", "行盡江山到真州，畫船旗鼓入揚州。"]'),
('23f8d946-41e3-4a27-92fd-350bae2f8174','送汝弼赴潭倅  其二','徐積','宋','宋诗','song-poetry','','[]','不作長沙行，湖湘少斯客。',48,'全唐诗/poet.song.37000.json','["不作長沙行，湖湘少斯客。", "潔身不可污，好義是所積。", "口不出巧言，面不爲邪色。", "誰可謀定交，斯人不可失。"]'),
('a827f837-ae42-4b98-b879-b66933330a63','富貴篇答李令','徐積','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我有一筒詩，寫出千年意。',377,'全唐诗/poet.song.37000.json','["我有一筒詩，寫出千年意。", "將令後世觀，不是前言戲。", "感君再唱洞庭謠，我亦重歌酬子惠。", "古人達者嘗有云，富不如貧賤勝貴。", "君不見古之富貴郎，父祖俱封異姓王。", "一門五侯三將軍，弟兄同入中書堂。", "對開大第連幾坊，私門列戟森鋒鋩。", "十二簾捲珠熒煌，雙姬扶起坐牙牀。", "綠鬟紅袖花成行，左盼右顧生春陽。", "高車食客劍佩鏘，堂上已滿坐兩廊。", "巨鑊大鼎烹牛羊，玉壺挹酒金船長。", "美人拜客求盡觴，歌姬一誤已絕吭。", "纏頭彩幣堆如岡，酬歌買笑金鴛鴦。", "奴袍火浣直兩箱，三千廐馬紅錦障。", "厠幃文繡爐薰香，更衣侍妾如閨房。", "主人意氣秋鷹揚，其心端如彩鳳凰。", "一言合意青雲翔，須臾睚眦磨刀鎗。", "門前臘月可烘裳，一日失勢成冰隍。", "小者腰領屍道旁，大者連頸宗族亡。", "犬鷄散盡空遺牆，野鳥入室山魈藏。", "嗚呼哀哉可歎傷，至死不悟猶陸梁。", "古來如此有多少，豈似洞庭湖上老。", "無租無稅一生閒，有飯有魚一杯飽。", "日落波閒烟正昏，雲開湖口山光曉。"]'),
('3858629d-5393-4439-93be-ab8c2c3de077','寄管久中','徐積','宋','宋诗','song-poetry','','[]','我頭未白心先老，吐出精誠爲君禱。',32,'全唐诗/poet.song.37000.json','["我頭未白心先老，吐出精誠爲君禱。", "若無歸計似陶潜，學取蕭生抱關好。"]'),
('d3aaa3bd-d3b3-4d59-ab7c-9170da7339f2','贈查宣教','徐積','宋','宋诗','song-poetry','','[]','晚來閒共秋風約，惟有黄花莫吹却。',32,'全唐诗/poet.song.37000.json','["晚來閒共秋風約，惟有黄花莫吹却。", "有人懷抱似陶潜，待向東籬共花酌。"]'),
('b176e351-9b6c-4899-9129-b4abf0eec6ef','答盧魯山秀才','徐積','宋','宋诗','song-poetry','','[]','吾道一於中，所得無背向。',72,'全唐诗/poet.song.37000.json','["吾道一於中，所得無背向。", "吾神充乎形，所得無衰王。", "氣入春風和，興與秋鷹揚。", "有累已驅除，無酒亦酣暢。", "外如不可撓，內如不可狀。", "更讀魯山詩，何樂可能尚。"]'),
('088560c5-9bca-427d-9d9b-5da59c126a6b','簽劉子靜秀才并示魯山','徐積','宋','宋诗','song-poetry','','[]','難逢一笑樂，易遇千黄金。',48,'全唐诗/poet.song.37000.json','["難逢一笑樂，易遇千黄金。", "而况吾胸中，所得蓋已深。", "百物正爛熳，二子方歌吟。", "一樂已自足，兩樂交吾心。"]'),
('402d2e87-e315-4f88-9c8f-37c0e3d9235a','和魯山感春  其一','徐積','宋','宋诗','song-poetry','','[]','君看紛紛能幾時，一番情態隨春盡。',48,'全唐诗/poet.song.37000.json','["君看紛紛能幾時，一番情態隨春盡。", "歡者常少戚者多，共君且趁春風歌。", "莫學時人種花草，不似山中松桂好。"]'),
('d2bd90c7-f366-4f7a-90f0-b62c304cb876','和魯山感春  其二','徐積','宋','宋诗','song-poetry','','[]','一笑一啼何日休，一榮一悴何時盡。',48,'全唐诗/poet.song.37000.json','["一笑一啼何日休，一榮一悴何時盡。", "樽中野酒亦無多，日伴吟翁慷慨歌。", "茅屋窗前棲亂草，勝却花閒繡裀好。"]'),
('653af60c-e9d9-43fc-8075-3a6354e62458','呈次中','徐積','宋','宋诗','song-poetry','','[]','煩公素葉詩，答我碧蘆柬。',48,'全唐诗/poet.song.37000.json','["煩公素葉詩，答我碧蘆柬。", "我亦爲長句，枕上不合眼。", "兩城俄相通，一意如同撰。", "用韵亦無殊，便可書之板。"]'),
('ad801be8-4cf0-438c-8f55-60dd94db6b79','述懷寄呂帥','徐積','宋','宋诗','song-poetry','','[]','君看關西山壁立，春雲突盡春空窄。',80,'全唐诗/poet.song.37000.json','["君看關西山壁立，春雲突盡春空窄。", "濃嵐洒去渭川寒，孤峰深與秦天碧。", "白雲流水豈無情，立馬吟詩定相憶。", "且倩東風先寄聲，我整西裝期已迫。", "吟到秋風放我歸，歸來待作瀟湘客。"]'),
('7f9d688a-a32a-453e-bafc-d79309c2496e','和李自明  其一','徐積','宋','宋诗','song-poetry','','["\u8861\u5c71"]','青松何嵒嵒，生在孤高處。',48,'全唐诗/poet.song.37000.json','["青松何嵒嵒，生在孤高處。", "能鳴月下風，更入雲閒路。", "雲漢何渺茫，遠過衡山陽。", "松風上河漢，高韵落三湘。"]'),
('0aa42acc-4368-4e85-95b4-3c6e4bed8c24','和李自明  其二','徐積','宋','宋诗','song-poetry','','[]','我有金玉交，家在臨流處。',48,'全唐诗/poet.song.37000.json','["我有金玉交，家在臨流處。", "秋來詩更清，吟喉飲風露。", "崔子在何方，清思滿殘陽。", "不知今夜夢，幾度過衡湘。"]'),
('1311d0b3-ed48-4292-b856-3d64a084775f','送沅州通判','徐積','宋','宋诗','song-poetry','','[]','過湘江時君且聽，但恐水中有冤聲。',96,'全唐诗/poet.song.37000.json','["過湘江時君且聽，但恐水中有冤聲。", "當時無地容屈平，衆人皆醉嫌獨醒。", "煩君須弔獨醒翁，以酒注之魚腹中。", "不須以物纏米筒，但投詩去責蛟龍。", "爲君質直有古風，能高其義哀其忠。", "投詩已罷弔已終，寄聲急報南城翁。"]'),
('4c2268b7-d839-4cce-9de1-c6b41c489468','贈呂帥','徐積','宋','宋诗','song-poetry','','[]','玉門關靜邊烽息，回首金城趙充國。',96,'全唐诗/poet.song.37000.json','["玉門關靜邊烽息，回首金城趙充國。", "繡帽霜鬚馬上吟，詩興如雲滿秋色。", "最好青門長樂坡，灞橋路上情更多。", "繡嶺風烟新草木，潼關形勢舊山河。", "洛陽城闕秋風緊，有詔疾驅催大尹。", "兩瞳直是有精神，管取無寬亦無猛。"]'),
('28eb9017-8b8d-40cf-88fd-81fa538911b4','寄道原  其一','徐積','宋','宋诗','song-poetry','','[]','好笑李詩翁，寄身明月中。',48,'全唐诗/poet.song.37000.json','["好笑李詩翁，寄身明月中。", "饑腸吞白露，醉口吐清風。", "時時跨霜鶴，步步凌秋空。", "相呼且相待，略住白雲峰。"]'),
('cadb56db-01cd-4a59-8628-56d13cbbc894','寄道原  其二','徐積','宋','宋诗','song-poetry','','[]','漫翁身上霜可刮，酒未醒時詩已發。',32,'全唐诗/poet.song.37000.json','["漫翁身上霜可刮，酒未醒時詩已發。", "急放人去守船門，恐向河中捉明月。"]'),
('2b225e15-ae6f-4aee-9632-f1011e30a87d','和李自明','徐積','宋','宋诗','song-poetry','','[]','病叟相逢恨不早，蒹葭敢比瑶林好。',64,'全唐诗/poet.song.37000.json','["病叟相逢恨不早，蒹葭敢比瑶林好。", "誰作羊車衛玠看，不道好玄揚子老。", "使君禮義高如山，清風更可清塵寰。", "明日王君來訪我，陶潜欲卧君須還。"]'),
('f5d83dd0-c7ab-4694-b052-732c690da4b1','送呂掾歸揚州','徐積','宋','宋诗','song-poetry','','[]','年年二月春色稠，今年二月寒未收。',64,'全唐诗/poet.song.37000.json','["年年二月春色稠，今年二月寒未收。", "路上無花空酒甌，清吟清嘯到揚州。", "到揚州後登高城，綠波芳草連江津。", "吟哦若望江南春，梅花便是江頭雲。"]'),
('e1242045-cf33-4986-8c7c-2ed298f5b2da','寄范掾','徐積','宋','宋诗','song-poetry','','[]','昨日沽酒典布襖，今朝所典未可保。',64,'全唐诗/poet.song.37000.json','["昨日沽酒典布襖，今朝所典未可保。", "最好綿衾剩典錢，又恐夜寒妻懊惱。", "兩務酒官俱見憐，沽我好酒如甘泉。", "爲報孟光莫惡發，待將黄卷換青錢。"]'),
('7f69d7e2-637a-409e-9c71-3d5b9b5c7c5c','送晦叔','徐積','宋','宋诗','song-poetry','','[]','兩人俱是白髪翁，不用語言情意通。',60,'全唐诗/poet.song.37000.json','["兩人俱是白髪翁，不用語言情意通。", "且喜胸中無一事，一生常在平易中。", "願公活百歲，我活九十九。", "白髪變成黄髪翁，回來同把一杯酒。"]'),
('62c507fb-ebab-42d2-9b1d-459ea8368d49','贈張敏叔','徐積','宋','宋诗','song-poetry','','[]','張子生平最多難，未老頭毛白一半。',64,'全唐诗/poet.song.37000.json','["張子生平最多難，未老頭毛白一半。", "頭雖更白詩更清，正作詩時人莫喚。", "頭不肯轉身不移，口中聲調霜風凄。", "太清宮殿月明時，第一莫吹松竹詩。"]'),
('d587b505-910f-4310-bad7-d55924869661','送辛朝奉','徐積','宋','宋诗','song-poetry','','[]','幾日遲遲辭我去，夢中猶憶南城路。',64,'全唐诗/poet.song.37000.json','["幾日遲遲辭我去，夢中猶憶南城路。", "不知昨夜月明時，泮水宮中來幾度。", "三月春風正向西，我將心逐春風飛。", "送過高麗亭下路，別遣春風隨客衣。"]'),
('f2202eb7-ea47-4049-bb88-f04ca771b0ae','送崔主簿赴雅安','徐積','宋','宋诗','song-poetry','','[]','見說西川好山水，此行便是秋風裏。',64,'全唐诗/poet.song.37000.json','["見說西川好山水，此行便是秋風裏。", "洛陽年少本多才，馬上一揮吟一紙。", "鳳凰羽翮非徒爾，上擊浮雲九千里。", "枳棘須教別鳥棲，自趁春風便飛起。"]'),
('c78e8c39-f4ca-4e73-bf29-7fa1d0f188b2','送張九掾兼簡同事錢明府可與慎叔良蔡彥規同一笑也','徐積','宋','宋诗','song-poetry','','[]','有人獨酌南窗酒，春是故人詩是友。',64,'全唐诗/poet.song.37000.json','["有人獨酌南窗酒，春是故人詩是友。", "故人消息在江南，爲我江頭探楊柳。", "詩人見春雙眼明，迎春送春俱有情。", "何况溫溫張九掾，可無詩句贈君行。"]'),
('3a14fe7c-bb99-4e18-a003-cd777b456d27','送王潜聖','徐積','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','公車待報凡幾年，蕭生罷去心浩然。',96,'全唐诗/poet.song.37000.json','["公車待報凡幾年，蕭生罷去心浩然。", "鹽瀆野中尋舊隠，揚子江頭呼渡船。", "太湖波浪濕秋天，洞庭橘柚生紅烟。", "馬踏新霜吳嶺外，猿啼小雪建溪邊。", "關西夫子雖遲暮，行笑行吟正安步。", "菑川海上牧羊兒，亦說公孫放豚去。"]'),
('bab39c4d-042e-4783-8686-2aa22fbe8df6','寄張文潜','徐積','宋','宋诗','song-poetry','','[]','不知今之人，誰識張縣尉。',168,'全唐诗/poet.song.37000.json','["不知今之人，誰識張縣尉。", "勿問胸中事，但看面上氣。", "所謂人英者，正是斯人輩。", "前年南郭中，文酒日夜會。", "一從舍我去，忽忽再逾歲。", "今茲歲且盡，爲子吟不睡。", "起坐却就枕，伸頭出紙被。", "約是三四更，老老抱雙脚。", "此時吟正酣，聲調不可却。", "春風起淮東，須臾到嵩洛。", "往往入子家，但子眠不覺。", "子覺將奈何，聲盡情思多。", "上東門外路，洛水生春波。", "還我大松來，不用寄詩歌。"]'),
('6194ff46-cf7c-433c-acb0-a032fa40e326','代簡呈通理察院','徐積','宋','宋诗','song-poetry','','[]','去年過時花未紅，今年過時春未融。',64,'全唐诗/poet.song.37000.json','["去年過時花未紅，今年過時春未融。", "春未融時得子來，吟翁面上生春風。", "吟翁近來成白頷，種種頭毛無一半。", "唯有胸中氣未衰，更得公來激吾懦。"]'),
('185b1cc2-cac4-4760-999c-a988c539c2e9','送詩僧嚴上人','徐積','宋','宋诗','song-poetry','','[]','日晚孤雲飛，故山在何處。',36,'全唐诗/poet.song.37000.json','["日晚孤雲飛，故山在何處。", "八月凉秋時，正望江頭去。", "定無塵埃氣，清風與白露。"]'),
('356479ea-94e8-4b62-8ded-4cedf534812c','送端叔  其一','徐積','宋','宋诗','song-poetry','','[]','端叔上馬去，巷口馬頭轉。',64,'全唐诗/poet.song.37000.json','["端叔上馬去，巷口馬頭轉。", "我喚端叔時，端叔急回面。", "記取此時意，莫使落風埃。", "上東門外水，正望楚州來。", "此水一來不復見，不及黄沙塞頭雁。"]'),
('1fa9e71d-b730-4fd8-8000-e1450b412732','送端叔  其二','徐積','宋','宋诗','song-poetry','','[]','是物可寄情，是物可寄聲。',56,'全唐诗/poet.song.37000.json','["是物可寄情，是物可寄聲。", "不須使黄犬，延州歧路遠。", "莫怪不登淮上樓，只爲淮水不西流。", "直待銜蘆雁却回，其時隨到天盡頭。"]'),
('083a137b-dae6-48ab-a1ca-b0abadb7247c','再送端叔','徐積','宋','宋诗','song-poetry','','[]','關中日落時，但見山相接。',136,'全唐诗/poet.song.37000.json','["關中日落時，但見山相接。", "塞上閉城時，但聽吹蘆葉。", "延州平安火過早，月出山頭照孤堡。", "王家池上醉欲倒，銅鉢聲中詩已了。", "落筆揮成露布草，主人更索平戎表。", "文章意氣入杳冥，金船插羽如飛鳥。", "諸軍鼓吹高牙曉，大纛門開撲餘燎。", "壯士犀衣劍氣寒，客身依舊紅霞繞。", "陸生待寄梅花枝，庾郎莫愛芙蓉好。"]'),
('c65460b2-ee83-4214-bf72-0036df92b49f','呈路倅','徐積','宋','宋诗','song-poetry','','[]','三十年居官，而無一椽屋。',168,'全唐诗/poet.song.37000.json','["三十年居官，而無一椽屋。", "隨身清風高，所至義行足。", "今茲盡室來，何可久船宿。", "奴僮已暴露，勿使乏饘粥。", "也須謀外物，種取柳與菊。", "記取節節高，愛我茅簷竹。", "其時花盡落，手把麥黄綠。", "公酌我須釂，公吟我須續。", "慷慨見懷抱，靜介無所欲。", "最是謁祠堂，老淚潸可掬。", "邇來六七歲，病叟頭已禿。", "萬事置浮雲，壯氣自滿腹。", "感激論忠義，猶愛唐衢哭。", "更思桓野王，把笛吹一曲。"]'),
('2e5525d8-10f5-4183-893e-a31f43b710d9','奉呈河中教授','徐積','宋','宋诗','song-poetry','','[]','不息之謂誠，誠所以入德。',48,'全唐诗/poet.song.37000.json','["不息之謂誠，誠所以入德。", "無微而弗大，何往不可適。", "惟其能言者，自求其所得。", "唯其自得之，久而能弗失。"]'),
('e6ce3c42-cea4-40a6-9f32-d57d8dbb1983','奉酬守道','徐積','宋','宋诗','song-poetry','','[]','教官昨自江南來，但有清風無塵埃。',32,'全唐诗/poet.song.37000.json','["教官昨自江南來，但有清風無塵埃。", "曾遇芙蓉池上客，仍過方家舊釣臺。"]'),
('05b053cb-1e39-4e97-be9b-d09e09e48185','贈蔡長官子','徐積','宋','宋诗','song-poetry','','[]','去年冬至第一日，省墓人回船過急。',32,'全唐诗/poet.song.37000.json','["去年冬至第一日，省墓人回船過急。", "不知兩眼血乾無，使我時時爲君泣。"]'),
('f22958c1-e119-48d5-a7e5-a276daf26b84','謝董元達','徐積','宋','宋诗','song-poetry','','[]','鄱陽董元達，七叩樵夫門。',48,'全唐诗/poet.song.37000.json','["鄱陽董元達，七叩樵夫門。", "新葅乏三韭，濁酒欠一樽。", "名言有餘理，老懷思共論。", "今日復一來，刮我兩眼昏。"]'),
('853df652-f1e0-4925-801b-1da756524da0','謝石運幹仲謀','徐積','宋','宋诗','song-poetry','','[]','奉議清而溫，義心無所遺。',56,'全唐诗/poet.song.37000.json','["奉議清而溫，義心無所遺。", "已能顧白鬚，更與吟清詩。", "更與吟詩清奈何，樵翁一夜爲吟哦。", "吟到四更月出後，牀頭看月忽成歌。"]'),
('e68bb40a-8a86-485c-8414-303548fd474a','寄陳伯模','徐積','宋','宋诗','song-poetry','','[]','臘月初四日，有人叩吾廬。',48,'全唐诗/poet.song.37000.json','["臘月初四日，有人叩吾廬。", "言從江上來，手把鄱陽書。", "發書見康强，細字盈數紙。", "仍說九雛中，兩雛正飛起。"]'),
('35c85c3d-e4de-4866-b4fa-44faeea3b9fd','送李光道','徐積','宋','宋诗','song-poetry','','[]','憶昔見子時，我在西關住。',216,'全唐诗/poet.song.37000.json','["憶昔見子時，我在西關住。", "顧我已衰朽，愛子特明悟。", "其後十數年，於此數見之。", "氣貌日益好，胸中即可知。", "貌者德之表，精神氣所爲。", "氣無所不適，其本在養頤。", "所養得其正，其美充四肢。", "子是名公孫，家法能自持。", "子學有舊業，尤富禮與詩。", "重之以所養，何適而弗宜。", "古人有大路，行者皆坦夷。", "夫以子之明，豈惑於多歧。", "修鞭與長轡，逸駕無停時。", "古人亦何人，勿問皆可追。", "昨見子筆札，老人爲子喜。", "其言遜而恭，賁然有文理。", "願子更勉之，莫忘老人語。", "所居求正人，正人德之輔。"]'),
('4725c1fe-d935-4e78-8304-7533c2b7d217','卜居一篇二章別望之  其一','徐積','宋','宋诗','song-poetry','','[]','卜居何所尚，靜軒栽此君。',24,'全唐诗/poet.song.37000.json','["卜居何所尚，靜軒栽此君。", "萬事付流水，一心遊白雲。"]'),
('54693ea9-9635-4657-a731-3e3be3cf14bb','卜居一篇二章別望之  其二','徐積','宋','宋诗','song-poetry','','[]','亦有靈壽杖，可登浮光山。',24,'全唐诗/poet.song.37000.json','["亦有靈壽杖，可登浮光山。", "聖朝須舊德，玉筍虛清班。"]'),
('80a82e99-bcc6-46e4-a177-653b93e2ed81','西山高寄崔刑部','徐積','宋','宋诗','song-poetry','','[]','西山高，胡爲高。',161,'全唐诗/poet.song.37000.json','["西山高，胡爲高。", "上有磨天之巨勢，下有黄河不測之險，甚於蜀道之難。", "西山高，長安之路如雲霄。", "乘無逸駕兮飛無勁翮，我欲往兮有千艱百險之相遼。", "西山高，長安之路如天遥。", "夜短夢不到，白日其心勞。", "西山高，我欲往兮方窮處於蓬蒿。", "恩之大兮報不可以速，太山之重兮置之有若鴻毛。", "西山高，無如之何兮徒引領而長謠。", "青門路兮有時到，願公之壽兮如松喬。"]'),
('8246bb99-1ec4-440f-b092-51c3d716926c','答崔伯易白雪之句','徐積','宋','宋诗','song-poetry','','[]','北叟有奇歌，調與聲俱絕。',180,'全唐诗/poet.song.37000.json','["北叟有奇歌，調與聲俱絕。", "此歌本難名，强名爲白雪。", "一唱白雲開，再唱青雲裂。", "朝唱迎朱霞，暮唱入明月。", "聲在明月宮，桂樹生秋風。", "秋風吹明河，銀浪翻長虹。", "河漢與海通，安知聲所終。", "如此誰可知，但問牽牛公。", "如此誰可聽，直須登青冥。", "酒仙騎赤龍，詩仙騎長鯨。", "一夜到平明，北叟聲且停。", "遺響來南城，猶似孤鸞鳴。", "南公對北叟，阮籍逢孫登。", "阮籍正長嘯，孫登作鳳鳴。", "羞殺阮步兵，笑殺孫先生。"]'),
('8ed72a23-87d1-412a-b712-b037a0844359','送張宜父赴南從幕府','徐積','宋','宋诗','song-poetry','','[]','江南秋色芙蓉香，滿江秋水傾銀潢。',208,'全唐诗/poet.song.37000.json','["江南秋色芙蓉香，滿江秋水傾銀潢。", "泛水依花人姓張，濤翻浪湧揮文章。", "突然出者何蒼蒼，巨鼇曝背來中央。", "黿鼉仰首伏四旁，登臨談笑得庾郎。", "安得霜鶻腰胯長，騎上秋空追鷫鸘。", "北望海門形勢强，美哉壯觀吳封疆。", "若將前代論興亡，直談孫氏到陳梁。", "凡爲佐命可哀傷，其諸姦孽如豺狼。", "傾讒正直誣忠良，以國販賣爲賈商。", "歌姬舞女金滿堂，不須爲盜持刀鎗。", "身雖幸免遺其殃，子孫戮辱甚犬羊。", "所以不欲讀史書，鼻洟目汁沾髭鬚。", "潤州支使相如無，山陽老子如唐衢。"]'),
('89a5acb6-1d54-4e90-8dd1-082abd49cca1','寄吳行甫','徐積','宋','宋诗','song-poetry','','[]','人事無窮時，白日常紛紛。',48,'全唐诗/poet.song.37000.json','["人事無窮時，白日常紛紛。", "夜久靜不眠，枕上還思君。", "形神有合離，忽過江之濆。", "已過江之濆，更隨東南雲。"]'),
('5fb24616-d606-4f1c-b119-0dec531914bb','贈荆南王秀才天爵集虛二堂求詩仍往武陵','徐積','宋','宋诗','song-poetry','','[]','天爵名甚高，集虛名甚悟。',28,'全唐诗/poet.song.37000.json','["天爵名甚高，集虛名甚悟。", "悟高已與俗人非，更望武陵花下去。"]'),
('d297b646-b868-48ef-856a-85ed8452f06f','送李昂長官','徐積','宋','宋诗','song-poetry','','["\u8861\u5c71", "\u6d1e\u5ead\u6e56"]','征南兵勢欲平蠻，軍聲殺氣秋風寒。',240,'全唐诗/poet.song.37000.json','["征南兵勢欲平蠻，軍聲殺氣秋風寒。", "南國此時霜霰早，八月草黄楓葉丹。", "江有渚兮山有麓，君向洞庭何處宿。", "四垂天幕亂波平，九嶷山送愁嵐綠。", "日斜葉落黄陵祠，月明風起清湘竹。", "愁娥遠放峽雲來，冤臣莫借江聲哭。", "雁號孤喙度蒼梧，猿叫哀腸抱霜木。", "君看樵塢與漁村，綠橘黄柑隨柿熟。", "此行正合風騷情，縣衙仍在衡山足。", "新嵐老翠滴吟窗，風松雲溜生琴曲。", "衡人側耳聽先聲，報道官來不碌碌。", "可使汝農無逃田，可使汝市無冤獄。", "汝胥可脫簿書煩，汝民可免鞭笞辱。", "日中放吏不坐廳，夜半投金不受囑。", "回時唯載俸餘錢，茶滿衡山無一掬。"]'),
('024f2d16-5635-4098-8129-dced7207a1a6','謝江倅','徐積','宋','宋诗','song-poetry','','[]','病叟在所收，越已爲高義。',48,'全唐诗/poet.song.37000.json','["病叟在所收，越已爲高義。", "就而飲食之，盛具煩親致。", "讓榻行殊禮，朋酒代賄幣。", "非徒追古風，兼使奉時祭。"]'),
('37b67920-40a6-488b-96d0-11838921b3c0','謝李次翁','徐積','宋','宋诗','song-poetry','','[]','次翁情義高，不在古人下。',48,'全唐诗/poet.song.37000.json','["次翁情義高，不在古人下。", "惠我春山芽，清吟爲增價。", "記得西窗無，言詩遂及雅。", "且待李張來，說子到清夜。"]'),
('013533e9-f4c5-4049-b2b5-39e6cf348f04','答李昂長官富貴貧賤終篇之貺','徐積','宋','宋诗','song-poetry','','[]','前日正憑几，長鬚叩我門。',288,'全唐诗/poet.song.37000.json','["前日正憑几，長鬚叩我門。", "手置一筒詩，義高辭且溫。", "三讀至終篇，尤愛子所存。", "我有不言意，子已自得之。", "余將缺不報，嘉意忽如遺。", "吾聞諸物理，動靜固其性。", "靜有不如動，動有不如靜。", "所病入於邪，大率要歸正。", "窮通存乎時，死生存乎命。", "與其以邪通，孰如以正窮。", "漢之主父偃，其卒敗以凶。", "不義而有生，不如死於夭。", "所以君子徒，而惡蹠壽考。", "謂富不如貧，謂貴不如賤。", "其說豈徒爾，亦各有所見。", "貧賤與富貴，亦不必去取。", "始也以道得，卒也以道處。", "豈特區區身，時乎非小補。", "萬世頼其法，天下受其祜。", "所以古君子，得之亦不拒。", "處之不以道，君子所不與。", "景公馬千駟，孔子賢夷齊。", "曾孟藐晉楚，原顔甘凍饑。", "我愛張車騎，我愛郭汾陽。"]'),
('58817f85-43ce-4402-aaaa-4a6c48c8e784','贈陳留逸人  其一','徐積','宋','宋诗','song-poetry','','[]','不知何許人，忽在陳留市。',90,'全唐诗/poet.song.37000.json','["不知何許人，忽在陳留市。", "生來無得失，物則有泰否。", "春時看物生，秋冬看物老。", "大意寓之笛，餘情付雲鳥。", "無處不可居，不問江與湖，亦不問田廬。", "今夜入城市，往往呼狂夫。", "狂夫勝獨醒，以身葬江魚。"]'),
('283e824f-e1a9-4685-8a23-04c6b42e48f5','贈陳留逸人  其二','徐積','宋','宋诗','song-poetry','','[]','有人持一管，不用蘆葉卷。',144,'全唐诗/poet.song.37000.json','["有人持一管，不用蘆葉卷。", "能作隴頭聲，其女操六板。", "吹者寓其聲，拍者會其情。", "情聲與氣貌，內外俱和平。", "時時入酒家，便插幾枝花。", "歸來無一事，醉卧日西斜。", "人或問所得，答云無憂嗟。", "或問其所欲，何物可相累。", "我愛斯人者，富貴所不如。", "有如此娛樂，作如何稱呼。", "呼爲無憂人，畫作無憂圖。", "更畫幾枝花，酒瓢與酒壺。"]'),
('fa19d315-1d99-4c19-bf8d-88ad8678677f','謝葉祖洽','徐積','宋','宋诗','song-poetry','','[]','葉公有高義，常叩茅茨居。',48,'全唐诗/poet.song.37000.json','["葉公有高義，常叩茅茨居。", "不嫌杜微病，更附荆州書。", "龔遂合馳傳，郭伋方駐車。", "海人受公賜，約在秋風初。"]'),
('0aebca19-3553-4d0e-befe-004d9c1d72f5','送沈判官','徐積','宋','宋诗','song-poetry','','[]','四月芙蓉花未開，王家客去登瑶臺。',64,'全唐诗/poet.song.37000.json','["四月芙蓉花未開，王家客去登瑶臺。", "瑶臺高在白玉京，麟毫玉譜書姓名。", "名儒庾子能清悟，肯學買臣與嚴助。", "受福王明不爲身，澤遍生民便歸去。"]'),
('cb85e79d-0747-43dc-9c58-a4ba23c8b6aa','酬傳道','徐積','宋','宋诗','song-poetry','','[]','有客從東來，迺是徐方秀。',48,'全唐诗/poet.song.37000.json','["有客從東來，迺是徐方秀。", "言行過乎恭，篇章一何富。", "顧我白髪叟，贈以青瑶枝。", "我將投木桃，桃始開花時。"]'),
('d582fcea-b854-463d-84f9-460712e7d010','寄龔豫之','徐積','宋','宋诗','song-poetry','','[]','海角龔支使，平生無所苟。',48,'全唐诗/poet.song.37000.json','["海角龔支使，平生無所苟。", "而今五十六，豈肯變所守。", "豈獨龔支使，古來無奈何。", "達人自知命，世俗徒悲歌。"]'),
('3e0748b3-8e27-4fa3-8177-4c7ef1656c7c','謝永城令陳德任舉','徐積','宋','宋诗','song-poetry','','[]','縣令有餘義，以碣表孤墳。',48,'全唐诗/poet.song.37000.json','["縣令有餘義，以碣表孤墳。", "昔嘗致酒脯，兩手披荆榛。", "今乃重加惠，使與羣塚辨。", "數十百年後，名亦附公傳。"]'),
('4254f6cb-7e6b-4882-a426-f5bb36d9e096','寄豫之','徐積','宋','宋诗','song-poetry','','[]','掘地須臾便得泉，主人勁直使之然。',64,'全唐诗/poet.song.37000.json','["掘地須臾便得泉，主人勁直使之然。", "此水埋藏千萬年，豈無勃勃氣衝天。", "主人意氣蟄亦久，不知誰是掘泉手。", "最好鹽場作選人，面目心腸無所苟。"]'),
('422ff797-fbd2-4ac3-b3b5-aa1af5fe212d','贈郎朝散','徐積','宋','宋诗','song-poetry','','[]','仕宦何須論權貴，司賓且喜屬郎倅。',64,'全唐诗/poet.song.37000.json','["仕宦何須論權貴，司賓且喜屬郎倅。", "篇章淮上至今傳，德性清溫善酬對。", "神仙船過北神來，應思詩老任員外。", "沙河路上且吟詩，猶有黄花伴吟醉。"]'),
('c5356e36-9e51-4b69-b14a-2e3074afffc2','乞留草贈路倅  其一','徐積','宋','宋诗','song-poetry','','[]','膝上已無三尺桐，門前更少兩株柳。',32,'全唐诗/poet.song.37000.json','["膝上已無三尺桐，門前更少兩株柳。", "唯有庭蕪似野風，告留且伴東臯叟。"]'),
('d0e8307c-f70d-4fe6-aa05-71984f7a6889','乞留草贈路倅  其二','徐積','宋','宋诗','song-poetry','','[]','君看我家門外草，欲把烟姿慰吟老。',32,'全唐诗/poet.song.37000.json','["君看我家門外草，欲把烟姿慰吟老。", "誰知人靜雨餘時，還似村深日斜好。"]'),
('73278a06-d25a-4a8b-a2ca-a912284f9c2d','答倪令挑戰之句','徐積','宋','宋诗','song-poetry','','[]','南城病客方閉門，西郭檄書俄入手。',64,'全唐诗/poet.song.37000.json','["南城病客方閉門，西郭檄書俄入手。", "霜濤洗開醉合眼，清風吹起困低首。", "詩陣須知少敢當，吟魔已遁無何有。", "可笑將軍不用機，示以强兵殆非誘。"]'),
('1292d806-2ea6-4961-8b24-7915787ec5bb','答俞簿','徐積','宋','宋诗','song-poetry','','[]','詩者爲樂章，所以貴聲調。',48,'全唐诗/poet.song.37000.json','["詩者爲樂章，所以貴聲調。", "我雖好之篤，子乃得之妙。", "子妙既相逢，如何慰病翁。", "有時聞數闋，盡日想清風。"]'),
('d2757638-f501-489d-83ff-47088652806c','送思權隨趙守往揚州','徐積','宋','宋诗','song-poetry','','[]','一自移船便恐行，城中兩夜夢河汀。',64,'全唐诗/poet.song.37000.json','["一自移船便恐行，城中兩夜夢河汀。", "武林夫子在船宿，往往將身夢入城。", "夫子戀德雖未休，不過送公到揚州。", "我遣吟魂無遠近，直過瀟湘江渡頭。"]'),
('26ad2dc3-95da-4d78-8482-81908bf02abd','謝存中送四花并酒','徐積','宋','宋诗','song-poetry','','[]','有人自折四般花，手中四色成雲霞。',224,'全唐诗/poet.song.37000.json','["有人自折四般花，手中四色成雲霞。", "瑶瓶貯酒白如沙，呼童急送野人家。", "一般花是水林檎，白處偷紅紅不勻。", "笑臉易殘留恨色，淺粧難就带啼痕。", "無夫少婦善居寡，以禮自防容不冶。", "君看盈盈閃色桃，酒紅睡起未全消。", "意待傾城又傾國，花中偷得兩般色。", "深色桃花將奈何，猩猩血染春衫羅。", "欲成鸞鳳吹簫急，借塗鉛粉施朱多。", "却是梨花白爲勝，四色花中容最正。", "若與梅花相並時，花葉花柯較麤硬。", "爲花傾出瑶瓶酒，香泉急溜蚍蜉走。", "兩手各擎花一枝，深閃桃花將與誰。", "主人醉起欲騎馬，自插烏紗带取歸。"]'),
('6cb92ad1-571c-4c79-97d1-76db83055609','寄蔣大漕','徐積','宋','宋诗','song-poetry','','[]','大使莫憂淮上老，無山可望梅花少。',96,'全唐诗/poet.song.37000.json','["大使莫憂淮上老，無山可望梅花少。", "梅花可種山奈何，日中枕上山更多。", "不開兩眼行一步，懸崖絕磴青嵯峨。", "豈無閒僧坐林下，亦有樵子持斧柯。", "起來恍惚從萬里，便買玄猿栽薜蘿。", "人閒流水寓之意，天外白雲來者歌。"]'),
('a0ccb002-6ec1-4e9b-9521-7aaef96cb863','寄汝弼','徐積','宋','宋诗','song-poetry','','[]','行人過江來，遺我數紙書。',48,'全唐诗/poet.song.37000.json','["行人過江來，遺我數紙書。", "書云困行役，家事仍紛如。", "真州嫁孤妹，蘇州取病弟。", "方且謀醫藥，相期未可冀。"]'),
('8c5f5016-0226-4ed3-b7d0-9a29baa739d4','古風一篇贈梅使君','徐積','宋','宋诗','song-poetry','','[]','古有賢令尹，爲貧民出租。',72,'全唐诗/poet.song.37000.json','["古有賢令尹，爲貧民出租。", "今亦有賢令，代民償所逋。", "何必償所逋，不忍傷肌膚。", "君以古人心，能爲古人義。", "我是吟哦翁，亦有古人意。", "幾夜月明中，爲君吟古風。"]'),
('e84fb142-dc92-4f2e-8ff4-df072410b6a0','寄江子和','徐積','宋','宋诗','song-poetry','','[]','客有江子和，時時慰衰老。',48,'全唐诗/poet.song.37000.json','["客有江子和，時時慰衰老。", "寄我江黄書，其意不草草。", "恐我有疾病，欲我得壽考。", "古人正如是，但恐今人少。"]'),
('36bf4386-e6e3-4b8f-b39e-abf1120a5bae','送呂明府','徐積','宋','宋诗','song-poetry','','[]','古人呂明府，而愛南郭吟。',56,'全唐诗/poet.song.37000.json','["古人呂明府，而愛南郭吟。", "不嫌我衰朽，知子有良心。", "良心何愛吟笑翁，爲我平生懷抱空。", "一心常在浮雲外，萬事付之流水中。"]'),
('5e268f4c-2bb5-4556-bee8-dce49d30c876','送陳明府','徐積','宋','宋诗','song-poetry','','[]','人而有常德，古人良所貴。',48,'全唐诗/poet.song.37000.json','["人而有常德，古人良所貴。", "乃有陳明府，其如斯所謂。", "予常察之久，得之辭與氣。", "何以爲不忘，比諸大羹味。"]'),
('6c01e3e8-589c-4012-9b6a-4362b68dee21','再送呂明府','徐積','宋','宋诗','song-poetry','','[]','昨泛江都船，曾作寒冷篇。',80,'全唐诗/poet.song.37000.json','["昨泛江都船，曾作寒冷篇。", "今浮清洛水，仍是清風裏。", "野岸有幽花，孤村有酒家。", "此酒與此花，尤宜日西斜。", "大抵人生要自樂，保必持花與杯酌。", "有無酒花俱笑吟，爲我回頭望南郭。"]'),
('f95b0703-288b-4dfc-b382-e28231da32b8','有客所養厚一首贈送吳安中歸省其兄','徐積','宋','宋诗','song-poetry','','["\u897f\u6e56"]','有客所養厚，氣貌已可知。',72,'全唐诗/poet.song.37000.json','["有客所養厚，氣貌已可知。", "而况五日閒，議論未停時。", "亹亹來逼人，我覺老且疲。", "何人慰衰朽，須臾合復離。", "所爲安中喜，鴻鵠翩翩飛。", "最好西湖上，一牀同寢衣。"]'),
('eeafca81-8179-4ebe-ba5c-5694a174c94c','和吳奉議','徐積','宋','宋诗','song-poetry','','[]','一物勿令侵吾神，一事勿使摇吾真。',64,'全唐诗/poet.song.37000.json','["一物勿令侵吾神，一事勿使摇吾真。", "養諸內者氣欲息，散所滯者體欲伸。", "爲報平居既安叟，幸爲平世難老臣。", "亦有閒僧晤言否，呼來伴子逍遥身。"]'),
('8fef9f98-d2cf-4925-8705-96952cf10bcc','贈程秀才','徐積','宋','宋诗','song-poetry','','[]','我是南郭翁，門前兩株柳。',56,'全唐诗/poet.song.37000.json','["我是南郭翁，門前兩株柳。", "君是誰家雋，肯來顧衰朽。", "兄弟六人應姓荀，一人錯認李膺門。", "不談俗物唯談文，更說長淮謠主人。"]'),
('8d38a3ad-e06c-4906-9818-31b6905d4bbd','所祝送寧秀才','徐積','宋','宋诗','song-poetry','','[]','所祝君者，豈敢如息。',85,'全唐诗/poet.song.37000.json','["所祝君者，豈敢如息。", "在養在正，在進在德。", "在好聞過，在親亮直。", "精講明辨，所以臧也。", "早夜思索，不可忘也。", "以正而通，以正而窮。", "以義而始，以義而終。", "勉之戒之，其所養者，勿使害之。"]'),
('1c612b00-13d8-4b07-9f72-6c93feec5430','送張子厚滕縣行','徐積','宋','宋诗','song-poetry','','[]','戰國甚於狼虎鬬，孟子力將仁義興。',32,'全唐诗/poet.song.37000.json','["戰國甚於狼虎鬬，孟子力將仁義興。", "豈無父老傳聞事，爲我訪之鄒薛滕。"]'),
('cad9915b-69f6-418e-8755-6860f4f7e716','送錢思權','徐積','宋','宋诗','song-poetry','','[]','子處我爲兄，我以子如弟。',60,'全唐诗/poet.song.37000.json','["子處我爲兄，我以子如弟。", "何待去呼喚，自可來相視。", "不敢苦留君，留君住數日。", "待問六年事，但恐煩紙筆。", "昨日從早起，等君到昏黑。"]'),
('bfe3a9f9-b598-4f31-8060-9fc65b6453f8','贈張教授','徐積','宋','宋诗','song-poetry','','[]','君看兩鴻亡所依，江南塞北何所歸。',64,'全唐诗/poet.song.37000.json','["君看兩鴻亡所依，江南塞北何所歸。", "一鴻留在淮之湄，一鴻獨犯霜露飛。", "哀復哀兮將奈何，願期弟子廢蓼莪。", "先翁經却憂患多，爲君半夜成悲歌。"]'),
('66021d04-2159-42b1-bb62-b66399c72004','戲答  其一','徐積','宋','宋诗','song-poetry','','[]','我喉已吞霜，我口復吞月。',140,'全唐诗/poet.song.37000.json','["我喉已吞霜，我口復吞月。", "吞霜吞月太麤豪，五臟心胸總清徹。", "東家亦有人中清，一從年少名豪英。", "文章餘事能用兵，蛇矛丈八折羽旌。", "排成大陣將橫行，太華屹立洪河傾。", "螭騰豹躣哮虎鳴，斗膽可落突眼睛。", "衝車突騎出不意，鋒不可當聲動地。", "前軍已勝後兵繼，唱罷凱歌氈帳睡。", "將軍但築受降城，老大不煩修武備。"]'),
('5f22df3e-209e-49bd-b14a-680f802a89d9','戲答  其二','徐積','宋','宋诗','song-poetry','','[]','君看月上霜，君看霜下月。',168,'全唐诗/poet.song.37000.json','["君看月上霜，君看霜下月。", "不知月蓋霜，不知霜蓋月。", "但覺我一身，上下中央四旁總澄徹。", "霜是何物如此清，月是何物如此明。", "白頭老翁坐中庭，半夜可數毛髪莖。", "羣陰積聚純粹精，蝦蟆吸盡瑶池津。", "銀河兩道來藏冰，玉龍走入蟠千尋。", "倩君兩耳爲我聽，其閒恐有波浪聲。", "初出海時蛟螭鳴，却入海時潮頭生。", "小鯨走入尾閭內，大鯨大鰍寒不睡。", "莫教射倒金銀宮，鰲背神人難設備。"]'),
('927fc3e3-bf4e-474e-917d-277058ce3def','贈徐彥','徐積','宋','宋诗','song-poetry','','[]','昔者見君面，記得秋風時。',48,'全唐诗/poet.song.37000.json','["昔者見君面，記得秋風時。", "遺我壽陽書，故人情可知。", "一從西城居，復來南郭住。", "時時還憶君，不知在何處。"]'),
('bca18b1a-efd0-4ae3-840a-c4c9136bf858','寄朱少府','徐積','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','過巴陵後北風猛，洞庭水白湘波冷。',64,'全唐诗/poet.song.37000.json','["過巴陵後北風猛，洞庭水白湘波冷。", "江頭風猛霜霰多，竹節老硬竹梢緊。", "此時誰爲湘江行，其人有道直而清。", "宜其所至無冤情，蛟龍不復侵屈平。"]'),
('5037eff4-46dc-4e95-9014-f3795e63d914','代人上陝西漕生辰','徐積','宋','宋诗','song-poetry','','[]','嘗聞五百歲，一有賢人生。',180,'全唐诗/poet.song.37000.json','["嘗聞五百歲，一有賢人生。", "議者實在公，仍與聖運并。", "全資五嶽粹，高挹太元清。", "與帝爲元老，與國爲名卿。", "中外試已煩，玉振而金聲。", "漕柄雖云劇，其道安足行。", "宜哉廊廟器，蹇蹇王之庭。", "春色滿長安，春山圍長坰。", "春芳森綺繡，春風鏘瑶瓊。", "秦封幾千里，富庶而安榮。", "人與春意和，淨竦長安城。", "何以獻公壽，莊氏之椿齡。", "何以獻公福，洪範之康寧。", "黄河爲富貴，太華爲功名。", "此詩何爲者，聊用歌羣情。"]'),
('cd7b96b5-d8cd-4bef-8895-96e5b6945ca9','贈慎伯筠','徐積','宋','宋诗','song-poetry','','[]','掘盡崑崙山，美璞纔一雙。',48,'全唐诗/poet.song.37000.json','["掘盡崑崙山，美璞纔一雙。", "何人橫大陣，未戰敵已降。", "秋風吹老檜，明月沈空江。", "禮天者大事，其器不可尨。"]'),
('977d3db3-36de-49c9-8899-88f760a71837','送秦漕','徐積','宋','宋诗','song-poetry','','[]','維古之人，厥修有道。',246,'全唐诗/poet.song.37000.json','["維古之人，厥修有道。", "使臣之美，於詩可考。", "其馬維良，曰騏曰駒。", "六轡賁如，如沃如濡。", "而况其身，潔不可汙。", "身不可汙，其可辱乎。", "載驅載馳，載馳載驅。", "雖則馳驅，咨詢咨諏。", "以來厥修，聚其所聞。", "使于四方，如圭如璋。", "燁燁煌煌，爲國之光。", "其美無疆，後人不忘。", "維時不忘，而有斯人。", "斯人維何，維古人是思。", "古人是思，是思是爲，如璋如圭。", "如圭如璋，維德之輝。", "如醖如藉，維德之儀。", "維德在躬，維日不足。", "是問是辯，善也彌篤。", "美哉是乎，誠自中出。", "誠隠而顯，成己成物。", "維誠則然，亦在所勉。", "勉而弗已，終之不倦。", "所往所居，老生腐儒。"]'),
('bda8a674-32cd-4f13-a810-82d664ea0311','寄太康知縣周宣德','徐積','宋','宋诗','song-poetry','','[]','冬之季月，月及上弦。',240,'全唐诗/poet.song.37000.json','["冬之季月，月及上弦。", "太康書來，慰此皤然。", "并其成法，別爲一書。", "敏而有術，使我嗟吁。", "考其大指，官之楷模。", "官守其約，事總其要。", "何弊不除，何隠弗照。", "如陛高臺，俯視四旁。", "不持度量，是物可量。", "挈裘之領，提綱之綱。", "維簡維能，維能維精。", "維精維思，維思維誠。", "既誠既明，既信既行。", "日有餘力，民亦閒暇。", "不肯頑惡，孰爲欺詐。", "不出一符，不遺一力。", "或將爾車，或負爾穡。", "四境之內，如雲坌集。", "一歲之事，先期以辦。", "私無所擾，公無所患。", "至於盜賊，無處伏藏。", "情既暴露，脫身奔亡。", "吏案可空，刑書可閣。", "俾爾室家，既安且樂。"]'),
('ac348cbf-6ce7-48b5-af5a-9288a7d82094','送張漕正','徐積','宋','宋诗','song-poetry','','[]','以正名官，居官以正。',230,'全唐诗/poet.song.37000.json','["以正名官，居官以正。", "豈惟朝廷，生民之幸。", "名官以正，居官以直。", "豈惟生民，宗廟社稷。", "積者爲慶，流者爲澤。", "遠者無疆，久者無極。", "此奚有他，一言之力。", "維時我后，智勇兼有。", "揭日當天，操杓運斗。", "隨手如意，不勞而治。", "明明赫赫，有因有革。", "所因者宜，所革者當。", "維當維宜，生民之望。", "維正維言，民之望之。", "維言維正，何以尚之。", "越有諍臣，義不顧身。", "白刃可蹈，赤心可傾。", "既曰真矣，弗變弗移。", "既曰直矣，弗阿弗隨。", "何事可沮，何利可回。", "不可則止，其可則爲。", "往司厥官，往成厥功。", "回天論事，有祖之風。"]'),
('a37694a4-bf39-4586-8769-fd413890d2a2','送趙漕偁','徐積','宋','宋诗','song-poetry','','[]','人之古貌，心未必醇。',240,'全唐诗/poet.song.37000.json','["人之古貌，心未必醇。", "心醇貌古，或非通人。", "我視趙公，其貌甚古。", "心德俱醇，通達明悟。", "我曹山野，豈足盡知。", "但據所見，以類可推。", "大河之說，何其通達。", "精簡平允，明辨昭皙。", "蓋其心得，身至自閱。", "坐而可言，起而可設。", "又云九河，勿守故迹。", "但求禹意，然後爲得。", "此說尤奇，漢儒不及。", "我自黑頭，盡心河渠。", "逢人輒問，三十年餘。", "得公此說，庶幾成書。", "既講大河，遂及賑饑。", "如此方略，所繫甚大。", "鄉官胥徒，實爲巨害。", "使領雖賢，吏不可乏。", "必得官吏，斯爲善法。", "可爲利澤，可制奸猾。", "如其備預，莫若義倉。", "勿取軍民，勿法隋唐。"]'),
('441d8d2b-8be6-46b3-88bd-1cf4c24781ab','送趙守','徐積','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','齊有高密，有沂有沐。',240,'全唐诗/poet.song.37000.json','["齊有高密，有沂有沐。", "旁有泰山，莒魯郊關。", "粵有人焉，氣清神聳。", "立節以高，處義而重。", "維節維義，肇自布衣。", "根本淵源，所養可知。", "以義爲文，洪暢精微。", "以義持守，隠如堅城。", "以義作爲，動如精兵。", "面有正色，口無諛聲。", "赤心可割，肝膽可傾。", "以義接物，不矜不驕。", "以義臨民，實庇汝曹。", "實康實濟，實愷實悌。", "民實宜之，實受其惠。", "方今天下，雖曰治安。", "正在所恤，民有饑寒。", "公所往居，豈肯草草。", "戒吏侵漁，欲民溫飽。", "言者爲準，行者爲表。", "維恕維平，除煩去擾。", "狼摧其牙，虎縮其爪。", "父子室家，足以相保。", "作此詩者，豈徒然乎。"]'),
('c0d43c21-6dd6-40d8-89b0-eb9f9a409352','謝玉師','徐積','宋','宋诗','song-poetry','','[]','河沙亦可數，海水亦有畔。',132,'全唐诗/poet.song.37000.json','["河沙亦可數，海水亦有畔。", "師恩及吾母，其多卒無算。", "遠者窮無邊，深者入黄泉。", "黄泉兒莫到，慈母忽有告。", "冥冥長夜中，如行白日道。", "兒一別母容，可想不可逢。", "憑師無量恩，恍惚如相通。", "師恩若何爲，真誠與高義。", "幽明雖有殊，母子各有慰。", "欲報將奈何，肉鎸骨可磨。", "泣盡感恩淚，慷慨成悲歌。"]'),
('f4d178f2-a38f-45b0-bdce-b0bd7a2c6da0','送雲鶴山人','徐積','宋','宋诗','song-poetry','','[]','星非甘公，卦非焦贛。',100,'全唐诗/poet.song.37000.json','["星非甘公，卦非焦贛。", "善言五部，枝幹迭用。", "所據甚精，所發必中。", "輔之以教，其益彌衆。", "以剛止邪，以柔止訟。", "躁者使靜，義者使動。", "仁使之修，虐戒之縱。", "險者使平，浮者使重。", "如此庶乎，殆可折衷。", "行矣勉之，斯言可誦。"]'),
('f0a39911-f173-40ae-b7fc-e7289e25cd8c','送李守孝博','徐積','宋','宋诗','song-poetry','','[]','外官之重，其惟使乎。',240,'全唐诗/poet.song.37000.json','["外官之重，其惟使乎。", "使者之重，兵政刑誅。", "持挈綱領，設施楷模。", "以實去僞，以清革汙。", "善本須養，惡根必鉏。", "非嚴不肅，非寬不舒。", "非威不行，非信不孚。", "諸如此類，一不可無。", "而况百粵，嶺陽海隅。", "其俗彍悍，戒吏侵漁。", "緩之則懷，擾之則吁。", "又况其徼，谿洞蠻居。", "慮要先定，戒須早圖。", "使臣之重，不其然歟。", "命使維何，曰山陽守。", "維山陽守，其質忠厚。", "既明而恕，惟所自有。", "以嚴以威，以左以右。", "維恕維平，維詳維精。", "所濟維敏，所孚維誠。", "刑無必用，事皆原情。", "或虛其獄，或空其庭。", "稱者盈巷，傳者盈城。", "四境之內，盡爲歡聲。"]'),
('0aec55b9-e1e6-40aa-aa7c-4b7a690fa680','贈武夷旅人','徐積','宋','宋诗','song-poetry','','[]','武夷旅人，而有氣節。',40,'全唐诗/poet.song.37000.json','["武夷旅人，而有氣節。", "不肯瑣瑣，亦不屑屑。", "持此守身，歸慰其親。", "既慰其親，亦告鄉人。"]'),
('3177d06c-1fe3-4f49-b397-ff9a4386fa03','贈龐公','徐積','宋','宋诗','song-poetry','','[]','司馬德操，來就龐公。',180,'全唐诗/poet.song.37000.json','["司馬德操，來就龐公。", "杖履直入，名姓不通。", "坐其堂上，指揮呼索。", "催令作黍，云我有客。", "龐公妻子，堂下羅列。", "拜且聽命，奔走陳設。", "此時龐公，適自外歸。", "忽見司馬，其喜可知。", "一堂之上，相從笑語。", "其旁觀者，莫分客主。", "我讀其書，愛其古風。", "真厚如此，精誠交通。", "量如溟海，義薄雲空。", "至於妻子，亦爲歎者。", "苟非其人，往往見駡。", "蓋有是夫，而有是婦。", "能佐夫義，善敬夫友。", "可警薄俗，可示厥後。"]'),
('f96b5671-e8ff-43d8-9b69-688110546f4f','送裴守','徐積','宋','宋诗','song-poetry','','[]','維時西南，巴蜀一道。',240,'全唐诗/poet.song.37000.json','["維時西南，巴蜀一道。", "强楚侵疆，故蜀東徼。", "水激以猛，山迫而峭。", "人性堅悍，地形險要。", "孰往而使，孰撫而教。", "惟帝難之，乃眷東顧。", "曰山陽守，智足知務。", "能正而和，能察而恕。", "嚴所以立，寬所以輔。", "性不狎侮，躬有法度。", "是表是儀，可俾可付。", "其往欽哉，所居必裕。", "公拜稽首，馳傳以起。", "入境褰帷，登山叱馭。", "設施有本，先後有序。", "可者立行，不可立去。", "公曰來汝，吏受約束。", "天子聖人，汝勿苛酷。", "民心無他，罪生不足。", "窮閻荒村，頹垣破屋。", "豈可羅網，更入牢獄。", "公曰兵官，當去其懦。", "賊侮則犯，賊畏則挫。", "勉之在勤，戒之在惰。"]'),
('a0a05855-9719-46ac-902f-6481e077fb79','送范宣德','徐積','宋','宋诗','song-poetry','','[]','客有斯人，而有美質。',40,'全唐诗/poet.song.37000.json','["客有斯人，而有美質。", "可養而充，其在不息。", "養之以正，充之以義。", "何適不可，何爲弗至。"]'),
('ae2b8555-c8d4-415d-8519-3241a62fa8d1','送李推官','徐積','宋','宋诗','song-poetry','','[]','物有所興，因人而就。',240,'全唐诗/poet.song.37000.json','["物有所興，因人而就。", "其人維何，所性忠厚。", "能謀而果，能明而究。", "身任其責，力成厥構。", "既成之法，可繼於後。", "入門而東，自南而北。", "如汙斯隆，如枉斯直。", "如塞斯通，如隘斯闢。", "如翼斯張，如衡斯舉。", "如蔀斯赫，如閴斯睹。", "室有明窗，牆有堅堵。", "地無游蟻，穴無伏鼠。", "既完既成，既安既處。", "師乎師乎，豈可苟然。", "心爲道本，身爲義先。", "心之所無，道不可傳。", "身之所無，口不可宣。", "唯正唯直，求己以全。", "以義以命，如耕平田。", "處心積慮，貫通神明。", "無忝鄉校，勿負朝廷。", "成人子弟，慰人父兄。", "二三職事，其亦警戒。", "欲善諸外，先治諸內。"]'),
('1b69fbe5-67df-4797-a5fd-89e72dc21556','送喬司法','徐積','宋','宋诗','song-poetry','','[]','喬掾循循，有如寒士。',40,'全唐诗/poet.song.37000.json','["喬掾循循，有如寒士。", "面無浮氣，能訓諸理。", "可養可充，曰正曰直。", "其維思誠，其在不息。"]'),
('0641699f-605c-498b-873b-a9a7c9354065','送賈鎮卿','徐積','宋','宋诗','song-poetry','','[]','蕭縣大夫，氣質端勁。',130,'全唐诗/poet.song.37000.json','["蕭縣大夫，氣質端勁。", "其中所養，不邪而正。", "正以輔才，恕以輔明。", "面無諛色，口無諛聲。", "若斯人者，宜於王庭。", "而况一縣，爲惠爲澤。", "恕所以惠，威所以立。", "猛寬得中，韋抗是也。", "誅姦殄寇，有賀齊者。", "東漢龐參，作守漢陽。", "政所以茂，實繄任棠。", "以君之正，以君常德。", "力追古人，是宜是適。"]'),
('aa79c92f-4f6f-4d1e-8847-c30333db38d8','可養一章贈別范子舟','徐積','宋','宋诗','song-poetry','','[]','可養可充，曰性曰氣。',30,'全唐诗/poet.song.37000.json','["可養可充，曰性曰氣。", "以君美質，斯已可貴。", "養而充之，何所弗至。"]'),
('36fb2b00-6e3e-4d28-bb58-0f3e4e3b9daf','送山陽宰','徐積','宋','宋诗','song-poetry','','[]','大夫三年，平恕如一。',40,'全唐诗/poet.song.37000.json','["大夫三年，平恕如一。", "靜而不煩，民安厥室。", "大夫去矣，何以述之。", "我述民言，民實德之。"]'),
('8c92eddc-7b29-4e31-a665-caec2c9bc8bb','贈呂公侍講','徐積','宋','宋诗','song-poetry','','[]','我敬呂公，以其德齒。',60,'全唐诗/poet.song.37000.json','["我敬呂公，以其德齒。", "敬之愛之，何時已已。", "美哉呂公，文在其中。", "見乎外者，古人之風。", "維賢有德，神相其祉。", "何以祝公，勿藥有喜。"]'),
('44f61253-be7e-4683-8fe7-197f94123509','送汪宮教','徐積','宋','宋诗','song-poetry','','[]','堯親其親，教官得人。',140,'全唐诗/poet.song.37000.json','["堯親其親，教官得人。", "所性忠厚，貌純氣真。", "學爲耕稼，經爲本根。", "實之爲行，賁之爲文。", "辭令出口，法度在身。", "大學小學，其誰弗循。", "循之維何，維義是適。", "不驕不肆，無邪無僻。", "大者敬義，如漢元王。", "小者樂善，如漢王蒼。", "樂善敬義，何有不臧。", "保躬無悔，受福無疆。", "無疆之福，維順維忠。", "維忠維順，維師之功。"]'),
('41a7fb79-f73f-4c2d-98c9-ac7e3b48d8a0','代諸生送蔣守  其一','徐積','宋','宋诗','song-poetry','','[]','明明楚侯，爲國之光。',115,'全唐诗/poet.song.37000.json','["明明楚侯，爲國之光。", "王明是選，王命是將。", "皇皇者華，六轡如濡。", "轡且如濡，其德可孚。", "其孚維何，潔不可汙。", "皇皇者華，六轡沃若。", "轡且沃若，其德可度。", "其度維何，清不可濁。", "潔也不汙，清也不濁。", "德則不渝，澤則不涸。", "民則宜之，民則樂之，神亦作之。"]'),
('d7bea4b2-6cbb-458f-a074-b38afa9a5182','代諸生送蔣守  其二','徐積','宋','宋诗','song-poetry','','[]','長淮之南，楚爲最劇。',170,'全唐诗/poet.song.37000.json','["長淮之南，楚爲最劇。", "守者爲誰，以才以德。", "守既視事，未逾厥月。", "吏則胥畏，民則胥悅。", "物來必應，事至立决。", "守之動靜，皆有法度。", "不苟不簡，不暴不怒。", "處煩以敏，輔嚴以恕。", "庭無滯訟，獄無冤囚。", "民無愁歎，俗有歌謳。", "古之三府，謠言奏事。", "今豈不然，兼採公議。", "付之使節，是以用之。", "付之遠俗，是以重之。", "其俗既平，其刑既清。", "章德表功，來朝兩宮。", "兩宮聖明，柱上記名。"]'),
('5bb6c57b-3345-45c0-992f-3d3189412bef','送山陽太守李公','徐積','宋','宋诗','song-poetry','','[]','維淮東南，孰爲州最。',240,'全唐诗/poet.song.37000.json','["維淮東南，孰爲州最。", "曰李大夫，實勞於外。", "公雖老矣，方壯方剛。", "處劇而靜，不煩以詳。", "大率郡縣，事如草芒。", "而况楚州，車輪中央。", "侯繇其衝，客出四旁。", "北迎大車，南亂巨航。", "公移私訊，駢檄交章。", "大夫酬應，談笑以將。", "大夫甚健，日力有餘。", "事至立决，罪無囚拘。", "教以好語，完其體膚。", "據案而坐，處之須臾。", "吏休兩廊，庭中空虛。", "所以楚人，愛公之敏。", "揮刀截繩，彎弓射隼。", "敏所以輔，其本則明。", "窮姦破僞，窺心見情。", "譬如工師，譬如良匠。", "手無所設，目無所妄。", "物隨以就，法隨以施。", "大尋小尺，方矩圓規。", "嗟民雖愚，所以有幾。"]'),
('1c42c658-e43e-4660-841e-68bde55a291a','送江倅','徐積','宋','宋诗','song-poetry','','[]','昔之別駕，則有王祥。',240,'全唐诗/poet.song.37000.json','["昔之別駕，則有王祥。", "其民歌之，海隅稱焉。", "今亦有人，能紹厥後。", "民之悅之，稱不容口。", "庶民所見，乃其皮膚。", "見察情僞，見敏簿書。", "見法平恕，見獄空虛。", "事見無留，才見有餘。", "己不敢肆，人安厥居。", "其所見者，止於君子。", "良士大夫，謂其所性。", "得之剛毅，所以能斷。", "所以無蔽，所以敢爲，所以勇義。", "决遣簿書，是其餘事。", "漢之朱博，趙張龔尹。", "撫恤大衆，何獨古人。", "王祥雖賢，失在寶刀。", "正而平者，心則不摇。", "人或贈之，則弗受之。", "借曰受之，何佩有之。", "弗佩曰正，曰平維平，宜於朝廷。", "用之一方，一方之綱。", "在我者正，是謂爲政。"]'),
('cfca8ed1-6594-4e89-a9ca-36b488961fda','送蔡守','徐積','宋','宋诗','song-poetry','','[]','維淮之南，楚爲劇州。',240,'全唐诗/poet.song.37000.json','["維淮之南，楚爲劇州。", "守土之吏，孰明以周。", "蔡公既來，爰究爰乂。", "明維照姦，威維沮僞。", "維明維威，無敢恣睢。", "侯曰可矣，其治孔易。", "迺興學校，示之本原。", "儒居儒處，禮容義言。", "迺修釋奠，教民之恭。", "有嚴其色，有孚其顒。", "迺行鄉飲，躬爲主人。", "拜辱拜豆，盥洗獻賓。", "其儀孔肅，其禮孔均。", "迺召父老，父老俱來。", "幅巾短褐，浩其盛哉。", "父老升矣，侯則興矣。", "父老坐矣，侯則妥矣。", "父老未醉，笑歌其聲。", "父老既醉，髪白顔頳。", "父老去矣，侯則舉矣。", "餽之物矣，告之語矣。", "其語維何，維善是示。", "善者使修，惡者使止。", "告爾宗族，告爾鄰里。"]'),
('30c2db51-56a1-477a-a750-5242a2a8e23f','謝李自明','徐積','宋','宋诗','song-poetry','','[]','養以其久，真以其積。',80,'全唐诗/poet.song.37000.json','["養以其久，真以其積。", "維積維久，是以爲德。", "德而德之，或表而失。", "德而弗德，然後能造。", "孰爲斯施，孰爲斯報。", "德其德者，伐幹以斧。", "弗德其德，培以根土。", "德乎斯乎，其孰禦乎。"]'),
('1a25e301-cde8-419e-b25c-2763651b6ffd','贈胡大夫','徐積','宋','宋诗','song-poetry','','[]','兵有三難，一曰難知。',95,'全唐诗/poet.song.37000.json','["兵有三難，一曰難知。", "二曰難處，三曰難言。", "眇忽精微。", "偉哉胡公，講辨必精。", "以兵爲難，是爲知兵。", "是爲力學，是爲老成。", "惜乎老矣，未見設施。", "其誰知公，胸中之奇。", "弗施於兵，施於有政。", "所在所居，斯民之幸。"]'),
('4db36e55-6073-4daa-aca5-f8f37df690ad','送呂清叔  其一','徐積','宋','宋诗','song-poetry','','[]','寒水如烟霜似雪，半夜疏窗透明月。',32,'全唐诗/poet.song.37000.json','["寒水如烟霜似雪，半夜疏窗透明月。", "此時有客正不眠，淮上吟聲無斷絕。"]'),
('38896731-b91c-490e-add8-5e65198d28da','送呂清叔  其二','徐積','宋','宋诗','song-poetry','','[]','昨夜月初圓，今宵月初缺。',28,'全唐诗/poet.song.37000.json','["昨夜月初圓，今宵月初缺。", "月圓月缺本無情，惟有文通恨難說。"]'),
('9585fa10-faed-4815-9d84-3037a6012c14','送呂清叔  其三','徐積','宋','宋诗','song-poetry','','[]','慘慘黄昏天欲雪，蕭蕭淮浦人聲絕。',32,'全唐诗/poet.song.37000.json','["慘慘黄昏天欲雪，蕭蕭淮浦人聲絕。", "風擊寒雲雁正鳴，客眠孤棹燈方滅。"]'),
('dfd3ad30-9c6c-4000-8234-692b9d0af492','贈王觀文','徐積','宋','宋诗','song-poetry','','[]','一自西征登將壇，探其窟穴除其殘。',128,'全唐诗/poet.song.37000.json','["一自西征登將壇，探其窟穴除其殘。", "鄰羌餘喘雖偷安，匈奴右臂殊不完。", "聞公姓字摧膽肝，穹廬部落匿可汗。", "何當飲馬朔海乾，雄文高勒燕然山。", "古來從事多壯夫，凱歌得意更豪麤。", "共公談笑觀投壺，醉筆揮成露布書。", "歸來却佐神聖王，愛賢樂道不敢忘。", "德功甚盛謙尊光，始終一節郭汾陽。"]'),
('905eaed9-f891-4c6a-8a46-850bda6bcb39','答張文剛','徐積','宋','宋诗','song-poetry','','[]','張子問著書，使我長嗟吁。',48,'全唐诗/poet.song.37000.json','["張子問著書，使我長嗟吁。", "有意在黄絹，無能任白駒。", "筋力如老驥，頤頷生霜鬚。", "二子少且壯，努力相雕枯。"]'),
('1fcb633e-08ff-4ab5-959b-54cdfb15a994','答劉子靜','徐積','宋','宋诗','song-poetry','','[]','風蘭不復採，風樹何由靜。',48,'全唐诗/poet.song.37000.json','["風蘭不復採，風樹何由靜。", "一日復一日，大龍自馳騁。", "無限好花開，何異秋風景。", "灑淚報君詩，正是鶴孤警。"]'),
('7eb3e8b5-f8ae-41f8-8f45-717e45f1fd44','答穎叔','徐積','宋','宋诗','song-poetry','','[]','大使莫憂淮上叟，萬事付之詩與酒。',32,'全唐诗/poet.song.37000.json','["大使莫憂淮上叟，萬事付之詩與酒。", "若問我家何所營，爲比陶潜少三柳。"]'),
('217fbd53-a78b-4a12-bf5a-422322ad469b','和張文潜晚春  其一','徐積','宋','宋诗','song-poetry','','[]','春在亦飲酒，春去亦飲酒。',24,'全唐诗/poet.song.37000.json','["春在亦飲酒，春去亦飲酒。", "若問此閒時，便是無何有。"]'),
('1a133a4b-b912-4272-8ca6-9211bf62853f','和張文潜晚春  其二','徐積','宋','宋诗','song-poetry','','[]','昨日枝頭紅，鮮鮮染人指。',24,'全唐诗/poet.song.37000.json','["昨日枝頭紅，鮮鮮染人指。", "今朝尋不見，已在汙泥底。"]'),
('5ec3e180-19ae-4f5b-bc2a-a8f3837e2145','和張文潜晚春  其三','徐積','宋','宋诗','song-poetry','','[]','麥穎未黄乾，桑實半紅濕。',24,'全唐诗/poet.song.37000.json','["麥穎未黄乾，桑實半紅濕。", "恰得一犁雨，田事正火急。"]'),
('2e1c8c87-7653-4149-a8c8-f8f2f06ec8c0','和張文潜晚春  其四','徐積','宋','宋诗','song-poetry','','[]','人事無如何，多於道傍草。',24,'全唐诗/poet.song.37000.json','["人事無如何，多於道傍草。", "但問酒有無，莫管老不老。"]'),
('5735dce4-9163-474d-af1d-5b7a1dba0df9','和張文潜晚春  其五','徐積','宋','宋诗','song-poetry','','[]','人生少娛樂，閒日亦有數。',24,'全唐诗/poet.song.37000.json','["人生少娛樂，閒日亦有數。", "藥草正肥時，好望雲山去。"]'),
('0cc2131e-031f-4283-97cc-78cf238e66da','和張文潜晚春  其六','徐積','宋','宋诗','song-poetry','','[]','風暖燕窠牢，雲晴鳥翅健。',24,'全唐诗/poet.song.37000.json','["風暖燕窠牢，雲晴鳥翅健。", "物生自有樂，亦各適其願。"]'),
('b8f1ff31-7bfc-4550-b545-c45f5ca3e158','示諸生','徐積','宋','宋诗','song-poetry','','[]','子莫爲文學纖麗，須是渾渾有古氣。',32,'全唐诗/poet.song.37000.json','["子莫爲文學纖麗，須是渾渾有古氣。", "本源要在養諸中，不然恐汝爲時輩。"]'),
('f3e198db-df5b-472b-8700-7f0cbdf0eaef','謝張尉','徐積','宋','宋诗','song-poetry','','[]','魚葅乃以玉版名，可將苦酒試光明。',32,'全唐诗/poet.song.37000.json','["魚葅乃以玉版名，可將苦酒試光明。", "張華陸機勿下筯，盤中恐作霹靂聲。"]'),
('afbb89ac-6976-43c4-8e57-354f1d1869b5','送秦漕','徐積','宋','宋诗','song-poetry','','[]','以身送客情幾何，以心送客情最多。',32,'全唐诗/poet.song.37000.json','["以身送客情幾何，以心送客情最多。", "任意所之無遠近，不論山險與風波。"]'),
('42346df7-558e-4f32-a2a7-b66029b24428','贈鄭毅夫','徐積','宋','宋诗','song-poetry','','[]','摩天羽翮森森齊，胸中壯氣蟠虹霓。',32,'全唐诗/poet.song.37000.json','["摩天羽翮森森齊，胸中壯氣蟠虹霓。", "區區世俗誰相知，青雲歧路看如泥。"]'),
('a42adc1c-afb2-4c82-8e52-1403e532f790','送陳長官赴衡陽','徐積','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','楚天摇落霜風早，山色依依江渺渺。',67,'全唐诗/poet.song.37000.json','["楚天摇落霜風早，山色依依江渺渺。", "洞庭水寒帆影孤，雁聲正在衡陽道。", "君不見屈原憔悴賈生夭，遺恨至今猶未了。", "日晚江頭船住時，行人莫望江邊草。"]'),
('367cdc49-b84c-4037-854f-bedf95086bb8','南山有奇木贈慎彥鄰','徐積','宋','宋诗','song-poetry','','[]','人皆患窮餓，子獨無寒饑。',180,'全唐诗/poet.song.37000.json','["人皆患窮餓，子獨無寒饑。", "子乃何爲者，汲汲售於是。", "漢之公孫弘，唐之張柬之。", "子豈不知此，與世相驅馳。", "南山有奇木，犖犖松檜姿。", "此木在深山，年代不可知。", "烟雲終日蔭，雨露早夜滋。", "一幹可爲棟，一枝可爲榱。", "耽耽廊廟中，小大皆可施。", "子豈不知此，汲汲將何爲。", "子其自努力，發憤而忘疲。", "孔孟非異域，行者皆可幾。", "退之雖絕足，大步亦可追。", "嗟子之兄弟，與我如四支。", "余言子其聽，無使我歔欷。"]'),
('76bdb01a-9fe2-4635-bcaf-f9d5956c472e','答何楚才','徐積','宋','宋诗','song-poetry','','[]','有客能操耒，而捨其良田。',120,'全唐诗/poet.song.37000.json','["有客能操耒，而捨其良田。", "有客善攻玉，而探珠於淵。", "二者之是非，子以謂何如。", "子乃捨所急，若是其渠渠。", "然余有二說，可爲不可爲。", "所爲不可者，子家無寒饑。", "所謂可爲者，奉養之所資。", "余此二說者，子當慎擇之。", "余嘗奇子貌，亦嘗憐子文。", "不能爲子謀，嗟哉空云云。"]'),
('33793704-6934-41a0-a71d-07a9a0665d1c','還崔秀才唱和詩','徐積','宋','宋诗','song-poetry','','[]','元白有餘勢，孟韓無困辭。',158,'全唐诗/poet.song.37000.json','["元白有餘勢，孟韓無困辭。", "子美骨格老，太白文采奇。", "當時大道久破碎，人人文字萎薾而支離。", "天生數子將卓卓，鴟鴞正成羣，一鶚摩天飛。", "嗟君不與數子共，使君逸氣填塞無所施。", "我來雖無知，黄金白玉看如泥。", "自從詩卷一入手，掣然直上青雲梯。", "十宵不睡亦不困，厭賓日日關柴扉。", "秋風獵獵吹橫河，蒼天萬里生銀波。", "起來半夜吸一口，睡魂酒病都消磨。"]'),
('c780ab93-937e-4063-ba77-d70d307753dc','贈慎叔良  其一','徐積','宋','宋诗','song-poetry','','[]','昔日黑頭交，今爲白髪叟。',48,'全唐诗/poet.song.37000.json','["昔日黑頭交，今爲白髪叟。", "約是三十年，情好於此久。", "且待花開時，同把一盞酒。", "君看我門前，兼有兩株柳。"]'),
('92d1109c-2e13-4b06-aedd-6c78882c5e37','贈慎叔良  其二','徐積','宋','宋诗','song-poetry','','[]','昨日故人來，慰此白頷叟。',72,'全唐诗/poet.song.37000.json','["昨日故人來，慰此白頷叟。", "兩叟忽相見，面色如飲酒。", "將此酒色面，抵却春風寒。", "飲酒豈易比，歡好良所難。", "我已五十八，君已五十七。", "人生勿草草，兩公須努力。"]'),
('c230f907-09f8-4cac-b0a9-11aa3d586c4a','贈慎叔良  其三','徐積','宋','宋诗','song-poetry','','[]','相逢便吐胸中奇，直道而交與世違。',64,'全唐诗/poet.song.37000.json','["相逢便吐胸中奇，直道而交與世違。", "硯席已逾三載共，鸞凰須約一時飛。", "嗟予從事於今僻，似子知音自古稀。", "好去上書言得失，買臣猶取虎符歸。"]'),
('41d3f80a-12b4-4e31-94b7-cf040154d802','贈盧魯山  其一','徐積','宋','宋诗','song-poetry','','[]','充囊勿用錢，古律長短篇。',24,'全唐诗/poet.song.37000.json','["充囊勿用錢，古律長短篇。", "子勉如不已，斯文終可傳。"]'),
('e8661f6e-62e1-4b55-b679-5722165c763b','贈盧魯山  其二','徐積','宋','宋诗','song-poetry','','[]','一詩將兩年，不出非空然。',168,'全唐诗/poet.song.37000.json','["一詩將兩年，不出非空然。", "爲子有佳行，重爲進德篇。", "孔孟有常處，四通八達路。", "其道甚坦夷，行之莫能御。", "夜思而晝行，求至慎勿遽。", "存誠防他歧，積微從寸步。", "積之能不已，其率可馳騖。", "仁義固其常，忠信乃先具。", "正直常與游，前却慎勿顧。", "所謂氣馬者，尤宜審其御。", "孟子言最詳，揚雄亦深悟。", "勉之復勉之，子無忽吾語。", "凡我今之人，皆欲達其所。", "而况鄉閭中，待君爲處女。"]'),
('9c6cc49a-d9c5-428d-b8eb-e1a7005929f8','寄秦少游','徐積','宋','宋诗','song-poetry','','[]','子用心於我，知者蔡彥規。',48,'全唐诗/poet.song.37000.json','["子用心於我，知者蔡彥規。", "彥規今死矣，誰能述所爲。", "若說子用心，古人如此稀。", "顧我不能報，臨老形於詩。"]'),
('b88c5dfc-166e-4f16-9b68-4174b15344a5','贈錢思權  其一','徐積','宋','宋诗','song-poetry','','[]','好笑兩學官，果然作不了。',48,'全唐诗/poet.song.37000.json','["好笑兩學官，果然作不了。", "子去恐無船，我眠幸有草。", "君看野田中，閒花亦不少。", "昨日有人來，贈我吟詩藁。"]'),
('9bdf0559-3aa9-4abe-b0e8-f628f9a0878c','贈錢思權  其二','徐積','宋','宋诗','song-poetry','','[]','有客叩茅廬，時來見鰥老。',48,'全唐诗/poet.song.37000.json','["有客叩茅廬，時來見鰥老。", "今朝二十七，春風有多少。", "共子樂有餘，如何醉不倒。", "坐中忽索馬，歸慰親懷抱。"]'),
('d1c9bc0b-0b62-4673-a004-016de8115579','贈錢思權  其三','徐積','宋','宋诗','song-poetry','','[]','有客懷剛義，無物能干抱。',48,'全唐诗/poet.song.37000.json','["有客懷剛義，無物能干抱。", "堂有白頭親，惟憂甘旨少。", "其家十五口，行計亦草草。", "也須謀饘粥，不可使饑倒。"]'),
('a092d99f-baef-4cf7-94c9-56bdbf17885f','贈錢思權  其四','徐積','宋','宋诗','song-poetry','','[]','同室與鄉鄰，勢與他人異。',48,'全唐诗/poet.song.37000.json','["同室與鄉鄰，勢與他人異。", "義當同子去，豈敢徇於利。", "但恐登舟時，無以慰親意。", "沽與玉甕醅，豈煩酒官義。"]'),
('23267b9f-22b2-4e76-90ba-d2272021f00b','贈袁評事','徐積','宋','宋诗','song-poetry','','[]','今年七十歲，歲歲增康寧。',36,'全唐诗/poet.song.37000.json','["今年七十歲，歲歲增康寧。", "人閒有壽鶴，天上有壽星。", "更若欲齊椿，但看南華經。"]'),
('da3d5bce-0752-43cf-a996-08aca6952554','大河上蔣寶文','徐積','宋','宋诗','song-poetry','','[]','大河者大事，我輩安足明。',48,'全唐诗/poet.song.37000.json','["大河者大事，我輩安足明。", "野人好狂言，夫子知本情。", "念此有官守，不可從公行。", "心方愧古人，渤海之王生。"]'),
('7b57fddf-647c-4484-922e-2e759ff45420','寄王十七丈','徐積','宋','宋诗','song-poetry','','[]','舒州懷寧尉，是我丈人行。',48,'全唐诗/poet.song.37000.json','["舒州懷寧尉，是我丈人行。", "兩遺小書去，其禮若非抗。", "何德稱殊禮，胡顔拜首貺。", "更致附吟哦，以問公無恙。"]'),
('574b3e3d-e364-45a1-ab8a-79aeaecdcb70','寄張芸叟','徐積','宋','宋诗','song-poetry','','[]','豳有張芸叟，言行俱無邪。',48,'全唐诗/poet.song.37000.json','["豳有張芸叟，言行俱無邪。", "攝官爲別駕，虢州仍近家。", "寄書來報我，便可取其兄。", "兩縑爲一被，同卧復同行。"]'),
('ebddb469-5c1c-4bc7-a998-8c8042920208','寄吳安中','徐積','宋','宋诗','song-poetry','','[]','十月十四日，人自江東來。',48,'全唐诗/poet.song.37000.json','["十月十四日，人自江東來。", "書詢杜微病，粟代陸生梅。", "高義有如子，卹病而救災。", "老身將入土，報之何如哉。"]'),
('1c540509-7a78-4ca5-b8f0-b96a1a93953c','贈魏教諭','徐積','宋','宋诗','song-poetry','','[]','酒官幸得風流掾，任貴須沽不須賤。',48,'全唐诗/poet.song.37000.json','["酒官幸得風流掾，任貴須沽不須賤。", "共君吟笑醉春風，詩似陽春共黄絹。", "祝君長作白頭吟，台背肌膚凍黧面。"]'),
('ad58fbe8-1e34-4beb-bce7-faae43d235c3','贈陳誠父','徐積','宋','宋诗','song-poetry','','[]','東海陳誠父，回身過山陽。',48,'全唐诗/poet.song.37000.json','["東海陳誠父，回身過山陽。", "登時來見我，言恕而行方。", "主人太山野，薄意似酒漿。", "仍勸客莫飲，恐酒有所傷。"]'),
('35d31ac8-7704-4128-b32f-d2dd3a0f3e4a','贈張才父','徐積','宋','宋诗','song-poetry','','[]','自笑陶潜輩，相逢却論兵。',72,'全唐诗/poet.song.37000.json','["自笑陶潜輩，相逢却論兵。", "誰知陣上客，時訪郭西生。", "喜公抱忠義，顧我非縱橫。", "今來求篤論，古事聊一評。", "奇正要兩存，衆寡不可輕。", "兵間有萬變，所慙思弗精。"]'),
('8381feb6-32e9-488a-bfc9-8750ee46b50d','贈陳糾','徐積','宋','宋诗','song-poetry','','[]','子來別我時，送子到巷口。',48,'全唐诗/poet.song.37000.json','["子來別我時，送子到巷口。", "約去百步地，出巷更引首。", "乃與二三子，回所舍依依。", "故人情可見，何用送行詩。"]'),
('043ea661-fb79-4c8e-9113-bf754c0c9675','和蔣龍圖  其一','徐積','宋','宋诗','song-poetry','','[]','公之所設施，道德之餘事。',168,'全唐诗/poet.song.37000.json','["公之所設施，道德之餘事。", "有性給其才，無物蔽其意。", "大車積以載，牛刀迎者解。", "以要操其綱，以妙觀其會。", "善譽不盡知，善毀沒可譏。", "校之古人輩，彼若有所爲。", "公之所然者，以智不以鑿。", "其力日以裕，其濟日以博。", "至於我曹者，使相望相聞。", "猶能領官屬，携詩叩吾門。", "先看陶家柳，次看陶家菊。", "茶中許投花，坐上呼燃燭。", "顧我爲樂叟，勉我以不倦。", "我是孟東野，終附鄭公傳。"]'),
('cf5fd0d5-046a-496f-9a9a-b8cd1abcf469','和蔣龍圖  其二','徐積','宋','宋诗','song-poetry','','[]','鷁口啣波船過猛，檣幔排雲北風緊。',64,'全唐诗/poet.song.37000.json','["鷁口啣波船過猛，檣幔排雲北風緊。", "耽吟俊老繡衣寒，傳詩急使筠筒冷。", "詩同使者從何來，謝安枕上吟哦回。", "吟哦去望江南雪，雪中往往梅花開。"]'),
('6d3039c2-db69-43bb-b7c6-81fc717ab529','和李自明','徐積','宋','宋诗','song-poetry','','[]','自明多奇辭，更爲奇怪歌。',369,'全唐诗/poet.song.37000.json','["自明多奇辭，更爲奇怪歌。", "好共盧仝騎綠耳，吟哦直上崑崙坡。", "更令張旭輩，醉中揮筆書嵯峨。", "安用呼老子，兩脚跨橐駝。", "有命得堅疾，無術除沉痾。", "一從水木迭用事，肺爲廢物囚網羅。", "而況小暑之後有初伏與大暑，更添熱厲兼昏魔。", "骨閒赫赤炭丸走，皮上烘炙鐵手摩。", "有時一屋之內但覺湯火近，不辨鑊與鍋。", "手持匕箸腹先脹，酒到喉嚨顔已酡。", "青黏漆葉無所用，鳥伸熊顧其奈何。", "五臟孰云可湔洗，百骸終恐生蟲窠。", "脫身難上赤霄路，夢魂忽泛滄溟波。", "滄溟盡處是星漢，有人常弄機與梭。", "枯槎去後更無客，歷歷赤桂來經過。", "取得良書掛牛角，持將斗柄吞明河。", "但把明河吞滿腹，不去龍田拾瑶玉。", "便控鼇頭出海來，霞點雲痕在眉目。", "起穿兩柳行青莎，怪歌使我須吟哦。", "吟哦作文非小事，要爲法度後世無譏訶。", "大抵文章本諸內，歸之無憾斯平和。", "擬之於經輔之友，精講明辯相切磋。", "君雖病肝，其心可用教。", "我雖病肺，心亦不自阿。"]'),
('40c34fc6-c99d-4e30-b116-c48ce3121f75','和倪敦復  其一','徐積','宋','宋诗','song-poetry','','[]','一別北軒君，參商與胡越。',288,'全唐诗/poet.song.37000.json','["一別北軒君，參商與胡越。", "先聲從西來，塵榻爲君拂。", "吟行時引頭，吟坐即摇筆。", "未見問行人，既見惜短日。", "緩頰相問勞，劇談盡忠切。", "耳竅雖塞豆，口角自流沫。", "崔子祥而論，祝令閔且說。", "籬閒菊參差，樽中酒澄澈。", "把酒互相勸，投菊兩不絕。", "客主莫分辨，僮僕亦娛悅。", "若比龐公家，妻子不羅列。", "悔令唱驪歌，惜不醉寒月。", "念子爲令尹，行義高突兀。", "當官志不回，斂版腰可折。", "與俗皆背馳，而慕古遺烈。", "竹節生便堅，劍氣久已發。", "其時東野外，頻煩大夫謁。", "篇章日相尋，氣勢誰可遏。", "仍携大軸來，使我兩目閱。", "人事有合離，歲月成恍惚。", "逸翮騰方高，駿馬足不蹷。", "子實不我忘，我亦不子忽。", "與之氣類同，見之心欲豁。", "金城不可破，鐵槊不可奪。"]'),
('5fedd7cc-92eb-422c-ae43-e353fbf4289a','和倪敦復  其二','徐積','宋','宋诗','song-poetry','','[]','縣令醉時花滿睫，縣令卧時雲滿榻。',144,'全唐诗/poet.song.37000.json','["縣令醉時花滿睫，縣令卧時雲滿榻。", "其時北面竹軒凉，雨聲霎罷風颯颯。", "美人爭唱醒酒歌，濕透紅綃聲未匝。", "玉容沃以沉香水，瑶槃凍屑珠璣雜。", "魂夢適從何處來，帳中猶把浮雲踏。", "自說騎鸞向閬風，到時玉洞諸仙合。", "只被桃花迷殺人，行顧瑶關忽雙闔。", "枕上猶能走筆吟，纍纍吐出珠千蛤。", "壓倒唐時白與元，兩翁相顧如何答。"]'),
('6e4cd501-5c62-4e9b-8f34-f6e50c4ebef9','答范君錫  其一','徐積','宋','宋诗','song-poetry','','[]','醉中吟問風流掾，酒價太高何日賤。',80,'全唐诗/poet.song.37000.json','["醉中吟問風流掾，酒價太高何日賤。", "如何使我典衣沽，詩人未有春衫絹。", "詩人有酒不須歌，自有春風四面多。", "山陽才吏倪大夫，煩君爲我特致書。", "正月臘寒猶未去，諸君吟坐待圍爐。"]'),
('5814bee1-c58b-4d25-8073-c1b9e052fb30','答范君錫  其二','徐積','宋','宋诗','song-poetry','','[]','報漫翁，無錢可沽酒。',98,'全唐诗/poet.song.37000.json','["報漫翁，無錢可沽酒。", "青衫典不得，黄卷賣不售。", "借問公田中，秫米種幾斗。", "休管將來旱與水，莫爲妻兒種粳米。", "兄來留下二萬錢，送與酒家主人未。", "不然何計見春風，空將花插白頭翁。", "簿書營營幾時了，何如載酒訪揚雄。"]'),
('6a0068cc-9ed9-4284-805d-e04f3e50db40','答范君錫  其三','徐積','宋','宋诗','song-poetry','','[]','漫翁俊逸幾無偶，安得吟詩類中酒。',64,'全唐诗/poet.song.37000.json','["漫翁俊逸幾無偶，安得吟詩類中酒。", "却是蓬頭枕上吟，不知還有人嗔否。", "漫翁春思今如何，但覺新詩老更多。", "却應笑我粗豪甚，頗似將軍出塞歌。"]'),
('4bbf8549-2cc9-4fcd-ad30-f0489ad6d06b','呈周裕之','徐積','宋','宋诗','song-poetry','','[]','海陵周裕之，又爲淮上客。',48,'全唐诗/poet.song.37000.json','["海陵周裕之，又爲淮上客。", "來尋南郭路，不見張宜伯。", "宜伯在京口，不知誰與遊。", "時時應北望，只可見瓜州。"]'),
('54fc99b0-b1d6-4705-8627-c28768d2c842','恨君不作洛陽客','徐積','宋','宋诗','song-poetry','','[]','余雖不作洛陽客，自有吟魂兼醉魄。',160,'全唐诗/poet.song.37000.json','["余雖不作洛陽客，自有吟魂兼醉魄。", "吟魂醉魄御風行，看盡千花萬花色。", "寧知洛浦有人留，挽定春衫歸不得。", "脫身誤入嵩山中，山中逢見白鬚翁。", "歡然借我雙金童，須臾引入花林中。", "亂花深處迷西東，花光照天香薰空。", "金盆挹酒雙瑶鍾，酒酣邀我吟春風。", "紺雲千丈揮玉虹，搜羅萬變窮神功。", "有人飛下紫霄峰，酬詩解佩聲玲瓏。", "余方却步不與語，笑余不似鄭交甫。"]'),
('894cd259-ea64-4ba4-9fa1-ebe787b32b71','答錢思權','徐積','宋','宋诗','song-poetry','','[]','兩箇學官位，都來一步地。',48,'全唐诗/poet.song.37000.json','["兩箇學官位，都來一步地。", "青眼與白眼，五日不相視。", "子爲道塗行，我爲刀筆吏。", "兩者較勤勞，大同而小異。"]'),
('4620e855-2a68-40e3-9c5d-603072435c62','妾薄命','徐積','宋','宋诗','song-poetry','','[]','妾家本住吳山側，曾與吳姬鬬顔色。',160,'全唐诗/poet.song.37000.json','["妾家本住吳山側，曾與吳姬鬬顔色。", "燕脂兩臉綠雙鬟，有貌有才爲第一。", "十歲能吟謝女詩，十五爲文學班姬。", "十六七後漸多難，一身困瘁成流離。", "爾後孤貧事更多，教妾一身無奈何。", "其時癡騃被人誤，遂入朱門披綺羅。", "朱門美人多嫉妒，教妾一身無所措。", "眉不敢畫眼不擡，飲氣吞聲過朝暮。", "受盡苦辛人不知，却待歸時不得歸。", "羅衣滿身空挹淚，何時却著舊時衣。"]'),
('015370e7-c61a-4819-908e-673c5c627445','如今','徐積','宋','宋诗','song-poetry','','[]','如今八月九月時，吟翁還愛黄菊籬。',64,'全唐诗/poet.song.37000.json','["如今八月九月時，吟翁還愛黄菊籬。", "及見清風楊柳枝，時時對柳呼酒卮。", "頭顱半禿牙齒稀，村田未去尋牛衣。", "爲唱驪駒不及時，主人先道無庸歸。"]'),
('53dbe077-164c-46ad-a90d-1070bc8dc2e4','夢中作','徐積','宋','宋诗','song-poetry','','[]','詩翁吟袖忽翩然，使脫紅塵騰紫烟。',96,'全唐诗/poet.song.37000.json','["詩翁吟袖忽翩然，使脫紅塵騰紫烟。", "一身病骨如生翅，兩道銀河不用船。", "奔星相隨趁明月，鳴鸞引去追飛仙。", "琅玕樹下夜宴起，雲童爲汲瑶山水。", "仍遣詩筒寄閬風，詩筒落下烟霞中。", "人閒知是吟哦翁，舉頭齊望青冥空。"]'),
('3662aee5-41ef-44b5-80ee-e271a06d8d17','誰何哭','徐積','宋','宋诗','song-poetry','','[]','誰何哭，哀且危。',139,'全唐诗/poet.song.37000.json','["誰何哭，哀且危。", "白頭母，朱顔兒。", "兒忽捨母去，母何用生爲。", "架上有兒書，篋中有兒衣。", "兒聲不復聞，兒貌不復窺。", "誰何哭，哀復哀。", "腸未絕，心先摧。", "母恃兒爲命，兒去不復來。", "朝看他人兒，暮看他人子。", "一日一夜閒，十生九復死。", "君不見昨夜人靜黄昏時，含辛抱痛無人知。", "其時忽不記兒死，倚門引頸望兒歸。"]'),
('7a53348b-6102-4c6a-9c17-d8fd0e5da838','客去','徐積','宋','宋诗','song-poetry','','[]','客去即吟詩，吟詩即飲酒。',48,'全唐诗/poet.song.37000.json','["客去即吟詩，吟詩即飲酒。", "時時進一盃，往往積成斗。", "貪憶洛陽花，忘却江頭柳。", "借問別離客，得似尋常否。"]'),
('d74ceb33-269c-49b9-84f1-d2e79156f75b','醉中詠牡丹','徐積','宋','宋诗','song-poetry','','[]','此花未開時，美子藏深閨。',118,'全唐诗/poet.song.37000.json','["此花未開時，美子藏深閨。", "香心若無有，深淺何由知。", "前日花忽開，美人放出深閨來。", "春風盡日不相管，鶑是郎兮蝶是媒。", "誰將金錢擲西子，笑中不掩燕脂腮。", "君王親執紫金盞，太真又醉白瑶臺。", "此花萬態不可說，莫教容易爲塵埃。", "我心雖然淡如水，爲花一醉何辭哉。"]'),
('24a8f294-738c-4596-8406-fc1c1f0f070e','楊柳枝','徐積','宋','宋诗','song-poetry','','[]','楊柳楊柳復楊柳，舞罷青衫困垂手。',64,'全唐诗/poet.song.37000.json','["楊柳楊柳復楊柳，舞罷青衫困垂手。", "相如病思最多情，沈約才清更酣酒。", "君看好鳥鳴枝閒，日與春風問安否。", "清明前後峭寒時，好把香綿閒抖擻。"]'),
('a284f3b1-5a25-486d-883c-2e7f6256d368','睡  其一','徐積','宋','宋诗','song-poetry','','[]','睡入凈域居，夢有殊方樂。',48,'全唐诗/poet.song.37000.json','["睡入凈域居，夢有殊方樂。", "不須汎海裝，去採神仙藥。", "手闢黄金闕，足踏巨鼇殻。", "更作西方行，真到崑崙脚。"]'),
('e3d9a149-ecb5-418d-a46a-670a31fb2c25','睡  其二','徐積','宋','宋诗','song-poetry','','[]','人莫嗟勞生，睡者吾一樂。',48,'全唐诗/poet.song.37000.json','["人莫嗟勞生，睡者吾一樂。", "困來入醉鄉，夢去得仙藥。", "瘦脛鶴伸足，老背龜側殻。", "日出紙窗明，烟霞忽失脚。"]'),
('1c779f0b-9202-49a6-9eea-08d2c6c8ec45','醉題友人詩後','徐積','宋','宋诗','song-poetry','','[]','可惜兩眼青，不見一室白。',56,'全唐诗/poet.song.37000.json','["可惜兩眼青，不見一室白。", "爲子吟喉乾，使我酒面赤。", "醉中一夜騎鸞鳳，麻姑空敞桃花洞。", "南樓下去北軒中，西關放過東臯夢。"]'),
('26b11b72-0708-45a6-a00e-916f63f937c5','同門人夜看花示盧魯山','徐積','宋','宋诗','song-poetry','','[]','罷酒已半夜，重來慰幽花。',48,'全唐诗/poet.song.37000.json','["罷酒已半夜，重來慰幽花。", "可惜遭風雨，太半成泥沙。", "移坐環其叢，含香嚼其華。", "五人摘滿手，歸來千萬葩。"]'),
('7d6bc35f-13b3-47c6-a748-9364b612d65f','謝人惠梅花','徐積','宋','宋诗','song-poetry','','[]','江南費盡春風力，嶺頭驛使無消息。',32,'全唐诗/poet.song.37000.json','["江南費盡春風力，嶺頭驛使無消息。", "有人贈我一枝花，滿面春風與春色。"]'),
('cb901f04-9f4d-43f7-8ed6-eb0b0dc1b351','代簡招魏君','徐積','宋','宋诗','song-poetry','','[]','詩老今朝頗安否，且來同酌一盃酒。',32,'全唐诗/poet.song.37000.json','["詩老今朝頗安否，且來同酌一盃酒。", "雖無鼓吹相歡娛，自可笑吟相拍手。"]'),
('844f0f28-f812-4044-a018-0e7d4f29a3fa','偶題','徐積','宋','宋诗','song-poetry','','[]','軺車使者良苦辛，手持漢節入紅塵。',312,'全唐诗/poet.song.37000.json','["軺車使者良苦辛，手持漢節入紅塵。", "青嶂斷時初見日，黄沙飛處不逢人。", "妾身安在何足卹，紅簾翠幙遮羅裙。", "男兒大抵貴忠義，而況委質爲人臣。", "不憂死節奉王事，但恐偷生爲妾身。", "妾嫁郎時尚癡騃，可惜黄金如土賣。", "誤將玉體與儇兒，身卧汙泥佩蘭茝。", "無禮無義將奈何，但抱羅衣千萬带。", "欲令高節比梁鴻，說與墦閒仍不改。", "莫嗟遠別離，離合良有時。", "所願君自愛，養取胸中奇。", "莫恨別離久，願君自持守。", "所守義或非，得之適爲醜。", "君莫愛妾身，妾以死奉君。", "一片玉爲面，百尺布裁裙。", "子亦當何如，爲國愛其軀。", "一節死不變，如妾事吾夫。", "束带人待行，牽衣未能別。", "遺子酒一卮，聽我歌三闋。", "其一獻君壽，白髪爲君偶。", "其二祝康寧，玉體和而平。", "其三無累家，無令妾咨嗟。", "不患不富貴，所患入於邪。"]'),
('eae6822a-0c73-4815-ac2b-9271d5288d24','三月三日作','徐積','宋','宋诗','song-poetry','','[]','今朝乃是三月三，三分春色二分去。',160,'全唐诗/poet.song.37000.json','["今朝乃是三月三，三分春色二分去。", "一分春色能幾多，吟翁老病無如何。", "却思翁在秦中時，年少愛遊山與溪。", "其時人物如神仙，手携酒榼擎花枝。", "人不惜錢似癡騃，乞者與之見者買。", "人人俱著好衣裳，處處紛紛成五采。", "山上山前鬧如市，人半歸時城欲閉。", "西溪最是柏坡頭，人家占却無閒地。", "更有幾處入城早，清明上巳踏芳草。", "若無疾病與死亡，人家大抵無煩惱。"]'),
('6cbe16ce-32d2-4464-9b72-0d048f1d5b00','雁從何處來','徐積','宋','宋诗','song-poetry','','[]','雁從何處來，正望東南飛。',48,'全唐诗/poet.song.37000.json','["雁從何處來，正望東南飛。", "毛閒認白露，肚下看殘暉。", "浮雲共烟水，日夜爲所依。", "衡陽是故山，但恐故人稀。"]'),
('232bc95a-ff5b-4dc1-a833-35c39793cab8','金沙行','徐積','宋','宋诗','song-poetry','','[]','關西不雨凡幾城，孜孜誰獨勞其情。',96,'全唐诗/poet.song.37000.json','["關西不雨凡幾城，孜孜誰獨勞其情。", "鎮潼太守真賢明，驅車遠有金沙行。", "春空破碧幢高旌，東風環珮鏘瑶瓊。", "溪翁不釣童不耕，隆隆千里謳歌聲。", "從容禱罷殘霞橫，蓮花頂上微雲生。", "雲兮雲兮雲莫停，霈然一灑塵埃清。"]'),
('67e60890-9f61-4657-8d54-ffb22bd8df9c','夢李白','徐積','宋','宋诗','song-poetry','','[]','烏紗巾，紫綺裘。',40,'全唐诗/poet.song.37000.json','["烏紗巾，紫綺裘。", "夢中太白從吾遊，陶陶爛醉江山秋。", "半夜起來覓不見，頭背長安淚如霰。"]'),
('c68b41ef-f5f4-4458-90a4-d692382fc05f','好笑南郭翁','徐積','宋','宋诗','song-poetry','','[]','好笑南郭翁，白鬢愛楊柳。',132,'全唐诗/poet.song.37000.json','["好笑南郭翁，白鬢愛楊柳。", "如今十月後，猶飲菊花酒。", "楊柳色漬面，菊花香漬牙。", "喉嚨溜香汁，腸胃浮香葩。", "所飲幾何酒，所吟無限詩。", "若言絲與管，便是吟哦時。", "心無一事累，意與千古期。", "一身成土木，兩脚登雲霓。", "但欲比陶潜，豈肯爲杜微。", "公有如此客，可不使公知。", "更問公安否，且喜公來歸。"]'),
('160a9f63-97a4-4c54-9407-d99f56893813','觀草  其一','徐積','宋','宋诗','song-poetry','','[]','一從有意惜庭蕪，幾日無心到楊柳。',64,'全唐诗/poet.song.37000.json','["一從有意惜庭蕪，幾日無心到楊柳。", "好色盡歸簾下翁，餘光掬與船中叟。", "紺液難從日下乾，芳姿易向霜中老。", "纔到春還車馬稀，青青勝却朱顔好。"]'),
('f7427159-dbc7-4f4f-8583-66a04950fe7b','觀草  其二','徐積','宋','宋诗','song-poetry','','[]','山前勝入樵兒手，亦勝江頭伴烟柳。',64,'全唐诗/poet.song.37000.json','["山前勝入樵兒手，亦勝江頭伴烟柳。", "閒中好步陶先生，醉裏宜眠鄭雲叟。", "我闢閒階恨不早，草正茸茸花又老。", "人心好惡任不齊，但問青紅阿誰好。"]'),
('7ace89c4-f159-488b-94a9-99039a10d40c','觀草  其三','徐積','宋','宋诗','song-poetry','','[]','觀草亦有術，可使無涯際。',48,'全唐诗/poet.song.37000.json','["觀草亦有術，可使無涯際。", "誰知簾下情，或有林閒味。", "南郭雖如此，東臯亦何異。", "便可棄衣冠，閒枕青雲睡。"]'),
('7efd1ff5-845d-4525-90c6-3556f59f48af','繡屏戲呈思權','徐積','宋','宋诗','song-poetry','','[]','先生卧內花爲屏，錦堆四面紅雲生。',48,'全唐诗/poet.song.37000.json','["先生卧內花爲屏，錦堆四面紅雲生。", "珊瑚枕上三四更，半醒半醉魂夢驚。", "安得仙葩千萬英，不是天台是武陵。"]'),
('094ef34b-1f33-4e66-bd1f-b40214d52d28','與熊熊作策寫詩','徐積','宋','宋诗','song-poetry','','[]','此是熊熊策，先題吳季詩。',36,'全唐诗/poet.song.37000.json','["此是熊熊策，先題吳季詩。", "季自題學書，如此怜吾兒。", "季有古人風，怜兒心可知。"]'),
('ee8c6057-fcb9-4d07-ab40-9443675c64dc','莫望草','徐積','宋','宋诗','song-poetry','','[]','莫望坡頭日，日色催行人。',48,'全唐诗/poet.song.37000.json','["莫望坡頭日，日色催行人。", "莫望河上草，草色空連雲。", "雲邊芳草路，茫然是何處。", "行人望不見，草色自如故。"]'),
('c4868aa7-f799-4aa4-90c3-5079262eebbe','書樂陵王伯年太子傳','徐積','宋','宋诗','song-poetry','','[]','酷哉武成，枉殺樂陵。',170,'全唐诗/poet.song.37000.json','["酷哉武成，枉殺樂陵。", "一步一杖，遶堂土頳。", "投之池中，池水盡赤。", "其妃哀號，至死不食。", "其指其手，拳不可擘。", "九院之後，小屍猶在。", "骨碎肉爛，緋袍金带。", "一袍有靴，一髻有解。", "哀哉嗚呼，此兒何罪。", "賊人之孤，負人之託。", "毒如豺狼，險如谿壑。", "身自爲孽，其子受之。", "扼咽蒙頭，連頸橫屍。", "報應如此，其來勿問。", "與其自殺，不容尺寸。", "我哀其愚，作爲此詩。", "永貽厥鑒，勿爲險欺。"]'),
('c47b38b6-07dc-49cb-9b83-3814af85b984','哭崔刑部','徐積','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','前年離長安，與公爲死訣。',172,'全唐诗/poet.song.37000.json','["前年離長安，與公爲死訣。", "長安門外長樂坡，胸中壯氣渾消磨。", "其時夜宿灞橋上，夢中勒馬猶西望。", "江淮之上情愈勞，去年曾寄西山高。", "今年今日春將歸，春風不似秋風時。", "山陽數月雨不止，泥深窮巷行人稀。", "忽聞公死終南山，坐中忽過東西關。", "黄泉一去幾萬里，吁嗟公兮何時還。", "盂有水兮無食薦，烹有茶兮無酒奠。", "魂兮來兮不可知，來若飄風去如電。", "報恩之事終有期，未必儒生只貧賤。"]'),
('488aedfe-49aa-48ae-a31f-42775cf0b9a2','哭狗狗','徐積','宋','宋诗','song-poetry','','[]','東門園上春風微，醇醇塚上花成圍。',62,'全唐诗/poet.song.37000.json','["東門園上春風微，醇醇塚上花成圍。", "醇醇一去不復返，食一盂兮酒一卮。", "悲莫悲乎今日，傷莫傷乎舊衣。", "思其言而想其貌，吁嗟乎天殤吾兒。"]'),
('55470e31-b2f2-42b6-aecd-c4ad395f6f9b','偶述','徐積','宋','宋诗','song-poetry','','[]','罇中一勺水，其味誠淡薄。',48,'全唐诗/poet.song.37000.json','["罇中一勺水，其味誠淡薄。", "盡日設重席，無人與酬酢。", "東鄰有旨酒，金壺而玉爵。", "門前羅軒車，陶陶一何樂。"]'),
('93de17f5-111e-4db5-9900-db3a254913ce','閔災詞','徐積','宋','宋诗','song-poetry','','[]','神地出淵泉，商羊向天舞。',176,'全唐诗/poet.song.37000.json','["神地出淵泉，商羊向天舞。", "電火燒黑空，雷車震金鼓。", "大塊噫風吹黄沙，黄沙須臾化爲霧。", "此時陰氣一何盛，蚓噓雲兮鬼嘯雨。", "雨繩繩兮雲蒸蒸，天慘慘兮朝復莫。", "嗟爾長淮之民，何生而苦。", "方饉而饑，方疫而愈。", "乃有此患，普及於汝。", "地湧水泉，天降淫雨。", "浩浩之勢，包山逾阜。", "汝居無廬，汝耕無土。", "汝口嗷嗷，其誰安訴。", "吾聞堯水凡九年，民雖昏墊不失所。", "願我君王發德音，一變悲號作歌舞。"]'),
('efd89be6-e0ed-45d5-bd01-fe3bf4c6238c','復古頌','徐積','宋','宋诗','song-poetry','','[]','其難其難，道亦大艱，或缺或完。',330,'全唐诗/poet.song.37000.json','["其難其難，道亦大艱，或缺或完。", "戰國盜竊，嬴秦暴孽，遺風餘烈。", "所存幾何，枯株之柯，填源之波。", "漢得天下，方有學者，其徒蓋寡。", "孝文孝武，稍稍復古。", "仲舒之伍，巉嵒崢嶸。", "窮先王經，道乃大明。", "西漢之風，與三代同，實儒之功。", "晉魏寇讎，學者寖浮，不源而流。", "齊梁之閒，斧斫刀剜，大樸益殘。", "隋唱唐和，元氣盡破，爲斯文禍。", "學者皇皇，賦道大光，六經逃藏。", "冶容艷膚，繡衣紅襦。", "衆奔羣趨，若大有爲。", "謂之背馳，終身寒饑。", "物不終盛，皇帝有命，萬口齊慶。", "復明經科，大張網羅，海隅山阿。", "麟之奔奔，鳳之軒軒，龍之蜿蜿。", "會稽之竹，崑崙之玉，牛山之木。", "逄蒙執射，伯樂進馬，造父御駕。", "琴瑟既更，韶音遊聲，復還於今。", "唐虞之謨，夏商之書，其庶幾乎。", "天下之賦，摧縮消沮，迷失道路。", "革萬世弊，興萬世利，繄我皇帝。"]'),
('85a694bc-4976-4120-bd40-a72f799ae831','暴雨','徐積','宋','宋诗','song-poetry','','[]','玉女投壺天大笑，千尋火炬當空照。',48,'全唐诗/poet.song.37000.json','["玉女投壺天大笑，千尋火炬當空照。", "老龍行遲天忽怒，雷車壯士渹連鼓。", "黑鱗鐵甲十萬許，急把銀河傾作雨。"]'),
('a27a0f84-565a-47f3-a335-d04dba4fbe7a','思誠齋夜坐','徐積','宋','宋诗','song-poetry','','[]','胸中不平氣，忽然凌太虛。',24,'全唐诗/poet.song.37000.json','["胸中不平氣，忽然凌太虛。", "無人哭一聲，半夜思唐衢。"]'),
('959d3e14-253a-470a-9fce-ad5398e2cf9d','逃席','徐積','宋','宋诗','song-poetry','','[]','主人雖好事，其來不知幾。',48,'全唐诗/poet.song.37000.json','["主人雖好事，其來不知幾。", "胡不築高垣，胡不關重扉。", "不敢直道退，遂由邪徑歸。", "飲過即有疾，何以慰親闈。"]'),
('b70e03a5-cd31-460f-90d0-c52d35a6a177','有客何爲者','徐積','宋','宋诗','song-poetry','','[]','有客何爲者，不穿亦不鑿。',48,'全唐诗/poet.song.37000.json','["有客何爲者，不穿亦不鑿。", "匣中是何物，塵埃漬鋒鍔。", "登山守直道，荆榛與溝壑。", "安得百畝田，以就斑衣樂。"]'),
('8d82e5f0-600e-453f-8c3e-a0b0d28e7133','周長官出二子詩相示','徐積','宋','宋诗','song-poetry','','[]','丹山一鳳雙雛生，十分羽翼三分成。',64,'全唐诗/poet.song.37000.json','["丹山一鳳雙雛生，十分羽翼三分成。", "未能飛奮先能鳴，纔鳴不作凡鳥聲。", "羽毛安得相混并，鵬霄九萬當冥冥。", "簫韶九奏儀王庭，光華舜旦魁羣經。"]'),
('720d2201-e1b8-4cb3-a47a-dae127cdf4ab','又贈二子','徐積','宋','宋诗','song-poetry','','[]','周氏二子千人英，余觀其詩余輒驚。',96,'全唐诗/poet.song.37000.json','["周氏二子千人英，余觀其詩余輒驚。", "渾然骨格已老成，凜乎辭句冰霜清。", "不然何以知君名，余知必作詩之精。", "今觀君詩眉且低，文章老大無人知。", "少年便莫相輕欺，丈夫壯氣如虹蜺。", "古之庸者猶雄飛，青雲自有相逢時。"]'),
('cf828183-7b29-4dfa-80a0-2f4331c03adc','封本堂','徐積','宋','宋诗','song-poetry','','[]','物無其實，其名弗至。',90,'全唐诗/poet.song.37000.json','["物無其實，其名弗至。", "實以先之，名以次之。", "事無其實，君子弗名。", "可表其實，可考其行。", "名以表之，行以考之。", "信斯名者，斯民可見。", "樂斯名者，斯堂可燕。", "可燕可歌，使臣之光。", "有孚實惠，民悅無疆。"]'),
('42927f16-1f34-4126-956f-c66e8db2dfde','書江氏芝草記後','徐積','宋','宋诗','song-poetry','','[]','天門嶪嶪，洞達通徹。',240,'全唐诗/poet.song.37000.json','["天門嶪嶪，洞達通徹。", "地雖幽陰，明白昭晰。", "有來即應，無往弗答。", "或旋其日，或逾厥月。", "或降吉祥，或出妖孽。", "或生美好，或産醜缺。", "或使合并，或令分裂。", "凡皆若此，其故可說。", "人之所喜，神則歡悅。", "和氣流暢，精粹凝結。", "草木受之，形類孤絕。", "其無所苟，而不徒設。", "爰有江氏，世載其德。", "子子孫孫，能敬勿失。", "其叔有令，如出諸意。", "戮力同心，道路相繼。", "二十六喪，收斂聚會。", "在圉之北，同日俱痤。", "迺有二物，以彰厥美。", "其一維何，是曰靈芝。", "如蓋上設，如杠下持。", "其色黄紫，其光陸離。", "其肉堅厚，弗柯弗衰。", "其二維何，是曰連理。"]'),
('db9ea2e0-d11b-485e-a606-c3daaab11821','新安呂公尚書夫人墳','徐積','宋','宋诗','song-poetry','','[]','彼美新安，有水有山。',130,'全唐诗/poet.song.37000.json','["彼美新安，有水有山。", "有墳巋然，百五十年。", "爰有曾孫，赤韍朱軒。", "來守茲土，以慰斯墳。", "掃除必躬，奉祠必親。", "水毛陸産，膋牲上尊。", "百物皆具，千兵駿奔。", "觀者如堵，從者如雲。", "心追無窮，誠通無垠。", "溟漠之魄，恍惚之魂。", "如闢其塗，如啟其門。", "如興于寢，如作于室。", "如出黄泉，如見白日。"]'),
('637934af-075c-48e7-a265-a444f0a57d81','謝秀才晦菴','徐積','宋','宋诗','song-poetry','','[]','山有武夷，水有建溪。',30,'全唐诗/poet.song.37000.json','["山有武夷，水有建溪。", "有猿有鶴，有菴可棲。", "有菴可棲，云乎不歸。"]'),
('f14ff676-a21f-4dad-9e0c-91d9de0ded4e','哀吟贈蔡子驤女','徐積','宋','宋诗','song-poetry','','[]','蔡氏之子，彼仲女者。',240,'全唐诗/poet.song.37000.json','["蔡氏之子，彼仲女者。", "考之古今，如仲者寡。", "有德之容，有德之性。", "所好所習，一出於正。", "貌莊而麗，氣溫而醇。", "女子之中，而有斯人。", "慈良端厚，內敏而重。", "終日寡言，亦不戲弄。", "字無難易，所見輒識。", "不知此女，從何而得。", "讀釋氏書，欣然有適。", "身之所有，皆出自然。", "如何不幸，不假之年。", "揚州道中，死於六月。", "二十七日，暑氣酷烈。", "二十九日，三更大殮。", "形神如生，體亦不變。", "其氣甚潔，其香甚郁。", "附於身者，何用珠玉。", "不知此女，而往何處。", "杳杳冥冥，雲霞烟霧。", "世之所有，則維其常。", "若斯人者，獨秀孤芳。", "吾於其母，是爲內兄。"]'),
('fce1ad0b-b34d-4b17-b7a3-fa9ad6058657','題淮陰泰山行宮廟','徐積','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','泰山隆隆，作鎮于東。',40,'全唐诗/poet.song.37000.json','["泰山隆隆，作鎮于東。", "有如配林，在淮之陰。", "厥廟維嚴，厥貌維肖。", "斯民奉之，是爲別廟。"]'),
('cd848a90-495c-4c93-9293-f59584724755','登淮陰古城','徐積','宋','宋诗','song-poetry','','[]','此城不可名甘羅，淮陰侯國冤忿多。',32,'全唐诗/poet.song.37000.json','["此城不可名甘羅，淮陰侯國冤忿多。", "其氣鬰鬰而勃勃，遂令平地生嵯峨。"]'),
('15e7655e-cd2e-47f1-9c46-2ef263b79db0','愛愛歌','徐積','宋','宋诗','song-poetry','','[]','吳越佳人古云好，破家亡國可勝道。',384,'全唐诗/poet.song.37000.json','["吳越佳人古云好，破家亡國可勝道。", "昨夜閒觀愛愛歌，坐中歎息無如何。", "愛愛乃是娼家女，渾金璞玉埋塵土。", "歌舞吳中第一人，綠髪雙鬟纔十五。", "耳聞眼見是何事，不謂其人乃如許。", "操心危兮慮患深，半夜燈前淚如雨。", "假如一笑得千金，不如嫁作良人婦。", "桃李不爲當路花，芙蓉開向秋風渚。", "忽然一日逢張氏，便約終身不相棄。", "山可磨兮海可枯，生唯一兮死無二。", "有如樗櫟叢中木，忽然化作瀟湘竹。", "又如黄鳥春風時，遷喬木兮出幽谷。", "文君走馬來成都，弄玉吹簫纔幾曲。", "不聞馬上琵琶聲，却在山頭望夫哭。", "去年春風還滿房，昨夜月明還滿牀。", "行人一去不復返，不是江山歧路長。", "前年猶惜金縷衣，去年不畫深燕脂。", "今年今日萬事已，鮫綃翡翠看如泥。", "一女二夫兮妾之所羞，不忠於所事兮其將何求。", "蛾眉皓齒兮乃妾之讎，不如無生兮庶幾無尤。", "喓喓草蟲兮趯趯阜螽，靡不有初兮鮮克有終。", "鴛鴦于飛兮畢之羅之，人閒此恨兮消何時。", "深山人迹不到處，病鸞斂翅巢空枝。"]'),
('f9d5f458-b885-443e-a401-97ec4fd87c5a','一般花下飲一盞','徐積','宋','宋诗','song-poetry','','[]','一般花下飲一盞，但是花開不須揀。',32,'全唐诗/poet.song.37000.json','["一般花下飲一盞，但是花開不須揀。", "亂紅亂翠已迷人，猶望桃源迴醉眼。"]'),
('571c2977-624d-4f90-a453-293489b26292','題寄亭','徐積','宋','宋诗','song-poetry','','[]','大抵人閒同一寓，外物之來寓中寓。',306,'全唐诗/poet.song.37000.json','["大抵人閒同一寓，外物之來寓中寓。", "主人於爾本無心，誰使之來誰使去。", "來時無所增吾悅，去時談笑亦不輟。", "惟有山叟與溪翁，屋裏閒雲船上月。", "一從古往成蹉跎，失之則憾得之歌。", "不從平路從風波，或遭陷穽或網羅。", "有人嚙臂遺其親，有人之楚復之秦。", "侯門灑掃寧苦辛，牛衣涕泣傷賤貧。", "誰人衒鬻來上書，誰人乞貸留公車。", "誰人入關便棄繻，誰思躣馬疾其驅。", "更有隋時二隠夫，欲將林壑謀金朱。", "倒行之輩尤可吁，當時自欲烹其軀。", "却是揚雄所性恬，誰須名字學韋賢。", "積薪可恨汲生言，不道真風任自然。", "自然處者其爲誰，以寄名亭如此奇。", "俗人所患在失之，安知達者靜者心平夷。", "達者洞然無所蔽，靜者泊然無所累。", "無蔽無累無所營，其中主者性與誠。", "登斯亭兮觀斯名，人閒萬事皆可平。"]'),
('c9a4a63a-91dc-4633-9c90-635c762b8881','耳邊啼鳥喚不起','徐積','宋','宋诗','song-poetry','','[]','耳邊啼鳥喚不起，有人醉卧春風裏。',32,'全唐诗/poet.song.37000.json','["耳邊啼鳥喚不起，有人醉卧春風裏。", "被花迷入夢魂中，却上烟霞弄瑶水。"]'),
('673823cf-3b0d-4104-96d6-aec22990db06','偶述','徐積','宋','宋诗','song-poetry','','[]','淮陰寄食卒爲將，南陽閒卧卒爲相。',32,'全唐诗/poet.song.37000.json','["淮陰寄食卒爲將，南陽閒卧卒爲相。", "孟軻之道其如何，枉尺如何直尋丈。"]'),
('64812691-ea0e-4521-9ee4-cfc695b3d5a9','有客不爲賦','徐積','宋','宋诗','song-poetry','','[]','有客不爲賦，而乃求榮階。',140,'全唐诗/poet.song.37000.json','["有客不爲賦，而乃求榮階。", "是猶適吳楚，却背東西來。", "孟郊從進士，聞者徒相咍。", "退之髪已禿，知己其誰哉。", "余獨謂不然，此事何足哀。", "但恐子之道，未足爲奇侅。", "子歌堅誠好，不爲利所回。", "得則爲顔氏，失則爲隤孏。", "爲子歌一闋，爲子酌一杯。", "余歌爲爾宜何歌，余聞日月如飛梭。", "但憂其道不到古，窮通之事余如何。"]'),
('becab23b-a879-43a0-bbcd-dbe226bb8000','八月十四夜','徐積','宋','宋诗','song-poetry','','[]','有人望月吟太虛，半夜秋風生碧蘆。',72,'全唐诗/poet.song.37000.json','["有人望月吟太虛，半夜秋風生碧蘆。", "碧蘆風起吹老桂，吟聲入月驚蟾蜍。", "明夜中秋更好吟，兔肥蟾大桂成林。", "桂兔之外有何物，玉池水到中秋溢，秋風刮水如霜滴。"]'),
('1020bafa-00ff-447c-a10d-a253e6988517','中秋月下作贈呂祕校','徐積','宋','宋诗','song-poetry','','[]','去年中秋月，與子共吟詩。',48,'全唐诗/poet.song.37000.json','["去年中秋月，與子共吟詩。", "今年中秋月，與子嗟別離。", "前書約相見，頗說中秋期。", "夜久風霜寒，對月空相思。"]'),
('f7431d5b-5df7-4465-9b63-176bedbc565d','寄汝弼','徐積','宋','宋诗','song-poetry','','[]','山陽如許大，不與我同住。',48,'全唐诗/poet.song.37000.json','["山陽如許大，不與我同住。", "翩翩雁與鴻，可惜分飛去。", "淮中極清泚，亦有洲與沚。", "一雁自安棲，一鴻望江水。"]'),
('1592d5c5-2dac-428d-896d-023efadc068e','寄張宜伯','徐積','宋','宋诗','song-poetry','','[]','空中氣候何蒼蒼，風力不勁雲不黄。',64,'全唐诗/poet.song.37000.json','["空中氣候何蒼蒼，風力不勁雲不黄。", "一冬無雪農家忙，爲憂麰麥不豐穰。", "若有雪時滿引觴，仍將詩去報庾郎。", "牢收浙帥厨中羊，恐有劍客過城隍。"]'),
('fb05aa4d-70bf-4be5-ad2f-9220ecc9fadd','漁者','徐積','宋','宋诗','song-poetry','','[]','縛竹編茅雜亂蓬，四籬俱是野花叢。',128,'全唐诗/poet.song.37000.json','["縛竹編茅雜亂蓬，四籬俱是野花叢。", "莫道江湖山色好，籬落不禁秋後風。", "秋後風從西北起，身上蓑衣冷如水。", "夫妻却在釣船中，兒孫走入蘆花裏。", "夫妻不會作活計，辛苦賣魚沽酒費。", "兒孫身上更貧窮，白日無衣夜無被。", "昨日前村酤酒處，今朝忽見無人住。", "聞道江南地更暖，移舟急望江南去。"]'),
('d73b8052-8dfd-4819-ad10-4b261a3169bc','釣者','徐積','宋','宋诗','song-poetry','','[]','有人口誦浮雲曲，手把瀟湘一竿竹。',32,'全唐诗/poet.song.37000.json','["有人口誦浮雲曲，手把瀟湘一竿竹。", "荻花洲上作茅菴，坐看江頭浪如屋。"]'),
('2c986749-cf1f-4e73-ae1e-4bc4ec035802','漁翁','徐積','宋','宋诗','song-poetry','','[]','白髪老翁心似鐵，網盡溪魚猶未歇。',32,'全唐诗/poet.song.37000.json','["白髪老翁心似鐵，網盡溪魚猶未歇。", "船中渾是賣魚錢，買酒烹魚醉明月。"]'),
('4e04a762-12d8-4a23-80e6-f6fbb62810d5','漁父樂','徐積','宋','宋诗','song-poetry','','[]','水曲山隈四五家，夕陽烟火隔蘆花。',32,'全唐诗/poet.song.37000.json','["水曲山隈四五家，夕陽烟火隔蘆花。", "漁唱歇，醉眠斜，綸竿蓑笠是生涯。"]'),
('2daf7dd1-316d-487e-aaf0-17bb4e60babe','漁父樂 無一事','徐積','宋','宋诗','song-poetry','','[]','見說紅塵罩九衢，貪名逐利各區區。',32,'全唐诗/poet.song.37000.json','["見說紅塵罩九衢，貪名逐利各區區。", "論得失，問榮枯，爭似儂家占五湖。"]'),
('c7fc4209-8e66-4d33-88df-58fe6e7d35eb','漁父樂 堪畫看','徐積','宋','宋诗','song-poetry','','[]','討得漁竿買得船，歸休何必待高年。',32,'全唐诗/poet.song.37000.json','["討得漁竿買得船，歸休何必待高年。", "深浪裏，亂雲邊，只有逍遥是水仙。"]'),
('e0db0ee7-7582-4023-b9a1-dab5de260b7e','漁父樂 誰學得','徐積','宋','宋诗','song-poetry','','[]','飽則高歌醉即眠，只知頭白不知年。',32,'全唐诗/poet.song.37000.json','["飽則高歌醉即眠，只知頭白不知年。", "江遶屋，水隨船，買得風光不著錢。"]'),
('7b437037-8504-4ce4-97f2-1cb5697f3fc9','漁父樂 君看取','徐積','宋','宋诗','song-poetry','','[]','管得江湖占得山，白雲同散學雲閒。',32,'全唐诗/poet.song.37000.json','["管得江湖占得山，白雲同散學雲閒。", "清旦出，夕陽還，不知身在畫屏閒。"]');
